    static let card = adaptive(light: (0.963, 0.954, 0.938), dark: (0.090, 0.129, 0.110))
    static let foreground = adaptive(light: (0.084, 0.156, 0.120), dark: (0.922, 0.906, 0.878))
    static let muted = adaptive(light: (0.936, 0.925, 0.904), dark: (0.141, 0.180, 0.161))
    static let mutedForeground = adaptive(light: (0.405, 0.495, 0.450), dark: (0.604, 0.569, 0.494))
    static let primary = adaptive(light: (0.132, 0.308, 0.220), dark: (0.392, 0.706, 0.549))
    static let secondary = adaptive(light: (0.800, 0.500, 0.200), dark: (0.675, 0.451, 0.224))
    static let accent = adaptive(light: (0.910, 0.490, 0.190), dark: (0.824, 0.447, 0.176))
    static let success = adaptive(light: (0.160, 0.640, 0.336), dark: (0.224, 0.675, 0.388))
    static let warning = adaptive(light: (0.960, 0.623, 0.040), dark: (0.902, 0.608, 0.098))
    static let destructive = adaptive(light: (0.936, 0.264, 0.264), dark: (0.851, 0.149, 0.149))
    static let inputBackground = adaptive(light: (1.000, 1.000, 1.000), dark: (0.118, 0.157, 0.137))
    static let inputForeground = adaptive(light: (0.084, 0.156, 0.120), dark: (0.922, 0.906, 0.878))
    static let inputMutedForeground = adaptive(light: (0.405, 0.495, 0.450), dark: (0.604, 0.569, 0.494))
    static let inputBorder = adaptive(light: (0.849, 0.831, 0.795), dark: (0.222, 0.278, 0.240))
    static let radius: CGFloat = 16

    private static func adaptive(light: (Double, Double, Double), dark: (Double, Double, Double)) -> Color {
        Color(uiColor: UIColor { traits in
            let rgb = traits.userInterfaceStyle == .dark ? dark : light
            return UIColor(red: rgb.0, green: rgb.1, blue: rgb.2, alpha: 1)
        })
    }
}

@main
struct ScampagnateApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) private var appDelegate
    @Environment(\.scenePhase) private var scenePhase
    @StateObject private var store = AppStore()
    @StateObject private var pushNotifications = PushNotificationService.shared

    var body: some Scene {
        WindowGroup {
            RootView()
                .fontDesign(.rounded)
                .environmentObject(store)
                .environmentObject(pushNotifications)
                .task {
                    await store.bootstrap()
                }
                .onChange(of: scenePhase) { _, phase in
                    guard phase == .active, !store.isAuthenticated else { return }
                    Task { await store.refreshEventData(reportingErrors: false) }
                }
        }
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate, @preconcurrency UNUserNotificationCenterDelegate {
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]? = nil) -> Bool {
        UNUserNotificationCenter.current().delegate = self
        return true
    }

    func application(_ application: UIApplication, didRegisterForRemoteNotificationsWithDeviceToken deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02x", $0) }.joined()
        Task { @MainActor in
            await PushNotificationService.shared.handleRegisteredDeviceToken(token)
        }
    }

    func application(_ application: UIApplication, didFailToRegisterForRemoteNotificationsWithError error: Error) {
        Task { @MainActor in
            PushNotificationService.shared.handleRegistrationError(error)
        }
    }

    func userNotificationCenter(
        _ center: UNUserNotificationCenter,
        willPresent notification: UNNotification,
        withCompletionHandler completionHandler: @escaping (UNNotificationPresentationOptions) -> Void
    ) {
        completionHandler([.banner, .list, .sound])
    }

    func userNotificationCenter(
        _ center: UNUserNotificationCenter,
        didReceive response: UNNotificationResponse,
        withCompletionHandler completionHandler: @escaping () -> Void
    ) {
        let destination = NotificationDestination.from(userInfo: response.notification.request.content.userInfo)
        Task { @MainActor in
            PushNotificationService.shared.handleNotificationDestination(destination)
            completionHandler()
        }
    }
}

@MainActor
final class AppStore: ObservableObject {
    @Published var session: AuthSession?
    @Published var profile: Profile?
    @Published var events: [Event] = []
    @Published var categories: [EventCategory] = []
    @Published var myEvents: [Registration] = []
    @Published var savedEvents: [SavedEvent] = []
    @Published var eventOpeningReminders: [EventOpeningReminder] = []
    @Published var eventParticipants: [String: [EventParticipant]] = [:]
    @Published var eventStaff: [String: [EventStaffMember]] = [:]
    @Published var organizerProfiles: [String: PublicProfile] = [:]
    @Published var organizerPublicProfiles: [String: OrganizerPublicProfile] = [:]
    @Published var notifications: [UserNotification] = []
    @Published var products: [MerchProduct] = []
    @Published var rewards: [Reward] = []
    @Published var missions: [MissionCardModel] = []
    @Published var badges: [UserBadge] = []
    @Published var allBadges: [BadgeDefinition] = []
    @Published var eventClosingSentences: [String] = defaultEventClosingSentences
    @Published var communityLevels: [CommunityLevelDefinition] = []
    @Published var roles: Set<AppRole> = []
    @Published var organizerEvents: [Event] = []
    @Published var organizerDashboardRegistrations: [OrganizerDashboardRegistration] = []
    @Published var isLoadingOrganizerDashboard = false
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var pendingPayment: PendingPayment?
    @Published var homeDiscoveryRequest: HomeDiscoveryRequest?

    private let api = SupabaseAPI()
    private let pushNotifications = PushNotificationService.shared
    private var isRefreshingUserData = false
    private var isRefreshingEventData = false

    var isAuthenticated: Bool { session?.accessToken.isEmpty == false }
    var isAdmin: Bool { roles.contains(.admin) }
    var isOrganizer: Bool { roles.contains(.admin) || roles.contains(.organizer) }
    var needsOnboarding: Bool {
        guard isAuthenticated, let profile else { return false }
        let oldDone = !profile.phone.isEmpty && !(profile.trekkingExperience ?? "").isEmpty && !(profile.activityFrequency ?? "").isEmpty
        return !(profile.onboardingCompleted ?? false) && !oldDone
    }

    func bootstrap() async {
        session = AuthSession.load()
        pendingPayment = PendingPayment.load()
        await pushNotifications.refreshAuthorizationStatus()
        if session != nil {
            await refreshUserData(reportingErrors: false)
            if let session {
                await pushNotifications.syncIfPossible(session: session)
            } else {
                await loadPublicData(reportingErrors: false)
            }
        } else {
            await loadPublicData(reportingErrors: false)
        }
    }

    func loadPublicData(reportingErrors: Bool = true) async {
        async let eventsTask = api.fetchEvents(session: session)
        async let categoriesTask = api.fetchCategories(session: session)
        async let productsTask = api.fetchProducts()
        async let allBadgesTask = api.fetchAllBadges()
        async let closingSentencesTask = api.fetchEventClosingSentences(session: session)
        async let communityLevelsTask = api.fetchCommunityLevels()

        var firstError: Error?
        do { events = try await eventsTask } catch { remember(error, in: &firstError) }
        do { categories = try await categoriesTask } catch { remember(error, in: &firstError) }
        do { products = try await productsTask } catch { remember(error, in: &firstError) }
        do { allBadges = try await allBadgesTask } catch { remember(error, in: &firstError) }
        do { updateEventClosingSentences(try await closingSentencesTask) } catch { eventClosingSentences = defaultEventClosingSentences }
        do { communityLevels = try await communityLevelsTask } catch { remember(error, in: &firstError) }

        report(firstError, when: reportingErrors)
    }

    func refreshUserData(reportingErrors: Bool = true) async {
        guard !isRefreshingUserData else { return }
        isRefreshingUserData = true
        defer { isRefreshingUserData = false }
        isLoading = true
        defer { isLoading = false }
        do {
            let authSession = try await authenticatedSession()
            async let profileTask = api.fetchProfile(session: authSession)
            async let eventsTask = api.fetchEvents(session: authSession)
            async let categoriesTask = api.fetchCategories(session: authSession)
            async let registrationsTask = api.fetchMyEvents(session: authSession)
            async let savedTask = api.fetchSavedEvents(session: authSession)
            async let openingRemindersTask = api.fetchEventOpeningReminders(session: authSession)
            async let notificationsTask = api.fetchNotifications(session: authSession)
            async let productsTask = api.fetchProducts()
            async let rewardsTask = api.fetchRewards(session: authSession)
            async let missionsTask = api.fetchMissionCards(session: authSession)
            async let badgesTask = api.fetchUserBadges(session: authSession)
            async let allBadgesTask = api.fetchAllBadges()
            async let closingSentencesTask = api.fetchEventClosingSentences(session: authSession)
            async let communityLevelsTask = api.fetchCommunityLevels()
            async let rolesTask = api.fetchUserRoles(session: authSession)

            var firstError: Error?
            do { profile = try await profileTask } catch { remember(error, in: &firstError) }
            do { events = try await eventsTask } catch { remember(error, in: &firstError) }
            do { categories = try await categoriesTask } catch { remember(error, in: &firstError) }
            do { myEvents = try await registrationsTask } catch { remember(error, in: &firstError) }
            do { savedEvents = try await savedTask } catch { remember(error, in: &firstError) }
            do { eventOpeningReminders = try await openingRemindersTask } catch { remember(error, in: &firstError) }
            do { notifications = try await notificationsTask } catch { remember(error, in: &firstError) }
            do { products = try await productsTask } catch { remember(error, in: &firstError) }
            do { rewards = try await rewardsTask } catch { remember(error, in: &firstError) }
            do { missions = try await missionsTask } catch { remember(error, in: &firstError) }
            do { badges = try await badgesTask } catch { remember(error, in: &firstError) }
            do { allBadges = try await allBadgesTask } catch { remember(error, in: &firstError) }
            do { updateEventClosingSentences(try await closingSentencesTask) } catch { eventClosingSentences = defaultEventClosingSentences }
            do { communityLevels = try await communityLevelsTask } catch { remember(error, in: &firstError) }
            do { roles = Set(try await rolesTask) } catch { remember(error, in: &firstError) }

            report(firstError, when: reportingErrors)
            await loadOrganizerDashboardIfAvailable(session: authSession, reportingErrors: reportingErrors)
        } catch {
            report(error, when: reportingErrors)
            if session == nil {
                await loadPublicData(reportingErrors: false)
            }
        }
    }

    func refreshEventData(reportingErrors: Bool = true) async {
        guard !isRefreshingUserData, !isRefreshingEventData else { return }
        isRefreshingEventData = true
        defer { isRefreshingEventData = false }

        if session != nil {
            do {
                let authSession = try await authenticatedSession()
                async let eventsTask = api.fetchEvents(session: authSession)
                async let categoriesTask = api.fetchCategories(session: authSession)
                async let registrationsTask = api.fetchMyEvents(session: authSession)
                async let savedTask = api.fetchSavedEvents(session: authSession)
                async let openingRemindersTask = api.fetchEventOpeningReminders(session: authSession)

                var firstError: Error?
                do { events = try await eventsTask } catch { remember(error, in: &firstError) }
                do { categories = try await categoriesTask } catch { remember(error, in: &firstError) }
                do { myEvents = try await registrationsTask } catch { remember(error, in: &firstError) }
                do { savedEvents = try await savedTask } catch { remember(error, in: &firstError) }
                do { eventOpeningReminders = try await openingRemindersTask } catch { remember(error, in: &firstError) }

                report(firstError, when: reportingErrors)
            } catch {
                report(error, when: reportingErrors)
            }
        } else {
            async let eventsTask = api.fetchEvents(session: nil)
            async let categoriesTask = api.fetchCategories(session: nil)
            var firstError: Error?
            do {
                events = try await eventsTask
            } catch { remember(error, in: &firstError) }
            do {
                categories = try await categoriesTask
            } catch { remember(error, in: &firstError) }
            report(firstError, when: reportingErrors)
        }
    }

    func refreshEventDetail(eventId: String, reportingErrors: Bool = true) async {
        if session != nil {
            do {
                let authSession = try await authenticatedSession()
                async let eventTask = api.fetchEvent(eventId: eventId, session: authSession)
                async let registrationsTask = api.fetchMyEvents(session: authSession)
                async let savedTask = api.fetchSavedEvents(session: authSession)
                async let openingRemindersTask = api.fetchEventOpeningReminders(session: authSession)

                var firstError: Error?
                do { mergeEventSnapshot(try await eventTask) } catch { remember(error, in: &firstError) }
                do { myEvents = try await registrationsTask } catch { remember(error, in: &firstError) }
                do { savedEvents = try await savedTask } catch { remember(error, in: &firstError) }
                do { eventOpeningReminders = try await openingRemindersTask } catch { remember(error, in: &firstError) }

                report(firstError, when: reportingErrors)
                await loadEventStaff(eventId: eventId)
                await refreshParticipants(eventId: eventId, session: authSession)
            } catch {
                report(error, when: reportingErrors)
            }
        } else {
            do {
                mergeEventSnapshot(try await api.fetchEvent(eventId: eventId, session: nil))
            } catch {
                await refreshEventData(reportingErrors: false)
                report(error, when: reportingErrors)
            }
            await loadEventStaff(eventId: eventId)
            await loadParticipants(eventId: eventId)
        }
    }

    func refreshEventClosingSentences(reportingErrors: Bool = false) async {
        do {
            updateEventClosingSentences(try await api.fetchEventClosingSentences(session: session))
        } catch {
            eventClosingSentences = defaultEventClosingSentences
            report(error, when: reportingErrors)
        }
    }

    private func updateEventClosingSentences(_ values: [String]) {
        let cleaned = values.compactMap { $0.normalizedClosingSentence.nilIfBlank }
        eventClosingSentences = cleaned.isEmpty ? defaultEventClosingSentences : cleaned
    }

    func signIn(email: String, password: String) async -> Bool {
        isLoading = true
        defer { isLoading = false }
        do {
            let auth = try await api.signIn(email: email, password: password)
            session = auth.session
            session?.save()
            await refreshUserData()
            await pushNotifications.syncIfPossible(session: auth.session)
            return true
        } catch {
            report(error)
            return false
        }
    }

    func signUp(email: String, password: String, firstName: String, lastName: String, consents: RegistrationConsents) async -> Bool {
        isLoading = true
        defer { isLoading = false }
        do {
            let auth = try await api.signUp(email: email, password: password, firstName: firstName, lastName: lastName)
            session = auth.session
            session?.save()
            try await api.saveConsents(userId: auth.user.id, consents: consents, session: auth.session)
            await refreshUserData()
            await pushNotifications.syncIfPossible(session: auth.session)
            return true
        } catch {
            report(error)
            return false
        }
    }

