    private func authenticatedSession() async throws -> AuthSession {
        guard let current = session else { throw AppError.message("Sessione mancante") }
        guard current.shouldRefresh else { return current }
        guard let refreshToken = current.refreshToken, !refreshToken.isEmpty else {
            clearUserSession()
            throw AppError.message("Sessione scaduta. Effettua di nuovo il login.")
        }

        do {
            let auth = try await api.refreshSession(refreshToken: refreshToken)
            let refreshed = auth.session
            session = refreshed
            refreshed.save()
            return refreshed
        } catch {
            clearUserSession()
            throw AppError.message("Sessione scaduta. Effettua di nuovo il login.")
        }
    }

    private func clearUserSession() {
        AuthSession.clear()
        PendingPayment.clear()
        session = nil
        profile = nil
        roles = []
        organizerEvents = []
        organizerDashboardRegistrations = []
        myEvents = []
        savedEvents = []
        eventOpeningReminders = []
        notifications = []
        rewards = []
        missions = []
        badges = []
        allBadges = []
        communityLevels = []
        pendingPayment = nil
    }

    private func refreshEventState(session providedSession: AuthSession? = nil, participantEventId: String? = nil) async {
        var resolvedSession: AuthSession?
        do {
            let authSession: AuthSession
            if let providedSession {
                authSession = providedSession
            } else {
                authSession = try await authenticatedSession()
            }
            resolvedSession = authSession
            async let profileTask = api.fetchProfile(session: authSession)
            async let eventsTask = api.fetchEvents(session: authSession)
            async let registrationsTask = api.fetchMyEvents(session: authSession)
            async let savedTask = api.fetchSavedEvents(session: authSession)
            async let openingRemindersTask = api.fetchEventOpeningReminders(session: authSession)
            async let rewardsTask = api.fetchRewards(session: authSession)
            async let missionsTask = api.fetchMissionCards(session: authSession)
            async let badgesTask = api.fetchUserBadges(session: authSession)
            async let allBadgesTask = api.fetchAllBadges()
            async let communityLevelsTask = api.fetchCommunityLevels()
            async let rolesTask = api.fetchUserRoles(session: authSession)
            profile = try await profileTask
            events = try await eventsTask
            myEvents = try await registrationsTask
            savedEvents = try await savedTask
            eventOpeningReminders = try await openingRemindersTask
            rewards = try await rewardsTask
            missions = try await missionsTask
            badges = try await badgesTask
            allBadges = try await allBadgesTask
            communityLevels = try await communityLevelsTask
            roles = Set(try await rolesTask)
        } catch {
            report(error)
        }
        if let participantEventId {
            await refreshParticipants(eventId: participantEventId, session: resolvedSession ?? session)
        }
    }

