    private func registrationRecord(for eventId: String) -> Registration? {
        myEvents.mostRecent(forEventId: eventId)
    }

    private func mergeEventSnapshot(_ event: Event) {
        if let index = events.firstIndex(where: { $0.id == event.id }) {
            events[index] = event
        } else if event.isVisibleInUpcomingList {
            events.insert(event, at: 0)
        }
    }

    private func mergeRegistrationSnapshot(_ registration: Registration) {
        if let index = myEvents.firstIndex(where: { $0.id == registration.id }) {
            myEvents[index] = registration
        } else {
            myEvents.insert(registration, at: 0)
        }
    }

    private func markRegistrationCancelled(eventId: String) {
        for index in myEvents.indices where myEvents[index].isForEvent(eventId) {
            myEvents[index].status = "cancelled"
        }
    }

    private func remember(_ error: Error, in firstError: inout Error?) {
        guard !error.isCancellation, firstError == nil else { return }
        firstError = error
    }

    private func report(_ error: Error?, when shouldReport: Bool) {
        guard shouldReport, let error else { return }
        report(error)
    }

    private func report(_ error: Error) {
        guard !error.isCancellation else { return }
        if error.isTimeout {
            errorMessage = "Connessione lenta o instabile. Alcuni dati potrebbero non essere aggiornati, riprova tra poco."
        } else {
            errorMessage = error.localizedDescription
        }
    }
}

