enum NotificationDestination: Equatable, Sendable {
    case event(String)
    case events
    case mission(id: String?, completedAt: String?)
    case profile(ProfileScrollTarget)
    case shop

    init?(type: String?, eventId: String?, missionId: String? = nil, completedAt: String? = nil, title: String? = nil, message: String? = nil) {
        let normalizedType = type?.notificationTypeKey
        if Self.isMissionNotification(type: normalizedType, title: title, message: message) {
            self = .mission(id: missionId?.nilIfBlank, completedAt: completedAt?.nilIfBlank)
            return
        }

        if let eventId = eventId?.nilIfBlank {
            self = .event(eventId)
            return
        }

        guard let normalizedType else { return nil }
        switch normalizedType {
        case "registration", "registration_confirmed", "event_registration", "waitlist", "waitlist_promotion", "payment", "payment_confirmed", "deposit", "balance", "balance_due", "event", "event_update", "event_opening", "event_reminder", "event_reminder_24h", "event_reminder_3h":
            self = .events
        case "membership", "membership_payment", "membership_activated", "subscription":
            self = .profile(.membership)
        case "badge", "badge_unlocked", "user_badge":
            self = .profile(.badges)
        case "reward", "rewards", "points", "coupon", "coupon_unlocked", "mission_reward", "prize":
            self = .profile(.rewards)
        case "profile", "onboarding":
            self = .profile(.profile)
        case "shop", "merch", "merch_product", "product":
            self = .shop
        default:
            return nil
        }
    }

    static func from(userInfo: [AnyHashable: Any]) -> NotificationDestination? {
        let payloads = nestedPayloads(userInfo)
        let eventId = payloads.lazy.compactMap { stringValue(in: $0, keys: ["event_id", "eventId", "event"]) }.first
        let missionId = payloads.lazy.compactMap { stringValue(in: $0, keys: ["mission_id", "missionId", "mission"]) }.first
        let completedAt = payloads.lazy.compactMap { stringValue(in: $0, keys: ["completed_at", "completedAt", "created_at", "createdAt"]) }.first
        let type = payloads.lazy.compactMap { stringValue(in: $0, keys: ["type", "notification_type", "notificationType", "category"]) }.first
        let title = payloads.lazy.compactMap { stringValue(in: $0, keys: ["title", "alert_title", "alertTitle"]) }.first
        let message = payloads.lazy.compactMap { stringValue(in: $0, keys: ["message", "body", "alert", "subtitle"]) }.first
        if let destination = NotificationDestination(type: type, eventId: eventId, missionId: missionId, completedAt: completedAt, title: title, message: message) {
            return destination
        }

        guard let route = payloads.lazy.compactMap({ stringValue(in: $0, keys: ["route", "deeplink", "deep_link", "url"]) }).first else {
            return nil
        }
        return destination(fromRoute: route)
    }

    var actionTitle: String {
        switch self {
        case .event:
            return "Apri evento"
        case .events:
            return "Vai a My events"
        case .mission:
            return "Apri missione"
        case .profile(let target):
            switch target {
            case .membership:
                return "Vai alla tessera"
            case .missions:
                return "Vai alle missioni"
            case .rewards:
                return "Vai alle ricompense"
            case .badges:
                return "Vai ai badge"
            case .activity:
                return "Vai alle attività"
            case .help:
                return "Vai all'aiuto"
            case .profile:
                return "Vai al profilo"
            }
        case .shop:
            return "Apri shop"
        }
    }

    private static func destination(fromRoute route: String) -> NotificationDestination? {
        let normalizedRoute = route.lowercased()
        if normalizedRoute.contains("shop") || normalizedRoute.contains("merch") {
            return .shop
        }
        if normalizedRoute.contains("badge") {
            return .profile(.badges)
        }
        if normalizedRoute.contains("reward") || normalizedRoute.contains("coupon") || normalizedRoute.contains("punt") {
            return .profile(.rewards)
        }
        if normalizedRoute.contains("mission") {
            if let missionId = missionId(fromRoute: route) {
                return .mission(id: missionId, completedAt: nil)
            }
            return .profile(.missions)
        }
        if normalizedRoute.contains("membership") || normalizedRoute.contains("tessera") {
            return .profile(.membership)
        }
        if normalizedRoute.contains("profile") || normalizedRoute.contains("profilo") {
            return .profile(.profile)
        }
        if normalizedRoute.contains("event") || normalizedRoute.contains("evento") {
            if let url = URL(string: route),
               let eventId = [url.lastPathComponent, url.host ?? ""]
                .compactMap(\.nilIfBlank)
                .first(where: { !["event", "events", "evento", "eventi"].contains($0.lowercased()) }) {
                return .event(eventId)
            }
            return .events
        }
        return nil
    }

    private static func nestedPayloads(_ userInfo: [AnyHashable: Any]) -> [[AnyHashable: Any]] {
        var payloads = [userInfo]

        var index = 0
        while index < payloads.count {
            let payload = payloads[index]
            for key in ["data", "custom", "additionalData", "aps", "alert"] {
                if let nested = dictionaryValue(payload[AnyHashable(key)]) {
                    payloads.append(nested)
                }
            }
            index += 1
        }

        return payloads
    }

    private static func stringValue(in payload: [AnyHashable: Any], keys: [String]) -> String? {
        for key in keys {
            let value = payload[AnyHashable(key)]
            if let string = value as? String, let clean = string.nilIfBlank {
                return clean
            }
            if let number = value as? NSNumber, let clean = number.stringValue.nilIfBlank {
                return clean
            }
        }
        return nil
    }

    private static func dictionaryValue(_ value: Any?) -> [AnyHashable: Any]? {
        if let dictionary = value as? [AnyHashable: Any] {
            return dictionary
        }
        if let dictionary = value as? [String: Any] {
            return Dictionary(uniqueKeysWithValues: dictionary.map { (AnyHashable($0.key), $0.value) })
        }
        return nil
    }

    private static func isMissionNotification(type: String?, title: String?, message: String?) -> Bool {
        if let type, ["mission", "mission_completed", "challenge", "challenge_completed"].contains(type) {
            return true
        }

        return [title, message]
            .compactMap { $0?.nilIfBlank }
            .map(normalizedCopy)
            .contains { value in
                value.contains("missione completat") || value.contains("mission completed")
            }
    }

    private static func normalizedCopy(_ value: String) -> String {
        value
            .folding(options: .diacriticInsensitive, locale: .current)
            .lowercased()
            .replacingOccurrences(of: "_", with: " ")
            .replacingOccurrences(of: "-", with: " ")
    }

    private static func missionId(fromRoute route: String) -> String? {
        guard let url = URL(string: route) else { return nil }

        let queryItems = URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems ?? []
        if let missionId = queryItems
            .first(where: { ["mission_id", "missionId", "id"].contains($0.name) })?
            .value?
            .nilIfBlank {
            return missionId
        }

        let components = ([url.host].compactMap { $0 } + url.pathComponents)
            .filter { $0 != "/" }
        for (index, component) in components.enumerated() {
            let normalized = component.lowercased()
            guard ["mission", "missions", "missione", "missioni"].contains(normalized),
                  components.indices.contains(index + 1) else { continue }
            let candidate = components[index + 1]
            if let missionId = candidate.nilIfBlank,
               !["mission", "missions", "missione", "missioni"].contains(missionId.lowercased()) {
                return missionId
            }
        }

        return nil
    }
}

// MARK: - Push Notifications

@MainActor
final class PushNotificationService: ObservableObject {
    static let shared = PushNotificationService()

    @Published private(set) var authorizationStatus: UNAuthorizationStatus = .notDetermined
    @Published private(set) var isRegistering = false
    @Published private(set) var localNotificationsEnabled: Bool
    @Published private(set) var hasCompletedInitialPrompt: Bool
    @Published private(set) var tappedNotification: NotificationNavigationRequest?
    @Published var errorMessage: String?

    private let api = SupabaseAPI()
    private let enabledKey = "Scampagnate.pushNotificationsEnabled"
    private let initialPromptKey = "Scampagnate.pushInitialPromptCompleted"
    private let installationIdKey = "Scampagnate.installationId"
    private var pendingSession: AuthSession?
    private var currentToken: String?

    private init() {
        localNotificationsEnabled = UserDefaults.standard.bool(forKey: enabledKey)
        hasCompletedInitialPrompt = UserDefaults.standard.bool(forKey: initialPromptKey)
    }

    var isLocallyEnabled: Bool {
        get { localNotificationsEnabled }
        set {
            localNotificationsEnabled = newValue
            UserDefaults.standard.set(newValue, forKey: enabledKey)
        }
    }

    var installationId: String {
        if let value = UserDefaults.standard.string(forKey: installationIdKey) {
            return value
        }
        let value = UUID().uuidString.lowercased()
        UserDefaults.standard.set(value, forKey: installationIdKey)
        return value
    }

    var environment: String {
        #if DEBUG
        "sandbox"
        #else
        "production"
        #endif
    }

    var canOpenSettings: Bool { authorizationStatus == .denied }

    var shouldShowInitialPrompt: Bool {
        !hasCompletedInitialPrompt && authorizationStatus == .notDetermined
    }

    var isSystemAuthorized: Bool {
        authorizationStatus == .authorized || authorizationStatus == .provisional || authorizationStatus == .ephemeral
    }

    var isPushActive: Bool {
        isLocallyEnabled && isSystemAuthorized
    }

    var statusTitle: String {
        switch authorizationStatus {
        case .authorized, .provisional, .ephemeral:
            return isLocallyEnabled ? "Attive" : "Disattivate"
        case .denied:
            return "Bloccate da iOS"
        case .notDetermined:
            return "Non attivate"
        @unknown default:
            return "Stato sconosciuto"
        }
    }

    var statusMessage: String {
        switch authorizationStatus {
        case .authorized, .provisional, .ephemeral:
            return isLocallyEnabled ? "Riceverai aggiornamenti sugli eventi a cui partecipi." : "Le notifiche sono consentite da iOS ma disattivate per questo account."
        case .denied:
            return "Puoi abilitarle dalle Impostazioni di iOS."
        case .notDetermined:
            return "Attiva avvisi su iscrizioni, pagamenti e cambi evento."
        @unknown default:
            return "Controlla le impostazioni di notifica del dispositivo."
        }
    }

    func refreshAuthorizationStatus() async {
        let settings = await UNUserNotificationCenter.current().notificationSettings()
        authorizationStatus = settings.authorizationStatus
    }

    func requestPermissionAndRegister(session: AuthSession?) async {
        markInitialPromptCompleted()
        isRegistering = true
        errorMessage = nil
        defer { isRegistering = false }

        do {
            let granted = try await UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound])
            await refreshAuthorizationStatus()
            guard granted || authorizationStatus == .provisional || authorizationStatus == .ephemeral else {
                isLocallyEnabled = false
                return
            }

            isLocallyEnabled = true
            pendingSession = session
            UIApplication.shared.registerForRemoteNotifications()

            if let token = currentToken, let session {
                try await api.upsertIOSDeviceToken(token: token, installationId: installationId, environment: environment, deviceModel: UIDevice.current.model, session: session)
            }
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func syncIfPossible(session: AuthSession) async {
        await refreshAuthorizationStatus()
        guard isLocallyEnabled else { return }
        guard authorizationStatus == .authorized || authorizationStatus == .provisional || authorizationStatus == .ephemeral else { return }

        pendingSession = session
        UIApplication.shared.registerForRemoteNotifications()

        guard let token = currentToken else { return }
        do {
            try await api.upsertIOSDeviceToken(token: token, installationId: installationId, environment: environment, deviceModel: UIDevice.current.model, session: session)
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func unregister(session: AuthSession) async {
        markUnregisteredLocally()

        do {
            try await api.deleteIOSDeviceToken(installationId: installationId, environment: environment, session: session)
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func markUnregisteredLocally() {
        isLocallyEnabled = false
        pendingSession = nil
        UIApplication.shared.unregisterForRemoteNotifications()
    }

    func declineInitialPrompt() {
        markInitialPromptCompleted()
        isLocallyEnabled = false
    }

    private func markInitialPromptCompleted() {
        hasCompletedInitialPrompt = true
        UserDefaults.standard.set(true, forKey: initialPromptKey)
    }

    func openAppSettings() {
        guard let url = URL(string: UIApplication.openSettingsURLString) else { return }
        UIApplication.shared.open(url)
    }

    func handleRegisteredDeviceToken(_ token: String) async {
        currentToken = token
        guard isLocallyEnabled else { return }
        guard let session = pendingSession ?? AuthSession.load() else { return }

        do {
            try await api.upsertIOSDeviceToken(token: token, installationId: installationId, environment: environment, deviceModel: UIDevice.current.model, session: session)
        } catch {
            errorMessage = error.localizedDescription
        }
    }

    func handleRegistrationError(_ error: Error) {
        errorMessage = error.localizedDescription
    }

    func handleNotificationDestination(_ destination: NotificationDestination?) {
        tappedNotification = NotificationNavigationRequest(destination: destination)
    }

    func consumeTappedNotification(_ request: NotificationNavigationRequest) {
        guard tappedNotification?.id == request.id else { return }
        tappedNotification = nil
    }
}

