    }()

    func signIn(email: String, password: String) async throws -> AuthResponse {
        let body = ["email": email, "password": password]
        return try await request(path: "/auth/v1/token?grant_type=password", method: "POST", body: body, auth: nil, decode: AuthResponse.self)
    }

    func refreshSession(refreshToken: String) async throws -> AuthResponse {
        let body = ["refresh_token": refreshToken]
        return try await request(path: "/auth/v1/token?grant_type=refresh_token", method: "POST", body: body, auth: nil, decode: AuthResponse.self)
    }

    func signUp(email: String, password: String, firstName: String, lastName: String) async throws -> AuthResponse {
        let body: [String: JSONValue] = [
            "email": .string(email),
            "password": .string(password),
            "data": .object([
                "first_name": .string(firstName),
                "last_name": .string(lastName),
                "phone": .string("")
            ])
        ]
        return try await request(path: "/auth/v1/signup", method: "POST", body: body, auth: nil, decode: AuthResponse.self)
    }

    func sendPasswordReset(email: String) async throws {
        let body = ["email": email, "redirect_to": "scampagnate://reset-password"]
        let _: EmptyResponse = try await request(path: "/auth/v1/recover", method: "POST", body: body, auth: nil, decode: EmptyResponse.self)
    }

