        let _: EmptyResponse = try await request(path: "/auth/v1/logout", method: "POST", bodyData: nil, auth: session, decode: EmptyResponse.self)
    }

    func deleteAccount(session: AuthSession) async throws {
        let body: [String: JSONValue] = [
            "dry_run": .bool(false),
            "confirmation": .string("CANCELLA IL MIO ACCOUNT")
        ]
        let response: DeleteAccountResponse = try await function(name: "delete-account", body: body, session: session)
        if response.success, response.deleted == true {
            return
        }
        if response.dryRun == true {
            throw AppError.message("La cancellazione non è stata eseguita: Supabase ha risposto con una simulazione.")
        }
        if !response.success {
            throw AppError.message(response.error ?? "Cancellazione account non riuscita")
        }
        throw AppError.message("Cancellazione account non confermata dal server")
    }

    func fetchProfile(session: AuthSession) async throws -> Profile {
        let path = "/rest/v1/profiles?select=*&id=eq.\(session.user.id)"
        let profiles = try await request(path: path, method: "GET", bodyData: nil, auth: session, decode: [Profile].self)
        guard let profile = profiles.first else { throw AppError.message("Profilo non trovato") }
        return profile
    }

    func fetchUserRoles(session: AuthSession) async throws -> [AppRole] {
        let path = "/rest/v1/user_roles?select=role&user_id=eq.\(session.user.id.urlEncoded)"
        let rows = try await request(path: path, method: "GET", bodyData: nil, auth: session, decode: [UserRoleRow].self)
        return rows.map(\.role)
    }

    func fetchOrganizerOwnerOptions(session: AuthSession) async throws -> [OrganizerOwnerOption] {
        let roleRows: [OrganizerOwnerRoleRow] = try await request(path: "/rest/v1/user_roles?select=user_id,role&role=in.(admin,organizer)", method: "GET", bodyData: nil, auth: session, decode: [OrganizerOwnerRoleRow].self)
        let groupedRoles = Dictionary(grouping: roleRows, by: \.userId)
        let userIds = groupedRoles.keys.sorted()
        guard !userIds.isEmpty else { return [] }

        let profilesPath = "/rest/v1/profiles?select=id,first_name,last_name,email,phone,avatar_url,membership_id,membership_status&id=in.(\(userIds.joined(separator: ",")))"
        let profiles = try await request(path: profilesPath, method: "GET", bodyData: nil, auth: session, decode: [OrganizerSearchProfile].self)
        let profilesById = Dictionary(uniqueKeysWithValues: profiles.map { ($0.id, $0) })

        return userIds.map { userId in
            let roles = groupedRoles[userId]?.map(\.role) ?? []
            let primaryRole: AppRole = roles.contains(.admin) ? .admin : .organizer
            let profile = profilesById[userId]
            return OrganizerOwnerOption(
                id: userId,
                displayName: profile?.displayName.nilIfBlank ?? "Utente \(String(userId.prefix(8)))",
                email: profile?.email,
                avatarUrl: profile?.avatarUrl,
                role: primaryRole
            )
        }
        .sorted { lhs, rhs in
            if lhs.role != rhs.role { return lhs.role == .admin }
            return lhs.displayName.localizedCaseInsensitiveCompare(rhs.displayName) == .orderedAscending
        }
    }

    func fetchConsentPreferences(userId: String, session: AuthSession) async throws -> ConsentPreferences {
        let path = "/rest/v1/user_consents?select=consent_type,granted&user_id=eq.\(userId.urlEncoded)&consent_type=in.(marketing,media)"
        let rows = try await request(path: path, method: "GET", bodyData: nil, auth: session, decode: [UserConsentRow].self)

        var preferences = ConsentPreferences()
        for row in rows {
            switch ConsentPreferenceType(rawValue: row.consentType) {
            case .marketing:
                preferences.marketing = row.granted
            case .media:
                preferences.media = row.granted
            case nil:
                continue
            }
        }
        return preferences
    }

