    func saveDiscountCode(id: String?, code: String, description: String, discountType: String, discountValue: Double, eventIds: [String], assignedUserId: String?, maxUses: Int?, startsAt: String?, expiresAt: String?, appliesToAll: Bool, isSingleUse: Bool, waivesServiceFee: Bool, createdBy: String, session: AuthSession) async throws {
        let cleanStartsAt = startsAt?.nilIfBlank
        let cleanExpiresAt = expiresAt?.nilIfBlank
        let cleanAssignedUserId = assignedUserId?.nilIfBlank
        let payload: [String: JSONValue] = [
            "code": .string(code.uppercased()),
            "description": .string(description),
            "discount_type": .string(discountType),
            "discount_value": .number(discountValue),
            "event_ids": eventIds.isEmpty ? .null : .array(eventIds.map { .string($0) }),
            "assigned_user_id": cleanAssignedUserId.map { .string($0) } ?? .null,
            "max_uses": maxUses.map { .number(Double($0)) } ?? .null,
            "starts_at": cleanStartsAt.map { .string($0) } ?? .null,
            "expires_at": cleanExpiresAt.map { .string($0) } ?? .null,
            "applies_to_all": .bool(appliesToAll),
            "is_single_use": .bool(isSingleUse),
            "waives_service_fee": .bool(waivesServiceFee),
            "created_by": .string(createdBy),
