    func saveMission(id: String?, title: String, description: String, type: String, targetAction: String, targetValue: Int, rewardPoints: Int, rewardType: String, rewardValue: String?, rewardBadgeId: String?, category: String?, icon: String, isActive: Bool, resetOnFailure: Bool, streakCount: Int?, expiresAt: String?, sortOrder: Int?, session: AuthSession) async throws {
        let cleanRewardValue = rewardValue?.nilIfBlank
        let cleanRewardBadgeId = rewardBadgeId?.nilIfBlank
        let cleanCategory = category?.nilIfBlank
        let cleanExpiresAt = expiresAt?.nilIfBlank
        var payload: [String: JSONValue] = [
            "title": .string(title),
            "description": .string(description),
            "type": .string(type),
            "target_action": .string(targetAction),
            "target_value": .number(Double(targetValue)),
