            "reward_badge_id": cleanRewardBadgeId.map { .string($0) } ?? .null,
            "category": cleanCategory.map { .string($0) } ?? .null,
            "icon": .string(icon.nilIfBlank ?? "🎯"),
            "is_active": .bool(isActive),
            "reset_on_failure": .bool(resetOnFailure),
            "streak_count": streakCount.map { .number(Double($0)) } ?? .null,
            "expires_at": cleanExpiresAt.map { .string($0) } ?? .null,
            "updated_at": .string(ISO8601DateFormatter().string(from: Date()))
        ]
        if let sortOrder {
            payload["sort_order"] = .number(Double(sortOrder))
        }
        let data = try JSONEncoder().encode(payload)
        if let id {
            let _: EmptyResponse = try await request(path: "/rest/v1/missions?id=eq.\(id.urlEncoded)", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
