    func searchProfiles(query rawQuery: String, session: AuthSession) async throws -> [OrganizerSearchProfile] {
        let query = rawQuery.trimmingCharacters(in: .whitespacesAndNewlines)
        guard query.count >= 2 else { return [] }
        let escaped = query.replacingOccurrences(of: ",", with: " ")
        let term = escaped.urlEncoded
        let path = "/rest/v1/profiles?select=id,first_name,last_name,email,phone,avatar_url,membership_id,membership_status&or=(first_name.ilike.*\(term)*,last_name.ilike.*\(term)*,email.ilike.*\(term)*)&limit=12"
        return try await request(path: path, method: "GET", bodyData: nil, auth: session, decode: [OrganizerSearchProfile].self)
    }

