    func fetchMissionCards(session: AuthSession) async throws -> [MissionCardModel] {
        async let progressTask: [UserMissionProgress] = request(
            path: "/rest/v1/user_mission_progress?select=id,mission_id,cycle_key,current_value,target_value,is_completed,completed_at,updated_at&user_id=eq.\(session.user.id)&is_locked=eq.false&is_expired=eq.false&order=updated_at.desc",
            method: "GET",
            bodyData: nil,
            auth: session,
            decode: [UserMissionProgress].self
        )
        async let activeTask: [ActiveMissionDefinition] = request(
            path: "/rest/v1/missions?select=id,title,description,target_value,reward_points,type,icon,reward_type,reward_value,category,target_action,timezone,expires_at,mission_rewards(id,reward_kind,points_value,title,sort_order,visible_on_profile,physical_config,badges(name,icon))&is_active=eq.true&status=eq.active&visibility=eq.visible&is_archived=eq.false&order=sort_order.asc&order=created_at.asc",
            method: "GET",
            bodyData: nil,
            auth: session,
            decode: [ActiveMissionDefinition].self
        )

        let (progressRows, activeMissions) = try await (progressTask, activeTask)
        var progressRowsByMissionId: [String: [UserMissionProgress]] = [:]
        for row in progressRows {
            guard let missionId = row.missionId else { continue }
            progressRowsByMissionId[missionId, default: []].append(row)
        }

        return activeMissions.map { mission in
            let progress = mission.preferredProgress(in: progressRowsByMissionId[mission.id] ?? [])
            return MissionCardModel(
                id: progress?.id ?? mission.id,
                missionId: mission.id,
                progress: progress?.displayProgress ?? 0,
                completed: progress?.displayCompleted ?? false,
                completedAt: progress?.completedAt,
                missions: MissionDetail(
                    title: mission.title,
                    description: mission.description,
                    targetValue: progress?.targetValue ?? mission.targetValue,
                    rewardPoints: mission.rewardPoints,
                    type: mission.type,
                    icon: mission.icon,
                    rewardType: mission.rewardType,
                    rewardValue: mission.rewardValue,
                    category: mission.category,
                    targetAction: mission.targetAction,
                    timezone: mission.timezone,
                    expiresAt: mission.expiresAt,
                    missionRewards: mission.missionRewards
                )
            )
        }
    }

    func saveConsents(userId: String, consents: RegistrationConsents, session: AuthSession) async throws {
        let now = ISO8601DateFormatter().string(from: Date())
        let rows: [[String: JSONValue]] = [
            consentRow(userId: userId, type: "terms", granted: consents.terms, now: now),
            consentRow(userId: userId, type: "age", granted: consents.age, now: now),
            consentRow(userId: userId, type: "marketing", granted: consents.marketing, now: now),
            consentRow(userId: userId, type: "media", granted: consents.media, now: now)
        ]
        let data = try JSONEncoder().encode(rows)
        let _: [EmptyObject] = try await request(path: "/rest/v1/user_consents?on_conflict=user_id,consent_type", method: "POST", bodyData: data, auth: session, decode: [EmptyObject].self, prefer: "resolution=merge-duplicates,return=representation")
    }

    func saveConsent(userId: String, type: ConsentPreferenceType, granted: Bool, session: AuthSession) async throws {
        let now = ISO8601DateFormatter().string(from: Date())
        let rows = [consentRow(userId: userId, type: type.rawValue, granted: granted, now: now)]
        let data = try JSONEncoder().encode(rows)
        let _: EmptyResponse = try await request(
            path: "/rest/v1/user_consents?on_conflict=user_id,consent_type",
            method: "POST",
            bodyData: data,
            auth: session,
            decode: EmptyResponse.self,
            prefer: "resolution=merge-duplicates,return=minimal"
        )
    }

    private func consentRow(userId: String, type: String, granted: Bool, now: String) -> [String: JSONValue] {
        [
            "user_id": .string(userId),
            "consent_type": .string(type),
            "granted": .bool(granted),
            "version": .string("2026-04-01"),
            "granted_at": granted ? .string(now) : .null,
            "revoked_at": granted ? .null : .string(now),
            "updated_at": .string(now)
        ]
    }

    func updateProfile(input: OnboardingInput, session: AuthSession) async throws {
        let grade = input.experienceGrade
        let normalizedInstagramHandle = input.normalizedInstagramHandle
        guard OnboardingInput.isValidInstagramHandle(normalizedInstagramHandle) else {
            throw AppError.message("Inserisci solo username, @username o link instagram.com/username.")
        }
        var payload: [String: JSONValue] = [
            "phone": .string(input.phone),
            "birth_date": input.birthDate.isEmpty ? .null : .string(input.birthDate),
            "sex": input.sex.isEmpty ? .null : .string(input.sex),
            "instagram_handle": normalizedInstagramHandle.map { .string($0) } ?? .null,
