    func uploadAvatar(data: Data, session: AuthSession) async throws {
        let filePath = "\(session.user.id)/avatar.jpg"
        let encodedPath = filePath
            .split(separator: "/")
            .map { String($0).urlEncoded }
            .joined(separator: "/")
        let storageURL = ScampagnateConfig.supabaseURL.appending(path: "/storage/v1/object/avatars/\(encodedPath)")
        try await uploadStorageObject(url: storageURL, data: data, contentType: "image/jpeg", session: session)

        let publicURL = ScampagnateConfig.supabaseURL
            .appending(path: "/storage/v1/object/public/avatars/\(filePath)")
            .absoluteString + "?t=\(Int(Date().timeIntervalSince1970))"
        let payload: [String: JSONValue] = [
            "avatar_url": .string(publicURL),
            "updated_at": .string(ISO8601DateFormatter().string(from: Date()))
        ]
        try await patchProfile(payload, session: session)
    }

    func uploadEventImage(data: Data, fileExtension: String, session: AuthSession) async throws -> String {
        let normalizedExtension = fileExtension.trimmingCharacters(in: CharacterSet(charactersIn: ".")).nilIfBlank ?? "jpg"
        let filePath = "\(session.user.id)/\(Int(Date().timeIntervalSince1970)).\(normalizedExtension)"
        let encodedPath = filePath
            .split(separator: "/")
            .map { String($0).urlEncoded }
            .joined(separator: "/")
        let contentType: String
        switch normalizedExtension.lowercased() {
        case "png":
            contentType = "image/png"
        case "webp":
            contentType = "image/webp"
        default:
            contentType = "image/jpeg"
        }
        let storageURL = ScampagnateConfig.supabaseURL.appending(path: "/storage/v1/object/event-images/\(encodedPath)")
        try await uploadStorageObject(url: storageURL, data: data, contentType: contentType, session: session)

        return ScampagnateConfig.supabaseURL
            .appending(path: "/storage/v1/object/public/event-images/\(filePath)")
            .absoluteString
    }

    func uploadIssueMedia(_ media: PendingIssueMedia, session: AuthSession) async throws -> IssueMediaAttachment {
        let fileName = media.filename.sanitizedStorageFileName.nilIfBlank ?? "attachment.\(media.fileExtension)"
        let filePath = "\(session.user.id)/\(UUID().uuidString)-\(fileName)"
        let encodedPath = filePath
            .split(separator: "/")
            .map { String($0).urlEncoded }
            .joined(separator: "/")
        let storageURL = ScampagnateConfig.supabaseURL.appending(path: "/storage/v1/object/issue-media/\(encodedPath)")
        try await uploadStorageObject(url: storageURL, data: media.data, contentType: media.contentType, session: session, upsert: false)

        return IssueMediaAttachment(
            path: filePath,
            type: media.mediaType.rawValue,
            contentType: media.contentType,
            name: media.filename,
            size: media.data.count
        )
    }

    func updateOrganizerRegistration(id: String, updates: OrganizerRegistrationUpdate, session: AuthSession) async throws {
        var payload: [String: JSONValue] = [:]
        if let status = updates.status {
            payload["status"] = .string(status)
            payload["cancelled_at"] = status == "cancelled" ? .string(ISO8601DateFormatter().string(from: Date())) : .null
        }
        if let paymentStatus = updates.paymentStatus { payload["payment_status"] = .string(paymentStatus) }
        if let checkedIn = updates.checkedIn { payload["checked_in"] = .bool(checkedIn) }
        if updates.hasMeetingPointUpdate {
            payload["meeting_point_id"] = updates.meetingPointId.map { .string($0) } ?? .null
        }
        if updates.hasPriceOptionUpdate {
            payload["price_option_id"] = updates.priceOptionId.map { .string($0) } ?? .null
        }
        guard !payload.isEmpty else { return }
        let data = try JSONEncoder().encode(payload)
        let _: EmptyResponse = try await request(path: "/rest/v1/event_registrations?id=eq.\(id.urlEncoded)", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
    }

