    func saveOrganizerEvent(
        draft: OrganizerEventDraft,
        existingEventId: String?,
        organizerId: String,
        organizerName: String,
        preserveExistingOrganizer: Bool = false,
        session: AuthSession
    ) async throws -> String {
        let preservedEvent: Event?
        if let existingEventId {
            preservedEvent = try await fetchEvent(eventId: existingEventId, session: session)
        } else {
            preservedEvent = nil
        }
        let payload = draft.eventPayload(
            organizerId: organizerId,
            organizerName: organizerName,
            includeOrganizerFields: !(preserveExistingOrganizer && existingEventId != nil),
            preservedEvent: preservedEvent
        )
        let eventId: String
        let data = try JSONEncoder().encode(payload)
        if let existingEventId {
            let _: EmptyResponse = try await request(path: "/rest/v1/events?id=eq.\(existingEventId.urlEncoded)", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
            eventId = existingEventId
        } else {
            let rows: [InsertedEvent] = try await request(path: "/rest/v1/events?select=id", method: "POST", bodyData: data, auth: session, decode: [InsertedEvent].self, prefer: "return=representation")
            guard let inserted = rows.first else { throw AppError.message("Evento non creato") }
            eventId = inserted.id
        }

        try await replaceMeetingPoints(eventId: eventId, points: draft.meetingPoints, session: session)
        try await replacePriceOptions(eventId: eventId, options: draft.priceOptions, session: session)
        try await replaceSpecialBadges(eventId: eventId, badgeIds: draft.specialBadgeIds, session: session)
        try await replaceEventStaffIfAvailable(eventId: eventId, staff: draft.staffMembers, session: session)
        return eventId
    }

    private func replaceMeetingPoints(eventId: String, points: [OrganizerMeetingPointDraft], session: AuthSession) async throws {
        let existing = try await fetchEventMeetingPoints(eventId: eventId, session: session)
        let existingIds = existing.map(\.id)
        let validPoints = points.filter { $0.name.nilIfBlank != nil && $0.location.nilIfBlank != nil && $0.time.nilIfBlank != nil }
        let retainedServerIds = Set(validPoints.compactMap(\.serverId))
        let removedIds = existingIds.filter { !retainedServerIds.contains($0) }

        if !removedIds.isEmpty {
            let payload: [String: JSONValue] = ["meeting_point_id": .null]
            let data = try JSONEncoder().encode(payload)
            let ids = removedIds.map(\.urlEncoded).joined(separator: ",")
            let _: EmptyResponse = try await request(path: "/rest/v1/event_registrations?meeting_point_id=in.(\(ids))", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")

            let _: EmptyResponse = try await request(path: "/rest/v1/event_meeting_points?id=in.(\(ids))&event_id=eq.\(eventId.urlEncoded)", method: "DELETE", bodyData: nil, auth: session, decode: EmptyResponse.self)
        }

        for (index, point) in validPoints.enumerated() {
            let payload: [String: JSONValue] = [
                "event_id": .string(eventId),
                "name": .string(point.name),
                "location": .string(point.location),
                "time": .string(point.time),
                "notes": point.notes.nilIfBlank.map { .string($0) } ?? .null,
                "sort_order": .number(Double(index))
            ]
            let data = try JSONEncoder().encode(payload)
            if let serverId = point.serverId?.nilIfBlank {
                let _: EmptyResponse = try await request(path: "/rest/v1/event_meeting_points?id=eq.\(serverId.urlEncoded)&event_id=eq.\(eventId.urlEncoded)", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
            } else {
                let _: EmptyResponse = try await request(path: "/rest/v1/event_meeting_points", method: "POST", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
            }
        }
    }

    private func replacePriceOptions(eventId: String, options: [OrganizerPriceOptionDraft], session: AuthSession) async throws {
        let validOptions = options
        let existingOptions = try await fetchEventPriceOptions(eventId: eventId, session: session)
        let retainedServerIds = Set(validOptions.compactMap(\.serverId))
        let removedOptions = existingOptions.filter { !retainedServerIds.contains($0.id) }

        for removed in removedOptions {
            let registrations = try await request(path: "/rest/v1/event_registrations?select=id&price_option_id=eq.\(removed.id.urlEncoded)&limit=1", method: "GET", bodyData: nil, auth: session, decode: [InsertedRegistration].self)
            guard registrations.isEmpty else { continue }
            let _: EmptyResponse = try await request(path: "/rest/v1/event_price_options?id=eq.\(removed.id.urlEncoded)", method: "DELETE", bodyData: nil, auth: session, decode: EmptyResponse.self)
        }

        guard !validOptions.isEmpty else { return }

        for (index, option) in validOptions.enumerated() {
            let eligibleGroup = option.badgeIds.isEmpty ? (option.eligibleGroup.nilIfBlank ?? "all") : "badge:\(option.badgeIds.joined(separator: ","))"
            let resolvedPrice = option.paymentType == "free" ? 0 : option.price
            let resolvedBalance = max(0, resolvedPrice - option.depositAmount)
            let payload: [String: JSONValue] = [
                "event_id": JSONValue.string(eventId),
                "name": .string(option.name.nilIfBlank ?? ""),
                "price": .number(resolvedPrice),
                "sort_order": .number(Double(index)),
                "eligible_group": .string(eligibleGroup),
                "original_price": option.originalPrice.map { .number($0) } ?? .null,
                "is_promotional": .bool(option.isPromotional),
                "promo_start": option.promoStart.nilIfBlank.flatMap { PromoPricing.storageString(from: $0, boundary: .start) }.map { .string($0) } ?? .null,
                "promo_end": option.promoEnd.nilIfBlank.flatMap { PromoPricing.storageString(from: $0, boundary: .end) }.map { .string($0) } ?? .null,
                "payment_type": .string(option.paymentType),
                "deposit_amount": option.paymentType == "deposit" ? .number(option.depositAmount) : .null,
                "balance_amount": option.paymentType == "deposit" ? .number(resolvedBalance) : .null,
                "balance_payment_mode": option.paymentType == "deposit" ? .string(option.balancePaymentMode) : .null,
                "has_dedicated_spots": .bool(option.hasDedicatedSpots),
                "dedicated_spots": option.hasDedicatedSpots ? .number(Double(option.dedicatedSpots)) : .null,
                "waitlist_enabled": .bool(false)
            ]
            let data = try JSONEncoder().encode(payload)
            if let serverId = option.serverId {
                let _: EmptyResponse = try await request(path: "/rest/v1/event_price_options?id=eq.\(serverId.urlEncoded)", method: "PATCH", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
            } else {
                let _: EmptyResponse = try await request(path: "/rest/v1/event_price_options", method: "POST", bodyData: data, auth: session, decode: EmptyResponse.self, prefer: "return=minimal")
            }
        }
    }

    private func replaceSpecialBadges(eventId: String, badgeIds: [String], session: AuthSession) async throws {
        let _: EmptyResponse = try await request(path: "/rest/v1/event_special_badges?event_id=eq.\(eventId.urlEncoded)", method: "DELETE", bodyData: nil, auth: session, decode: EmptyResponse.self)
        let uniqueIds = Array(Set(badgeIds.filter { $0.nilIfBlank != nil }))
