    private func function<T: Decodable>(name: String, body: [String: JSONValue], session: AuthSession?) async throws -> T {
        let data = try JSONEncoder().encode(body)
        return try await request(url: ScampagnateConfig.supabaseURL.appending(path: "/functions/v1/\(name)"), method: "POST", bodyData: data, auth: session, decode: T.self, origin: ScampagnateConfig.stripeOrigin)
    }

    private func functionData(name: String, body: [String: JSONValue], session: AuthSession?) async throws -> Data {
        let data = try JSONEncoder().encode(body)
        return try await requestData(url: ScampagnateConfig.supabaseURL.appending(path: "/functions/v1/\(name)"), method: "POST", bodyData: data, auth: session, origin: ScampagnateConfig.stripeOrigin)
    }

    private func request<Body: Encodable, T: Decodable>(path: String, method: String, body: Body, auth: AuthSession?, decode: T.Type, prefer: String? = nil) async throws -> T {
        let data = try encoder.encode(body)
        return try await request(path: path, method: method, bodyData: data, auth: auth, decode: decode, prefer: prefer)
    }

    private func request<T: Decodable>(path: String, method: String, bodyData: Data?, auth: AuthSession?, decode: T.Type, prefer: String? = nil) async throws -> T {
        try await request(url: ScampagnateConfig.supabaseURL.appendingPath(path), method: method, bodyData: bodyData, auth: auth, decode: decode, prefer: prefer, origin: nil)
    }

    private func request<T: Decodable>(url: URL, method: String, bodyData: Data?, auth: AuthSession?, decode: T.Type, prefer: String? = nil, origin: String?) async throws -> T {
        var request = URLRequest(url: url)
        request.cachePolicy = .reloadIgnoringLocalCacheData
        request.httpMethod = method
        request.setValue(ScampagnateConfig.publishableKey, forHTTPHeaderField: "apikey")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        request.setValue("no-store", forHTTPHeaderField: "Cache-Control")
        request.setValue("no-cache", forHTTPHeaderField: "Pragma")
        request.setValue("Bearer \(auth?.accessToken ?? ScampagnateConfig.publishableKey)", forHTTPHeaderField: "Authorization")
        if let prefer { request.setValue(prefer, forHTTPHeaderField: "Prefer") }
        if let origin { request.setValue(origin, forHTTPHeaderField: "Origin") }
        request.httpBody = bodyData

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw AppError.message("Risposta non valida") }
        guard 200..<300 ~= http.statusCode else {
            if let apiError = try? decoder.decode(APIError.self, from: data) {
                throw AppError.message(apiError.displayMessage(statusCode: http.statusCode, url: url))
            }
            throw AppError.message("Errore Supabase \(http.statusCode)")
        }
        if data.isEmpty || T.self == EmptyResponse.self {
            return EmptyResponse() as! T
        }
        return try decoder.decode(T.self, from: data)
    }

    private func requestData(url: URL, method: String, bodyData: Data?, auth: AuthSession?, origin: String?) async throws -> Data {
        var request = URLRequest(url: url)
        request.cachePolicy = .reloadIgnoringLocalCacheData
        request.httpMethod = method
        request.setValue(ScampagnateConfig.publishableKey, forHTTPHeaderField: "apikey")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/vnd.apple.pkpass", forHTTPHeaderField: "Accept")
        request.setValue("no-store", forHTTPHeaderField: "Cache-Control")
        request.setValue("no-cache", forHTTPHeaderField: "Pragma")
        request.setValue("Bearer \(auth?.accessToken ?? ScampagnateConfig.publishableKey)", forHTTPHeaderField: "Authorization")
        if let origin { request.setValue(origin, forHTTPHeaderField: "Origin") }
        request.httpBody = bodyData

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw AppError.message("Risposta non valida") }
        guard 200..<300 ~= http.statusCode else {
            if let apiError = try? decoder.decode(APIError.self, from: data) {
                throw AppError.message(apiError.displayMessage(statusCode: http.statusCode, url: url))
            }
            throw AppError.message("Errore Supabase \(http.statusCode)")
        }
        return data
    }

    private func uploadStorageObject(url: URL, data: Data, contentType: String, session: AuthSession, upsert: Bool = true) async throws {
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue(ScampagnateConfig.publishableKey, forHTTPHeaderField: "apikey")
        request.setValue("Bearer \(session.accessToken)", forHTTPHeaderField: "Authorization")
        request.setValue(contentType, forHTTPHeaderField: "Content-Type")
        request.setValue(upsert ? "true" : "false", forHTTPHeaderField: "x-upsert")
        request.httpBody = data

        let (responseData, response) = try await URLSession.shared.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw AppError.message("Risposta non valida") }
        guard 200..<300 ~= http.statusCode else {
            if let apiError = try? decoder.decode(APIError.self, from: responseData) {
                throw AppError.message(apiError.displayMessage(statusCode: http.statusCode, url: url, fallbackPrefix: "upload"))
            }
            throw AppError.message("Errore upload \(http.statusCode)")
        }
    }
}

// MARK: - Models

enum AppRole: String, Codable, Hashable {
    case admin
    case organizer
    case user
}

struct UserRoleRow: Decodable {
    let role: AppRole
}

struct OrganizerOwnerRoleRow: Decodable {
    let userId: String
    let role: AppRole
}

struct EventClosingSentenceRow: Decodable {
    let sentence: String
}

struct AuthResponse: Decodable {
    let accessToken: String
    let refreshToken: String?
    let expiresIn: Int?
    let user: AuthUser

    var session: AuthSession {
        AuthSession(
            accessToken: accessToken,
            refreshToken: refreshToken,
            user: user,
            expiresAt: expiresIn.map { Date().addingTimeInterval(TimeInterval($0)) }
        )
    }
}

struct AuthUser: Codable, Identifiable {
    let id: String
    let email: String?
    let appMetadata: AuthAppMetadata?
    let identities: [AuthIdentity]?

    enum CodingKeys: String, CodingKey {
        case id
        case email
        case appMetadata = "app_metadata"
        case identities
    }

    var usesEmailProvider: Bool {
        if appMetadata?.provider == "email" { return true }
        if appMetadata?.providers?.contains("email") == true { return true }
        if identities?.contains(where: { $0.provider == "email" }) == true { return true }
        return appMetadata == nil && identities == nil
    }
}

struct AuthAppMetadata: Codable {
    let provider: String?
    let providers: [String]?
}

struct AuthIdentity: Codable {
    let provider: String?
}

struct AuthUpdateResponse: Decodable {
    let id: String?
    let email: String?
}

struct AuthSession: Codable {
    let accessToken: String
    let refreshToken: String?
    let user: AuthUser
    let expiresAt: Date?

    private static let storageKey = "scampagnate.session"
    private static let refreshWindow: TimeInterval = 120

    var shouldRefresh: Bool {
        guard let expiresAt else { return refreshToken?.isEmpty == false }
        return expiresAt <= Date().addingTimeInterval(Self.refreshWindow)
    }

    func replacingUser(_ user: AuthUser) -> AuthSession {
        AuthSession(accessToken: accessToken, refreshToken: refreshToken, user: user, expiresAt: expiresAt)
    }

    func save() {
        if let data = try? JSONEncoder().encode(self) {
            UserDefaults.standard.set(data, forKey: Self.storageKey)
        }
    }

    static func load() -> AuthSession? {
        guard let data = UserDefaults.standard.data(forKey: storageKey) else { return nil }
        return try? JSONDecoder().decode(AuthSession.self, from: data)
    }

    static func clear() {
        UserDefaults.standard.removeObject(forKey: storageKey)
    }
}

struct PasswordRecoveryLink: Identifiable {
    let id = UUID()
    let accessToken: String
    let refreshToken: String?
    let expiresAt: Date?
    let user: AuthUser

    var session: AuthSession {
        AuthSession(accessToken: accessToken, refreshToken: refreshToken, user: user, expiresAt: expiresAt)
    }

    init?(url: URL) {
        guard Self.isResetPasswordURL(url) else { return nil }
        let params = Self.parameters(from: url)
        guard (params["type"]?.lowercased() ?? "recovery") == "recovery" else { return nil }
        guard let accessToken = params["access_token"]?.nilIfBlank else { return nil }

        self.accessToken = accessToken
        self.refreshToken = params["refresh_token"]?.nilIfBlank
        self.expiresAt = Self.expiresAt(from: params, accessToken: accessToken)
        self.user = Self.user(from: accessToken)
    }

    static func isResetPasswordURL(_ url: URL) -> Bool {
        guard url.scheme == "scampagnate" else { return false }
        if url.host == "reset-password" { return true }
        return url.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")) == "reset-password"
    }

    static func errorMessage(from url: URL) -> String? {
        guard isResetPasswordURL(url) else { return nil }
        let params = parameters(from: url)
        if let description = params["error_description"]?.replacingOccurrences(of: "+", with: " ").nilIfBlank {
            return description
        }
        if params["error"] != nil || params["error_code"] != nil {
            return "Il link di reset non è più valido. Richiedine uno nuovo."
        }
        return nil
    }

    private static func parameters(from url: URL) -> [String: String] {
        var values: [String: String] = [:]
        append(URLComponents(url: url, resolvingAgainstBaseURL: false)?.queryItems, to: &values)
        if let fragment = url.fragment, !fragment.isEmpty {
            append(URLComponents(string: "scampagnate://reset?\(fragment)")?.queryItems, to: &values)
        }
        return values
    }

    private static func append(_ items: [URLQueryItem]?, to values: inout [String: String]) {
        items?.forEach { item in
            if let value = item.value {
                values[item.name] = value
            }
        }
    }

    private static func expiresAt(from params: [String: String], accessToken: String) -> Date? {
        if let expiresAt = params["expires_at"].flatMap(TimeInterval.init) {
            return Date(timeIntervalSince1970: expiresAt)
        }
        if let expiresIn = params["expires_in"].flatMap(TimeInterval.init) {
            return Date().addingTimeInterval(expiresIn)
        }
        let claims = jwtClaims(accessToken)
        if let exp = claims["exp"] as? NSNumber {
            return Date(timeIntervalSince1970: exp.doubleValue)
        }
        if let exp = claims["exp"] as? TimeInterval {
            return Date(timeIntervalSince1970: exp)
        }
        if let exp = claims["exp"] as? Int {
            return Date(timeIntervalSince1970: TimeInterval(exp))
        }
        return nil
    }

    private static func user(from accessToken: String) -> AuthUser {
        let claims = jwtClaims(accessToken)
        let id = (claims["sub"] as? String) ?? (claims["user_id"] as? String) ?? ""
        let email = claims["email"] as? String
        return AuthUser(id: id, email: email, appMetadata: AuthAppMetadata(provider: "email", providers: ["email"]), identities: nil)
    }

    private static func jwtClaims(_ token: String) -> [String: Any] {
        let parts = token.split(separator: ".")
        guard parts.count >= 2 else { return [:] }
        var payload = String(parts[1])
            .replacingOccurrences(of: "-", with: "+")
            .replacingOccurrences(of: "_", with: "/")
        while payload.count % 4 != 0 {
            payload.append("=")
        }
        guard let data = Data(base64Encoded: payload),
              let object = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            return [:]
        }
        return object
    }
}

struct Profile: Codable, Identifiable {
    let id: String
    var firstName: String?
    var lastName: String?
    var phone: String
    var instagramHandle: String?
    var avatarUrl: String?
    var bio: String?
    var totalPoints: Int?
    var trekkingExperience: String?
    var activityFrequency: String?
    var experienceGrade: Int?
    var membershipId: Int?
    var membershipStatus: String?
    var membershipRegistrationDate: String?
    var membershipYear: Int?
    var isFoundingMember: Bool?
    var accountStatus: String?
    var selfLevel: String?
    var hasCar: String?
    var interests: [String]?
    var onboardingCompleted: Bool?
    var eventMotivation: String?
    var healthSafetyStatus: String?
    var healthSafetyNotes: String?
    var emergencyMedicationHas: Bool?
    var emergencyMedicationNotes: String?
    var healthSafetyHelpNotes: String?
    var healthSafetyUpdatedAt: String?
    var birthDate: String?
    var sex: String?
    var birthPlace: String?
    var provinceOfBirth: String?
    var residentialAddress: String?
    var cityOfResidence: String?
    var provinceOfResidence: String?

    var displayName: String {
        [firstName, lastName].compactMap { $0 }.joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var hasActiveMembership: Bool {
        membershipStatus == "Active"
    }

    var membershipExpiryDate: Date {
        var components = DateComponents()
        components.calendar = Calendar(identifier: .gregorian)
        components.year = membershipYear ?? Calendar.current.component(.year, from: Date())
        components.month = 12
        components.day = 31
        return components.date ?? Date()
    }

    var membershipExpiryShortSlashes: String {
        DateFormatter.membershipSlashesItalian.string(from: membershipExpiryDate)
    }

    var hasCompleteMembershipProfile: Bool {
        missingMembershipFieldLabels.isEmpty
    }

    var isMissingMembershipSex: Bool {
        sex != "M" && sex != "F"
    }

    var missingMembershipFieldLabels: [String] {
        var labels: [String] = []
        if birthDate?.nilIfBlank == nil { labels.append("Data di nascita") }
        if isMissingMembershipSex { labels.append("Sesso anagrafico") }
        if birthPlace?.nilIfBlank == nil { labels.append("Luogo di nascita") }
        if provinceOfBirth?.nilIfBlank == nil { labels.append("Provincia di nascita") }
        if residentialAddress?.nilIfBlank == nil { labels.append("Indirizzo di residenza") }
        if cityOfResidence?.nilIfBlank == nil { labels.append("Città di residenza") }
        if provinceOfResidence?.nilIfBlank == nil { labels.append("Provincia di residenza") }
        return labels
    }
}

struct Event: Codable, Identifiable, Hashable {
    let id: String
    let title: String
    let date: String?
    let time: String?
    let location: String?
    let locationLabel: String?
    let categoryId: String?
    let status: String?
    let price: Double?
    let deposit: Double?
    let paymentType: String?
    let balancePaymentMode: String?
    let imageUrl: String?
    let difficulty: String?
    let distance: String?
    let elevation: String?
    let duration: String?
    let spotsTotal: Int?
    let spotsTaken: Int?
    let reservedSpots: Int?
    let featured: Bool?
    let eventBadges: [String]?
    let organizerId: String?
    let organizerName: String?
    let description: String?
    let cancellationPolicy: String?
    let visibility: String?
    let eventCategories: EventCategory?
    let eventMeetingPoints: [MeetingPoint]?
    let eventPriceOptions: [PriceOption]?
    let galleryImages: [GalleryImage]?
    let equipmentList: [EquipmentItem]?
    let additionalFields: JSONValue?
    let accessRules: JSONValue?
    let eventStaff: [EventStaffMember]?

    enum CodingKeys: String, CodingKey {
        case id, title, date, time, location, categoryId, status, price, deposit, difficulty, distance, elevation, duration, featured, description, visibility
        case locationLabel, paymentType, balancePaymentMode, imageUrl, spotsTotal, spotsTaken, reservedSpots, eventBadges, organizerId, organizerName, cancellationPolicy, galleryImages, equipmentList, additionalFields, accessRules, eventStaff
        case eventCategories, eventMeetingPoints, eventPriceOptions
    }

    var category: EventCategory? { eventCategories }
    var meetingPoints: [MeetingPoint] { (eventMeetingPoints ?? []).sortedChronologically() }
    var priceOptions: [PriceOption] { (eventPriceOptions ?? []).sorted { ($0.sortOrder ?? 0) < ($1.sortOrder ?? 0) } }
    var gallery: [GalleryImage] { (galleryImages ?? []).sorted { ($0.order ?? 0) < ($1.order ?? 0) } }
    var homeCardImageUrl: String? { additionalFields?.string(at: "home_card_image_url")?.nilIfBlank }
    var cardImageUrl: String? { homeCardImageUrl ?? imageUrl ?? gallery.first?.url }
    var equipmentItems: [EquipmentItem] { equipmentList ?? [] }
    var staffMembers: [EventStaffMember] { (eventStaff ?? []).sorted { ($0.sortOrder ?? 0) < ($1.sortOrder ?? 0) } }
    var hasEquipment: Bool { !equipmentItems.isEmpty }
    var hasEventTopBadge: Bool { featured == true || (eventBadges ?? []).contains("evento_top") }
    var hasActivePromo: Bool { priceOptions.contains { $0.hasActivePromo() } }
    var manualBadgeTexts: [String] {
        (eventBadges ?? []).compactMap { badge -> String? in
            let cleanBadge = badge.trimmingCharacters(in: .whitespacesAndNewlines)
            guard cleanBadge != "evento_top" else { return nil }
            return Self.manualEventBadgeLabels[cleanBadge]
        }
        .removingDuplicates()
    }
    var customBadgeText: String? {
        (eventBadges ?? []).compactMap { badge -> String? in
            let cleanBadge = badge.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !cleanBadge.isEmpty, !Self.managedEventBadgeIds.contains(cleanBadge) else { return nil }
            return cleanBadge
        }
        .first
    }
    var displayLocation: String { locationLabel ?? location ?? "Luogo da definire" }
    var normalizedStatus: String { status?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? "open" }
    var displayPrice: String {
        guard let price, price > 0 else { return "Gratis" }
        return "€\(Int(price))"
    }

    func displayPrice(profile: Profile?, badges: [UserBadge], registrations: [Registration]) -> String {
        let visibleOptions = priceOptions.available(for: PriceEligibilityContext(profile: profile, badges: badges, registrations: registrations))
        let bookableOptions = visibleOptions.filter { $0.isBookable(in: self) }
        let pricedOptions = bookableOptions.isEmpty ? visibleOptions : bookableOptions
        if let minimumPrice = pricedOptions.map({ $0.totalPrice(fallback: self) }).min() {
            guard minimumPrice > 0 else { return "Gratis" }
            let prefix = pricedOptions.count > 1 ? "da " : ""
            return "\(prefix)€\(Int(minimumPrice))"
        }
        return displayPrice
    }
    var attendeeSpotsTaken: Int {
        max(spotsTaken ?? 0, 0)
    }
    var availableSpots: Int { max(0, (spotsTotal ?? 0) - attendeeSpotsTaken) }
    var bookableSpots: Int { max(0, (spotsTotal ?? 0) - (spotsTaken ?? 0)) }
    var capacityFillRatio: Double {
        let total = spotsTotal ?? 0
        guard total > 0 else { return 0 }
        return min(1, max(0, Double(attendeeSpotsTaken) / Double(total)))
    }
    var capacityFillColor: Color {
        if isSoldOut || capacityFillRatio >= EventAvailabilityRules.lastSpotsFillRatio {
            return Brand.destructive
        }
        if capacityFillRatio >= EventAvailabilityRules.warningFillRatio {
            return Brand.warning
        }
        return Brand.success
    }
    var hasLastSpots: Bool {
        (spotsTotal ?? 0) > 0
            && capacityFillRatio >= EventAvailabilityRules.lastSpotsFillRatio
            && bookableSpots > 0
            && !isSoldOut
    }
    var hasBookableParticipationOption: Bool {
        guard acceptsRegistrations, !isSoldOut else { return false }
        guard !priceOptions.isEmpty else { return bookableSpots > 0 }
        return priceOptions.contains { $0.isBookable(in: self) }
    }
    var waitingListEnabled: Bool {
        additionalFields?.bool(at: "waiting_list_enabled") == true
    }
    var hasWaitlistParticipationOption: Bool {
        guard acceptsRegistrations else { return false }
        guard !priceOptions.isEmpty else { return isSoldOut && waitingListEnabled }
        return priceOptions.contains { $0.canJoinWaitlist(in: self) }
    }
    var availabilityLabel: String {
        let remaining = priceOptions.isEmpty ? bookableSpots : (priceOptions.map { $0.realRemainingSpots(in: self) }.max() ?? bookableSpots)
        if remaining > 0 {
            return remaining == 1 ? "1 posto disponibile" : "\(remaining) posti disponibili"
        }
        return hasWaitlistParticipationOption ? "Lista d'attesa" : "Sold out"
    }
    private var organizerSpotOffset: Int {
        organizerId?.nilIfBlank != nil || organizerName?.nilIfBlank != nil ? 1 : 0
    }
    var isManualSoldOut: Bool { normalizedStatus == "full" && bookableSpots > 0 }
    var isSoldOut: Bool { normalizedStatus == "full" || ((spotsTotal ?? 0) > 0 && bookableSpots <= 0) }
    var shouldShowPublicCapacity: Bool { !isManualSoldOut }
    var isFull: Bool { isSoldOut }
    var requiresOnlinePayment: Bool { paymentType == "paid" || paymentType == "deposit" }
    private static let lifecycleTimeZone = TimeZone(identifier: "Europe/Rome")!
    private static var lifecycleCalendar: Calendar {
        var calendar = Calendar(identifier: .gregorian)
        calendar.locale = Locale(identifier: "it_IT")
        calendar.timeZone = lifecycleTimeZone
        return calendar
    }
    private var lifecycleDateComponents: DateComponents? {
        guard let date else { return nil }
        let parts = date.prefix(10).split(separator: "-").compactMap { Int($0) }
        guard parts.count == 3 else { return nil }
        var components = DateComponents()
        components.calendar = Self.lifecycleCalendar
        components.timeZone = Self.lifecycleTimeZone
        components.year = parts[0]
        components.month = parts[1]
        components.day = parts[2]
        return components
    }
    var eventStartDateTime: Date? {
        guard var components = lifecycleDateComponents else { return nil }
        if let time = time?.prefix(5) {
            let parts = time.split(separator: ":").compactMap { Int($0) }
            if parts.count == 2 {
                components.hour = parts[0]
                components.minute = parts[1]
            }
        }
        components.second = 0
        return Self.lifecycleCalendar.date(from: components)
    }
    private var fallbackVisibilityEndDateTime: Date? {
        guard var components = lifecycleDateComponents else { return nil }
        components.day = (components.day ?? 0) + 1
        components.hour = 0
        components.minute = 0
        components.second = 0
        return Self.lifecycleCalendar.date(from: components)
    }
    private var lifecycleDurationMinutes: Int? {
        guard let duration = duration?.nilIfBlank?.lowercased() else { return nil }
        let days = lifecycleDurationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:giorn(?:o|i)?|gg|g|days?|d)\b"#)
        let hours = lifecycleDurationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:h|ore?|hours?)\b"#)
        let minutes = lifecycleDurationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:m|min|mins|minuti?)\b"#)
        let total = Int((days * 24 * 60 + hours * 60 + minutes).rounded())
        return total > 0 ? total : nil
    }
    private func lifecycleDurationComponent(in duration: String, matching pattern: String) -> Double {
        duration
            .firstRegexCapture(pattern)?
            .replacingOccurrences(of: ",", with: ".")
            .nilIfBlank
            .flatMap(Double.init) ?? 0
    }
    var eventVisibilityEndDateTime: Date? {
        if let start = eventStartDateTime, let lifecycleDurationMinutes {
            return start.addingTimeInterval(TimeInterval(lifecycleDurationMinutes * 60))
        }
        return fallbackVisibilityEndDateTime
    }
    var hasRegistrationStarted: Bool {
        eventStartDateTime.map { $0 <= Date() } ?? false
    }
    var acceptsRegistrations: Bool {
        guard ["available", "published", "open", "full"].contains(normalizedStatus) else { return false }
        guard let start = eventStartDateTime else { return true }
        return start > Date()
    }
    var canNotifyWhenRegistrationsOpen: Bool {
        guard ["draft", "unpublished", "upcoming"].contains(normalizedStatus) else { return false }
        guard let start = eventStartDateTime else { return true }
        return start > Date()
    }
    var acceptsWaitlistCompletion: Bool {
        guard ["available", "published", "open", "full"].contains(normalizedStatus) else { return false }
        guard let start = eventStartDateTime else { return true }
        return start > Date()
    }
    var isVisibleInUpcomingList: Bool {
        guard !["draft", "unpublished", "past", "completed", "cancelled", "archived"].contains(normalizedStatus) else { return false }
        guard let end = eventVisibilityEndDateTime else { return true }
        return end > Date()
    }
    var registrationUnavailableMessage: String {
        switch normalizedStatus {
        case "draft", "unpublished":
            return "Le iscrizioni non sono ancora aperte per questo evento."
        case "upcoming":
            return "Le iscrizioni non sono ancora aperte per questo evento."
        case "closed":
            return "Le iscrizioni per questo evento sono chiuse."
        case "rescheduled":
            return "Questo evento è in riprogrammazione."
        case "cancelled":
            return "Questo evento è stato annullato."
        case "past", "completed":
            return "Questo evento è già passato."
        case "archived":
            return "Questo evento non è più disponibile."
        default:
            if hasRegistrationStarted && !isPastOrCancelled {
                return "Le iscrizioni per questo evento sono chiuse."
            }
            if isPastOrCancelled {
                return "Questo evento è già passato."
            }
            return "Le iscrizioni per questo evento non sono disponibili."
        }
    }
    var isPastOrCancelled: Bool {
        if ["draft", "past", "completed", "cancelled", "archived"].contains(normalizedStatus) { return true }
        guard let end = eventVisibilityEndDateTime else { return false }
        return end <= Date()
    }
    var registrationDeadlineText: String? {
        guard let raw = additionalFields?.string(at: "registration_deadline")?.nilIfBlank else { return nil }
        if let date = DateFormatter.eventDate.date(from: String(raw.prefix(10))) ?? raw.iso8601Date {
            return DateFormatter.birthDateItalianSlashes.string(from: date)
        }
        return raw
    }

    func hash(into hasher: inout Hasher) { hasher.combine(id) }
    static func == (lhs: Event, rhs: Event) -> Bool { lhs.id == rhs.id }
}

struct EventStaffMember: Codable, Identifiable, Hashable {
    let id: String
    let eventId: String?
    let profileId: String?
    let displayName: String
    let roleLabel: String?
    let avatarUrl: String?
    let sortOrder: Int?
    let isPublic: Bool?

    var role: String {
        roleLabel?.nilIfBlank ?? "Staff"
    }

    var name: String {
        displayName.nilIfBlank ?? "Staff"
    }
}

struct CheckoutCustomField: Identifiable, Hashable {
    let id: String
    let label: String
    let type: String
    let placeholder: String
    let required: Bool
    let options: [String]

    init?(json: JSONValue, index: Int) {
        guard let label = json.string(at: "label")?.nilIfBlank else { return nil }
        self.id = "\(index)-\(label)"
        self.label = label
        self.type = json.string(at: "type")?.nilIfBlank?.lowercased() ?? "text"
        self.placeholder = json.string(at: "placeholder") ?? ""
        self.required = json.bool(at: "required") ?? false

        if let optionValues = json["options"]?.arrayValue {
            self.options = optionValues.compactMap { $0.stringValue?.nilIfBlank }
        } else if let optionString = json.string(at: "options") {
            self.options = optionString
                .split(separator: ",")
                .compactMap { String($0).nilIfBlank }
        } else {
            self.options = []
        }
    }
}

struct EventAccessRule: Identifiable, Hashable {
    let id = UUID()
    let type: String
    let value: String?
    let badgeIds: [String]
    let badgeName: String?
    let message: String?
    let enforcement: String?
    let interests: [String]

    init(json: JSONValue) {
        type = json.string(at: "type")?.nilIfBlank ?? ""
        if let number = json.double(at: "value") {
            value = String(Int(number))
        } else {
            value = json.string(at: "value")?.nilIfBlank
        }
        badgeIds = json.stringArray(at: "badge_ids") ?? json.string(at: "badge_id").map { [$0] } ?? []
        badgeName = json.string(at: "badge_name")?.nilIfBlank
        message = json.string(at: "message")?.nilIfBlank
        enforcement = json.string(at: "enforcement")?.nilIfBlank
        interests = json.stringArray(at: "interests") ?? []
    }

    var numericValue: Int {
        Int(value ?? "") ?? 1
    }

    var effectiveEnforcement: String {
        if type == "manual_approval" { return "hard" }
        if type == "interests" { return "soft" }
        return enforcement ?? "hard"
    }
}

struct EventAccessCheck: Equatable {
    let failedReasons: [String]
    let softWarnings: [String]
    let requiresApproval: Bool
    let restrictionMessage: String?

    var hasAccess: Bool { failedReasons.isEmpty }
    var isBlocking: Bool { !failedReasons.isEmpty }
    var hasWarnings: Bool { !softWarnings.isEmpty }

    static let open = EventAccessCheck(failedReasons: [], softWarnings: [], requiresApproval: false, restrictionMessage: nil)

    static func evaluate(event: Event, profile: Profile?, badges: [UserBadge], registrations: [Registration]) -> EventAccessCheck {
        let rules = event.accessRulesList
        if rules.isEmpty {
            return difficultyFallback(event: event, profile: profile, registrations: registrations)
        }

        guard let profile else {
            let failed = rules
                .filter { $0.effectiveEnforcement == "hard" }
                .map { $0.message ?? "Devi effettuare il login" }
            return EventAccessCheck(
                failedReasons: failed,
                softWarnings: [],
                requiresApproval: false,
                restrictionMessage: event.accessRules?.string(at: "restriction_message") ?? "Devi effettuare il login per verificare i requisiti di accesso."
            )
        }

        var failed: [String] = []
        var warnings: [String] = []
        var requiresApproval = false
        let completedBadgeIds = Set(badges.filter(\.isCompleted).compactMap(\.badgeId).map { $0.lowercased() })
        let completedBadgeNames = Set(badges.filter(\.isCompleted).map { $0.displayName.lowercased() })

        func add(_ message: String, for rule: EventAccessRule) {
            if rule.effectiveEnforcement == "soft" {
                warnings.append(message)
            } else {
                failed.append(message)
            }
        }

        for rule in rules {
            switch rule.type {
            case "require_membership":
                if !profile.hasActiveMembership {
                    add(rule.message ?? "Questo evento richiede una membership attiva.", for: rule)
                }
            case "min_trekking_events":
                let minCount = rule.numericValue
                if trekkingAttendanceCount(in: registrations) < minCount {
                    add(rule.message ?? "Questo evento richiede almeno \(minCount) esperienze di trekking completate.", for: rule)
                }
            case "min_attended_events":
                let minCount = rule.numericValue
                if attendedEventCount(in: registrations) < minCount {
                    add(rule.message ?? "Questo evento richiede almeno \(minCount) presenze totali.", for: rule)
                }
            case "require_badge":
                let requiredIds = badgeIds(for: rule)
                let hasRequiredId = !requiredIds.isEmpty && requiredIds.contains { completedBadgeIds.contains($0.lowercased()) }
                let hasRequiredName = rule.badgeName.map { completedBadgeNames.contains($0.lowercased()) } ?? false
                if !hasRequiredId && !hasRequiredName {
                    add(rule.message ?? "Questo evento richiede uno dei badge richiesti.", for: rule)
                }
            case "manual_approval":
                requiresApproval = true
            case "min_activities":
                let minCount = rule.numericValue
                if attendedEventCount(in: registrations) < minCount {
                    add(rule.message ?? "Questo evento richiede almeno \(minCount) attività completate.", for: rule)
                }
            case "min_level":
                let requiredLevel = rule.numericValue
                if levelValue(profile.selfLevel) < requiredLevel {
                    add(rule.message ?? "Questo evento richiede almeno un livello \(levelLabel(requiredLevel)).", for: rule)
                }
            case "min_experience":
                let requiredExperience = rule.numericValue
                if experienceValue(profile.trekkingExperience) < requiredExperience {
                    add(rule.message ?? "Questo evento richiede almeno \(experienceLabel(requiredExperience)).", for: rule)
                }
            case "min_activity_frequency":
                let requiredFrequency = rule.numericValue
                if frequencyValue(profile.activityFrequency) < requiredFrequency {
                    add(rule.message ?? "Questo evento richiede una frequenza di attività minima: \(frequencyLabel(requiredFrequency)).", for: rule)
                }
            case "interests":
                let userInterests = Set((profile.interests ?? []).map { $0.lowercased() })
                let eventInterests = rule.interests.map { $0.lowercased() }
                if !eventInterests.isEmpty && eventInterests.allSatisfy({ !userInterests.contains($0) }) {
                    warnings.append(rule.message ?? "Questo evento potrebbe non essere perfettamente in linea con i tuoi interessi.")
                }
            default:
                continue
            }
        }

        return EventAccessCheck(
            failedReasons: failed,
            softWarnings: warnings,
            requiresApproval: requiresApproval,
            restrictionMessage: failed.isEmpty ? nil : (event.accessRules?.string(at: "restriction_message") ?? failed.first)
        )
    }

    private static func badgeIds(for rule: EventAccessRule) -> [String] {
        if !rule.badgeIds.isEmpty { return rule.badgeIds }
        if let value = rule.value?.nilIfBlank { return [value] }
        return []
    }

    private static func difficultyFallback(event: Event, profile: Profile?, registrations: [Registration]) -> EventAccessCheck {
        guard let rawDifficulty = event.difficulty?.nilIfBlank,
              let difficulty = Int(rawDifficulty),
              difficulty >= 3,
              let profile else {
            return .open
        }

        if (profile.experienceGrade ?? 0) >= difficulty * 2 || profileMatchesDifficulty(profile, difficulty: difficulty) {
            return .open
        }

        let attended = uniqueAttendedRegistrations(in: registrations)
        let easyCount = attended.filter { registration in
            guard let raw = registration.event?.difficulty, let value = Int(raw) else { return false }
            return value <= 2
        }.count
        let intermediateCount = attended.filter { registration in
            guard let raw = registration.event?.difficulty, let value = Int(raw) else { return false }
            return value >= 3
        }.count

        if difficulty == 3 && easyCount >= 3 { return .open }
        if difficulty >= 4 && intermediateCount >= 3 { return .open }

        let reason = difficulty >= 4
            ? "Questo evento è riservato a escursionisti esperti con livello avanzato e buona preparazione fisica."
            : "Per questo evento è consigliata esperienza intermedia e attività fisica regolare."
        return EventAccessCheck(failedReasons: [], softWarnings: [reason], requiresApproval: false, restrictionMessage: nil)
    }

    private static func profileMatchesDifficulty(_ profile: Profile, difficulty: Int) -> Bool {
        if difficulty == 3 {
            let levelOk = profile.selfLevel == "intermediate" || profile.selfLevel == "advanced"
            let experienceOk = profile.trekkingExperience == "3_5" || profile.trekkingExperience == "5_plus" || profile.trekkingExperience == "5+"
            let fitnessOk = profile.activityFrequency == "medium" || profile.activityFrequency == "high" || profile.activityFrequency == "1-2/week" || profile.activityFrequency == ">2/week"
            return (levelOk || experienceOk) && fitnessOk
        }
        let levelOk = profile.selfLevel == "advanced"
        let experienceOk = profile.trekkingExperience == "5_plus" || profile.trekkingExperience == "5+"
        let fitnessOk = profile.activityFrequency == "high" || profile.activityFrequency == ">2/week"
        return levelOk && experienceOk && fitnessOk
    }

    private static func uniqueAttendedRegistrations(in registrations: [Registration]) -> [Registration] {
        var seen = Set<String>()
        return registrations
            .filter { $0.checkedIn == true || $0.normalizedStatus == "attended" }
            .filter { registration in
                guard let key = registration.eventId ?? registration.event?.id else { return false }
                return seen.insert(key).inserted
            }
    }

    private static func attendedEventCount(in registrations: [Registration]) -> Int {
        uniqueAttendedRegistrations(in: registrations).count
    }

    private static func trekkingAttendanceCount(in registrations: [Registration]) -> Int {
        uniqueAttendedRegistrations(in: registrations).filter { registration in
            let category = registration.event?.category?.name?.lowercased() ?? ""
            return category.contains("trekking") || category.contains("escursion")
        }.count
    }

    private static func levelValue(_ value: String?) -> Int {
        switch value {
        case "beginner": 1
        case "intermediate": 2
        case "advanced": 3
        default: 0
        }
    }

    private static func experienceValue(_ value: String?) -> Int {
        switch value {
        case "0_2": 1
        case "3_5": 2
        case "5_plus", "5+": 3
        default: 0
        }
    }

    private static func frequencyValue(_ value: String?) -> Int {
        switch value {
        case "low", "0-1/week": 1
        case "medium", "1-2/week": 2
        case "high", ">2/week": 3
        default: 0
        }
    }

    private static func levelLabel(_ value: Int) -> String {
        switch value {
        case 1: "Principiante"
        case 2: "Intermedio"
        case 3: "Avanzato"
        default: "richiesto"
        }
    }

    private static func experienceLabel(_ value: Int) -> String {
        switch value {
        case 1: "0-2 escursioni"
        case 2: "3-5 escursioni"
        case 3: "5+ escursioni"
        default: "l'esperienza richiesta"
        }
    }

    private static func frequencyLabel(_ value: Int) -> String {
        switch value {
        case 1: "Bassa (0-1/settimana)"
        case 2: "Media (1-2/settimana)"
        case 3: "Alta (>2/settimana)"
        default: "richiesta"
        }
    }
}

extension Event {
    var accessRulesList: [EventAccessRule] {
        accessRules?.array(at: "rules")?.map(EventAccessRule.init(json:)) ?? []
    }

    var checkoutCustomFields: [CheckoutCustomField] {
        let rawFields: [JSONValue]
        if let fields = additionalFields?.array(at: "fields") {
            rawFields = fields
        } else if let fields = additionalFields?.array(at: "custom_fields") {
            rawFields = fields
        } else if let fields = additionalFields?.arrayValue {
            rawFields = fields
        } else {
            rawFields = []
        }
        return rawFields.enumerated().compactMap { index, value in
            CheckoutCustomField(json: value, index: index)
        }
    }

    var asksCarAvailability: Bool {
        additionalFields?.bool(at: "car_availability_enabled") == true ||
        additionalFields?.bool(at: "ask_car_availability") == true
    }

    var isSportCategory: Bool {
        category?.name?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == "sport & movimento"
    }

    var requiresManualApproval: Bool {
        if accessRules?.bool(at: "manual_approval") == true { return true }
        if accessRules?.string(at: "type") == "manual_approval" { return true }
        return accessRulesList.contains { $0.type == "manual_approval" }
    }
}

