}

struct MeetingPoint: Codable, Identifiable, Hashable {
    let id: String
    let name: String?
    let location: String?
    let time: String?
    let notes: String?
}

private extension Array where Element == MeetingPoint {
    func sortedChronologically() -> [MeetingPoint] {
        enumerated()
            .sorted { lhs, rhs in
                let leftMinutes = lhs.element.minutesSinceMidnight
                let rightMinutes = rhs.element.minutesSinceMidnight

                switch (leftMinutes, rightMinutes) {
                case let (left?, right?) where left != right:
                    return left < right
                case (_?, nil):
                    return true
                case (nil, _?):
                    return false
                default:
                    return lhs.offset < rhs.offset
                }
            }
            .map(\.element)
    }
}

private extension MeetingPoint {
    var minutesSinceMidnight: Int? {
        guard let rawTime = time?.nilIfBlank else { return nil }
        let normalized = rawTime
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: ".", with: ":")
        let parts = normalized.split(separator: ":", omittingEmptySubsequences: false)
        guard let hourPart = parts.first,
              let hour = Int(hourPart),
              (0..<24).contains(hour) else {
            return nil
        }
        let minute = parts.dropFirst().first.flatMap { Int($0) } ?? 0
        guard (0..<60).contains(minute) else { return nil }
        return hour * 60 + minute
    }
}

struct PriceOption: Codable, Identifiable, Hashable {
    let id: String
    let name: String?
    let price: Double?
    let sortOrder: Int?
    let originalPrice: Double?
    let eligibleGroup: String?
    let isPromotional: Bool?
    let promoStart: String?
    let promoEnd: String?
    let paymentType: String?
    let depositAmount: Double?
    let balanceAmount: Double?
    let balancePaymentMode: String?
    let hasDedicatedSpots: Bool?
    let dedicatedSpots: Int?
    let spotsTaken: Int?
    let waitlistEnabled: Bool?

    var displayName: String {
        name?.priceOptionDisplayName ?? "Partecipazione evento"
    }

    var detailText: String {
        var parts: [String] = []
        if let eligible = eligibleGroup?.nilIfBlank, eligible.lowercased() != "all" {
            parts.append(eligibleLabel)
        }
        if isPromotional == true {
            parts.append(promoBadgeText())
        }
        return parts.joined(separator: " · ")
    }

    var eligibleLabel: String {
        guard let group = eligibleGroup?.nilIfBlank?.lowercased() else { return "" }
        if group == "members" { return "Soci" }
        if group == "new_users" { return "Nuovi utenti" }
        if group == "experienced" { return "Esperti" }
        if group == "loyal" { return "Fedeli" }
        if group.hasPrefix("badge:") { return "Promo riservata" }
        if group.hasPrefix("trekking_gt:") || group.hasPrefix("events_gt:") { return "Promo riservata" }
        return "Promo riservata"
    }

    var amount: Double {
        price ?? 0
    }

    func promoStatus(now: Date = Date()) -> PromoWindowStatus {
        guard isPromotional == true else { return .active }
        return PromoPricing.windowStatus(start: promoStart, end: promoEnd, now: now)
    }

    func showsPromoBadge(now: Date = Date()) -> Bool {
        guard isPromotional == true else { return false }
        return promoStatus(now: now) == .active
    }

    func hasActivePromo(now: Date = Date()) -> Bool {
        isPromotional == true && promoStatus(now: now) == .active
    }

    func promoBadgeText(now: Date = Date()) -> String {
        PromoPricing.badgeLabel(end: promoEnd, now: now)
    }

    func promoBadgeCountdownText(now: Date = Date()) -> String {
        PromoPricing.compactBadgeLabel(end: promoEnd, now: now)
    }

    var usesDedicatedSpots: Bool {
        hasDedicatedSpots == true && (dedicatedSpots ?? 0) > 0
    }

    var optionSpotsTaken: Int {
        max(spotsTaken ?? 0, 0)
    }

    var dedicatedRemainingSpots: Int? {
        guard usesDedicatedSpots else { return nil }
        return max((dedicatedSpots ?? 0) - optionSpotsTaken, 0)
    }

    func totalPrice(fallback event: Event) -> Double {
        price ?? event.price ?? 0
    }

    func effectivePaymentType(fallback event: Event) -> String {
        if let paymentType = paymentType?.nilIfBlank { return paymentType }
        if let eventPaymentType = event.paymentType?.nilIfBlank { return eventPaymentType }
        return totalPrice(fallback: event) > 0 ? "paid" : "free"
    }

    func effectiveDepositAmount(fallback event: Event) -> Double {
        depositAmount ?? event.deposit ?? 0
    }

    func effectiveBalanceAmount(fallback event: Event) -> Double {
        balanceAmount ?? max(0, totalPrice(fallback: event) - effectiveDepositAmount(fallback: event))
    }

    func effectiveBalancePaymentMode(fallback event: Event) -> String {
        balancePaymentMode?.nilIfBlank ?? event.balancePaymentMode?.nilIfBlank ?? "online"
    }

    func requiresOnlinePayment(fallback event: Event) -> Bool {
        let type = effectivePaymentType(fallback: event)
        return type == "paid" || type == "deposit"
    }

    func realRemainingSpots(in event: Event, eventSpotsTaken: Int? = nil, optionSpotsTaken: Int? = nil) -> Int {
        let effectiveEventSpotsTaken = max(eventSpotsTaken ?? event.spotsTaken ?? 0, 0)
        let eventRemaining = max((event.spotsTotal ?? 0) - effectiveEventSpotsTaken, 0)
        guard usesDedicatedSpots else { return eventRemaining }

        let effectiveOptionSpotsTaken = max(optionSpotsTaken ?? spotsTaken ?? 0, 0)
        let dedicatedRemaining = max((dedicatedSpots ?? 0) - effectiveOptionSpotsTaken, 0)
        return min(eventRemaining, dedicatedRemaining)
    }

    func isBookable(in event: Event, now: Date = Date(), eventSpotsTaken: Int? = nil, optionSpotsTaken: Int? = nil) -> Bool {
        guard isCurrentlyAvailable(now: now), event.acceptsRegistrations, event.normalizedStatus != "full" else { return false }
        return realRemainingSpots(in: event, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken) > 0
    }

    func canJoinWaitlist(in event: Event, now: Date = Date(), eventSpotsTaken: Int? = nil, optionSpotsTaken: Int? = nil) -> Bool {
        let remaining = realRemainingSpots(in: event, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken)
        guard isCurrentlyAvailable(now: now), event.acceptsRegistrations, event.normalizedStatus == "full" || remaining <= 0 else { return false }
        return !isBookable(in: event, now: now, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken) && event.waitingListEnabled
    }

    func availabilityText(in event: Event, now: Date = Date(), eventSpotsTaken: Int? = nil, optionSpotsTaken: Int? = nil) -> String {
        if isPromotional == true {
            switch promoStatus(now: now) {
            case .upcoming:
                return "Promozione non ancora attiva"
            case .expired:
                return "Promozione scaduta"
            case .active:
                break
            }
        }

        if isBookable(in: event, now: now, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken) {
            let remaining = realRemainingSpots(in: event, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken)
            return remaining == 1 ? "1 posto disponibile" : "\(remaining) posti disponibili"
        }
        return canJoinWaitlist(in: event, now: now, eventSpotsTaken: eventSpotsTaken, optionSpotsTaken: optionSpotsTaken) ? "Lista d'attesa disponibile" : "Sold out"
    }

    func paymentSummary(in event: Event) -> String {
        switch effectivePaymentType(fallback: event) {
        case "free":
            return "Gratis"
        case "location":
            return "Pagamento sul posto"
        case "deposit":
            let deposit = effectiveDepositAmount(fallback: event)
            let balance = effectiveBalanceAmount(fallback: event)
            let balanceLabel = effectiveBalancePaymentMode(fallback: event) == "on_site" ? "sul posto" : "online"
            return "€\(money(deposit)) ora + €\(money(balance)) \(balanceLabel)"
        default:
            return "Pagamento online"
        }
    }

    func checkoutSingleOptionTitle() -> String {
        displayName
    }

    func isCurrentlyAvailable(now: Date = Date()) -> Bool {
        guard isPromotional == true else { return true }
        return promoStatus(now: now) == .active
    }

    func isEligible(for context: PriceEligibilityContext) -> Bool {
        guard isCurrentlyAvailable() else { return false }
        guard let rawGroup = eligibleGroup?.nilIfBlank?.lowercased() else { return true }
        if rawGroup == "all" { return true }
        guard let profile = context.profile else { return false }

        if rawGroup == "members" {
            return profile.hasActiveMembership
        }
        if rawGroup == "new_users" {
            return context.attendedEventCount == 0
        }
        if rawGroup == "experienced" {
            return profile.selfLevel == "advanced" || (profile.experienceGrade ?? 0) >= 3 || profile.trekkingExperience == "advanced"
        }
        if rawGroup == "loyal" {
            return context.attendedEventCount >= 3
        }
        if rawGroup.hasPrefix("badge:") {
            let requiredBadgeIds = rawGroup
                .replacingOccurrences(of: "badge:", with: "")
                .split(separator: ",")
                .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            return !requiredBadgeIds.isEmpty && requiredBadgeIds.contains { context.completedBadgeIds.contains($0) }
        }
        if rawGroup.hasPrefix("trekking_gt:") {
            return context.attendedEventCount > threshold(from: rawGroup, prefix: "trekking_gt")
        }
        if rawGroup.hasPrefix("events_gt:") {
            return context.attendedEventCount > threshold(from: rawGroup, prefix: "events_gt")
        }
        if rawGroup.hasPrefix("user:") || rawGroup.hasPrefix("user_id:") || rawGroup.hasPrefix("profile:") || rawGroup.hasPrefix("assigned_user:") {
            guard let targetUserId = rawGroup.split(separator: ":", maxSplits: 1).dropFirst().first.map(String.init) else { return false }
            return targetUserId == profile.id.lowercased()
        }
        return false
    }

    private func threshold(from group: String, prefix: String) -> Int {
        guard group.hasPrefix("\(prefix):") else { return 0 }
        guard let value = group.split(separator: ":", maxSplits: 1).dropFirst().first else { return 0 }
        return Int(value) ?? 0
    }
}

struct PriceEligibilityContext {
    let profile: Profile?
    let badges: [UserBadge]
    let registrations: [Registration]

    var completedBadgeIds: Set<String> {
        Set(badges.filter(\.isCompleted).compactMap(\.badgeId).map { $0.lowercased() })
    }

    var attendedEventCount: Int {
        registrations
            .filter { $0.checkedIn == true || $0.normalizedStatus == "attended" }
            .compactMap { $0.eventId ?? $0.event?.id }
            .removingDuplicates()
            .count
    }
}

private extension Array where Element == PriceOption {
    func available(for context: PriceEligibilityContext) -> [PriceOption] {
        let eligibleOptions = filter { $0.isEligible(for: context) }
        if !eligibleOptions.isEmpty {
            return eligibleOptions
        }
        return filter { $0.eligibleGroup?.nilIfBlank == nil || $0.eligibleGroup?.lowercased() == "all" }
    }
}

