struct OrganizerRegistration: Codable, Identifiable, Hashable {
    let id: String
    let eventId: String?
    let userId: String?
    let meetingPointId: String?
    var status: String?
    var paymentStatus: String?
    var checkedIn: Bool?
    let createdAt: String?
    let sportLevel: String?
    let amountPaid: Double?
    let refundAmount: Double?
    let lastBalanceReminderSentAt: String?
    let additionalResponses: [String: String]?
    let profiles: OrganizerParticipantProfile?
    let priceOption: PriceOption?

    var normalizedStatus: String {
        status?.nilIfBlank?.lowercased() ?? "registered"
    }

    var isManual: Bool {
        sportLevel?.hasPrefix("manual:") == true
    }

    var manualName: String? {
        guard isManual else { return nil }
        return sportLevel?
            .replacingOccurrences(of: "manual:", with: "")
            .components(separatedBy: "|")
            .first?
            .nilIfBlank
    }

    var displayName: String {
        manualName ?? profiles?.displayName ?? "Partecipante"
    }

    func specialRequestAnswers(for event: Event) -> [SpecialRequestAnswer] {
        guard let additionalResponses else { return [] }

        var usedLabels = Set<String>()
        var answers: [SpecialRequestAnswer] = []
        let fieldLabels = event.checkoutCustomFields.compactMap { $0.label.nilIfBlank }

        for label in fieldLabels {
            guard let response = additionalResponses[label]?.nilIfBlank else { continue }
            usedLabels.insert(label)
            answers.append(SpecialRequestAnswer(label: label, response: response))
        }

        for key in additionalResponses.keys.sorted(by: { $0.localizedCaseInsensitiveCompare($1) == .orderedAscending }) {
            guard usedLabels.insert(key).inserted,
                  let label = key.nilIfBlank,
                  let response = additionalResponses[key]?.nilIfBlank
            else { continue }
            answers.append(SpecialRequestAnswer(label: label, response: response))
        }

        return answers
    }

    var isActive: Bool {
        ["registered", "deposit_paid", "paid", "attended", "no_show"].contains(normalizedStatus) &&
        paymentStatus?.nilIfBlank?.lowercased() != "pending"
    }

    var statusLabel: String {
        if normalizedStatus == "attended" || checkedIn == true { return "Presente" }
        if normalizedStatus == "no_show" { return "No-show" }
        if normalizedStatus == "cancelled" { return "Cancellato" }
        if normalizedStatus == "waitlist" { return "Waitlist" }
        if normalizedStatus == "pending_approval" { return "Da approvare" }
        if normalizedStatus == "pending_payment" { return "Pagamento" }
        if normalizedStatus == "deposit_paid" { return "Acconto" }
        return "Iscritto"
    }

    var statusColor: Color {
        if normalizedStatus == "attended" || checkedIn == true { return Brand.success }
        if normalizedStatus == "waitlist" || normalizedStatus == "pending_approval" || normalizedStatus == "pending_payment" { return Brand.warning }
        if normalizedStatus == "cancelled" || normalizedStatus == "no_show" { return Brand.destructive }
        return Brand.primary
    }

    func participantPaymentBadge(for event: Event) -> ParticipantPaymentBadgeInfo {
        let payment = paymentStatus?.nilIfBlank?.lowercased()
        let type = priceOption?.effectivePaymentType(fallback: event)
            ?? event.paymentType?.nilIfBlank
            ?? ((event.price ?? 0) > 0 ? "paid" : "free")
        let totalPrice = priceOption?.totalPrice(fallback: event) ?? event.price ?? 0

        if payment == "paid" || normalizedStatus == "paid" {
            return ParticipantPaymentBadgeInfo(label: "Pagato", needsAttention: false)
        }

        if type == "free" || totalPrice <= 0 {
            return ParticipantPaymentBadgeInfo(label: "Gratis", needsAttention: false)
        }

        if payment == "not_required" {
            return ParticipantPaymentBadgeInfo(label: "Non richiesto", needsAttention: false)
        }

        if payment == "deposit_paid" || normalizedStatus == "deposit_paid" {
            let balanceMode = priceOption?.effectiveBalancePaymentMode(fallback: event) ?? event.balancePaymentMode ?? "online"
            let balanceAmount = priceOption?.effectiveBalanceAmount(fallback: event) ?? max(0, (event.price ?? 0) - (event.deposit ?? 0))

            if balanceMode == "on_site" {
                return ParticipantPaymentBadgeInfo(label: "Saldo sul posto", needsAttention: false)
            }

            return balanceAmount > 0
                ? ParticipantPaymentBadgeInfo(label: "Da saldare", needsAttention: true)
                : ParticipantPaymentBadgeInfo(label: "Pagato", needsAttention: false)
        }

        if payment == "pay_on_location" || type == "location" {
            return ParticipantPaymentBadgeInfo(label: "Sul posto", needsAttention: true)
        }

        if payment == "pending" || normalizedStatus == "pending_payment" {
            return ParticipantPaymentBadgeInfo(label: "In attesa pagamento", needsAttention: true)
        }

        if payment == "failed" {
            return ParticipantPaymentBadgeInfo(label: "Pagamento fallito", needsAttention: true)
        }

        return type == "paid" || type == "deposit"
            ? ParticipantPaymentBadgeInfo(label: "In attesa pagamento", needsAttention: true)
            : ParticipantPaymentBadgeInfo(label: "Non richiesto", needsAttention: false)
    }
}

