struct OrganizerPriceOptionDraft: Identifiable, Equatable {
    var id = UUID()
    var serverId: String?
    var name = ""
    var price: Double = 0
    var paymentType = "free"
    var depositAmount: Double = 0
    var balanceAmount: Double = 0
    var balancePaymentMode = "online"
    var hasDedicatedSpots = false
    var dedicatedSpots = 0
    var waitlistEnabled = false
    var eligibleGroup = "all"
    var badgeIds: [String] = []
    var originalPrice: Double?
    var isPromotional = false
    var promoStart = ""
    var promoEnd = ""

    init() {}

    static func defaultFormula(
        named name: String = "",
        paymentType: String = "free",
        price: Double = 0,
        deposit: Double = 0,
        balancePaymentMode: String = "online"
    ) -> OrganizerPriceOptionDraft {
        var option = OrganizerPriceOptionDraft()
        option.name = name
        option.paymentType = paymentType
        option.price = paymentType == "free" ? 0 : price
        option.depositAmount = paymentType == "deposit" ? deposit : 0
        option.balanceAmount = paymentType == "deposit" ? max(0, option.price - deposit) : 0
        option.balancePaymentMode = balancePaymentMode
        return option
    }

    init(legacyEvent event: Event) {
        name = "Partecipazione"
        price = event.paymentType == "free" ? 0 : (event.price ?? 0)
        paymentType = event.paymentType ?? (price > 0 ? "paid" : "free")
        depositAmount = event.deposit ?? 0
        balanceAmount = max(0, price - depositAmount)
        balancePaymentMode = event.balancePaymentMode ?? "online"
        hasDedicatedSpots = false
        dedicatedSpots = 0
        waitlistEnabled = false
    }

    init(option: PriceOption) {
        serverId = option.id
        name = option.name ?? ""
        price = option.price ?? 0
        paymentType = option.paymentType ?? (price > 0 ? "paid" : "free")
        depositAmount = option.depositAmount ?? 0
        balanceAmount = option.balanceAmount ?? max(0, price - depositAmount)
        balancePaymentMode = option.balancePaymentMode ?? "online"
        hasDedicatedSpots = option.hasDedicatedSpots ?? false
        dedicatedSpots = option.dedicatedSpots ?? 0
        waitlistEnabled = option.waitlistEnabled ?? false
        eligibleGroup = option.eligibleGroup ?? "all"
        if let group = option.eligibleGroup, group.hasPrefix("badge:") {
            badgeIds = group.replacingOccurrences(of: "badge:", with: "").split(separator: ",").map(String.init)
        }
        originalPrice = option.originalPrice
        isPromotional = option.isPromotional ?? false
        promoStart = PromoPricing.dateInputString(from: option.promoStart)
        promoEnd = PromoPricing.dateInputString(from: option.promoEnd)
    }
}

