struct OrganizerAdditionalFieldDraft: Identifiable, Equatable {
    var id = UUID()
    var label = ""
    var type = "text"
    var required = false
    var options: [String] = []

    init() {}

    init(json: JSONValue) {
        label = json.string(at: "label") ?? ""
        type = json.string(at: "type") ?? "text"
        required = json.bool(at: "required") ?? false
        if let optionValues = json["options"]?.arrayValue {
            options = optionValues.compactMap { $0.stringValue?.nilIfBlank }
        } else if let optionString = json.string(at: "options") {
            options = optionString
                .split(separator: ",")
                .compactMap { String($0).nilIfBlank }
        } else {
            options = []
        }
    }

    var jsonValue: JSONValue {
        .object([
            "label": .string(label),
            "type": .string(type),
            "required": .bool(required),
            "options": .array(options.map { .string($0) })
        ])
    }
}

struct OrganizerAccessRuleDraft: Identifiable, Equatable {
    var id = UUID()
    var type: String
    var value = ""
    var enforcement = "hard"
    var badgeIds: [String] = []

    init(type: String, value: String = "", enforcement: String = "hard", badgeIds: [String] = []) {
        self.type = type
        self.value = value
        self.enforcement = enforcement
        self.badgeIds = badgeIds
    }

    init(json: JSONValue) {
        type = json.string(at: "type") ?? "manual_approval"
        if let number = json.double(at: "value") {
            value = String(Int(number))
        } else {
            value = json.string(at: "value") ?? ""
        }
        enforcement = json.string(at: "enforcement") ?? "hard"
        badgeIds = json.stringArray(at: "badge_ids") ?? json.string(at: "badge_id").map { [$0] } ?? []
    }

    var jsonValue: JSONValue {
        var object: [String: JSONValue] = [
            "type": .string(type),
            "enforcement": .string(enforcement)
        ]
        if let numeric = Double(value), !value.isEmpty {
            object["value"] = .number(numeric)
        } else if let cleanValue = value.nilIfBlank {
            object["value"] = .string(cleanValue)
        }
        if !badgeIds.isEmpty {
            object["badge_ids"] = .array(badgeIds.map { .string($0) })
            object["badge_id"] = .string(badgeIds[0])
        }
        return .object(object)
    }
}

struct OrganizerEventDraft: Equatable {
    var title = ""
    var description = ""
    var date = DateFormatter.eventDate.string(from: Date())
    var time = "09:00"
    var location = ""
    var locationLabel = ""
    var categoryId = ""
    var spotsTotal = 20
    var reservedSpots = 0
    var price: Double = 0
    var deposit: Double = 0
    var paymentType = "free"
    var balancePaymentMode = "online"
    var difficulty = ""
    var distance = ""
    var elevation = ""
    var duration = ""
    var featured = false
    var cancellationPolicy = "flexible_24h"
    var imageUrl = ""
    var homeCardImageUrl = ""
    var visibility = "public"
    var status = "open"
    var galleryImageURLs: [String] = []
    var manualBadges: [String] = []
    var customBadge = ""
    var specialBadgeIds: [String] = []
    var fitScoreMainCategory = ""
    var fitScoreSecondaryCategories: [String] = []
    var closingSentenceMode = "random"
    var closingSentence = ""
    var waitingListEnabled = true
    var askCarAvailability = false
    var weatherOverrideCondition = ""
    var weatherOverrideTempMin = ""
    var weatherOverrideTempMax = ""
    var weatherOverrideTempAvg = ""
    var exclusivityLabel = ""
    var restrictionMessage = ""
    var meetingPoints: [OrganizerMeetingPointDraft] = []
    var staffMembers: [OrganizerEventStaffDraft] = []
    var priceOptions: [OrganizerPriceOptionDraft] = [OrganizerPriceOptionDraft.defaultFormula()]
    var equipmentItems: [OrganizerEquipmentItemDraft] = []
    var additionalFields: [OrganizerAdditionalFieldDraft] = []
    var accessRules: [OrganizerAccessRuleDraft] = []
    private var originalAdditionalFields: [String: JSONValue] = [:]
    private var originalAccessRules: [String: JSONValue] = [:]
    private var originalCustomBadge = ""
    private var preservedEventBadges: [String] = []

    init() {}

    init(event: Event, meetingPoints: [MeetingPoint] = [], staffMembers: [EventStaffMember] = [], priceOptions: [PriceOption] = [], specialBadgeIds: [String] = [], duplicate: Bool = false) {
        title = duplicate ? "Copia di \(event.title)" : event.title
        description = event.description ?? ""
        date = duplicate ? "" : (event.date ?? DateFormatter.eventDate.string(from: Date()))
        time = duplicate ? "" : String((event.time ?? "09:00").prefix(5))
        location = event.location ?? ""
        locationLabel = event.locationLabel ?? ""
        categoryId = event.categoryId ?? event.category?.id ?? ""
        spotsTotal = event.spotsTotal ?? 20
        reservedSpots = duplicate ? 0 : (event.reservedSpots ?? 0)
        price = event.price ?? 0
        deposit = event.deposit ?? 0
        paymentType = event.paymentType ?? "free"
        balancePaymentMode = event.balancePaymentMode ?? "online"
        difficulty = event.difficulty ?? ""
        distance = event.distance?.replacingOccurrences(of: "km", with: "", options: .caseInsensitive).trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        elevation = event.elevation?.replacingOccurrences(of: "m", with: "", options: .caseInsensitive).trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        duration = event.duration ?? ""
        featured = duplicate ? false : (event.featured ?? false)
        cancellationPolicy = Self.normalizedCancellationPolicy(event.cancellationPolicy)
        imageUrl = event.imageUrl ?? ""
        homeCardImageUrl = event.homeCardImageUrl ?? ""
        visibility = duplicate ? "private" : Self.editableVisibility(event.visibility)
        status = duplicate ? "open" : Self.editableStatus(event.status)
        galleryImageURLs = event.gallery.compactMap(\.url)
        let manualBadgeIds = Set(OrganizerEventDraft.manualBadgeOptions.map(\.id))
        let nonManualBadges = (event.eventBadges ?? []).filter { !manualBadgeIds.contains($0) }
        manualBadges = (event.eventBadges ?? []).filter { manualBadgeIds.contains($0) }
        customBadge = nonManualBadges.first ?? ""
        originalCustomBadge = customBadge
        preservedEventBadges = Array(nonManualBadges.dropFirst())
        self.specialBadgeIds = duplicate ? [] : specialBadgeIds
        self.staffMembers = staffMembers.map { OrganizerEventStaffDraft(member: $0, duplicate: duplicate) }
        originalAdditionalFields = duplicate ? [:] : (event.additionalFields?.objectValue ?? [:])
        originalAccessRules = duplicate ? [:] : (event.accessRules?.objectValue ?? [:])
        fitScoreMainCategory = event.additionalFields?.string(at: "fit_score_main_category") ?? ""
        fitScoreSecondaryCategories = Array((event.additionalFields?.stringArray(at: "fit_score_secondary_categories") ?? [])
            .filter { $0 != fitScoreMainCategory }
            .prefix(2))
        let savedClosingSentence = event.additionalFields?.string(at: "closing_sentence")?.normalizedClosingSentence ?? ""
        if duplicate || savedClosingSentence.nilIfBlank == nil {
            closingSentenceMode = "random"
            closingSentence = ""
        } else if defaultEventClosingSentences.contains(savedClosingSentence) {
            closingSentenceMode = "preset"
            closingSentence = savedClosingSentence
        } else {
            closingSentenceMode = "manual"
            closingSentence = savedClosingSentence
        }
        askCarAvailability = event.additionalFields?.bool(at: "ask_car_availability") ?? event.additionalFields?.bool(at: "car_availability_enabled") ?? false
        waitingListEnabled = event.additionalFields?.bool(at: "waiting_list_enabled") ?? false
        weatherOverrideCondition = event.additionalFields?.string(at: "weather_override_condition") ?? ""
        weatherOverrideTempMin = event.additionalFields?.double(at: "weather_override_temp_min").map { $0.cleanInputString } ?? ""
        weatherOverrideTempMax = event.additionalFields?.double(at: "weather_override_temp_max").map { $0.cleanInputString } ?? ""
        weatherOverrideTempAvg = (
            event.additionalFields?.double(at: "weather_override_temp_avg")
                ?? event.additionalFields?.double(at: "weather_override_temp")
        ).map { $0.cleanInputString } ?? ""
        exclusivityLabel = event.accessRules?.string(at: "exclusivity_label") ?? ""
        restrictionMessage = event.accessRules?.string(at: "restriction_message") ?? ""
        self.meetingPoints = meetingPoints.map { OrganizerMeetingPointDraft(point: $0, duplicate: duplicate) }
        let mappedPriceOptions = priceOptions.map { option in
            var draft = OrganizerPriceOptionDraft(option: option)
            if duplicate {
                draft.serverId = nil
            }
            if draft.name.isGeneratedPriceOptionName {
                draft.name = ""
            }
            return draft
        }
        self.priceOptions = mappedPriceOptions.isEmpty
            ? [OrganizerPriceOptionDraft.defaultFormula(
                paymentType: paymentType,
                price: paymentType == "free" ? 0 : price,
                deposit: paymentType == "deposit" ? deposit : 0,
                balancePaymentMode: balancePaymentMode
            )]
            : mappedPriceOptions
        equipmentItems = event.equipmentItems.map(OrganizerEquipmentItemDraft.init(item:))
        additionalFields = (event.additionalFields?.array(at: "fields") ?? event.additionalFields?.array(at: "custom_fields") ?? event.additionalFields?.arrayValue)?
            .map(OrganizerAdditionalFieldDraft.init(json:)) ?? []
        accessRules = event.accessRules?.array(at: "rules")?.map(OrganizerAccessRuleDraft.init(json:)) ?? []
    }

    init(proposal: ActivityProposalAdmin) {
        title = proposal.activityTitle
        description = proposal.description ?? ""
        date = proposal.suggestedDate ?? DateFormatter.eventDate.string(from: Date())
        time = String((proposal.suggestedTime ?? "09:00").prefix(5))
        location = proposal.location ?? ""
        locationLabel = proposal.locationLabel ?? ""
        categoryId = proposal.categoryId ?? ""
        spotsTotal = proposal.maxParticipants ?? 20
        status = "open"
        visibility = "private"
    }

    static func editableStatus(_ status: String?) -> String {
        switch status {
        case "available", "published":
            return "open"
        case "unpublished":
            return "draft"
        case "past", "completed":
            return "closed"
        case "draft", "upcoming", "open", "closed", "full", "rescheduled", "cancelled":
            return status ?? "open"
        default:
            return "open"
        }
    }

    static func editableVisibility(_ visibility: String?) -> String {
        visibility == "private" ? "private" : "public"
    }

    static let manualBadgeOptions: [(id: String, label: String)] = [
        ("evento_top", "Evento top"),
        ("best_seller", "Best seller"),
        ("consigliato", "Consigliato"),
        ("prezzo_speciale", "Prezzo speciale"),
        ("early_bird", "Early bird"),
        ("pet_friendly", "🐶 Friendly")
    ]

    static let cancellationPolicies: [(id: String, label: String, description: String)] = [
        ("flexible_24h", "Flessibile 24h", "Rimborso completo fino a 24 ore prima, esclusa la fee di servizio."),
        ("flexible_48h", "Flessibile 48h", "Rimborso completo fino a 48 ore prima, esclusa la fee di servizio."),
        ("non_refundable", "Non rimborsabile", "Nessun rimborso in caso di cancellazione del partecipante.")
    ]

    static let fitScoreCategories = [
        "Trekking giornalieri",
        "Cammini plurigiornalieri",
        "Notti in tenda",
        "Trekking notturni",
        "Aperitivi e cene",
        "Sport e movimento",
        "Giochi e sfide",
        "Weekend fuori porta",
        "Degustazioni e cantine",
        "Mare e spiaggia"
    ]

    static func normalizedCancellationPolicy(_ raw: String?) -> String {
        let value = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let prefix = value.split(separator: ":", maxSplits: 1).first.map(String.init) ?? value
        switch prefix {
        case "flexible_24h", "flexible", "flessibile":
            return "flexible_24h"
        case "flexible_48h", "moderate", "moderata":
            return "flexible_48h"
        case "non_refundable", "strict", "rigida", "custom":
            return "non_refundable"
        default:
            return "flexible_24h"
        }
    }

    var validationMessage: String? {
        validationMessages.first
    }

    var validationMessages: [String] {
        var messages: [String] = []
        if title.nilIfBlank == nil { messages.append("Titolo evento") }
        if date.nilIfBlank == nil { messages.append("Data evento") }
        if time.nilIfBlank == nil { messages.append("Ora evento") }
        if location.nilIfBlank == nil { messages.append("Luogo evento") }
        if imageUrl.nilIfBlank == nil { messages.append("Immagine di copertina") }
        if fitScoreMainCategory.nilIfBlank == nil { messages.append("Categoria principale fit score") }
        if spotsTotal < 1 { messages.append("Capienza almeno 1 posto") }
        let validOptions = priceOptions
        if validOptions.isEmpty {
            if paymentType != "free" && paymentType != "location" && price <= 0 { messages.append("Prezzo totale evento") }
            if paymentType == "deposit" && deposit <= 0 { messages.append("Acconto evento") }
            if paymentType == "deposit" && price - deposit <= 0 { messages.append("Saldo evento maggiore di zero") }
        }
        if validOptions.contains(where: { $0.paymentType != "free" && $0.paymentType != "location" && $0.price <= 0 }) { messages.append("Prezzo per ogni formula a pagamento online") }
        if validOptions.contains(where: { $0.paymentType == "deposit" && $0.depositAmount <= 0 }) { messages.append("Acconto per le opzioni con acconto") }
        if validOptions.contains(where: { $0.paymentType == "deposit" && ($0.price - $0.depositAmount) <= 0 }) { messages.append("Saldo per le opzioni con acconto") }
        if validOptions.contains(where: { $0.hasDedicatedSpots && $0.dedicatedSpots < 1 }) { messages.append("Posti dedicati per le opzioni con limite attivo") }
        return messages
    }

    func eventPayload(organizerId: String, organizerName: String, includeOrganizerFields: Bool = true, preservedEvent: Event? = nil) -> [String: JSONValue] {
        let normalizedDistance = distance.nilIfBlank.map { value in
            value.lowercased().contains("km") ? value : "\(value) km"
        }
        let normalizedElevation = elevation.nilIfBlank.map { value in
            value.lowercased().contains("m") ? value : "\(value) m"
        }
        let image = imageUrl.nilIfBlank
        let gallery = galleryImageURLs.enumerated().map { index, url in
            JSONValue.object(["url": .string(url), "order": .number(Double(index))])
        }
        let customFieldValues = additionalFields.filter { $0.label.nilIfBlank != nil }.map(\.jsonValue)
        let preservedAdditionalFields = preservedEvent?.additionalFields?.objectValue ?? originalAdditionalFields
        let preservedAccessRules = preservedEvent?.accessRules?.objectValue ?? originalAccessRules
        var additionalObject = preservedAdditionalFields
        additionalObject.merge([
            "closing_sentence": closingSentenceMode == "random" ? .null : (closingSentence.nilIfBlank.map { .string($0) } ?? .null),
            "fit_score_main_category": fitScoreMainCategory.nilIfBlank.map { .string($0) } ?? .null,
            "fit_score_secondary_categories": .array(fitScoreSecondaryCategories.compactMap { $0.nilIfBlank }.map { .string($0) }),
            "fields": .array(customFieldValues),
            "custom_fields": .array(customFieldValues),
            "ask_car_availability": .bool(askCarAvailability),
            "waiting_list_enabled": .bool(waitingListEnabled),
            "home_card_image_url": homeCardImageUrl.nilIfBlank.map { .string($0) } ?? .null
        ]) { _, new in new }
        if preservedAdditionalFields["car_availability_enabled"] != nil {
            additionalObject["car_availability_enabled"] = .bool(askCarAvailability)
        }
        if preservedAdditionalFields["show_car_availability"] != nil {
            additionalObject["show_car_availability"] = .bool(askCarAvailability)
        }
        additionalObject["weather_override_condition"] = weatherOverrideCondition.nilIfBlank.map { .string($0) } ?? .null
        additionalObject["weather_override_temp_min"] = Double(weatherOverrideTempMin.replacingOccurrences(of: ",", with: ".")).map { .number($0) } ?? .null
        additionalObject["weather_override_temp_max"] = Double(weatherOverrideTempMax.replacingOccurrences(of: ",", with: ".")).map { .number($0) } ?? .null
        let averageOverride = Double(weatherOverrideTempAvg.replacingOccurrences(of: ",", with: "."))
        additionalObject["weather_override_temp_avg"] = averageOverride.map { .number($0) } ?? .null
        if preservedAdditionalFields["weather_override_temp"] != nil {
            additionalObject["weather_override_temp"] = averageOverride.map { .number($0) } ?? .null
        }
        let validAccessRules = accessRules.filter { $0.type.nilIfBlank != nil }
        var accessObject = preservedAccessRules
        accessObject["rules"] = .array(validAccessRules.map(\.jsonValue))
        accessObject["exclusivity_label"] = exclusivityLabel.nilIfBlank.map { .string($0) } ?? .null
        accessObject["restriction_message"] = restrictionMessage.nilIfBlank.map { .string($0) } ?? .null
        let manualBadgeIds = Set(Self.manualBadgeOptions.map(\.id))
        let originalUnknownBadges = ([originalCustomBadge.nilIfBlank].compactMap { $0 } + preservedEventBadges)
        let baseUnknownBadges = (preservedEvent?.eventBadges ?? originalUnknownBadges)
            .filter { !manualBadgeIds.contains($0) }
            .filter { $0 != originalCustomBadge }
        let eventBadges = (manualBadges + baseUnknownBadges + [customBadge.nilIfBlank].compactMap { $0 })
            .removingDuplicates()
        let cleanDescription = EventDescriptionHTML.cleanStoredHTML(from: description).nilIfBlank ?? title
        let validPriceOptions = priceOptions
        let legacyOption = validPriceOptions.first
        let legacyPaymentType = legacyOption?.paymentType ?? paymentType
        let legacyPrice = legacyPaymentType == "free" ? 0 : (legacyOption?.price ?? price)
        let legacyDeposit = legacyPaymentType == "deposit" ? (legacyOption?.depositAmount ?? deposit) : 0
        let legacyBalancePaymentMode = legacyPaymentType == "deposit" ? (legacyOption?.balancePaymentMode ?? balancePaymentMode) : "online"
        var payload: [String: JSONValue] = [
            "title": .string(title.nilIfBlank ?? "Evento"),
            "description": .string(cleanDescription),
            "date": .string(date),
            "time": .string(time),
            "location": .string(location.nilIfBlank ?? "Da definire"),
            "location_label": locationLabel.nilIfBlank.map { .string($0) } ?? .null,
            "category_id": categoryId.nilIfBlank.map { .string($0) } ?? .null,
            "spots_total": .number(Double(spotsTotal)),
            "reserved_spots": .number(Double(reservedSpots)),
            "price": .number(legacyPrice),
            "deposit": legacyPaymentType == "deposit" ? .number(legacyDeposit) : .null,
            "payment_type": .string(legacyPaymentType),
            "balance_payment_mode": legacyPaymentType == "deposit" ? .string(legacyBalancePaymentMode) : .null,
            "difficulty": difficulty.nilIfBlank.map { .string($0) } ?? .null,
            "distance": normalizedDistance.map { .string($0) } ?? .null,
            "elevation": normalizedElevation.map { .string($0) } ?? .null,
            "duration": duration.nilIfBlank.map { .string($0) } ?? .null,
            "featured": .bool(featured),
            "cancellation_policy": .string(Self.normalizedCancellationPolicy(cancellationPolicy)),
            "image_url": image.map { .string($0) } ?? .null,
            "visibility": .string(Self.editableVisibility(visibility)),
            "gallery_images": .array(gallery),
            "equipment_list": .array(equipmentItems.filter { $0.name.nilIfBlank != nil }.map(\.jsonValue)),
            "additional_fields": .object(additionalObject),
            "access_rules": validAccessRules.isEmpty && preservedAccessRules.isEmpty ? .null : .object(accessObject),
            "event_badges": .array(eventBadges.map { .string($0) }),
            "status": .string(status)
        ]
        if includeOrganizerFields {
            payload["organizer_id"] = .string(organizerId)
            payload["organizer_name"] = .string(organizerName)
        }
        return payload
    }
}

struct DiscountCode: Codable, Identifiable, Hashable {
    let id: String
    let code: String
    let description: String?
    let discountType: String
    let discountValue: Double
    let eventIds: [String]?
    let appliesToAll: Bool
    let maxUses: Int?
    let timesUsed: Int
    let expiresAt: String?
    let isActive: Bool
    let startsAt: String?
    let assignedUserId: String?
    let waivesServiceFee: Bool?

    func isUsable(for eventId: String, userId: String) -> Bool {
        guard isActive else { return false }
        if let assignedUserId, assignedUserId != userId { return false }
        if let maxUses, timesUsed >= maxUses { return false }
        if let startsAt, let startDate = startsAt.isoDate, startDate > Date() { return false }
        if let expiresAt, let expiryDate = expiresAt.isoDate, expiryDate < Date() { return false }
        if appliesToAll { return true }
        return eventIds?.contains(eventId) == true
    }

    var displayDescription: String {
        description?.nilIfBlank ?? displayValue
    }

    var displayValue: String {
        switch discountType.lowercased() {
        case "percentage", "percent":
            return "-\(Int(discountValue))%"
        case "fixed", "amount":
            return "-€\(money(discountValue))"
        default:
            return "Sconto attivo"
        }
    }

    func discountAmount(for subtotal: Double) -> Double {
        guard subtotal > 0 else { return 0 }
        switch discountType.lowercased() {
        case "percentage", "percent":
            return min(subtotal, subtotal * discountValue / 100)
        case "fixed", "amount":
            return min(subtotal, discountValue)
        default:
            return 0
        }
    }
}

