struct EventParticipant: Identifiable, Hashable, Codable {
    let id: String
    let userId: String?
    let firstName: String?
    let lastNameInitial: String?
    let avatarUrl: String?
    let age: Int?
    let totalPoints: Int?
    let role: String?
    let sortOrder: Int?

    init(id: String, userId: String?, firstName: String?, lastNameInitial: String?, avatarUrl: String?, age: Int? = nil, totalPoints: Int? = nil, role: String? = "participant", sortOrder: Int? = nil) {
        self.id = id
        self.userId = userId
        self.firstName = firstName
        self.lastNameInitial = lastNameInitial
        self.avatarUrl = avatarUrl
        self.age = age
        self.totalPoints = totalPoints
        self.role = role
        self.sortOrder = sortOrder
    }

    var isOrganizer: Bool {
        role == "organizer"
    }

    var isParticipant: Bool {
        role != "organizer"
    }

    var isPrivatePlaceholder: Bool {
        firstName?.nilIfBlank == nil && avatarUrl?.nilIfBlank == nil
    }

    var displayName: String {
        let name = firstName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let suffix = normalizedLastNameInitial.map { " \($0)." } ?? ""
        return (name.isEmpty || name == "?") ? "Partecipante" : name + suffix
    }

    var displayNameWithAge: String {
        guard let age else { return displayName }
        return "\(displayName), \(age)"
    }

    var publicFirstName: String {
        firstName?.nilIfBlank ?? (isOrganizer ? "Organizzatore" : "Partecipante")
    }

    var initial: String {
        String(displayName.prefix(1)).uppercased()
    }

    private var normalizedLastNameInitial: String? {
        guard let value = lastNameInitial?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else { return nil }
        return String(value.prefix(1)).uppercased()
    }
}

