    let title: String?
    let icon: String?
    let category: String?
    let missionRewards: [SourceMissionReward]?
}

struct SourceMissionReward: Codable {
    let title: String?
    let rewardKind: String?
    let physicalConfig: PhysicalRewardConfig?
    let badges: RewardBadgeInfo?
}

struct PhysicalRewardConfig: Codable {
    let rewardName: String?
    let stockQuantity: Int?
    let claimInstructions: String?
    let manualValidationRequired: Bool?
}

struct RewardBadgeInfo: Codable {
    let name: String?
    let icon: String?
    let description: String?
}

private extension Reward {
    enum Kind: Equatable {
        case points
        case badge
        case coupon
        case physical
        case other
    }

    var kind: Kind {
        switch normalizedType {
        case "point", "points", "punti", "score":
            return .points
        case "badge":
            return .badge
        case "coupon", "discount", "sconto":
            return .coupon
        case "physical", "prize", "premio":
            return .physical
        default:
            if looksLikePointsReward { return .points }
            return .other
        }
    }

    var normalizedType: String {
        type?.nilIfBlank?.lowercased() ?? ""
    }

    var physicalRewardConfig: PhysicalRewardConfig? {
        let missionConfigs = missions?.missionRewards?
            .filter { $0.rewardKind?.lowercased() == "physical" }
            .compactMap(\.physicalConfig) ?? []
        let configs = [sourceReward?.physicalConfig].compactMap { $0 } + missionConfigs

        return configs.first { $0.claimInstructions?.nilIfBlank != nil }
            ?? configs.first { $0.rewardName?.nilIfBlank != nil }
    }

    var physicalClaimInstructions: String? {
        physicalRewardConfig?.claimInstructions?.nilIfBlank ?? value?.nilIfBlank
    }

    var effectiveStatus: String {
        let rawStatus = status?.nilIfBlank?.lowercased() ?? "active"
        if rawStatus == "active",
           let expiryDate,
           let date = expiryDate.isoDate,
           date < Date() {
            return "expired"
        }
        return rawStatus
    }

    var statusStyle: (label: String, color: Color) {
        switch kind {
        case .points:
            switch effectiveStatus {
            case "expired": ("Scaduti", Brand.destructive)
            default: ("Accreditati", Brand.success)
            }
        case .badge:
            switch effectiveStatus {
            case "expired": ("Scaduto", Brand.destructive)
            default: ("Sbloccato", Brand.success)
            }
        case .coupon:
            switch effectiveStatus {
            case "used", "redeemed": ("Utilizzato", Brand.mutedForeground)
            case "expired": ("Scaduto", Brand.destructive)
            default: ("Disponibile", Brand.primary)
            }
        case .physical:
            switch effectiveStatus {
            case "pending": ("Da ritirare", Brand.warning)
            case "used", "redeemed": ("Ritirato", Brand.mutedForeground)
            case "expired": ("Scaduto", Brand.destructive)
            default: ("Disponibile", Brand.primary)
            }
        case .other:
            switch effectiveStatus {
            case "pending": ("Da riscattare", Brand.warning)
            case "used", "redeemed": ("Utilizzato", Brand.mutedForeground)
            case "expired": ("Scaduto", Brand.destructive)
            default: ("Disponibile", Brand.success)
            }
        }
    }

    var displayTitle: String {
        switch kind {
        case .points:
            return pointValueLabel ?? cleanTitle ?? "Punti guadagnati"
        case .badge:
            if isGenericBadgeTitle, let badgeName = sourceReward?.badges?.name?.nilIfBlank {
                return badgeName
            }
            if let title = cleanTitle, !Self.genericBadgeTitles.contains(title.lowercased()) {
                return title
            }
            return sourceReward?.badges?.name?.nilIfBlank ?? value?.nilIfBlank ?? missions?.title?.nilIfBlank ?? "Badge sbloccato"
        case .coupon:
            return cleanTitle ?? "Coupon disponibile"
        case .physical:
            return physicalRewardConfig?.rewardName?.nilIfBlank ?? cleanTitle ?? "Premio"
        case .other:
            return cleanTitle ?? "Ricompensa"
        }
    }

    var displayDescription: String {
        switch kind {
        case .points:
            return missions?.title?.nilIfBlank ?? "Punti accreditati"
        case .badge:
            if let description = sourceReward?.badges?.description?.nilIfBlank {
                return description
            }
            if let badgeName = sourceReward?.badges?.name?.nilIfBlank, badgeName != displayTitle {
                return badgeName
            }
            if let missionTitle = missions?.title?.nilIfBlank, missionTitle != displayTitle {
                return missionTitle
            }
            return "Badge ottenuto"
        case .coupon:
            if let value = value?.nilIfBlank {
                return "Codice: \(value)"
            }
            return "Coupon sbloccato"
        case .physical:
            return value?.nilIfBlank ?? missions?.title?.nilIfBlank ?? "Premio da gestire"
        case .other:
            return missions?.title?.nilIfBlank ?? value?.nilIfBlank ?? "Ricompensa ottenuta"
        }
    }

    var summaryDescription: String? {
        guard let description = displayDescription.nilIfBlank else { return nil }
        guard kind == .physical || kind == .other else { return description }
        return description == physicalClaimInstructions ? nil : description
    }

    var badgeIconValue: String? {
        kind == .badge ? sourceReward?.badges?.icon?.nilIfBlank : nil
    }

    var categoryLabel: String {
        if let category = category?.nilIfBlank {
            return Self.displayCategory(category)
        }
        if let missionCategory = missions?.category?.nilIfBlank {
            return Self.displayCategory(missionCategory)
        }
        if let type = type?.nilIfBlank {
            return Self.displayCategory(type)
        }
        switch kind {
        case .points: return "Punti"
        case .badge: return "Badge"
        case .coupon: return "Coupon"
        case .physical: return "Premio"
        case .other: return "Ricompensa"
        }
    }

    var earnedDescription: String {
        if let missionTitle = missions?.title?.nilIfBlank {
            return "Missione completata: \(missionTitle)"
        }
        switch kind {
        case .points:
            return "Accreditata dopo una partecipazione o un'azione completata."
        case .badge:
            return "Sbloccata completando un obiettivo della community."
        case .coupon:
            return "Sbloccata tramite una missione o una promozione disponibile."
        case .physical:
            return "Assegnata dal team dopo un obiettivo raggiunto."
        case .other:
            return "Assegnata dal team Scampagnate."
        }
    }

    var pointValueLabel: String? {
        let candidates = [value, title].compactMap { $0?.nilIfBlank }
        for candidate in candidates {
            let lowercased = candidate.lowercased()
            if lowercased.contains("punt") {
                if candidate.hasPrefix("+") { return candidate }
                if let points = candidate.firstInteger {
                    return "+\(points) punti"
                }
                return candidate
            }
            if let points = Int(candidate) {
                return "+\(points) punti"
            }
        }
        return nil
    }

    var iconName: String {
        switch kind {
        case .points: "star"
        case .badge: "trophy"
        case .coupon: "ticket"
        case .physical: "gift"
        case .other: "gift"
        }
    }

    var accentColor: Color {
        switch kind {
        case .points: Brand.secondary
        case .badge: Brand.accent
        case .coupon: Brand.primary
        case .physical: Brand.warning
        case .other: Brand.secondary
        }
    }

    var isCurrent: Bool {
        ["active", "pending"].contains(effectiveStatus)
    }

    var isHistory: Bool {
        ["used", "redeemed", "expired"].contains(effectiveStatus)
    }

    private var cleanTitle: String? {
        title?.nilIfBlank
    }

    private var isGenericBadgeTitle: Bool {
        guard let title = cleanTitle?.lowercased() else { return true }
        return Self.genericBadgeTitles.contains(title)
    }

    private var looksLikePointsReward: Bool {
        [title, value]
            .compactMap { $0?.nilIfBlank?.lowercased() }
            .contains { $0.contains("punt") }
    }

    private static let genericBadgeTitles: Set<String> = ["badge", "badge missione"]

    private static func displayCategory(_ raw: String) -> String {
        switch raw.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "point", "points", "punti", "score":
            return "Punti"
        case "badge":
            return "Badge"
        case "coupon", "discount", "sconto":
            return "Coupon"
        case "physical", "prize", "premio":
            return "Premio"
        default:
            return raw.replacingOccurrences(of: "_", with: " ").capitalized
        }
    }
}

