struct UserMissionProgress: Codable, Identifiable {
    let id: String
    let missionId: String?
    let cycleKey: String?
    let progress: Int?
    let completed: Bool?
    let currentValue: Int?
    let targetValue: Int?
    let isCompleted: Bool?
    let completedAt: String?
    let updatedAt: String?

    var displayProgress: Int {
        currentValue ?? progress ?? 0
    }

    var displayCompleted: Bool {
        isCompleted ?? completed ?? false
    }

    private var completionRatio: Double {
        guard let targetValue, targetValue > 0 else { return Double(displayProgress) }
        return Double(displayProgress) / Double(targetValue)
    }

    static func preferred(_ lhs: UserMissionProgress, _ rhs: UserMissionProgress) -> UserMissionProgress {
        if lhs.displayCompleted != rhs.displayCompleted {
            return rhs.displayCompleted ? rhs : lhs
        }
        if lhs.completionRatio != rhs.completionRatio {
            return rhs.completionRatio > lhs.completionRatio ? rhs : lhs
        }
        if lhs.displayProgress != rhs.displayProgress {
            return rhs.displayProgress > lhs.displayProgress ? rhs : lhs
        }
        let rhsDate = rhs.updatedAt?.isoDate ?? .distantPast
        let lhsDate = lhs.updatedAt?.isoDate ?? .distantPast
        return rhsDate > lhsDate ? rhs : lhs
    }
}

struct ActiveMissionDefinition: Codable, Identifiable {
    let id: String
    let title: String?
    let description: String?
    let targetValue: Int?
    let rewardPoints: Int?
    let type: String?
    let icon: String?
    let rewardType: String?
    let rewardValue: String?
    let category: String?
    let targetAction: String?
    let timezone: String?
    let expiresAt: String?
    let missionRewards: [MissionRewardDefinition]?
}

private extension ActiveMissionDefinition {
    var normalizedType: String {
        (type ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    var isPeriodic: Bool {
        normalizedType == "monthly" || normalizedType == "weekly"
    }

    func preferredProgress(in rows: [UserMissionProgress]) -> UserMissionProgress? {
        let scopedRows: [UserMissionProgress]
        if isPeriodic {
            let currentCycleKey = MissionCycle.currentKey(type: normalizedType, timezone: timezone)
            scopedRows = rows.filter { $0.cycleKey == currentCycleKey }
        } else {
            scopedRows = rows
        }

        return scopedRows.reduce(nil) { selected, row in
            guard let selected else { return row }
            return UserMissionProgress.preferred(selected, row)
        }
    }
}

enum MissionCycle {
    static func currentKey(type: String?, timezone: String?, date: Date = Date()) -> String {
        let normalizedType = (type ?? "").trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let timeZone = TimeZone(identifier: timezone?.nilIfBlank ?? "Europe/Rome") ?? TimeZone(identifier: "Europe/Rome")!
        var calendar = Calendar(identifier: normalizedType == "weekly" ? .iso8601 : .gregorian)
        calendar.timeZone = timeZone

        switch normalizedType {
        case "monthly":
            let components = calendar.dateComponents([.year, .month], from: date)
            let year = components.year ?? 0
            let month = components.month ?? 1
            return "\(year)-\(String(format: "%02d", month))"
        case "weekly":
            let components = calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: date)
            let year = components.yearForWeekOfYear ?? 0
            let week = components.weekOfYear ?? 1
            return "\(year)-W\(String(format: "%02d", week))"
        default:
            return "lifetime"
        }
    }
}

