private extension MissionCardModel {
    var isCompleted: Bool {
        completed == true || clampedProgress >= targetValue
    }

    var targetValue: Int {
        max(missions?.targetValue ?? 1, 1)
    }

    var clampedProgress: Int {
        min(max(progress ?? 0, 0), targetValue)
    }

    var completionRatio: Double {
        Double(clampedProgress) / Double(targetValue)
    }

    var displayTitle: String {
        missions?.title?.nilIfBlank ?? "Missione"
    }

    var displayDescription: String? {
        missions?.description?.nilIfBlank
    }

    var displayIcon: String {
        missions?.icon?.nilIfBlank ?? "lucide:Target"
    }

    var progressText: String {
        "\(clampedProgress) di \(targetValue)"
    }

    var remainingText: String {
        if isCompleted {
            return "Missione completata. La ricompensa collegata è stata sbloccata o assegnata."
        }
        let missing = max(targetValue - clampedProgress, 0)
        if missing == 1 {
            return "Ti manca ancora 1 passo per completarla."
        }
        return "Ti mancano ancora \(missing) passi per completarla."
    }

    var categoryText: String? {
        missions?.category?.nilIfBlank?.replacingOccurrences(of: "_", with: " ").capitalized
    }

    var rewardLabels: [(icon: String, text: String)] {
        var labels: [(icon: String, text: String)] = []
        let configuredRewards = (missions?.missionRewards ?? [])
            .filter { $0.visibleOnProfile != false }
            .sorted { ($0.sortOrder ?? 0) < ($1.sortOrder ?? 0) }

        if !configuredRewards.isEmpty {
            for reward in configuredRewards {
                let kind = reward.rewardKind?.nilIfBlank?.lowercased()
                switch kind {
                case "points":
                    if let points = reward.pointsValue, points > 0 {
                        labels.append(("star", "+\(points) punti"))
                    }
                case "coupon", "discount":
                    labels.append(("ticket", "Sblocca uno sconto"))
                case "badge":
                    labels.append(("trophy", "Sblocca un badge"))
                case "physical", "prize":
                    labels.append(("gift", reward.title?.nilIfBlank ?? "Premio al completamento"))
                default:
                    if let title = reward.title?.nilIfBlank {
                        labels.append(("gift", title))
                    }
                }
            }
            return labels
        }

        let rewardType = missions?.rewardType?.nilIfBlank?.lowercased()
        let rewardValue = missions?.rewardValue?.nilIfBlank
        if rewardType == "coupon" || rewardType == "discount" {
            labels.append(("ticket", "Sblocca uno sconto"))
        }
        if rewardType == "badge" {
            labels.append(("trophy", rewardValue ?? "Sblocca un badge"))
        }
        if rewardType == "physical" || rewardType == "prize" {
            labels.append(("gift", rewardValue ?? "Sblocca un premio"))
        }
        if let rewardPoints = missions?.rewardPoints, rewardPoints > 0 {
            labels.append(("star", "+\(rewardPoints) punti"))
        }
        return labels
    }

    var unlockText: String {
        let rewards = rewardLabels.map { $0.text }
        guard !rewards.isEmpty else {
            return "Il completamento viene registrato nel profilo e contribuisce alla tua progressione."
        }
        return rewards.joined(separator: " · ")
    }

    var actionText: String {
        let rawAction = (missions?.targetAction ?? missions?.type ?? "").lowercased()
        if rawAction.contains("attend") || rawAction.contains("particip") || rawAction.contains("event") {
            return "Partecipa agli eventi validi e completa il check-in quando sei presente."
        }
        if rawAction.contains("profile") {
            return "Completa le informazioni richieste nel tuo profilo."
        }
        if rawAction.contains("proposal") || rawAction.contains("suggest") {
            return "Invia una proposta attività completa e utile per la community."
        }
        if rawAction.contains("save") || rawAction.contains("bookmark") {
            return "Salva gli eventi che ti interessano e torna a consultarli."
        }
        return displayDescription ?? "Continua con le attività indicate dalla missione."
    }
}

