struct APIError: Decodable {
    let message: String?
    let errorDescription: String?
    let msg: String?
    let error: String?

    func displayMessage(statusCode: Int, url: URL, fallbackPrefix: String = "Supabase") -> String {
        if isPasswordLogin(url: url) {
            if contains("email not confirmed") {
                return "Prima di accedere devi confermare la tua email."
            }
            if statusCode == 400 || contains("invalid login credentials") || contains("invalid credentials") {
                return "Email o password non corretti. Controlla i dati e riprova."
            }
        }
        return rawMessage ?? "Errore \(fallbackPrefix) \(statusCode)"
    }

    private var rawMessage: String? {
        [message, errorDescription, msg, error]
            .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
            .first { !$0.isEmpty }
    }

    private var normalizedMessage: String {
        [message, errorDescription, msg, error]
            .compactMap { $0 }
            .joined(separator: " ")
            .lowercased()
    }

    private func contains(_ text: String) -> Bool {
        normalizedMessage.contains(text)
    }

    private func isPasswordLogin(url: URL) -> Bool {
        url.path == "/auth/v1/token" && (url.query?.contains("grant_type=password") ?? false)
    }
}

