private extension Error {
    var isCancellation: Bool {
        if self is CancellationError { return true }
        let nsError = self as NSError
        return nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorCancelled
    }

    var isTimeout: Bool {
        let nsError = self as NSError
        return nsError.domain == NSURLErrorDomain && nsError.code == NSURLErrorTimedOut
    }
}

private extension UIImage {
    func resizedJPEGData(maxDimension: CGFloat = 1800, compressionQuality: CGFloat = 0.82) -> Data? {
        let longestSide = max(size.width, size.height)
        guard longestSide > 0 else { return nil }
        let scale = min(1, maxDimension / longestSide)
        let targetSize = CGSize(width: size.width * scale, height: size.height * scale)

        let format = UIGraphicsImageRendererFormat()
        format.scale = 1
        format.opaque = true
        let renderer = UIGraphicsImageRenderer(size: targetSize, format: format)
        let image = renderer.image { context in
            UIColor.white.setFill()
            context.fill(CGRect(origin: .zero, size: targetSize))
            draw(in: CGRect(origin: .zero, size: targetSize))
        }
        return image.jpegData(compressionQuality: compressionQuality)
    }

    func avatarJPEGData(maxDimension: CGFloat = 512, compressionQuality: CGFloat = 0.8) -> Data? {
        let longestSide = max(size.width, size.height)
        guard longestSide > 0 else { return nil }
        let scale = min(1, maxDimension / longestSide)
        let targetSize = CGSize(width: size.width * scale, height: size.height * scale)

        let renderer = UIGraphicsImageRenderer(size: targetSize)
        let image = renderer.image { _ in
            draw(in: CGRect(origin: .zero, size: targetSize))
        }
        return image.jpegData(compressionQuality: compressionQuality)
    }

    func croppedAvatarJPEGData(offset: CGSize, zoom: CGFloat, cropSide: CGFloat, outputSide: CGFloat = 512, compressionQuality: CGFloat = 0.8) -> Data? {
        guard size.width > 0, size.height > 0, cropSide > 0 else { return nil }

        let baseScale = max(cropSide / size.width, cropSide / size.height)
        let displayScale = baseScale * max(zoom, 1)
        let outputScale = outputSide / cropSide
        let drawSize = CGSize(
            width: size.width * displayScale * outputScale,
            height: size.height * displayScale * outputScale
        )
        let drawOrigin = CGPoint(
            x: (outputSide - drawSize.width) / 2 + offset.width * outputScale,
            y: (outputSide - drawSize.height) / 2 + offset.height * outputScale
        )

        let format = UIGraphicsImageRendererFormat()
        format.scale = 1
        format.opaque = true
        let renderer = UIGraphicsImageRenderer(size: CGSize(width: outputSide, height: outputSide), format: format)
        let image = renderer.image { context in
            UIColor.white.setFill()
            context.fill(CGRect(origin: .zero, size: CGSize(width: outputSide, height: outputSide)))
            draw(in: CGRect(origin: drawOrigin, size: drawSize))
        }
        return image.jpegData(compressionQuality: compressionQuality)
    }

    func croppedJPEGData(offset: CGSize, zoom: CGFloat, cropSize: CGSize, outputSize: CGSize, compressionQuality: CGFloat = 0.78) -> Data? {
        guard size.width > 0, size.height > 0, cropSize.width > 0, cropSize.height > 0, outputSize.width > 0, outputSize.height > 0 else {
            return nil
        }

        let baseScale = max(cropSize.width / size.width, cropSize.height / size.height)
        let displayScale = baseScale * max(zoom, 1)
        let outputScaleX = outputSize.width / cropSize.width
        let outputScaleY = outputSize.height / cropSize.height
        let drawSize = CGSize(
            width: size.width * displayScale * outputScaleX,
            height: size.height * displayScale * outputScaleY
        )
        let drawOrigin = CGPoint(
            x: (outputSize.width - drawSize.width) / 2 + offset.width * outputScaleX,
            y: (outputSize.height - drawSize.height) / 2 + offset.height * outputScaleY
        )

        let format = UIGraphicsImageRendererFormat()
        format.scale = 1
        format.opaque = true
        let renderer = UIGraphicsImageRenderer(size: outputSize, format: format)
        let image = renderer.image { context in
            UIColor.white.setFill()
            context.fill(CGRect(origin: .zero, size: outputSize))
            draw(in: CGRect(origin: drawOrigin, size: drawSize))
        }
        return image.jpegData(compressionQuality: compressionQuality)
    }
}

enum JSONValue: Codable, Hashable {
    case string(String)
    case number(Double)
    case bool(Bool)
    case object([String: JSONValue])
    case array([JSONValue])
    case null

    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if container.decodeNil() { self = .null }
        else if let value = try? container.decode(Bool.self) { self = .bool(value) }
        else if let value = try? container.decode(Double.self) { self = .number(value) }
        else if let value = try? container.decode(String.self) { self = .string(value) }
        else if let value = try? container.decode([String: JSONValue].self) { self = .object(value) }
        else if let value = try? container.decode([JSONValue].self) { self = .array(value) }
        else { self = .null }
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case .string(let value): try container.encode(value)
        case .number(let value): try container.encode(value)
        case .bool(let value): try container.encode(value)
        case .object(let value): try container.encode(value)
        case .array(let value): try container.encode(value)
        case .null: try container.encodeNil()
        }
    }
}

extension JSONValue {
    subscript(key: String) -> JSONValue? {
        if case .object(let object) = self {
            return object[key]
        }
        return nil
    }

    var stringValue: String? {
        if case .string(let value) = self {
            return value
        }
        return nil
    }

    var arrayValue: [JSONValue]? {
        if case .array(let values) = self {
            return values
        }
        return nil
    }

    var objectValue: [String: JSONValue]? {
        if case .object(let object) = self {
            return object
        }
        return nil
    }

    var doubleValue: Double? {
        switch self {
        case .number(let value): return value
        case .string(let value): return Double(value)
        default: return nil
        }
    }

    var boolValue: Bool? {
        switch self {
        case .bool(let value): return value
        case .string(let value): return Bool(value)
        default: return nil
        }
    }

    func string(at key: String) -> String? {
        self[key]?.stringValue
    }

    func double(at key: String) -> Double? {
        self[key]?.doubleValue
    }

    func bool(at key: String) -> Bool? {
        self[key]?.boolValue
    }

    func array(at key: String) -> [JSONValue]? {
        guard case .array(let values) = self[key] else { return nil }
        return values
    }

    func stringArray(at key: String) -> [String]? {
        guard case .array(let values) = self[key] else { return nil }
        return values.compactMap(\.stringValue)
    }
}

// MARK: - Root

private enum AppChrome {
    static let topSafeAreaClearance: CGFloat = 6
}

struct RootView: View {
    @EnvironmentObject private var store: AppStore
    @EnvironmentObject private var pushNotifications: PushNotificationService
    @Environment(\.scenePhase) private var scenePhase
    @State private var selectedTab: AppTab = .home
    @State private var showAuth = false
    @State private var authInitialMode: AuthMode = .login
    @State private var showOnboarding = false
    @State private var onboardingMode: OnboardingView.Mode = .onboarding
    @State private var showPushPrompt = false
    @State private var showNotifications = false
    @State private var paymentFeedback: AppFeedback?
    @State private var routedEvent: EventNavigationTarget?
    @State private var routedProductId: String?
    @State private var routedOrganizerDashboardRoute: OrganizerDashboardRoute?
    @State private var routedOrganizerProfile: OrganizerNavigationTarget?
    @State private var routedContentPage: ContentPageRoute?
    @State private var routedMission: MissionNavigationTarget?
    @State private var profileScrollTarget: ProfileScrollTarget?
    @State private var routedRewards = false
    @State private var profileTabAvatarImage: UIImage?
    @State private var passwordRecoveryLink: PasswordRecoveryLink?

    var body: some View {
        ZStack {
            Brand.background.ignoresSafeArea()
            TabView(selection: $selectedTab) {
                HomeView(showAuth: $showAuth, showNotifications: $showNotifications)
                    .tabItem {
                        Label(AppTab.home.title, systemImage: AppTab.home.systemImage)
                    }
                    .tag(AppTab.home)

                MyEventsView(showAuth: $showAuth, routedEvent: $routedEvent)
                    .tabItem {
                        Label(AppTab.events.title, systemImage: AppTab.events.systemImage)
                    }
                    .tag(AppTab.events)

                if store.isOrganizer {
                    OrganizerDashboardView(showAuth: $showAuth, routedRoute: $routedOrganizerDashboardRoute)
                        .tabItem {
                            Label(AppTab.organizer.title, systemImage: AppTab.organizer.systemImage)
                    }
                        .tag(AppTab.organizer)
                }

                ShopView(routedProductId: $routedProductId)
                    .tabItem {
                        Label(AppTab.shop.title, systemImage: AppTab.shop.systemImage)
                    }
                    .tag(AppTab.shop)

                ProfileView(showAuth: $showAuth, scrollTarget: $profileScrollTarget, openRewards: $routedRewards, routedMission: $routedMission)
                    .tabItem {
                        profileTabItem
                    }
                    .tag(AppTab.profile)
            }
            .tint(Brand.primary)
            .nativeTabBarMinimizeOnScroll()
            .safeAreaPadding(.top, AppChrome.topSafeAreaClearance)
        }
        .background(KeyboardDismissOnTapView())
        .overlay(alignment: .top) {
            StatusBarShield()
        }
        .sheet(isPresented: $showAuth) {
            AuthView(initialMode: authInitialMode)
        }
        .sheet(isPresented: $showNotifications) {
            NotificationsView { destination in
                handleNotificationDestination(destination)
            }
        }
        .fullScreenCover(isPresented: $showOnboarding) {
            OnboardingView(mode: onboardingMode)
        }
        .alert("Scampagnate", isPresented: Binding(get: { store.errorMessage != nil }, set: { if !$0 { store.errorMessage = nil } })) {
            Button("OK") { store.errorMessage = nil }
        } message: {
            Text(store.errorMessage ?? "")
        }
        .sheet(item: $paymentFeedback) { feedback in
            AppFeedbackSheet(feedback: feedback)
                .presentationDetents([.height(300)])
        }
        .sheet(item: $passwordRecoveryLink) { recovery in
            PasswordRecoveryView(recovery: recovery)
                .presentationDetents([.large])
        }
        .sheet(item: $routedContentPage) { route in
            NavigationStack {
                HelpContentView(slug: route.slug, fallbackTitle: route.fallbackTitle)
            }
        }
        .fullScreenCover(item: $routedOrganizerProfile) { target in
            OrganizerProfileView(
                organizerId: target.id,
                fallbackName: nil,
                profile: store.organizerProfiles[target.id],
                showAuth: $showAuth
            )
            .environmentObject(store)
        }
        .alert("Vuoi attivare le notifiche?", isPresented: $showPushPrompt) {
            Button("Non ora", role: .cancel) {
                pushNotifications.declineInitialPrompt()
            }
            Button("Attiva") {
                Task {
                    await pushNotifications.requestPermissionAndRegister(session: store.session)
                }
            }
        } message: {
            Text("Ti avvisiamo solo per cose utili: posti che si liberano, cambi di programma, aggiornamenti sugli eventi e nuove esperienze da non perdere.")
        }
        .onChange(of: store.needsOnboarding) { _, needs in
            if needs {
                onboardingMode = .onboarding
                showOnboarding = true
            }
            updatePushPromptVisibility()
        }
        .onChange(of: showAuth) { _, _ in
            updatePushPromptVisibility()
        }
        .onChange(of: showOnboarding) { _, _ in
            updatePushPromptVisibility()
        }
        .onChange(of: showNotifications) { _, _ in
            updatePushPromptVisibility()
        }
        .onChange(of: store.isOrganizer) { _, isOrganizer in
            if !isOrganizer, selectedTab == .organizer {
                selectedTab = .home
            }
        }
        .onChange(of: store.homeDiscoveryRequest?.id) { _, requestId in
            guard requestId != nil else { return }
            selectedTab = .home
        }
        .onChange(of: pushNotifications.authorizationStatus) { _, _ in
            updatePushPromptVisibility()
        }
        .onChange(of: pushNotifications.tappedNotification?.id) { _, _ in
            guard let request = pushNotifications.tappedNotification else { return }
            handleNotificationRequest(request)
        }
        .onChange(of: scenePhase) { _, phase in
            guard phase == .active, store.isAuthenticated else { return }
            Task {
                await pushNotifications.refreshAuthorizationStatus()
                await store.refreshUserData(reportingErrors: false)
            }
        }
        .task {
            if store.needsOnboarding {
                onboardingMode = .onboarding
            }
            showOnboarding = store.needsOnboarding
            await pushNotifications.refreshAuthorizationStatus()
            updatePushPromptVisibility()
        }
        .task(id: profileTabAvatarKey) {
            await refreshProfileTabAvatar()
        }
        .onOpenURL { url in
            handleDeepLink(url)
        }
        .onContinueUserActivity(NSUserActivityTypeBrowsingWeb) { activity in
            guard let url = activity.webpageURL else { return }
            handleDeepLink(url)
        }
    }

    private func updatePushPromptVisibility() {
        showPushPrompt = pushNotifications.shouldShowInitialPrompt
            && store.isAuthenticated
            && !showAuth
            && !showOnboarding
            && !showNotifications
            && store.errorMessage == nil
            && paymentFeedback == nil
    }

    private var profileTabAvatarKey: String {
        guard store.isAuthenticated else { return "signed-out" }
        return [
            store.profile?.avatarUrl ?? "",
            store.profile?.firstName ?? "",
            store.profile?.lastName ?? "",
            store.profile?.displayName ?? ""
        ].joined(separator: "|")
    }

    @ViewBuilder
    private var profileTabItem: some View {
        if store.isAuthenticated {
            Image(uiImage: profileTabAvatarIcon)
            Text(AppTab.profile.title)
        } else {
            Label(AppTab.profile.title, systemImage: AppTab.profile.systemImage)
        }
    }

    private var profileTabAvatarIcon: UIImage {
        (profileTabAvatarImage ?? ProfileTabAvatarRenderer.placeholder(for: store.profile))
            .withRenderingMode(.alwaysOriginal)
    }

    private func refreshProfileTabAvatar() async {
        guard store.isAuthenticated else {
            profileTabAvatarImage = nil
            return
        }
        let image = await ProfileTabAvatarRenderer.image(for: store.profile)
        guard !Task.isCancelled else { return }
        profileTabAvatarImage = image
    }

    private func handleNotificationRequest(_ request: NotificationNavigationRequest) {
        if let destination = request.destination {
            handleNotificationDestination(destination)
        } else {
            showNotifications = true
        }
        pushNotifications.consumeTappedNotification(request)
    }

    private func handleNotificationDestination(_ destination: NotificationDestination) {
        showNotifications = false
        switch destination {
        case .event(let eventId):
            selectedTab = .events
            routeAfterSheetDismissal {
                routedEvent = EventNavigationTarget(id: eventId)
            }
        case .events:
            selectedTab = .events
        case .mission(let missionId, let completedAt):
            selectedTab = .profile
            Task { await store.refreshUserData(reportingErrors: false) }
            routeAfterSheetDismissal {
                profileScrollTarget = .missions
                routedMission = MissionNavigationTarget(missionId: missionId, completedAtHint: completedAt)
            }
        case .profile(let target):
            selectedTab = .profile
            routeAfterSheetDismissal {
                profileScrollTarget = target
            }
        case .shop:
            selectedTab = .shop
        }
    }

    private func handleDeepLink(_ url: URL) {
        if let recovery = PasswordRecoveryLink(url: url) {
            showAuth = false
            showNotifications = false
            showOnboarding = false
            passwordRecoveryLink = recovery
            return
        }

        if let message = PasswordRecoveryLink.errorMessage(from: url) {
            showAuth = false
            store.errorMessage = message
            return
        }

        if routeWebCompatibleURL(url) {
            return
        }

        guard url.scheme == "scampagnate" else { return }

        if url.isScampagnatePaymentCancellation {
            let eventId = url.queryValue(named: "event_id") ?? url.queryValue(named: "eventId")
            let registrationId = url.queryValue(named: "registration_id") ?? url.queryValue(named: "registrationId")
            Task {
                await store.handleEventPaymentCancellation(
                    sessionId: url.stripeCheckoutSessionId,
                    eventId: eventId,
                    registrationId: registrationId
                )
            }
            paymentFeedback = AppFeedback(title: "Pagamento annullato", message: "Non è stato addebitato nulla. Puoi riprendere quando vuoi.", icon: "xmark.circle.fill", tone: .warning)
            return
        }

        if url.host == "payment-success" || url.path.contains("payment-success") {
            verifyEventPaymentReturn(url)
            return
        }

        if url.host == "membership-success" || url.path.contains("membership-success") {
            verifyMembershipPaymentReturn(url)
        }
    }

    private func routeWebCompatibleURL(_ url: URL) -> Bool {
        guard let route = webRouteComponents(from: url) else { return false }
        guard let first = route.first else {
            selectedTab = .home
            return true
        }

        switch first {
        case "auth", "login", "register":
            authInitialMode = first == "register" || url.queryValue(named: "mode") == "register" ? .register : .login
            showAuth = true
            return true
        case "reset-password":
            authInitialMode = .reset
            showAuth = true
            return true
        case "profile-setup":
            if store.isAuthenticated {
                onboardingMode = url.queryValue(named: "mode") == "edit" ? .preferencesEdit : .onboarding
                showOnboarding = true
            } else {
                showAuth = true
            }
            return true
        case "payment-success":
            verifyEventPaymentReturn(url)
            return true
        case "membership-success":
            verifyMembershipPaymentReturn(url)
            return true
        case "event":
            guard let eventId = route.dropFirst().first?.nilIfBlank ?? url.queryValue(named: "id") ?? url.queryValue(named: "event_id") else { return false }
            let opensParticipants = route.dropFirst(2).first?.lowercased() == "participants"
            selectedTab = .events
            routeAfterSheetDismissal {
                routedEvent = EventNavigationTarget(id: eventId, opensParticipants: opensParticipants)
            }
            return true
        case "my-events":
            selectedTab = .events
            return true
        case "shop", "merch":
            selectedTab = .shop
            if let productId = route.dropFirst().first?.nilIfBlank ?? url.queryValue(named: "id") {
                routedProductId = productId
            }
            return true
        case "profile":
            selectedTab = .profile
            if let target = profileTarget(from: url.queryValue(named: "section")) {
                profileScrollTarget = target
            }
            return true
        case "notifications":
            showNotifications = true
            return true
        case "rewards":
            if store.isAuthenticated {
                selectedTab = .profile
                routeAfterSheetDismissal {
                    routedRewards = true
                }
            } else {
                showAuth = true
            }
            return true
        case "privacy":
            routedContentPage = ContentPageRoute(slug: "privacy-policy", fallbackTitle: "Informativa Privacy")
            return true
        case "terms":
            routedContentPage = ContentPageRoute(slug: "termini-di-servizio", fallbackTitle: "Termini di Servizio")
            return true
        case "page":
            guard let slug = route.dropFirst().first?.nilIfBlank else { return false }
            routedContentPage = ContentPageRoute(slug: slug)
            return true
        case "guida-difficolta-trekking":
            routedContentPage = ContentPageRoute(slug: "guida-difficolta-trekking")
            return true
        case "organizer":
            let segments = Array(route.dropFirst())
            if segments.first == "events" {
                selectedTab = .organizer
                routeAfterSheetDismissal {
                    routedOrganizerDashboardRoute = organizerDashboardRoute(from: Array(segments.dropFirst()))
                }
            } else if let organizerId = segments.first?.nilIfBlank {
                routedOrganizerProfile = OrganizerNavigationTarget(id: organizerId)
            } else if store.isOrganizer {
                selectedTab = .organizer
            }
            return true
        default:
            return false
        }
    }

    private func profileTarget(from section: String?) -> ProfileScrollTarget? {
        switch section?.lowercased() {
        case "profile", "account": .profile
        case "membership", "tessera": .membership
        case "missions", "missioni": .missions
        case "rewards", "ricompense": .rewards
        case "badges", "badge": .badges
        case "activity", "attivita", "attività": .activity
        case "help", "support", "assistenza": .help
        default: nil
        }
    }

    private func organizerDashboardRoute(from segments: [String]) -> OrganizerDashboardRoute? {
        guard let first = segments.first?.nilIfBlank else {
            return nil
        }
        if first == "new" {
            return OrganizerDashboardRoute(destination: .create)
        }
        if segments.dropFirst().first?.lowercased() == "edit" {
            return OrganizerDashboardRoute(destination: .edit(first))
        }
        return OrganizerDashboardRoute(destination: .manage(first))
    }

    private func webRouteComponents(from url: URL) -> [String]? {
        let scheme = (url.scheme ?? "").lowercased()
        if scheme == "http" || scheme == "https" {
            guard let host = url.host?.lowercased(),
                  ["scampagnate.com", "www.scampagnate.com", "127.0.0.1", "localhost"].contains(host)
            else { return nil }
            return url.path.split(separator: "/").map(String.init)
        }

        guard scheme == "scampagnate" else { return nil }
        var components: [String] = []
        if let host = url.host?.nilIfBlank {
            components.append(host)
        }
        components.append(contentsOf: url.path.split(separator: "/").map(String.init))
        return components
    }

    private func verifyEventPaymentReturn(_ url: URL) {
        guard let sessionId = url.stripeCheckoutSessionId ?? store.pendingPayment?.sessionId else {
            paymentFeedback = AppFeedback(title: "Verifica non riuscita", message: "Non ho ricevuto l'identificativo del checkout. Apri My events per controllare lo stato dell'iscrizione.", icon: "exclamationmark.triangle.fill", tone: .error)
            return
        }
        paymentFeedback = AppFeedback(title: "Verifico il pagamento", message: "Sto aggiornando iscrizione e profilo.", icon: "clock.fill", tone: .warning)
        Task {
            let status = await store.verifyEventPayment(sessionId: sessionId, eventId: url.queryValue(named: "event_id") ?? url.queryValue(named: "eventId"))
            paymentFeedback = AppFeedback(paymentStatus: status)
            if case .success = status {
                selectedTab = .events
            }
        }
    }

    private func verifyMembershipPaymentReturn(_ url: URL) {
        guard let sessionId = url.stripeCheckoutSessionId else {
            paymentFeedback = AppFeedback(title: "Verifica non riuscita", message: "Non ho ricevuto l'identificativo del checkout tessera.", icon: "exclamationmark.triangle.fill", tone: .error)
            return
        }
        paymentFeedback = AppFeedback(title: "Verifico la tessera", message: "Sto aggiornando il tuo profilo.", icon: "clock.fill", tone: .warning)
        Task {
            let status = await store.verifyMembershipPayment(sessionId: sessionId)
            paymentFeedback = AppFeedback(paymentStatus: status)
            if case .membershipSuccess = status {
                selectedTab = .profile
                profileScrollTarget = .membership
            }
        }
    }

    private func routeAfterSheetDismissal(_ action: @escaping () -> Void) {
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.28) {
            withAnimation(.snappy) {
                action()
            }
        }
    }
}

private struct StatusBarShield: View {
    var body: some View {
        GeometryReader { proxy in
            Brand.background
                .frame(height: proxy.safeAreaInsets.top)
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
                .ignoresSafeArea(edges: .top)
        }
        .allowsHitTesting(false)
        .accessibilityHidden(true)
    }
}

enum AppTab: CaseIterable, Hashable {
    case home
    case events
    case organizer
    case shop
    case profile

    var title: String {
        switch self {
        case .home: "Home"
        case .events: "My events"
        case .organizer: "Gestione"
        case .shop: "Shop"
        case .profile: "Profilo"
        }
    }

    var systemImage: String {
        switch self {
        case .home: "house.fill"
        case .events: "calendar"
        case .organizer: "list.clipboard"
        case .shop: "handbag"
        case .profile: "person.fill"
        }
    }
}

private extension View {
    @ViewBuilder
    func nativeTabBarMinimizeOnScroll() -> some View {
        if #available(iOS 26, *) {
            self.tabBarMinimizeBehavior(.onScrollDown)
        } else {
            self
        }
    }
}

enum ProfileTabAvatarRenderer {
    private static let pointSize = CGSize(width: 30, height: 30)

    @MainActor
    static func image(for profile: Profile?) async -> UIImage {
        if let avatarUrl = profile?.avatarUrl, let url = URL(string: avatarUrl) {
            do {
                let (data, _) = try await URLSession.shared.data(from: url)
                if !Task.isCancelled, let sourceImage = UIImage(data: data) {
                    return avatar(from: sourceImage, fallbackInitial: initial(for: profile))
                }
            } catch {
                return placeholder(for: profile)
            }
        }
        return placeholder(for: profile)
    }

    @MainActor
    static func placeholder(for profile: Profile?) -> UIImage {
        avatar(from: nil, fallbackInitial: initial(for: profile))
    }

    @MainActor
    private static func avatar(from sourceImage: UIImage?, fallbackInitial: String) -> UIImage {
        let format = UIGraphicsImageRendererFormat()
        format.scale = 3
        format.opaque = false

        return UIGraphicsImageRenderer(size: pointSize, format: format).image { context in
            let rect = CGRect(origin: .zero, size: pointSize)
            UIBezierPath(ovalIn: rect).addClip()

            if let sourceImage {
                sourceImage.drawAspectFill(in: rect)
            } else {
                UIColor(Brand.primary).setFill()
                context.cgContext.fill(rect)

                let paragraph = NSMutableParagraphStyle()
                paragraph.alignment = .center
                let attributes: [NSAttributedString.Key: Any] = [
                    .font: UIFont.systemFont(ofSize: 14, weight: .bold),
                    .foregroundColor: UIColor.white,
                    .paragraphStyle: paragraph
                ]
                let textRect = rect.offsetBy(dx: 0, dy: (rect.height - 16) / 2 - 1)
                fallbackInitial.draw(in: textRect, withAttributes: attributes)
            }
        }
    }

    private static func initial(for profile: Profile?) -> String {
        let name = [profile?.firstName, profile?.lastName, profile?.displayName]
            .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
            .first { !$0.isEmpty } ?? "S"
        return String(name.prefix(1)).uppercased()
    }
}

private extension UIImage {
    func drawAspectFill(in rect: CGRect) {
        guard size.width > 0, size.height > 0 else { return }
        let scale = max(rect.width / size.width, rect.height / size.height)
        let drawSize = CGSize(width: size.width * scale, height: size.height * scale)
        let drawRect = CGRect(
            x: rect.midX - drawSize.width / 2,
            y: rect.midY - drawSize.height / 2,
            width: drawSize.width,
            height: drawSize.height
        )
        draw(in: drawRect)
    }
}

struct PendingPaymentBanner: View {
    @EnvironmentObject private var store: AppStore
    let onStatus: (PaymentVerificationStatus) -> Void
    @State private var verifying = false

    var body: some View {
        HStack(spacing: 10) {
            Image(systemName: "creditcard.fill")
                .foregroundStyle(Brand.primary)
            VStack(alignment: .leading, spacing: 2) {
                Text("Pagamento in corso")
                    .font(.subheadline.weight(.bold))
                Text("Tocca per verificare dopo Stripe")
                    .font(.caption)
                    .foregroundStyle(Brand.mutedForeground)
            }
            Spacer()
            HStack(spacing: 8) {
                Button {
                    Task {
                        verifying = true
                        onStatus(await store.verifyPendingPayment())
                        verifying = false
                    }
                } label: {
                    HStack(spacing: 6) {
                        if verifying {
                            ProgressView()
                                .controlSize(.mini)
                                .tint(.white)
                        }
                        Text(verifying ? "Verifico" : "Verifica")
                    }
                }
                .font(.caption.weight(.bold))
                .buttonStyle(.borderedProminent)
                .tint(Brand.primary)
                .disabled(verifying)

                Button {
                    store.dismissPendingPaymentBanner()
