struct AppFeedback: Identifiable, Equatable {
    enum Tone: Equatable {
        case success
        case warning
        case error
    }

    let id = UUID()
    let title: String
    let message: String
    let icon: String
    let tone: Tone

    init(title: String, message: String, icon: String, tone: Tone) {
        self.title = title
        self.message = message
        self.icon = icon
        self.tone = tone
    }

    init(paymentStatus: PaymentVerificationStatus) {
        switch paymentStatus {
        case .success:
            self.init(title: "Pagamento confermato", message: "Sei ufficialmente iscritto all'evento.", icon: "checkmark.seal.fill", tone: .success)
        case .membershipSuccess:
            self.init(title: "Tessera attivata", message: "Pagamento confermato. Ora puoi completare l'iscrizione all'evento.", icon: "checkmark.shield.fill", tone: .success)
        case .spotTaken(let message):
            self.init(title: "Posto non confermato", message: message, icon: "person.2.slash", tone: .warning)
        case .error(let message):
            let defaultMessage = "Riprova tra qualche istante."
            let normalizedMessage = message.trimmingCharacters(in: .whitespacesAndNewlines)
            let displayMessage = normalizedMessage.isEmpty || normalizedMessage == "Pagamento non ancora confermato" ? defaultMessage : normalizedMessage
            self.init(title: "Pagamento da verificare", message: displayMessage, icon: "exclamationmark.triangle.fill", tone: .error)
        }
    }

    var color: Color {
        switch tone {
        case .success: Brand.success
        case .warning: Brand.warning
        case .error: Brand.destructive
        }
    }
}

