    init(url: URL, sessionId: String?, kind: CheckoutKind, eventId: String? = nil, registrationId: String? = nil) {
        self.url = url
        self.sessionId = sessionId
        self.kind = kind
        self.eventId = eventId
        self.registrationId = registrationId
    }
}

struct PaymentAuthenticationView: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let checkout: ActiveCheckout
    let onComplete: (AppFeedback?) -> Void
    @State private var completed = false
    @State private var isVerifying = false
    @State private var isCancelling = false

    var body: some View {
        ZStack(alignment: .bottom) {
            SafariCheckoutView(url: checkout.url) {
                handleCancellation()
            }
            .ignoresSafeArea()

            if isVerifying {
                HStack(spacing: 10) {
                    ProgressView()
                        .controlSize(.small)
                        .tint(Brand.primary)
                    Text("Verifico automaticamente il pagamento...")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                }
                .padding(.horizontal, 14)
                .padding(.vertical, 10)
                .background(.regularMaterial, in: Capsule())
                .padding(.bottom, 18)
            }
        }
        .task {
            await pollPaymentStatus()
        }
        .onOpenURL { url in
            handleCallback(url)
        }
    }

    private func handleCallback(_ url: URL) {
        guard url.scheme == "scampagnate" else { return }
        if url.isScampagnatePaymentCancellation {
            handleCancellation()
            return
        }
        guard url.host == "payment-success" || url.host == "membership-success" else { return }
        guard let sessionId = url.stripeCheckoutSessionId ?? checkout.sessionId else {
            finish(AppFeedback(title: "Verifica non riuscita", message: "Non ho ricevuto l'identificativo del checkout. Usa il banner di verifica tra qualche istante.", icon: "exclamationmark.triangle.fill", tone: .error))
            return
        }
        isVerifying = true
        Task {
            let status: PaymentVerificationStatus
            switch checkout.kind {
            case .eventPayment:
                status = await store.verifyEventPayment(sessionId: sessionId, eventId: checkout.eventId)
            case .membership:
                status = await store.verifyMembershipPayment(sessionId: sessionId)
            }
            finish(AppFeedback(paymentStatus: status))
        }
    }

    private func handleCancellation() {
        guard !completed && !isCancelling else { return }
        isCancelling = true
        isVerifying = true
        Task {
            if checkout.kind == .eventPayment {
                await store.handleEventPaymentCancellation(
                    sessionId: checkout.sessionId,
                    eventId: checkout.eventId,
                    registrationId: checkout.registrationId
                )
            }
            finish(AppFeedback(title: "Pagamento annullato", message: "Non è stato addebitato nulla. Puoi riprendere quando vuoi.", icon: "xmark.circle.fill", tone: .warning))
        }
    }

    private func pollPaymentStatus() async {
        guard checkout.sessionId != nil else { return }
        try? await Task.sleep(nanoseconds: 3_000_000_000)
        isVerifying = true
        defer { isVerifying = false }

        for _ in 0..<90 {
            guard !Task.isCancelled, !completed else { return }
            let status: PaymentVerificationStatus
            switch checkout.kind {
            case .eventPayment:
                guard let sessionId = checkout.sessionId else { return }
                status = await store.verifyEventPayment(sessionId: sessionId, eventId: checkout.eventId)
            case .membership:
                guard let sessionId = checkout.sessionId else { return }
                status = await store.verifyMembershipPayment(sessionId: sessionId)
            }

            switch status {
            case .success, .membershipSuccess, .spotTaken:
                finish(AppFeedback(paymentStatus: status))
                return
            case .error:
                try? await Task.sleep(nanoseconds: 4_000_000_000)
            }
        }
    }

    private func finish(_ feedback: AppFeedback) {
        guard !completed else { return }
        completed = true
        if let eventId = checkout.eventId {
            Task {
                await store.refreshEventDetail(eventId: eventId)
            }
        }
        onComplete(feedback)
        dismiss()
    }
}

struct SafariCheckoutView: UIViewControllerRepresentable {
    let url: URL
    let onFinish: () -> Void

    func makeUIViewController(context: Context) -> SFSafariViewController {
        let controller = SFSafariViewController(url: url)
        controller.delegate = context.coordinator
        controller.dismissButtonStyle = .close
        controller.preferredControlTintColor = UIColor(Brand.primary)
        return controller
    }

    func updateUIViewController(_ uiViewController: SFSafariViewController, context: Context) {}

    func makeCoordinator() -> Coordinator {
        Coordinator(onFinish: onFinish)
    }

    final class Coordinator: NSObject, SFSafariViewControllerDelegate {
        let onFinish: () -> Void

        init(onFinish: @escaping () -> Void) {
            self.onFinish = onFinish
        }

        func safariViewControllerDidFinish(_ controller: SFSafariViewController) {
            onFinish()
        }
    }
}

struct ShareSheet: UIViewControllerRepresentable {
