    }

    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
}

struct CalendarEventEditView: UIViewControllerRepresentable {
    @Environment(\.dismiss) private var dismiss
    let event: Event

    func makeCoordinator() -> Coordinator {
        Coordinator(dismiss: dismiss)
    }

    func makeUIViewController(context: Context) -> EKEventEditViewController {
        let controller = EKEventEditViewController()
        controller.eventStore = context.coordinator.eventStore
        controller.event = calendarEvent(in: context.coordinator.eventStore)
        controller.editViewDelegate = context.coordinator
        return controller
    }

    func updateUIViewController(_ uiViewController: EKEventEditViewController, context: Context) {}

    private func calendarEvent(in store: EKEventStore) -> EKEvent {
        let calendarEvent = EKEvent(eventStore: store)
        calendarEvent.title = event.title
        calendarEvent.location = event.location ?? event.displayLocation
        calendarEvent.notes = event.webURL?.absoluteString
        calendarEvent.url = event.webURL
        let start = event.calendarStartDate ?? Date()
        calendarEvent.startDate = start
        calendarEvent.endDate = event.calendarEndDate(from: start)
        calendarEvent.calendar = store.defaultCalendarForNewEvents
        return calendarEvent
    }

    final class Coordinator: NSObject, EKEventEditViewDelegate {
        let eventStore = EKEventStore()
        let dismiss: DismissAction

        init(dismiss: DismissAction) {
            self.dismiss = dismiss
        }

        nonisolated func eventEditViewController(_ controller: EKEventEditViewController, didCompleteWith action: EKEventEditViewAction) {
            Task { @MainActor [dismiss] in
                dismiss()
            }
        }
    }
}

// MARK: - Auth

struct AuthView: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    @State private var mode: AuthMode = .login
    @State private var email = ""
    @State private var password = ""
    @State private var firstName = ""
    @State private var lastName = ""
    @State private var showPassword = false
    @State private var consents = RegistrationConsents()
    @State private var feedback: String?

    init(initialMode: AuthMode = .login) {
        _mode = State(initialValue: initialMode)
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 16) {
                    Spacer(minLength: 18)
                    Image("Logo")
                        .resizable()
                        .scaledToFit()
                        .frame(width: 66, height: 66)
                        .clipShape(Circle())

                    VStack(spacing: 5) {
                        Text(mode.title)
                            .font(.system(size: 30, weight: .bold, design: .rounded))
                            .foregroundStyle(Brand.foreground)
                        Text(mode.subtitle)
                            .font(.system(.callout, design: .rounded))
                            .foregroundStyle(Brand.mutedForeground)
                    }

                    VStack(spacing: 10) {
                        if mode == .register {
                            HStack(spacing: 12) {
                                Field("Nome", text: $firstName, labelFont: authFieldLabelFont, textFont: authFieldTextFont, height: authFieldHeight, cornerRadius: authFieldRadius)
                                Field("Cognome", text: $lastName, labelFont: authFieldLabelFont, textFont: authFieldTextFont, height: authFieldHeight, cornerRadius: authFieldRadius)
                            }
                        }
                        Field("Email", text: $email, keyboard: .emailAddress, labelFont: authFieldLabelFont, textFont: authFieldTextFont, height: authFieldHeight, cornerRadius: authFieldRadius)
                            .textInputAutocapitalization(.never)
                        if mode != .reset {
                            PasswordField(password: $password, showPassword: $showPassword, labelFont: authFieldLabelFont, textFont: authFieldTextFont, height: authFieldHeight, cornerRadius: authFieldRadius)
                        }

                        if mode == .register, !password.isEmpty {
                            PasswordStrengthView(strength: AuthPasswordStrength(password: password))
                        }

                        if mode == .login {
                            HStack {
                                Spacer()
                                Button("Password dimenticata?") { mode = .reset }
                                    .font(.subheadline.weight(.medium))
                                    .foregroundStyle(Brand.primary)
                            }
                        }

                        if mode == .register {
                            LegalConsentToggle(isOn: $consents.terms)
                            ConsentToggle(
                                title: "Confermo di avere almeno 18 anni e di partecipare alle attività sotto la mia responsabilità",
                                subtitle: "",
                                required: true,
                                isOn: $consents.age
                            )
                            ConsentToggle(
                                title: "Comunicazioni e novità",
                                subtitle: "Ti terremo aggiornato su nuove iniziative, promozioni, eventi speciali e contenuti della community",
                                required: false,
                                isOn: $consents.marketing
                            )
                            ConsentToggle(
                                title: "Fai parte dei nostri racconti",
                                subtitle: "Possiamo condividere foto e momenti delle esperienze sui canali Scampagnate",
                                required: false,
                                isOn: $consents.media
                            )
                        }

                        if mode == .reset {
                            Text("Inserisci la tua email e ti invieremo un link di reset.")
                                .font(.subheadline)
                                .foregroundStyle(Brand.mutedForeground)
                                .frame(maxWidth: .infinity, alignment: .leading)
                        }

                        if let feedback {
                            Text(feedback)
                                .font(.footnote.weight(.medium))
                                .foregroundStyle(Brand.success)
                                .frame(maxWidth: .infinity, alignment: .leading)
                        }

                        Button {
                            Task { await submit() }
                        } label: {
                            if store.isLoading {
                                HStack(spacing: 10) {
                                    ProgressView()
                                        .tint(.white)
                                    Text(loadingActionTitle)
                                }
                                .frame(maxWidth: .infinity)
                            } else {
                                Text(actionTitle)
                                    .frame(maxWidth: .infinity)
                            }
                        }
                        .buttonStyle(PrimaryButtonStyle(height: 52))
                        .disabled(store.isLoading || !canSubmit)

                        Button(mode.switchTitle) {
                            withAnimation(.snappy) { mode = mode.next }
                        }
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(store.isLoading ? Brand.mutedForeground : Brand.primary)
                        .padding(.top, 4)
                        .disabled(store.isLoading)

                        if mode == .register {
                            NavigationLink {
                                HelpContentView(slug: "guida-difficolta-trekking", fallbackTitle: "Guida difficoltà trekking")
                            } label: {
                                VStack(spacing: 4) {
                                    Label("Che livello sei?", systemImage: "info.circle")
                                        .font(.subheadline.weight(.semibold))
                                        .foregroundStyle(Brand.secondary)
                                    Text("Scopri quale esperienza è giusta per te")
                                        .font(.caption)
                                        .foregroundStyle(Brand.mutedForeground)
                                }
                                .frame(maxWidth: .infinity)
                                .padding(.top, 12)
                            }
                            .buttonStyle(.plain)
                        }
                    }
                }
                .padding(22)
            }
            .background(Brand.background)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Chiudi") { dismiss() }
                }
            }
        }
    }

    private var canSubmit: Bool {
        switch mode {
        case .login:
            return !email.isEmpty && !password.isEmpty
        case .register:
            return !email.isEmpty && password.count >= 6 && !firstName.isEmpty && !lastName.isEmpty && consents.terms && consents.age
        case .reset:
            return !email.isEmpty
        }
    }

    private var authFieldLabelFont: Font {
        .caption.weight(.semibold)
    }

    private var authFieldTextFont: Font {
        .system(.callout, design: .rounded)
    }

    private var authFieldHeight: CGFloat { 50 }

    private var authFieldRadius: CGFloat { 12 }

    private var actionTitle: String {
        switch mode {
        case .login: "Accedi"
        case .register: "Registrati"
        case .reset: "Invia Link di Reset"
        }
    }

    private var loadingActionTitle: String {
        switch mode {
        case .login: "Accesso..."
        case .register: "Creazione account..."
        case .reset: "Invio..."
        }
    }

    private func submit() async {
        switch mode {
        case .login:
            if await store.signIn(email: email, password: password) { dismiss() }
        case .register:
            if await store.signUp(email: email, password: password, firstName: firstName, lastName: lastName, consents: consents) { dismiss() }
        case .reset:
            if await store.sendPasswordReset(email: email) {
                feedback = "Se l'email è collegata a un account, riceverai un link di reset."
            }
        }
    }
}

struct PasswordRecoveryView: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let recovery: PasswordRecoveryLink
    @State private var password = ""
    @State private var confirmPassword = ""
    @State private var showPassword = false
    @State private var showConfirmPassword = false
    @State private var isSubmitting = false

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 22) {
                    Spacer(minLength: 22)

                    Image("Logo")
                        .resizable()
                        .scaledToFit()
                        .frame(width: 76, height: 76)
                        .clipShape(Circle())

                    VStack(spacing: 6) {
                        Text("Nuova password")
                            .font(.system(size: 32, weight: .bold, design: .rounded))
                            .foregroundStyle(Brand.foreground)
                        Text("Scegli una nuova password per rientrare in Scampagnate.")
                            .font(.system(.subheadline, design: .rounded))
                            .foregroundStyle(Brand.mutedForeground)
                            .multilineTextAlignment(.center)
                    }

                    VStack(spacing: 14) {
                        RecoveryPasswordField(
                            title: "Nuova password",
                            text: $password,
                            isVisible: $showPassword
                        )
                        if !password.isEmpty {
                            PasswordStrengthView(strength: AuthPasswordStrength(password: password))
                        }
                        RecoveryPasswordField(
                            title: "Conferma password",
                            text: $confirmPassword,
                            isVisible: $showConfirmPassword
                        )

                        Text("La password deve contenere almeno 6 caratteri.")
                            .font(.footnote)
                            .foregroundStyle(Brand.mutedForeground)
                            .frame(maxWidth: .infinity, alignment: .leading)

                        Button {
                            Task { await submit() }
                        } label: {
                            if isSubmitting {
                                HStack(spacing: 10) {
                                    ProgressView()
                                        .tint(.white)
                                    Text("Aggiornamento...")
                                }
                                .frame(maxWidth: .infinity)
                            } else {
                                Text("Aggiorna password")
                                    .frame(maxWidth: .infinity)
                            }
                        }
                        .buttonStyle(PrimaryButtonStyle(height: 54))
                        .disabled(isSubmitting || password.count < 6 || confirmPassword.isEmpty)
                        .padding(.top, 4)
                    }
                }
                .padding(24)
            }
            .background(Brand.background)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Chiudi") { dismiss() }
                        .disabled(isSubmitting)
                }
            }
        }
    }

    private func submit() async {
        guard !isSubmitting else { return }
        guard password.count >= 6 else {
            store.errorMessage = "La password deve avere almeno 6 caratteri."
            return
        }
        guard password == confirmPassword else {
            store.errorMessage = "Le password non corrispondono."
            return
        }

        isSubmitting = true
        if await store.completePasswordRecovery(recovery, newPassword: password) {
            dismiss()
        }
        isSubmitting = false
    }
}

