    @FocusState private var searchFocused: Bool

    var upcomingEvents: [Event] {
        store.events.filter { event in
            event.isVisibleInUpcomingList
        }
    }

    var filteredEvents: [Event] {
        upcomingEvents.filter { event in
            let normalizedQuery = query.normalizedSearchText
            let matchesQuery = normalizedQuery.isEmpty || [
                event.title,
                event.displayLocation,
                event.location ?? "",
                event.description ?? "",
                event.category?.name ?? ""
            ].contains { $0.normalizedSearchText.contains(normalizedQuery) }
            let matchesCategory = selectedCategories.isEmpty || selectedCategories.contains(event.category?.name ?? "")
            let matchesQuickFilter = activeQuickFilters.matchesAny(event)
            let matchesPrice = priceFilter.matches(event)
            return matchesQuery && matchesCategory && matchesQuickFilter && matchesPrice
        }
    }

    var featured: Event? {
        upcomingEvents.first(where: { $0.featured == true }) ?? upcomingEvents.first
    }

    var recommendedItems: [PersonalizedEventRecommendation] {
        PersonalizedEventRecommendation.items(
            events: upcomingEvents.filter { $0.id != featured?.id },
            profile: store.profile,
            registrations: store.myEvents
        )
    }

    var hasActiveDiscoveryFilters: Bool {
        !query.normalizedSearchText.isEmpty ||
        !selectedCategories.isEmpty ||
        !activeQuickFilters.isEmpty ||
        priceFilter != .all
    }

    var listTitle: String {
        hasActiveDiscoveryFilters ? "Risultati ricerca (\(filteredEvents.count))" : "Prossimi eventi"
    }

    var body: some View {
        NavigationStack {
            GeometryReader { proxy in
                ScrollView {
                    VStack(alignment: .leading, spacing: 14) {
                        AppHeader(
                            showAuth: $showAuth,
                            searchOpen: $searchOpen,
                            showNotifications: $showNotifications
                        ) {
                            showCalendar = true
                        }
                        .zIndex(10)

                        if searchOpen {
                            SearchField(query: $query, isFocused: $searchFocused)
                            HomeSearchFilters(
                                priceFilter: $priceFilter,
                                hasActiveFilters: priceFilter != .all
                            ) {
                                clearSearchFilters()
                            }
                        }

                        if !hasActiveDiscoveryFilters, let featured {
                            FeaturedEventCard(event: featured)
                                .onTapGesture { selectedEvent = featured }
                        }

                        VStack(alignment: .leading, spacing: 6) {
                            CategoryStrip(categories: store.categories, selected: $selectedCategories)
                            QuickFilterStrip(selected: $activeQuickFilters)
                        }

                        if store.isAuthenticated && !recommendedItems.isEmpty && !hasActiveDiscoveryFilters {
                            RecommendedEventsSection(
                                recommendations: recommendedItems,
                                availableWidth: max(proxy.size.width - 32, 0),
                                selectedEvent: $selectedEvent
                            )
                        }

                        Text(listTitle)
                            .font(.system(.title3, design: .rounded, weight: .bold))
                            .foregroundStyle(Brand.foreground)
                            .padding(.top, 6)

                        if filteredEvents.isEmpty {
                            HomeEventsEmptyState(hasActiveFilters: hasActiveDiscoveryFilters) {
                                if hasActiveDiscoveryFilters {
                                    clearAllDiscoveryFilters()
                                } else if store.isAuthenticated {
                                    showProposal = true
                                } else {
                                    showAuth = true
                                }
                            }
                        } else {
                            LazyVStack(spacing: 12) {
                                ForEach(filteredEvents) { event in
                                    EventCard(event: event)
                                        .onTapGesture { selectedEvent = event }
                                }
                            }
                        }

                        if !filteredEvents.isEmpty {
                            ProposalCard {
                                if store.isAuthenticated {
                                    showProposal = true
                                } else {
                                    showAuth = true
                                }
                            }
                        }
                    }
                    .frame(width: max(proxy.size.width - 32, 0), alignment: .leading)
                    .padding(.horizontal, 16)
                    .padding(.bottom, 0)
                }
                .contentMargins(.bottom, 0, for: .scrollContent)
                .background(Brand.background)
            }
            .navigationDestination(item: $selectedEvent) { event in
                EventDetailView(eventId: event.id, showAuth: $showAuth)
            }
            .navigationDestination(isPresented: $showCalendar) {
                EventCalendarView(showAuth: $showAuth)
            }
            .sheet(isPresented: $showProposal) {
                ActivityProposalSheet()
            }
            .onChange(of: searchOpen) { _, isOpen in
                if isOpen {
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.12) {
                        searchFocused = true
                    }
                } else {
                    query = ""
                    priceFilter = .all
                    searchFocused = false
                }
            }
            .onChange(of: store.homeDiscoveryRequest?.id) { _, _ in
                applyHomeDiscoveryRequest()
            }
            .task {
                await store.refreshEventData(reportingErrors: false)
                while !Task.isCancelled {
                    do {
                        try await Task.sleep(nanoseconds: 30_000_000_000)
                    } catch {
                        break
                    }
                    await store.refreshEventData(reportingErrors: false)
                }
            }
            .refreshable {
                await store.refreshEventData()
            }
        }
    }

    private func clearSearchFilters() {
        priceFilter = .all
    }

    private func clearAllDiscoveryFilters() {
        query = ""
        selectedCategories.removeAll()
        activeQuickFilters.removeAll()
        clearSearchFilters()
    }

    private func applyHomeDiscoveryRequest() {
        guard let request = store.homeDiscoveryRequest else { return }
        query = ""
        selectedCategories = Set(request.category.map { [$0] } ?? [])
        activeQuickFilters = Set(request.quickFilter.map { [$0] } ?? [])
        priceFilter = .all
        searchOpen = false
        searchFocused = false
    }
}

struct EventCalendarView: View {
    @EnvironmentObject private var store: AppStore
    @Binding var showAuth: Bool
    @State private var visibleMonth = Calendar.current.startOfMonth(for: Date())
    @State private var selectedDate = Calendar.current.startOfDay(for: Date())
    @State private var selectedEvent: Event?
    @State private var selectedCategories: Set<String> = []

    private var visibleEvents: [Event] {
        store.events.filter { event in
            event.isVisibleInUpcomingList && (selectedCategories.isEmpty || selectedCategories.contains(event.category?.name ?? ""))
        }
    }

    private var eventsByDay: [Date: [Event]] {
        Dictionary(grouping: visibleEvents) { event in
            event.calendarDay ?? .distantFuture
        }
        .mapValues { events in
            events.sorted {
                ($0.time ?? "") < ($1.time ?? "")
            }
        }
    }

    private var selectedEvents: [Event] {
        eventsByDay[Calendar.current.startOfDay(for: selectedDate)] ?? []
    }

    var body: some View {
        GeometryReader { proxy in
            ScrollView {
                VStack(alignment: .leading, spacing: 18) {
                    CategoryStrip(categories: store.categories, selected: $selectedCategories)

                    EventMonthCalendar(
                        visibleMonth: $visibleMonth,
                        selectedDate: $selectedDate,
                        eventsByDay: eventsByDay
                    )

                    VStack(alignment: .leading, spacing: 12) {
                        HStack(alignment: .firstTextBaseline, spacing: 8) {
                            Text("Eventi del \(DateFormatter.calendarDayMonth.string(from: selectedDate))")
                                .font(.system(.title3, design: .rounded, weight: .bold))
                                .foregroundStyle(Brand.foreground)
                            Text("(\(selectedEvents.count))")
                                .font(.subheadline.weight(.semibold))
                                .foregroundStyle(Brand.mutedForeground)
                        }

                        if selectedEvents.isEmpty {
                            EmptyState(
                                icon: "calendar.badge.exclamationmark",
                                title: "Nessun evento in questa data",
                                message: "Scegli un altro giorno con un indicatore oppure cambia mese."
                            )
                            .padding(.top, 18)
                        } else {
                            LazyVStack(spacing: 12) {
                                ForEach(selectedEvents) { event in
                                    EventCalendarEventRow(event: event)
                                        .onTapGesture { selectedEvent = event }
                                }
                            }
                        }
                    }
                }
                .frame(width: max(proxy.size.width - 32, 0), alignment: .leading)
                .padding(16)
            }
            .contentMargins(.bottom, 0, for: .scrollContent)
            .background(Brand.background)
        }
        .navigationTitle("Calendario eventi")
        .navigationBarTitleDisplayMode(.inline)
        .navigationDestination(item: $selectedEvent) { event in
            EventDetailView(eventId: event.id, showAuth: $showAuth)
        }
        .refreshable { await store.refreshEventData() }
    }
}

struct EventMonthCalendar: View {
    @Binding var visibleMonth: Date
    @Binding var selectedDate: Date
    let eventsByDay: [Date: [Event]]

    private let columns = Array(repeating: GridItem(.flexible(), spacing: 6), count: 7)
    private let weekdaySymbols = ["L", "M", "M", "G", "V", "S", "D"]

    private var days: [Date?] {
        let calendar = Calendar.current
        guard let interval = calendar.dateInterval(of: .month, for: visibleMonth) else { return [] }
        let monthDays = calendar.days(from: interval.start, to: interval.end)
        let offset = ((calendar.component(.weekday, from: interval.start) + 5) % 7)
        return Array(repeating: nil, count: offset) + monthDays.map(Optional.some)
    }

    var body: some View {
        VStack(spacing: 14) {
            HStack {
                Button {
                    visibleMonth = Calendar.current.date(byAdding: .month, value: -1, to: visibleMonth) ?? visibleMonth
                } label: {
                    Image(systemName: "chevron.left")
                        .font(.system(size: 16, weight: .bold))
                        .foregroundStyle(Brand.foreground)
                        .frame(width: 36, height: 36)
                }
                .buttonStyle(.plain)

                Spacer()

                Text(DateFormatter.calendarMonth.string(from: visibleMonth))
                    .font(.system(.title3, design: .rounded, weight: .bold))
                    .foregroundStyle(Brand.foreground)
                    .textCase(.uppercase)

                Spacer()

                Button {
                    visibleMonth = Calendar.current.date(byAdding: .month, value: 1, to: visibleMonth) ?? visibleMonth
                } label: {
                    Image(systemName: "chevron.right")
                        .font(.system(size: 16, weight: .bold))
                        .foregroundStyle(Brand.foreground)
                        .frame(width: 36, height: 36)
                }
                .buttonStyle(.plain)
            }

            LazyVGrid(columns: columns, spacing: 8) {
                ForEach(Array(weekdaySymbols.enumerated()), id: \.offset) { _, symbol in
                    Text(symbol)
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.mutedForeground)
                        .frame(maxWidth: .infinity)
                }

                ForEach(Array(days.enumerated()), id: \.offset) { _, day in
                    if let day {
                        EventCalendarDayButton(
                            day: day,
                            isSelected: Calendar.current.isDate(day, inSameDayAs: selectedDate),
                            isToday: Calendar.current.isDateInToday(day),
                            eventCount: eventsByDay[Calendar.current.startOfDay(for: day)]?.count ?? 0
                        ) {
                            selectedDate = Calendar.current.startOfDay(for: day)
                        }
                    } else {
                        Color.clear
                            .aspectRatio(1, contentMode: .fit)
                    }
                }
            }
        }
        .padding(14)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 18))
        .overlay(RoundedRectangle(cornerRadius: 18).stroke(Brand.muted, lineWidth: 1))
    }
}

