enum HomePriceFilter: String, CaseIterable, Identifiable {
    case all
    case free
    case paid

    var id: String { rawValue }

    var title: String {
        switch self {
        case .all: "Tutti i prezzi"
        case .free: "Gratis"
        case .paid: "A pagamento"
        }
    }

    func matches(_ event: Event) -> Bool {
        switch self {
        case .all:
            return true
        case .free:
            return (event.price ?? 0) <= 0
        case .paid:
            return (event.price ?? 0) > 0
        }
    }
}

