                                .padding(.horizontal, 12)
                                .padding(.vertical, 7)
                                .background(.black.opacity(0.50), in: UnevenRoundedRectangle(bottomLeadingRadius: 16, topTrailingRadius: 20))
                        }
                    }
                    Spacer()
                }
                .frame(width: cardWidth, height: 260)

                VStack(alignment: .leading, spacing: 8) {
                    Label("\(formatDate(event.date)) · \(event.displayLocation)", systemImage: "calendar")
                        .font(.caption.weight(.medium))
                        .foregroundStyle(.white.opacity(0.82))
                        .lineLimit(1)
                    Text(event.title)
                        .font(.system(size: 26, weight: .bold, design: .rounded))
