// MARK: - Event Detail

struct EventDetailView: View {
    @Environment(\.dismiss) private var dismiss
    @EnvironmentObject private var store: AppStore
    @EnvironmentObject private var pushNotifications: PushNotificationService
    @Binding var showAuth: Bool
    let eventId: String
    let openParticipantsOnAppear: Bool
    @State private var showCheckout = false
    @State private var showCancelConfirm = false
    @State private var feedback: AppFeedback?
    @State private var activeCheckout: ActiveCheckout?
    @State private var showStaff = false
    @State private var showParticipants = false
    @State private var showGallery = false
    @State private var selectedGalleryIndex = 0
    @State private var descriptionExpanded = false
    @State private var savingEvent = false
    @State private var togglingOpeningReminder = false
    @State private var showShare = false
    @State private var showCalendar = false
    @State private var showAccessWarning = false
    @State private var requestApprovalOverride = false
    @State private var showOrganizerContact = false
    @State private var showOrganizerProfile = false
    @State private var showDirectionsOptions = false
    @State private var directionsDestination = ""
    @State private var paymentLoading = false
    @State private var scrollOffset: CGFloat = 0
    @State private var didOpenInitialParticipants = false

    init(eventId: String, showAuth: Binding<Bool>, openParticipantsOnAppear: Bool = false) {
        self.eventId = eventId
        self._showAuth = showAuth
        self.openParticipantsOnAppear = openParticipantsOnAppear
    }

    var event: Event? {
        store.events.first { $0.id == eventId }
        ?? store.myEvents.compactMap(\.event).first { $0.id == eventId }
        ?? store.savedEvents.compactMap(\.event).first { $0.id == eventId }
    }

    var registration: Registration? {
        guard let registration = store.myEvents.mostRecent(forEventId: eventId),
              registration.blocksNewRegistration else {
            return nil
        }
        return registration
    }

    var isSaved: Bool {
        store.savedEvents.contains { $0.event?.id == eventId || $0.eventId == eventId }
    }

    var isOpeningReminderActive: Bool {
        store.eventOpeningReminders.contains { $0.eventId == eventId && $0.isActive }
    }

    var participants: [EventParticipant] {
        store.eventParticipants[eventId] ?? []
    }

    var attendeeParticipants: [EventParticipant] {
        participants.filter(\.isParticipant)
    }

    var organizerProfile: PublicProfile? {
        event?.organizerId.flatMap { store.organizerProfiles[$0] }
    }

    var activeParticipantCount: Int {
        attendeeParticipants.isEmpty ? (event?.attendeeSpotsTaken ?? 0) : attendeeParticipants.count
    }

    var staffMembers: [EventStaffMember] {
        store.eventStaff[eventId] ?? event?.staffMembers ?? []
    }

    var canViewParticipantDetails: Bool {
        store.isAuthenticated && store.profile != nil && !store.needsOnboarding
    }

    private func accessCheck(for event: Event) -> EventAccessCheck {
        EventAccessCheck.evaluate(event: event, profile: store.profile, badges: store.badges, registrations: store.myEvents)
    }

    var body: some View {
        Group {
            if let event {
                GeometryReader { proxy in
                    ZStack(alignment: .top) {
                        ScrollView {
                            LazyVStack(spacing: 0) {
                                hero(event, width: proxy.size.width, topInset: proxy.safeAreaInsets.top)
                                content(event)
                                    .frame(width: proxy.size.width, alignment: .leading)
                            }
                            .frame(width: proxy.size.width, alignment: .leading)
                            .padding(.bottom, 20)
                            .background {
                                GeometryReader { scrollProxy in
                                    Color.clear.preference(
                                        key: ScrollOffsetPreferenceKey.self,
                                        value: max(0, -scrollProxy.frame(in: .named("event-detail-scroll")).minY)
                                    )
                                }
                            }
                        }
                        .coordinateSpace(name: "event-detail-scroll")
                        .refreshable {
                            await store.refreshEventDetail(eventId: eventId)
                        }
                        .ignoresSafeArea(edges: .top)
                        .modifier(EventDetailScrollTracker(scrollOffset: $scrollOffset))
                        .onPreferenceChange(ScrollOffsetPreferenceKey.self) { newValue in
                            scrollOffset = newValue
                        }

                        let headerProgress = compactHeaderProgress()
                        compactHeader(event)
                            .opacity(headerProgress > 0.04 ? 1 : 0)
                            .offset(y: compactHeaderOffset(progress: headerProgress))
                            .allowsHitTesting(headerProgress > 0.35)
                            .zIndex(20)
                    }
                    .safeAreaInset(edge: .bottom, spacing: 0) {
                        bottomBar(event)
                    }
                    .overlay {
                        if showOrganizerContact {
                            OrganizerContactDialog(
                                event: event,
                                profile: organizerProfile,
                                onProfile: {
                                    showOrganizerContact = false
                                    showOrganizerProfile = true
                                },
                                onClose: {
                                    showOrganizerContact = false
                                }
                            )
                            .transition(.opacity.combined(with: .scale(scale: 0.96)))
                            .zIndex(100)
                        }
                    }
                    .animation(.easeOut(duration: 0.18), value: showOrganizerContact)
                    .sheet(isPresented: $showCheckout) {
                        RegistrationCheckoutSheet(event: event, requestApprovalOverride: requestApprovalOverride) { result in
                            if result.free {
                                feedback = AppFeedback(
                                    title: requestApprovalOverride || event.requiresManualApproval ? "Richiesta inviata" : "Iscrizione confermata",
                                    message: requestApprovalOverride || event.requiresManualApproval ? "La richiesta è stata inviata agli organizzatori." : "Ci sei. Abbiamo aggiornato i tuoi eventi.",
                                    icon: "checkmark.seal.fill",
                                    tone: .success
                                )
                            }
                            if let url = result.url {
                                activeCheckout = ActiveCheckout(
                                    url: url,
                                    sessionId: result.sessionId,
                                    kind: result.kind,
                                    eventId: event.id,
                                    registrationId: store.pendingPayment?.registrationId
                                )
                            }
                            requestApprovalOverride = false
                        }
                        .presentationDetents([.large])
                    }
                    .onChange(of: showCheckout) { _, isPresented in
                        if !isPresented {
                            requestApprovalOverride = false
                        }
                    }
                    .sheet(isPresented: $showCancelConfirm) {
                        CancelRegistrationSheet(event: event, registration: registration, feedback: $feedback)
                            .presentationDetents([.height(360)])
                    }
                    .fullScreenCover(item: $activeCheckout) { checkout in
                        PaymentAuthenticationView(checkout: checkout) { result in
                            feedback = result
                        }
                    }
                    .sheet(item: $feedback) { feedback in
                        AppFeedbackSheet(feedback: feedback)
                            .presentationDetents([.height(300)])
                    }
                    .sheet(isPresented: $showParticipants) {
                        ParticipantsSheet(eventId: eventId, fallbackCount: activeParticipantCount, showAuth: $showAuth)
                            .presentationDetents([.medium, .large])
                    }
                    .sheet(isPresented: $showStaff) {
                        EventStaffSheet(event: event, staffMembers: staffMembers, organizerProfile: organizerProfile, showAuth: $showAuth)
                            .presentationDetents([.medium, .large])
                    }
                    .fullScreenCover(isPresented: $showGallery) {
                        GalleryViewer(images: event.gallery.compactMap(\.url), selectedIndex: $selectedGalleryIndex)
                    }
                    .sheet(isPresented: $showShare) {
                        ShareSheet(activityItems: shareItems(for: event))
                            .presentationDetents([.medium])
                    }
                    .sheet(isPresented: $showCalendar) {
                        CalendarEventEditView(event: event)
                    }
                    .sheet(isPresented: $showAccessWarning) {
                        EventAccessWarningSheet(
                            check: accessCheck(for: event),
                            canContactOrganizer: organizerProfile?.phone?.nilIfBlank != nil,
                            onProceed: {
                                showAccessWarning = false
                                requestApprovalOverride = false
                                showCheckout = true
                            },
                            onRequestApproval: {
                                showAccessWarning = false
                                requestApprovalOverride = true
                                showCheckout = true
                            },
                            onContactOrganizer: {
                                showAccessWarning = false
                                showOrganizerContact = true
                            }
                        )
                        .presentationDetents([.medium, .large])
                    }
                    .confirmationDialog("Apri indicazioni con", isPresented: $showDirectionsOptions, titleVisibility: .visible) {
                        ForEach(DirectionsApp.allCases) { app in
                            Button(app.title) {
                                openDirections(to: directionsDestination, using: app)
                            }
                        }
                        Button("Annulla", role: .cancel) {}
                    } message: {
                        Text(directionsDestination)
                    }
                    .fullScreenCover(isPresented: $showOrganizerProfile) {
                        OrganizerProfileView(organizerId: event.organizerId, fallbackName: event.organizerName, profile: organizerProfile, showAuth: $showAuth)
                            .environmentObject(store)
                    }
                }
            } else {
                ContentUnavailableView("Evento non trovato", systemImage: "calendar.badge.exclamationmark")
            }
        }
        .background(Brand.background)
        .navigationBarBackButtonHidden(true)
        .toolbar(.hidden, for: .tabBar)
        .task(id: eventId) {
            await store.refreshEventDetail(eventId: eventId, reportingErrors: false)
            openInitialParticipantsIfNeeded()
        }
        .task(id: event?.organizerId ?? "") {
            await store.loadOrganizerProfile(organizerId: event?.organizerId)
        }
        .task(id: "\(eventId)-\(store.session?.user.id ?? "anon")-\(store.needsOnboarding)") {
            await store.loadParticipants(eventId: eventId)
        }
    }

    private func hero(_ event: Event, width: CGFloat, topInset: CGFloat) -> some View {
        let safeTop = max(topInset, 22)
        let imageHeight = width
        let heroHeight = safeTop + imageHeight
        let heroOpacity = heroOpacity(heroHeight: heroHeight)
        let heroTranslateY = scrollOffset * 0.08

        return ZStack(alignment: .top) {
            Brand.background

            RemoteImage(urlString: event.imageUrl, contentMode: .fill)
                .frame(width: width, height: imageHeight)
                .background(Brand.muted.opacity(0.28))
                .saturation(event.isSoldOut ? 0 : 1)
                .offset(y: heroTranslateY)
                .opacity(heroOpacity)
                .overlay {
                    LinearGradient(
                        stops: event.isSoldOut
                            ? [
                                .init(color: .black.opacity(0.08), location: 0),
                                .init(color: .clear, location: 0.38),
                                .init(color: .black.opacity(0.38), location: 0.68),
                                .init(color: .black.opacity(0.78), location: 1)
                            ]
                            : [
                                .init(color: .black.opacity(0.04), location: 0),
                                .init(color: .clear, location: 0.38),
                                .init(color: .black.opacity(0.32), location: 0.68),
                                .init(color: .black.opacity(0.72), location: 1)
                            ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .opacity(heroOpacity)
                }
                .overlay {
                    if event.isSoldOut {
                        SoldOutRibbon(fontSize: 18)
                            .opacity(heroOpacity)
                    }
                }
                .clipped()
                .padding(.top, safeTop)

            VStack {
                HStack {
                    EventDetailCircleButton(systemImage: "chevron.left") {
                        dismiss()
                    }
                    Spacer()
                    HStack(spacing: 10) {
                        EventDetailCircleButton(systemImage: isSaved ? "bookmark.fill" : "bookmark") {
                            Task { await toggleSaved(event) }
                        }
                        .disabled(savingEvent)
                        EventDetailCircleButton(systemImage: "square.and.arrow.up") {
                            showShare = true
                        }
                    }
                }
                .padding(.horizontal, 16)
                .padding(.top, safeTop + 10)
                Spacer()
            }
            .frame(width: width, height: safeTop + imageHeight)
            .opacity(heroOpacity)

            VStack(alignment: .leading, spacing: 12) {
                Spacer()
                Text(event.title)
                    .font(.system(size: 28, weight: .bold, design: .rounded))
                    .foregroundStyle(.white)
                    .lineLimit(3)
                    .minimumScaleFactor(0.75)
                    .fixedSize(horizontal: false, vertical: true)
                    .frame(width: max(width - 36, 0), alignment: .leading)
                    .padding(.horizontal, 18)
                    .padding(.bottom, 34)
            }
            .frame(width: width, height: heroHeight, alignment: .bottomLeading)
            .opacity(heroOpacity)
        }
        .frame(width: width, height: heroHeight)
        .background(Brand.background)
        .clipped()
    }

    private func heroOpacity(heroHeight: CGFloat) -> Double {
        max(0, min(Double(1 - scrollOffset / (heroHeight * 0.7)), 1))
    }

    private func compactHeaderProgress() -> Double {
        let revealStart: CGFloat = 190
        let revealEnd: CGFloat = 260
        guard scrollOffset > revealStart else { return 0 }
        let progress = min(Double((scrollOffset - revealStart) / (revealEnd - revealStart)), 1)
        return progress * progress * (3 - 2 * progress)
    }

    private func compactHeaderOffset(progress: Double) -> CGFloat {
        guard progress > 0 else { return -78 }
        let entrance = -78 * (1 - progress)
        let bump = sin(progress * .pi) * 9
        return CGFloat(entrance + bump)
    }

