                    EventInfoActionRow(icon: "calendar", title: formatLongDate(event.date), subtitle: timeRange(event), tint: Brand.primary)
                }
                .buttonStyle(.plain)

                Button {
                    presentDirectionsOptions(for: event.location ?? event.displayLocation)
                } label: {
                    EventInfoActionRow(icon: "mappin.circle", title: event.displayLocation, subtitle: event.location ?? "", tint: Brand.secondary)
                }
                .buttonStyle(.plain)
