    private func bottomBar(_ event: Event) -> some View {
        let check = accessCheck(for: event)
        let availabilityLabel = event.canNotifyWhenRegistrationsOpen
            ? (isOpeningReminderActive ? "Ti avviseremo all'apertura" : "Iscrizioni non ancora aperte")
            : event.availabilityLabel

        return VStack(spacing: 0) {
            if store.isAuthenticated, check.isBlocking {
                Text(check.restrictionMessage ?? check.failedReasons.first ?? "Non soddisfi i requisiti per partecipare a questo evento.")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(Brand.destructive)
                    .multilineTextAlignment(.center)
                    .lineLimit(2)
                    .frame(maxWidth: .infinity)
                    .padding(.horizontal, 16)
                    .padding(.vertical, 8)
                    .background(Brand.destructive.opacity(0.08))
            }

            HStack(spacing: 16) {
                VStack(alignment: .leading, spacing: 2) {
                    Text(event.displayPrice(profile: store.profile, badges: store.badges, registrations: store.myEvents))
                        .font(.title2.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                    Text(availabilityLabel)
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                    if let registration, registration.normalizedStatus == "deposit_paid" || registration.paymentStatus == "deposit_paid" {
                        Text(registration.displayStatusLabel(in: event))
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    if let deadline = event.registrationDeadlineText {
                        Text("Iscrizioni fino al \(deadline)")
                            .font(.caption2)
                            .foregroundStyle(Brand.mutedForeground)
                    }
                }
                Spacer()
                if let registration {
                    let pendingCheckout = store.pendingCheckout(for: registration, event: event)
                    if pendingCheckout != nil || registration.canResumePayment(in: event) {
                        Button(paymentLoading ? "Attendere..." : resumeActionTitle(for: registration, event: event, pendingCheckout: pendingCheckout)) {
                            Task { await continueRegistration(registration, event: event) }
                        }
                        .buttonStyle(PrimaryButtonStyle(width: 170))
                        .disabled(paymentLoading)
                    } else {
                        let statusStyle = registration.displayStatusStyle(in: event)
                        Text(registration.displayStatusLabel(in: event) + (registration.isActive ? " ✓" : ""))
                            .font(.headline.weight(.bold))
                            .foregroundStyle(statusStyle.foreground)
                            .padding(.horizontal, 22)
                            .frame(height: 50)
                            .background(statusStyle.background, in: RoundedRectangle(cornerRadius: 18))
                    }
                } else if event.canNotifyWhenRegistrationsOpen {
                    Button {
                        Task { await toggleOpeningReminder(event) }
                    } label: {
                        Label(
                            togglingOpeningReminder ? "Attendere..." : (isOpeningReminderActive ? "Avviso attivo" : "Avvisami"),
                            systemImage: isOpeningReminderActive ? "bell.fill" : "bell"
                        )
                        .lineLimit(1)
                    }
                    .buttonStyle(OpeningReminderButtonStyle(isActive: isOpeningReminderActive, width: 170))
                    .disabled(togglingOpeningReminder)
                } else if !event.acceptsRegistrations {
                    Text(event.statusStyle.label)
                        .font(.headline.weight(.bold))
                        .foregroundStyle(event.statusStyle.foreground)
                        .padding(.horizontal, 22)
                        .frame(height: 50)
                        .background(event.statusStyle.background, in: RoundedRectangle(cornerRadius: 18))
                } else if event.isFull && !event.hasWaitlistParticipationOption {
                    Text("Sold out")
                        .font(.headline.weight(.bold))
                        .foregroundStyle(event.statusStyle.foreground)
                        .padding(.horizontal, 22)
                        .frame(height: 50)
                        .background(event.statusStyle.background, in: RoundedRectangle(cornerRadius: 18))
                } else {
                    VStack(spacing: -8) {
                        if event.hasLastSpots {
                            LastSpotsCTABadge()
                                .zIndex(1)
                        }
                        Button(check.isBlocking ? "Requisiti" : (event.isFull ? "Entra in lista d'attesa" : "Partecipa")) {
                            if !store.isAuthenticated {
                                showAuth = true
                            } else if check.isBlocking || check.hasWarnings {
                                showAccessWarning = true
                            } else {
                                requestApprovalOverride = false
                                showCheckout = true
                            }
                        }
                        .buttonStyle(PrimaryButtonStyle(width: 170))
                    }
                }
            }
            .padding(.horizontal, 18)
            .padding(.top, 10)
            .padding(.bottom, 8)
        }
        .background(.thinMaterial)
    }

    private func detailMetrics(for event: Event) -> [DetailMetric] {
        var metrics: [DetailMetric] = []
        if let distance = event.distance?.nilIfBlank {
            metrics.append(DetailMetric(title: distance, subtitle: "Distanza", icon: "point.topleft.down.curvedto.point.bottomright.up"))
        }
        if let elevation = event.elevation?.nilIfBlank {
            metrics.append(DetailMetric(title: elevation, subtitle: "Dislivello", icon: "mountain.2"))
        }
        if let duration = event.duration?.nilIfBlank {
            metrics.append(DetailMetric(title: duration, subtitle: "Durata", icon: "clock"))
        }
        metrics.append(DetailMetric(title: event.shouldShowPublicCapacity ? "\(activeParticipantCount)/\(event.spotsTotal ?? 0)" : "Sold out", subtitle: "Posti", icon: "person.2"))
        return metrics
    }

    private func canViewMeetingPoints(for event: Event) -> Bool {
        store.isAuthenticated && (registration != nil || store.session?.user.id == event.organizerId || store.isAdmin)
    }

    private func continueRegistration(_ registration: Registration, event: Event) async {
        guard !paymentLoading else { return }
        paymentLoading = true
        defer { paymentLoading = false }

        if let pendingCheckout = store.pendingCheckout(for: registration, event: event) {
            activeCheckout = ActiveCheckout(
                url: pendingCheckout.checkoutURL,
                sessionId: pendingCheckout.sessionId,
                kind: .eventPayment,
                eventId: event.id,
                registrationId: registration.id
            )
            return
        }

        if registration.waitlistSpotAvailable(in: event), !registration.requiresOnlinePayment(in: event) {
            if await store.completeWaitlistBooking(for: registration) {
                feedback = AppFeedback(title: "Prenotazione completata", message: "Il posto è tuo. Abbiamo aggiornato i tuoi eventi.", icon: "checkmark.seal.fill", tone: .success)
            }
            return
        }

        if let result = await store.resumeCheckout(for: registration, event: event) {
            if result.free {
                feedback = AppFeedback(title: "Prenotazione completata", message: "Abbiamo aggiornato i tuoi eventi.", icon: "checkmark.seal.fill", tone: .success)
            } else if let url = result.url {
                activeCheckout = ActiveCheckout(url: url, sessionId: result.sessionId, kind: result.kind, eventId: event.id, registrationId: registration.id)
            }
        }
    }

    private func resumeActionTitle(for registration: Registration, event: Event, pendingCheckout: PendingPayment?) -> String {
        guard pendingCheckout != nil else { return registration.resumeActionTitle(in: event) }
        if registration.normalizedStatus == "deposit_paid" || registration.paymentStatus == "deposit_paid" {
            return "Completa il saldo"
        }
        if registration.waitlistSpotAvailable(in: event) {
            return registration.requiresOnlinePayment(in: event) ? "Completa prenotazione" : "Conferma il posto"
        }
        return registration.resumeActionTitle(in: event)
    }

    private func toggleSaved(_ event: Event) async {
        guard store.isAuthenticated else {
            showAuth = true
            return
        }
        guard !savingEvent else { return }
        savingEvent = true
        await store.toggleSave(eventId: event.id)
        savingEvent = false
    }

    private func toggleOpeningReminder(_ event: Event) async {
        guard store.isAuthenticated else {
            showAuth = true
            return
        }
        guard !togglingOpeningReminder else { return }
        let wasActive = isOpeningReminderActive
        togglingOpeningReminder = true
        defer { togglingOpeningReminder = false }

        if !wasActive {
            guard await preparePushNotificationsForOpeningReminder() else { return }
        }

        let success = await store.toggleEventOpeningReminder(eventId: event.id)
        guard success else { return }

        feedback = AppFeedback(
            title: wasActive ? "Avviso disattivato" : "Avviso attivo",
            message: wasActive
                ? "Non riceverai la notifica quando apriremo le iscrizioni."
                : "Ti avviseremo appena apriremo le iscrizioni.",
            icon: wasActive ? "bell.slash.fill" : "bell.badge.fill",
            tone: .success
        )
    }

    private func preparePushNotificationsForOpeningReminder() async -> Bool {
        guard let session = store.session else { return false }

        await pushNotifications.refreshAuthorizationStatus()

        switch pushNotifications.authorizationStatus {
        case .notDetermined:
            await pushNotifications.requestPermissionAndRegister(session: session)
            await pushNotifications.refreshAuthorizationStatus()
        case .denied:
            openNotificationSettingsForReminder()
            return false
        case .authorized, .provisional, .ephemeral:
            if pushNotifications.isPushActive {
                await pushNotifications.syncIfPossible(session: session)
                return true
            }
            await pushNotifications.requestPermissionAndRegister(session: session)
            await pushNotifications.refreshAuthorizationStatus()
        @unknown default:
            feedback = AppFeedback(
                title: "Notifiche non disponibili",
                message: "Controlla le impostazioni di notifica del dispositivo e riprova.",
                icon: "bell.slash.fill",
                tone: .warning
            )
            return false
        }

        if pushNotifications.authorizationStatus == .denied {
            openNotificationSettingsForReminder()
            return false
        }

        guard pushNotifications.isPushActive else {
            feedback = AppFeedback(
                title: "Notifiche non attive",
                message: "Per ricevere l'avviso quando apriamo le iscrizioni, abilita le notifiche dell'app.",
                icon: "bell.slash.fill",
                tone: .warning
            )
            return false
        }

        await pushNotifications.syncIfPossible(session: session)
        return true
    }

    private func openNotificationSettingsForReminder() {
        pushNotifications.openAppSettings()
        feedback = AppFeedback(
            title: "Notifiche bloccate",
            message: "Abilita le notifiche dalle Impostazioni di iOS, poi torna qui per attivare l'avviso.",
            icon: "bell.slash.fill",
            tone: .warning
        )
    }

    private func shareItems(for event: Event) -> [Any] {
        var items: [Any] = ["\(event.title)\n\(formatLongDate(event.date))"]
        if let url = event.webURL { items.append(url) }
        return items
    }

    private func openInitialParticipantsIfNeeded() {
        guard openParticipantsOnAppear, !didOpenInitialParticipants else { return }
        didOpenInitialParticipants = true
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            showParticipants = true
        }
    }

    private func presentDirectionsOptions(for destination: String) {
        guard let destination = destination.nilIfBlank else { return }
        directionsDestination = destination
        showDirectionsOptions = true
    }

    private func openDirections(to destination: String, using app: DirectionsApp) {
        guard let encoded = encodedDirectionsDestination(destination),
              let fallbackURL = app.fallbackURL(encodedDestination: encoded) else { return }
        let appURL = app.nativeURL(encodedDestination: encoded)
        let url = appURL.flatMap { UIApplication.shared.canOpenURL($0) == true ? $0 : nil } ?? fallbackURL
        UIApplication.shared.open(url)
    }

    private func encodedDirectionsDestination(_ destination: String) -> String? {
        var allowedCharacters = CharacterSet.urlQueryAllowed
        allowedCharacters.remove(charactersIn: "?&=+")
        return destination.nilIfBlank?.addingPercentEncoding(withAllowedCharacters: allowedCharacters)
    }

}

struct RegistrationEditHintCard: View {
    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            Label("Vuoi modificare la tua iscrizione?", systemImage: "square.and.pencil")
                .font(.caption.weight(.bold))
                .foregroundStyle(Brand.foreground)
            Text("Per cambiare meeting point o altre preferenze, vai su My events e gestisci la tua partecipazione da lì.")
                .font(.caption)
                .foregroundStyle(Brand.mutedForeground)
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(12)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 14))
        .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.muted.opacity(0.5), lineWidth: 1))
    }
}

struct DetailMetric: Identifiable {
    let id = UUID()
    let title: String
    let subtitle: String
    let icon: String
}

private enum DirectionsApp: CaseIterable, Identifiable {
    case appleMaps
    case googleMaps
    case waze

    var id: Self { self }

    var title: String {
        switch self {
        case .appleMaps: return "Apple Maps"
        case .googleMaps: return "Google Maps"
        case .waze: return "Waze"
        }
    }

    func nativeURL(encodedDestination: String) -> URL? {
        switch self {
        case .appleMaps:
            return fallbackURL(encodedDestination: encodedDestination)
        case .googleMaps:
            return URL(string: "comgooglemaps://?daddr=\(encodedDestination)&directionsmode=driving")
        case .waze:
            return URL(string: "waze://?q=\(encodedDestination)&navigate=yes")
        }
    }

    func fallbackURL(encodedDestination: String) -> URL? {
        switch self {
        case .appleMaps:
            return URL(string: "https://maps.apple.com/?daddr=\(encodedDestination)")
        case .googleMaps:
            return URL(string: "https://www.google.com/maps/dir/?api=1&destination=\(encodedDestination)&travelmode=driving")
        case .waze:
            return URL(string: "https://waze.com/ul?q=\(encodedDestination)&navigate=yes")
        }
    }
}

struct EventPillsRow: View {
    @EnvironmentObject private var store: AppStore
    let event: Event

    var body: some View {
        HStack(spacing: 8) {
            CompactEventPill(text: categoryLabel(event.category), color: Brand.muted, foreground: Brand.mutedForeground)

            if let difficulty = event.difficultyLabel {
                CompactEventPill(text: difficulty.text, color: difficulty.background, foreground: difficulty.foreground)
            }

            if shouldShowStatusPill {
                CompactEventPill(text: event.statusStyle.label, color: event.statusStyle.background, foreground: event.statusStyle.foreground)
            }

            if event.hasLastSpots {
                CompactEventPill(text: "🔥 Ultimi posti", color: Brand.destructive.opacity(0.14), foreground: Brand.destructive)
            }

            if let customBadge = event.customBadgeText {
                CompactEventPill(text: customBadge, color: Brand.accent.opacity(0.16), foreground: Brand.accent)
            }

            if event.hasEventTopBadge {
                CompactEventPill(text: "⭐ Evento Top", color: Color(hue: 38.0 / 360.0, saturation: 0.60, brightness: 0.75), foreground: Brand.foreground)
            }

            ForEach(event.manualBadgeTexts, id: \.self) { badge in
                CompactEventPill(text: badge, color: Brand.primary.opacity(0.14), foreground: Brand.primary)
            }

            if event.price == 0 {
                CompactEventPill(text: "Gratis", color: Brand.success.opacity(0.85), foreground: .white)
            }

            ForEach(EventAccessPill.pills(for: event)) { pill in
                CompactEventPill(text: pill.label, color: pill.background, foreground: pill.foreground)
            }

            if (store.isOrganizer || store.isAdmin), let visibilityPill {
                CompactEventPill(text: visibilityPill.label, color: visibilityPill.background, foreground: visibilityPill.foreground)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(.vertical, 1)
    }

    private var shouldShowStatusPill: Bool {
        event.normalizedStatus != "open" || event.isFull || event.isPastOrCancelled
    }

    private var visibilityPill: EventAccessPill? {
        switch event.visibility?.nilIfBlank?.lowercased() {
        case "private":
            EventAccessPill(label: "Privato", background: Brand.warning.opacity(0.15), foreground: Brand.warning)
        case "hidden":
            EventAccessPill(label: "Nascosto", background: Brand.foreground.opacity(0.78), foreground: .white)
        default:
            nil
        }
    }
}

struct EventAccessPill: Identifiable {
    let id = UUID()
    let label: String
    let background: Color
    let foreground: Color

    static func pills(for event: Event) -> [EventAccessPill] {
        let rules = event.accessRulesList
        guard !rules.isEmpty else { return [] }

        if let customLabel = event.accessRules?.string(at: "exclusivity_label")?.nilIfBlank, customLabel.lowercased() != "auto" {
            return [EventAccessPill(label: customLabel, background: Brand.secondary.opacity(0.14), foreground: Brand.secondary)]
        }

        let ruleTypes = Set(rules.map(\.type))
        if ruleTypes.contains("require_membership") {
            return [EventAccessPill(label: "Solo membri", background: Brand.primary.opacity(0.12), foreground: Brand.primary)]
        }

        let experienceRules: Set<String> = ["min_trekking_events", "min_attended_events", "min_activities", "min_level", "min_experience", "min_activity_frequency"]
        if !ruleTypes.isDisjoint(with: experienceRules) {
            return [EventAccessPill(label: "Esperienza richiesta", background: Brand.warning.opacity(0.14), foreground: Brand.warning)]
        }

        if ruleTypes.contains("manual_approval") {
            return [EventAccessPill(label: "Evento esclusivo", background: Brand.secondary.opacity(0.14), foreground: Brand.secondary)]
        }

        return [EventAccessPill(label: "Accesso limitato", background: Brand.primary.opacity(0.10), foreground: Brand.primary)]
    }
}

