struct WeatherForecastRow: View {
    let event: Event
    @State private var weather: WeatherDisplay?
    @State private var loaded = false

    var body: some View {
        let display = weather ?? WeatherDisplay.override(from: event.additionalFields)

        Group {
            if let display {
                InfoRow(icon: display.systemImage, title: display.title, subtitle: display.subtitle)
            } else if WeatherDisplay.shouldShowWeather(for: event.date) {
                InfoRow(icon: "cloud", title: loaded ? "Meteo in aggiornamento" : "Meteo in caricamento", subtitle: loaded ? "Previsioni non disponibili per questa località" : "")
            }
        }
        .task(id: "\(event.id)-\(event.date ?? "")-\(event.location ?? "")") {
            guard WeatherDisplay.override(from: event.additionalFields) == nil else { return }
            loaded = false
            weather = await WeatherDisplay.fetch(location: event.location, displayLocation: event.displayLocation, date: event.date)
            loaded = true
        }
    }
}

struct WeatherDisplay: Equatable {
    let title: String
    let subtitle: String
    let systemImage: String

    static func override(from fields: JSONValue?) -> WeatherDisplay? {
        guard let fields else { return nil }
        let condition = fields.string(at: "weather_override_condition")?.nilIfBlank
        let min = fields.double(at: "weather_override_temp_min")
        let max = fields.double(at: "weather_override_temp_max")
        let average = fields.double(at: "weather_override_temp_avg") ?? fields.double(at: "weather_override_temp")
        guard condition != nil || min != nil || max != nil || average != nil else { return nil }
        let label = weatherLabel(condition) ?? condition ?? "Meteo"
        return WeatherDisplay(
            title: title(condition: label, average: average, min: min, max: max),
            subtitle: subtitle(min: min, max: max),
            systemImage: icon(for: condition, code: nil)
        )
    }

    static func shouldShowWeather(for date: String?) -> Bool {
        guard let date = date?.nilIfBlank else { return false }
        return shouldFetch(date: date)
    }

    static func fetch(location: String?, displayLocation: String?, date: String?) async -> WeatherDisplay? {
        guard let location = location?.nilIfBlank, let date = date?.nilIfBlank, shouldFetch(date: date) else { return nil }
        let searchLocations = geocodingCandidates(location: location, displayLocation: displayLocation)
        for searchLocation in searchLocations {
            guard let encodedLocation = searchLocation.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed),
                  let geoURL = URL(string: "https://geocoding-api.open-meteo.com/v1/search?name=\(encodedLocation)&count=1&language=it"),
                  let (geoData, _) = try? await URLSession.shared.data(from: geoURL),
                  let geo = try? JSONDecoder().decode(OpenMeteoGeocodingResponse.self, from: geoData),
                  let place = geo.results?.first else { continue }

            let weatherURLString = "https://api.open-meteo.com/v1/forecast?latitude=\(place.latitude)&longitude=\(place.longitude)&daily=temperature_2m_max,temperature_2m_min,weathercode,precipitation_probability_max&timezone=Europe/Rome&start_date=\(date)&end_date=\(date)"
            guard let weatherURL = URL(string: weatherURLString),
                  let (weatherData, _) = try? await URLSession.shared.data(from: weatherURL),
                  let forecast = try? JSONDecoder().decode(OpenMeteoForecastResponse.self, from: weatherData),
                  forecast.daily.time.isEmpty == false else { continue }

            let code = forecast.daily.weathercode.first
            let min = forecast.daily.temperature2MMin.first
            let max = forecast.daily.temperature2MMax.first
            let label = label(for: code)
            return WeatherDisplay(title: title(condition: label, average: nil, min: min, max: max), subtitle: subtitle(min: min, max: max), systemImage: icon(for: nil, code: code))
        }
        return nil
    }

    private static func shouldFetch(date: String) -> Bool {
        guard let eventDate = DateFormatter.eventDate.date(from: date) else { return false }
        let days = Calendar.current.dateComponents([.day], from: Calendar.current.startOfDay(for: Date()), to: Calendar.current.startOfDay(for: eventDate)).day ?? 0
        return days >= 0 && days <= 14
    }

    private static func geocodingCandidates(location: String, displayLocation: String?) -> [String] {
        let parts = location.split(separator: ",").map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        var candidates: [String] = []
        if parts.count >= 2, let geoLocation = parts.last?.nilIfBlank {
            candidates.append(geoLocation)
        }
        candidates.append(location)
        if let displayLocation = displayLocation?.nilIfBlank {
            candidates.append(displayLocation)
        }
        if let first = parts.first?.nilIfBlank {
            candidates.append(first)
        }
        for part in parts.dropFirst().dropLast() {
            let cleaned = part
                .replacingOccurrences(of: #"^\d{4,5}\s*"#, with: "", options: .regularExpression)
                .replacingOccurrences(of: #"\s+[A-Z]{2}$"#, with: "", options: .regularExpression)
                .nilIfBlank
            if let cleaned, !cleaned.allSatisfy(\.isNumber) {
                candidates.append(cleaned)
            }
        }
        return candidates.removingDuplicates()
    }

    private static func weatherLabel(_ condition: String?) -> String? {
        switch condition {
        case "sereno": "Sereno"
        case "parzialmente_nuvoloso": "Parzialmente nuvoloso"
        case "nuvoloso": "Nuvoloso"
        case "pioggia_debole": "Pioggia debole"
        case "pioggia": "Pioggia"
        case "temporale": "Temporale"
        case "ventoso": "Ventoso"
        case "neve": "Neve"
        case "nebbia": "Nebbia"
        default: condition
        }
    }

    private static func label(for code: Int?) -> String {
        switch code {
        case 0: "Sereno"
        case 1: "Prevalentemente sereno"
        case 2: "Parzialmente nuvoloso"
        case 3: "Nuvoloso"
        case 45: "Nebbia"
        case 48: "Nebbia gelata"
        case 51: "Pioggerella leggera"
        case 53: "Pioggerella"
        case 55: "Pioggerella intensa"
        case 61: "Pioggia leggera"
        case 63: "Pioggia"
        case 65: "Pioggia intensa"
        case 66: "Pioggia gelata"
        case 67: "Pioggia gelata intensa"
        case 71: "Neve leggera"
        case 73: "Neve"
        case 75: "Neve intensa"
        case 77: "Granuli di neve"
        case 80: "Rovesci leggeri"
        case 81: "Rovesci"
        case 82: "Rovesci intensi"
        case 85: "Rovesci di neve"
        case 86: "Rovesci di neve intensi"
        case 95: "Temporale"
        case 96: "Temporale con grandine"
        case 99: "Temporale con grandine intensa"
        default: "Meteo"
        }
    }

    private static func icon(for condition: String?, code: Int?) -> String {
        switch condition {
        case "sereno": return "sun.max"
        case "parzialmente_nuvoloso": return "cloud.sun"
        case "nuvoloso": return "cloud"
        case "pioggia_debole", "pioggia": return "cloud.rain"
        case "temporale": return "cloud.bolt.rain"
        case "ventoso": return "wind"
        case "neve": return "snowflake"
        case "nebbia": return "cloud.fog"
        default: break
        }
        switch code {
        case 0, 1: return "sun.max"
        case 2: return "cloud.sun"
        case 3: return "cloud"
        case 45, 48: return "cloud.fog"
        case 51, 53, 55: return "cloud.drizzle"
        case 61, 63, 65, 66, 67, 80, 81, 82: return "cloud.rain"
        case 71, 73, 75, 77, 85, 86: return "snowflake"
        case 95, 96, 99: return "cloud.bolt.rain"
        default: return "cloud"
        }
    }

    private static func title(condition: String, average: Double?, min: Double?, max: Double?) -> String {
        let temp = average ?? min.flatMap { minValue in max.map { round((minValue + $0) / 2) } } ?? max
        guard let temp else { return condition }
        return "\(condition) \(Int(temp.rounded()))°"
    }

    private static func subtitle(min: Double?, max: Double?) -> String {
        let parts = [
            min.map { "Min \(Int($0.rounded()))°" },
            max.map { "Max \(Int($0.rounded()))°" }
        ].compactMap { $0 }
        return parts.joined(separator: "  ")
    }
}

struct OpenMeteoGeocodingResponse: Decodable {
    let results: [OpenMeteoPlace]?
}

struct OpenMeteoPlace: Decodable {
    let latitude: Double
    let longitude: Double
}

struct OpenMeteoForecastResponse: Decodable {
    let daily: OpenMeteoDaily
}

struct OpenMeteoDaily: Decodable {
    let time: [String]
    let temperature2MMax: [Double]
    let temperature2MMin: [Double]
    let weathercode: [Int]

    enum CodingKeys: String, CodingKey {
        case time
        case temperature2MMax = "temperature_2m_max"
        case temperature2MMin = "temperature_2m_min"
        case weathercode
    }
}

