struct DescriptionBlock: View {
    let description: String
    @Binding var expanded: Bool
    @State private var renderedHeight: CGFloat = 1
    private let collapsedHeight: CGFloat = 168

    var body: some View {
        VStack(alignment: .leading, spacing: 9) {
            SectionTitle("L'esperienza")
            ZStack(alignment: .bottom) {
                EventDescriptionHTMLView(html: EventDescriptionHTML.cleanStoredHTML(from: description), height: $renderedHeight)
                    .frame(height: expanded ? renderedHeight : min(renderedHeight, collapsedHeight))
                    .clipped()

                if isLongDescription && !expanded {
                    LinearGradient(
                        colors: [Brand.background.opacity(0), Brand.background],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .frame(height: 46)
                    .allowsHitTesting(false)
                }
            }

            if isLongDescription {
                Button(expanded ? "Mostra meno" : "Leggi di più") {
                    withAnimation(.easeInOut(duration: 0.2)) {
                        expanded.toggle()
                    }
                }
                .font(.subheadline.weight(.bold))
                .foregroundStyle(Brand.primary)
            }
        }
    }

    private var isLongDescription: Bool {
        description.htmlPlainText.count > 520 || renderedHeight > collapsedHeight + 20
    }
}

private struct EventDescriptionHTMLView: UIViewRepresentable {
    let html: String
    @Binding var height: CGFloat

    func makeUIView(context: Context) -> WKWebView {
        let configuration = WKWebViewConfiguration()
        configuration.defaultWebpagePreferences.allowsContentJavaScript = true
        let webView = WKWebView(frame: .zero, configuration: configuration)
        webView.navigationDelegate = context.coordinator
        webView.isOpaque = false
        webView.backgroundColor = .clear
        webView.scrollView.backgroundColor = .clear
        webView.scrollView.isScrollEnabled = false
        webView.scrollView.bounces = false
        webView.scrollView.contentInset = .zero
        webView.scrollView.contentInsetAdjustmentBehavior = .never
        webView.scrollView.showsVerticalScrollIndicator = false
        webView.scrollView.showsHorizontalScrollIndicator = false
        return webView
    }

    func updateUIView(_ webView: WKWebView, context: Context) {
        let document = EventDescriptionHTML.renderDocument(for: html)
        guard context.coordinator.loadedDocument != document else { return }
        context.coordinator.loadedDocument = document
        webView.loadHTMLString(document, baseURL: nil)
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(height: $height)
    }

    final class Coordinator: NSObject, WKNavigationDelegate {
        @Binding private var height: CGFloat
        var loadedDocument = ""

        init(height: Binding<CGFloat>) {
            self._height = height
        }

        func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
            updateHeight(webView)
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.12) { [weak self, weak webView] in
                guard let webView else { return }
                self?.updateHeight(webView)
            }
        }

        @MainActor
        func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping @MainActor @Sendable (WKNavigationActionPolicy) -> Void) {
            guard navigationAction.navigationType == .linkActivated,
                  let url = navigationAction.request.url else {
                decisionHandler(.allow)
                return
            }
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
        }

        private func updateHeight(_ webView: WKWebView) {
            let script = "Math.max(document.body.scrollHeight, document.documentElement.scrollHeight, document.body.offsetHeight, document.documentElement.offsetHeight);"
            webView.evaluateJavaScript(script) { [weak self] result, _ in
                let value = (result as? NSNumber)?.doubleValue ?? result as? Double ?? 0
                let nextHeight = max(CGFloat(value).rounded(.up), 1)
                guard abs((self?.height ?? 0) - nextHeight) > 1 else { return }
                self?.height = nextHeight
            }
        }
    }
}

private enum EventDescriptionHTML {
    static let bodyFontSize: CGFloat = 16
    static let heading1FontSize: CGFloat = bodyFontSize * 1.5
    static let heading2FontSize: CGFloat = bodyFontSize * 1.25
    static let heading3FontSize: CGFloat = bodyFontSize * 1.1
    static let minFontSize: CGFloat = 12
    static let maxFontSize: CGFloat = 30
    static let fontSizeStep: CGFloat = 1

    static func cleanStoredHTML(from source: String) -> String {
        let trimmed = source.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return ""
        }

        if trimmed.containsHTMLMarkup {
            return sanitizeRawHTML(trimmed).nilIfBlank ?? markdownHTML(from: trimmed.htmlPlainText)
        }

        return markdownHTML(from: trimmed)
    }

    static func attributedStringForEditing(from source: String) -> NSMutableAttributedString {
        let cleanHTML = cleanStoredHTML(from: source)
        let document = editorDocument(for: cleanHTML)
        guard let data = document.data(using: .utf8),
              let attributed = try? NSMutableAttributedString(
                data: data,
                options: [
                    .documentType: NSAttributedString.DocumentType.html,
                    .characterEncoding: String.Encoding.utf8.rawValue
                ],
                documentAttributes: nil
              ) else {
            return NSMutableAttributedString(string: source.htmlStripped, attributes: editorTypingAttributes())
        }

        normalizeForEditing(attributed)
        trim(attributed)
        return attributed
    }

    static func cleanHTML(from attributedString: NSAttributedString) -> String {
        let text = attributedString.string.replacingOccurrences(of: "\u{FFFC}", with: "")
        guard text.nilIfBlank != nil else { return "" }

        let fullText = text as NSString
        var position = 0
        var parts: [String] = []
        var openList: String?

        func closeList() {
            if let openList {
                parts.append("</\(openList)>")
            }
            openList = nil
        }

        func hasNonBlankText(after location: Int) -> Bool {
            guard location < fullText.length else { return false }
            let remainingRange = NSRange(location: location, length: fullText.length - location)
            return fullText
                .substring(with: remainingRange)
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .nilIfBlank != nil
        }

        while position < fullText.length {
            let paragraphRange = fullText.paragraphRange(for: NSRange(location: position, length: 0))
            defer { position = paragraphRange.location + paragraphRange.length }
            let paragraph = trimmedAttributedSubstring(from: attributedString, range: paragraphRange)
            let plain = paragraph.string.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !plain.isEmpty else {
                closeList()
                if !parts.isEmpty, hasNonBlankText(after: NSMaxRange(paragraphRange)) {
                    parts.append("<p><br></p>")
                }
                continue
            }

            if let listInfo = listInfo(for: paragraph) {
                if openList != listInfo.tag {
                    closeList()
                    parts.append("<\(listInfo.tag)>")
                    openList = listInfo.tag
                }
                parts.append("<li>\(inlineHTML(from: listInfo.content))</li>")
                continue
            }

            closeList()
            parts.append("<p>\(inlineHTML(from: paragraph))</p>")
        }

        closeList()
        return sanitizeRawHTML(parts.joined(separator: "\n"))
    }

    static func cleanHTMLFromPasteboard(_ pasteboard: UIPasteboard) -> String? {
        for item in pasteboard.items {
            for (type, value) in item {
                let lowercasedType = type.lowercased()
                if lowercasedType.contains("html") {
                    if let html = value as? String {
                        return cleanStoredHTML(from: html)
                    }
                    if let data = value as? Data, let html = string(fromHTMLData: data) {
                        return cleanStoredHTML(from: html)
                    }
                }
            }
        }

        for item in pasteboard.items {
            for (type, value) in item where type.lowercased().contains("rtf") {
                guard let data = value as? Data,
                      let attributed = try? NSAttributedString(
                        data: data,
                        options: [.documentType: NSAttributedString.DocumentType.rtf],
                        documentAttributes: nil
                      ) else { continue }
                return cleanHTML(from: attributed)
            }
        }

        if let plainText = pasteboard.string?.nilIfBlank {
            return cleanStoredHTML(from: plainText)
        }

        return nil
    }

    static func editorTypingAttributes() -> [NSAttributedString.Key: Any] {
        let paragraphStyle = NSMutableParagraphStyle()
        paragraphStyle.lineSpacing = 5
        paragraphStyle.paragraphSpacing = 14
        return [
            .font: UIFont.systemFont(ofSize: bodyFontSize, weight: .regular),
            .foregroundColor: UIColor(Brand.inputForeground),
            .paragraphStyle: paragraphStyle
        ]
    }

    static func cssPixels(_ value: CGFloat) -> String {
        let rounded = (Double(value) * 10).rounded() / 10
        if rounded.rounded() == rounded {
            return "\(Int(rounded))px"
        }
        return "\(rounded)px"
    }

    static func renderDocument(for html: String) -> String {
        let body = html.nilIfBlank ?? "<p>Nessuna descrizione disponibile</p>"
        return """
        <!doctype html>
        <html>
        <head>
        <meta charset="utf-8">
        <meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover">
        <style>
        :root { color-scheme: light dark; }
        html, body { margin: 0; padding: 0; background: transparent; }
        body {
          color: #15281F;
          font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "Helvetica Neue", Arial, sans-serif;
          font-size: \(Self.cssPixels(bodyFontSize));
          line-height: 1.55;
          -webkit-font-smoothing: antialiased;
          overflow-wrap: anywhere;
        }
        h1 {
          font-size: \(Self.cssPixels(heading1FontSize));
          font-weight: 800;
          line-height: 1.2;
          margin: 0.8em 0 0.4em;
        }
        h2 {
          font-size: \(Self.cssPixels(heading2FontSize));
          font-weight: 800;
          line-height: 1.25;
          margin: 0.7em 0 0.3em;
        }
        h3 {
          font-size: \(Self.cssPixels(heading3FontSize));
          font-weight: 700;
          line-height: 1.35;
          margin: 0.6em 0 0.2em;
        }
        p {
          margin: 0.5em 0;
          line-height: 1.55;
        }
        ul, ol {
          margin: 8px 0 18px;
          padding-left: 20px;
        }
        li {
          line-height: 1.5;
          margin: 0 0 8px;
          padding-left: 2px;
        }
        strong, b { font-weight: 800; }
        em, i { font-style: italic; }
        a {
          color: #224E38;
          font-weight: 700;
          text-decoration-thickness: 1px;
          text-underline-offset: 3px;
        }
        blockquote {
          margin: 18px 0;
          padding: 4px 0 4px 16px;
          border-left: 3px solid #DAD5C9;
          color: #657064;
        }
        hr {
          border: 0;
          border-top: 1px solid #DAD5C9;
          margin: 22px 0;
        }
        img {
          display: block;
          max-width: 100%;
          height: auto;
          border-radius: 18px;
          margin: 18px 0;
        }
        h1:first-child, h2:first-child, h3:first-child, p:first-child, ul:first-child, ol:first-child, blockquote:first-child, img:first-child { margin-top: 0; }
        p:last-child, ul:last-child, ol:last-child, li:last-child, blockquote:last-child, img:last-child { margin-bottom: 0; }
        @media (prefers-color-scheme: dark) {
          body { color: #EBE7E0; }
          a { color: #64B48C; }
          blockquote { color: #B8B0A4; border-left-color: #47443F; }
          hr { border-top-color: #47443F; }
        }
        </style>
        </head>
        <body>\(body)</body>
        </html>
        """
    }

    private static func editorDocument(for html: String) -> String {
        """
        <html>
        <head>
        <meta charset="utf-8">
        <style>
        body {
          font-family: -apple-system;
          font-size: \(Self.cssPixels(bodyFontSize));
          line-height: 1.45;
          margin: 0;
          color: #15281F;
        }
        h1 { font-size: \(Self.cssPixels(heading1FontSize)); font-weight: 800; line-height: 1.2; margin: 0.8em 0 0.4em; }
        h2 { font-size: \(Self.cssPixels(heading2FontSize)); font-weight: 800; line-height: 1.25; margin: 0.7em 0 0.3em; }
        h3 { font-size: \(Self.cssPixels(heading3FontSize)); font-weight: 700; line-height: 1.35; margin: 0.6em 0 0.2em; }
        p { margin: 0.5em 0; }
        ul, ol { margin: 8px 0 14px 20px; padding: 0; }
        li { margin: 0 0 6px; }
        </style>
        </head>
        <body>\(html)</body>
        </html>
        """
    }

    private static func normalizeForEditing(_ attributed: NSMutableAttributedString) {
        let fullRange = NSRange(location: 0, length: attributed.length)
        guard fullRange.length > 0 else { return }
        attributed.enumerateAttribute(.font, in: fullRange) { value, range, _ in
            let currentFont = value as? UIFont ?? UIFont.systemFont(ofSize: bodyFontSize)
            let pointSize = normalizedFontSize(currentFont.pointSize)
            var traits = UIFontDescriptor.SymbolicTraits()
            if currentFont.fontDescriptor.symbolicTraits.contains(.traitBold) {
                traits.insert(.traitBold)
            }
            if currentFont.fontDescriptor.symbolicTraits.contains(.traitItalic) {
                traits.insert(.traitItalic)
            }

            let baseFont = UIFont.systemFont(ofSize: pointSize)
            let styledDescriptor = baseFont.fontDescriptor.withSymbolicTraits(traits) ?? baseFont.fontDescriptor
            attributed.addAttribute(.font, value: UIFont(descriptor: styledDescriptor, size: pointSize), range: range)
        }
        attributed.removeAttribute(.foregroundColor, range: fullRange)
        attributed.removeAttribute(.backgroundColor, range: fullRange)
        attributed.addAttribute(.foregroundColor, value: UIColor(Brand.inputForeground), range: fullRange)
    }

    private static func normalizedFontSize(_ value: CGFloat) -> CGFloat {
        if abs(value - bodyFontSize) < 0.75 { return bodyFontSize }
        return min(max((value * 2).rounded() / 2, minFontSize), maxFontSize)
    }

    private static func sanitizeRawHTML(_ source: String) -> String {
        var html = source
            .replacingOccurrences(of: "\r\n", with: "\n")
            .replacingOccurrences(of: "\r", with: "\n")
            .replacingOccurrences(of: "&nbsp;", with: " ")
            .replacingOccurrences(of: "\u{200B}", with: "")

        html = html.replacingOccurrences(of: #"(?is)<!--.*?-->"#, with: "", options: .regularExpression)
        html = html.replacingOccurrences(of: #"(?is)<(script|style|head|meta|link|xml)[^>]*>.*?</\1>"#, with: "", options: .regularExpression)

        guard let regex = try? NSRegularExpression(pattern: #"<\s*(/?)\s*([a-zA-Z0-9]+)([^>]*)>"#) else {
            return html.htmlStripped.nilIfBlank.map(markdownHTML(from:)) ?? ""
        }

        let nsHTML = html as NSString
        var result = html
        let matches = regex.matches(in: html, range: NSRange(location: 0, length: nsHTML.length))
        for match in matches.reversed() {
            let slash = nsHTML.substring(with: match.range(at: 1))
            let rawTag = nsHTML.substring(with: match.range(at: 2)).lowercased()
            let attributes = nsHTML.substring(with: match.range(at: 3))
            let replacement = sanitizedTag(rawTag, slash: slash, attributes: attributes)
            guard let range = Range(match.range, in: result) else { continue }
            result.replaceSubrange(range, with: replacement)
        }

        result = result.replacingOccurrences(of: #"(?is)<p>\s*</p>"#, with: "<p><br></p>", options: .regularExpression)
            .replacingOccurrences(of: #"(?is)(<br>\s*){3,}"#, with: "<br><br>", options: .regularExpression)
            .replacingOccurrences(of: #"\n{3,}"#, with: "\n\n", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)

        return result
    }

    private static func sanitizedTag(_ rawTag: String, slash: String, attributes: String) -> String {
        let isClosing = !slash.isEmpty
        if rawTag == "img" {
            guard !isClosing, let src = srcValue(from: attributes) else { return "" }
            return "<img src=\"\(escapeAttribute(src))\">"
        }

        let mappedTag: String
        switch rawTag {
        case "b":
            mappedTag = "strong"
        case "i":
            mappedTag = "em"
        case "strike", "del":
            mappedTag = "s"
        case "div":
            mappedTag = "p"
        case "h1", "h2", "h3", "p", "strong", "em", "u", "s", "span", "ul", "ol", "li", "br", "a", "blockquote", "hr":
            mappedTag = rawTag
        case "h4", "h5", "h6":
            mappedTag = "h3"
        default:
            return ""
        }

        if mappedTag == "br" || mappedTag == "hr" {
            return isClosing ? "" : "<\(mappedTag)>"
        }

        if isClosing {
            return "</\(mappedTag)>"
        }

        if mappedTag == "a", let href = hrefValue(from: attributes) {
            return "<a href=\"\(escapeAttribute(href))\">"
        }

        if mappedTag == "span", let style = fontSizeStyle(from: attributes) {
            return "<span style=\"\(style)\">"
        }

        return "<\(mappedTag)>"
    }

    private static func hrefValue(from attributes: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: #"(?i)href\s*=\s*["']([^"']+)["']"#) else { return nil }
        let nsAttributes = attributes as NSString
        guard let match = regex.firstMatch(in: attributes, range: NSRange(location: 0, length: nsAttributes.length)),
              match.range(at: 1).location != NSNotFound else { return nil }
        let value = nsAttributes.substring(with: match.range(at: 1)).trimmingCharacters(in: .whitespacesAndNewlines)
        guard value.hasPrefix("http://") || value.hasPrefix("https://") || value.hasPrefix("mailto:") else { return nil }
        return value
    }

    private static func srcValue(from attributes: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: #"(?i)src\s*=\s*["']([^"']+)["']"#) else { return nil }
        let nsAttributes = attributes as NSString
        guard let match = regex.firstMatch(in: attributes, range: NSRange(location: 0, length: nsAttributes.length)),
              match.range(at: 1).location != NSNotFound else { return nil }
        let value = nsAttributes.substring(with: match.range(at: 1)).trimmingCharacters(in: .whitespacesAndNewlines)
        guard value.hasPrefix("http://") || value.hasPrefix("https://") else { return nil }
        return value
    }

    private static func fontSizeStyle(from attributes: String) -> String? {
        guard let styleRegex = try? NSRegularExpression(pattern: #"(?i)style\s*=\s*["']([^"']+)["']"#),
              let sizeRegex = try? NSRegularExpression(pattern: #"(?i)(?:^|;)\s*font-size\s*:\s*([0-9]+(?:\.[0-9]+)?)(px|pt|em|rem)?"#) else {
            return nil
        }
        let nsAttributes = attributes as NSString
        guard let styleMatch = styleRegex.firstMatch(in: attributes, range: NSRange(location: 0, length: nsAttributes.length)),
              styleMatch.range(at: 1).location != NSNotFound else {
            return nil
        }
        let style = nsAttributes.substring(with: styleMatch.range(at: 1))
        let nsStyle = style as NSString
        guard let sizeMatch = sizeRegex.firstMatch(in: style, range: NSRange(location: 0, length: nsStyle.length)),
              sizeMatch.range(at: 1).location != NSNotFound,
              let rawValue = Double(nsStyle.substring(with: sizeMatch.range(at: 1))) else {
            return nil
        }
        let rawUnit = sizeMatch.range(at: 2).location == NSNotFound ? "px" : nsStyle.substring(with: sizeMatch.range(at: 2)).lowercased()
        let multiplier: CGFloat = (rawUnit == "em" || rawUnit == "rem") ? bodyFontSize : 1
        let pointSize = min(max(CGFloat(rawValue) * multiplier, minFontSize), maxFontSize)
        guard abs(pointSize - bodyFontSize) >= 0.5 else { return nil }
        return "font-size: \(cssPixels(pointSize))"
    }

    private static func markdownHTML(from source: String) -> String {
        let lines = source.components(separatedBy: .newlines)
        var parts: [String] = []
        var paragraphLines: [String] = []
        var openList: String?

        func closeList() {
            if let openList {
                parts.append("</\(openList)>")
            }
            openList = nil
        }

        func flushParagraph() {
            guard !paragraphLines.isEmpty else { return }
            parts.append("<p>\(paragraphLines.map(inlineMarkdownHTML).joined(separator: "<br>"))</p>")
            paragraphLines.removeAll()
        }

        func hasNonBlankLine(after index: Int) -> Bool {
            guard index + 1 < lines.count else { return false }
            return lines[(index + 1)...].contains { line in
                line.trimmingCharacters(in: .whitespacesAndNewlines).nilIfBlank != nil
            }
        }

        for (index, rawLine) in lines.enumerated() {
            let line = rawLine.trimmingCharacters(in: .whitespaces)
            guard !line.isEmpty else {
                flushParagraph()
                closeList()
                if !parts.isEmpty, hasNonBlankLine(after: index) {
                    parts.append("<p><br></p>")
                }
                continue
            }

            if line.hasPrefix("### ") {
                flushParagraph()
                closeList()
                parts.append("<h3>\(inlineMarkdownHTML(String(line.dropFirst(4))))</h3>")
            } else if line.hasPrefix("## ") {
                flushParagraph()
                closeList()
                parts.append("<h2>\(inlineMarkdownHTML(String(line.dropFirst(3))))</h2>")
            } else if line.hasPrefix("# ") {
                flushParagraph()
                closeList()
                parts.append("<h1>\(inlineMarkdownHTML(String(line.dropFirst(2))))</h1>")
            } else if let bullet = plainListItem(line) {
                flushParagraph()
                if openList != bullet.tag {
                    closeList()
                    parts.append("<\(bullet.tag)>")
                    openList = bullet.tag
                }
                parts.append("<li>\(inlineMarkdownHTML(bullet.text))</li>")
            } else {
                paragraphLines.append(line)
            }
        }

        flushParagraph()
        closeList()
        return parts.joined(separator: "\n")
    }

    private static func plainListItem(_ line: String) -> (tag: String, text: String)? {
        if line.hasPrefix("- ") || line.hasPrefix("* ") || line.hasPrefix("• ") {
            return ("ul", String(line.dropFirst(2)).trimmingCharacters(in: .whitespaces))
        }
        guard let regex = try? NSRegularExpression(pattern: #"^\d+[\.)]\s+(.+)$"#) else { return nil }
        let nsLine = line as NSString
        guard let match = regex.firstMatch(in: line, range: NSRange(location: 0, length: nsLine.length)),
              match.range(at: 1).location != NSNotFound else { return nil }
        return ("ol", nsLine.substring(with: match.range(at: 1)).trimmingCharacters(in: .whitespaces))
    }

    private static func inlineMarkdownHTML(_ string: String) -> String {
        escapedHTML(string)
            .replacingOccurrences(of: #"(?s)\*\*(.+?)\*\*"#, with: "<strong>$1</strong>", options: .regularExpression)
            .replacingOccurrences(of: #"(?s)__(.+?)__"#, with: "<strong>$1</strong>", options: .regularExpression)
            .replacingOccurrences(of: #"(?s)(?<!\*)\*(?!\s)(.+?)(?<!\s)\*(?!\*)"#, with: "<em>$1</em>", options: .regularExpression)
    }

    private static func listInfo(for attributed: NSAttributedString) -> (tag: String, content: NSAttributedString)? {
        let plain = attributed.string.trimmingCharacters(in: .whitespacesAndNewlines)
        let nsPlain = plain as NSString
        let patterns: [(tag: String, pattern: String)] = [
            ("ul", #"^\s*(?:•|-|\*)\s+(.+)$"#),
            ("ol", #"^\s*\d+[\.)]\s+(.+)$"#)
        ]

        for entry in patterns {
            guard let regex = try? NSRegularExpression(pattern: entry.pattern),
                  let match = regex.firstMatch(in: plain, range: NSRange(location: 0, length: nsPlain.length)),
                  match.range(at: 1).location != NSNotFound else { continue }
            let prefixLength = match.range(at: 1).location
            let original = attributed.string as NSString
            let contentRange = NSRange(location: min(prefixLength, original.length), length: max(original.length - prefixLength, 0))
            return (entry.tag, attributed.attributedSubstring(from: contentRange))
        }

        return nil
    }

    private static func trimmedAttributedSubstring(from attributed: NSAttributedString, range: NSRange) -> NSAttributedString {
        let clippedRange = NSRange(
            location: max(0, min(range.location, attributed.length)),
            length: max(0, min(range.length, attributed.length - max(0, min(range.location, attributed.length))))
        )
        guard clippedRange.length > 0 else { return NSAttributedString(string: "") }
        let substring = attributed.attributedSubstring(from: clippedRange)
        let text = substring.string as NSString
        var start = 0
        var end = text.length
        while start < end {
            let scalar = text.substring(with: NSRange(location: start, length: 1)).unicodeScalars.first
            if let scalar, CharacterSet.whitespacesAndNewlines.contains(scalar) {
                start += 1
            } else {
                break
            }
        }
        while end > start {
            let scalar = text.substring(with: NSRange(location: end - 1, length: 1)).unicodeScalars.first
            if let scalar, CharacterSet.whitespacesAndNewlines.contains(scalar) {
                end -= 1
            } else {
                break
            }
        }
        guard end > start else { return NSAttributedString(string: "") }
        return substring.attributedSubstring(from: NSRange(location: start, length: end - start))
    }

    private static func inlineHTML(from attributed: NSAttributedString, suppressBold: Bool = false, suppressFontSize: Bool = false) -> String {
        let range = NSRange(location: 0, length: attributed.length)
        guard range.length > 0 else { return "" }
        var output = ""
        attributed.enumerateAttributes(in: range) { attributes, currentRange, _ in
            let text = (attributed.string as NSString).substring(with: currentRange)
            var fragment = escapedHTML(text).replacingOccurrences(of: "\n", with: "<br>")
            var wrappers: [(open: String, close: String)] = []
            if let link = attributes[.link] {
                let urlString = (link as? URL)?.absoluteString ?? String(describing: link)
                wrappers.append(("<a href=\"\(escapeAttribute(urlString))\">", "</a>"))
            }
            if let font = attributes[.font] as? UIFont {
                let pointSize = normalizedFontSize(font.pointSize)
                if !suppressFontSize, abs(pointSize - bodyFontSize) >= 0.5 {
                    wrappers.append(("<span style=\"font-size: \(cssPixels(pointSize))\">", "</span>"))
                }
                let traits = font.fontDescriptor.symbolicTraits
                if traits.contains(.traitBold), !suppressBold {
                    wrappers.append(("<strong>", "</strong>"))
                }
                if traits.contains(.traitItalic) {
                    wrappers.append(("<em>", "</em>"))
                }
            }
            if attributes[.underlineStyle] != nil {
                wrappers.append(("<u>", "</u>"))
            }
            if attributes[.strikethroughStyle] != nil {
                wrappers.append(("<s>", "</s>"))
            }

            for wrapper in wrappers {
                fragment = wrapper.open + fragment + wrapper.close
            }
            output += fragment
        }
        return output
    }

    private static func trim(_ attributed: NSMutableAttributedString) {
        while let first = attributed.string.unicodeScalars.first,
              CharacterSet.whitespacesAndNewlines.contains(first) {
            attributed.deleteCharacters(in: NSRange(location: 0, length: 1))
        }
        while let last = attributed.string.unicodeScalars.last,
              CharacterSet.whitespacesAndNewlines.contains(last) {
            attributed.deleteCharacters(in: NSRange(location: attributed.length - 1, length: 1))
        }
    }

    private static func escapedHTML(_ string: String) -> String {
        string
            .replacingOccurrences(of: "&", with: "&amp;")
            .replacingOccurrences(of: "<", with: "&lt;")
            .replacingOccurrences(of: ">", with: "&gt;")
            .replacingOccurrences(of: "\"", with: "&quot;")
            .replacingOccurrences(of: "'", with: "&#39;")
    }

    private static func escapeAttribute(_ string: String) -> String {
        escapedHTML(string)
    }

    private static func string(fromHTMLData data: Data) -> String? {
        String(data: data, encoding: .utf8)
            ?? String(data: data, encoding: .utf16)
            ?? String(data: data, encoding: .isoLatin1)
    }
}

struct GalleryViewer: View {
    @Environment(\.dismiss) private var dismiss
    let images: [String]
    @Binding var selectedIndex: Int
    @State private var visibleIndex: Int?

    var body: some View {
        GeometryReader { proxy in
            ZStack(alignment: .topTrailing) {
                Color.black.ignoresSafeArea()

                if !images.isEmpty {
                    ScrollView(.horizontal) {
                        LazyHStack(spacing: 0) {
                            ForEach(Array(images.enumerated()), id: \.offset) { index, url in
                                RemoteImage(urlString: url, contentMode: .fit)
                                    .frame(width: proxy.size.width, height: proxy.size.height)
                                    .id(index)
                            }
                        }
                        .scrollTargetLayout()
                    }
                    .scrollIndicators(.hidden)
                    .scrollTargetBehavior(.paging)
                    .scrollPosition(id: $visibleIndex)
                    .onAppear {
                        let initialIndex = clampedIndex(selectedIndex)
                        selectedIndex = initialIndex
                        visibleIndex = initialIndex
                    }
                    .onChange(of: visibleIndex) { _, index in
                        guard let index else { return }
                        selectedIndex = clampedIndex(index)
                    }
                    .onChange(of: selectedIndex) { _, index in
                        let nextIndex = clampedIndex(index)
                        if visibleIndex != nextIndex {
                            visibleIndex = nextIndex
                        }
                    }
                }

                Button {
                    dismiss()
                } label: {
                    Image(systemName: "xmark")
                        .font(.headline.weight(.bold))
                        .foregroundStyle(.white)
                        .frame(width: 42, height: 42)
                        .background(.white.opacity(0.16), in: Circle())
                }
                .padding(.top, 54)
                .padding(.trailing, 18)
            }
        }
        .ignoresSafeArea()
    }

    private func clampedIndex(_ index: Int) -> Int {
        guard !images.isEmpty else { return 0 }
        return min(max(index, 0), images.count - 1)
    }
}

struct GalleryPreviewImage: View {
    let urlString: String?
    @State private var phase: RemoteImageLoadPhase = .idle

    private let previewHeight: CGFloat = 152
    private let minPreviewWidth: CGFloat = 92
    private let maxPreviewWidth: CGFloat = 228

    var body: some View {
        ZStack {
            Brand.muted
            content
        }
        .frame(width: previewWidth, height: previewHeight)
        .clipShape(RoundedRectangle(cornerRadius: 14))
        .task(id: imageURL?.absoluteString ?? urlString ?? "") {
            await loadImage()
        }
    }

    @ViewBuilder
    private var content: some View {
        switch phase {
        case .idle, .loading:
            ProgressView()
                .tint(Brand.primary)
        case .success(let image):
            Image(uiImage: image)
                .resizable()
                .aspectRatio(contentMode: .fit)
                .frame(width: previewWidth, height: previewHeight)
        case .failure:
            Image(systemName: "photo")
                .font(.title2)
                .foregroundStyle(Brand.mutedForeground)
        }
    }

    private var previewWidth: CGFloat {
        guard case .success(let image) = phase,
              image.size.width > 0,
              image.size.height > 0 else {
            return 152
        }
        let aspectRatio = image.size.width / image.size.height
        return min(max(previewHeight * aspectRatio, minPreviewWidth), maxPreviewWidth)
    }

    private var imageURL: URL? {
        SupabaseImageTransform.url(from: urlString, maxWidth: 900, quality: 78)
    }

    @MainActor
    private func loadImage() async {
        guard let imageURL else {
            phase = .failure
            return
        }

        if let cachedImage = RemoteImageStore.shared.cachedImage(for: imageURL) {
            phase = .success(cachedImage)
            return
        }

        phase = .loading
        do {
            let image = try await RemoteImageStore.shared.image(for: imageURL)
            guard !Task.isCancelled else { return }
            phase = .success(image)
        } catch is CancellationError {
            return
        } catch {
            guard !Task.isCancelled else { return }
            phase = .failure
        }
    }
}

