        CancellationPolicyInfo(raw: event.cancellationPolicy)
    }

    private var closingSentence: String {
        event.additionalFields?.string(at: "closing_sentence")?.normalizedClosingSentence.nilIfBlank ?? deterministicClosingSentence(seed: event.id)
    }

    private var rules: [(icon: String, text: String)] {
        if event.paymentType == "free" || event.price ?? 0 == 0 {
            return [
                ("checkmark", "Puoi disdire in qualsiasi momento direttamente dall'app"),
                ("warning", "Se non puoi più venire, libera il posto il prima possibile"),
                ("waitlist", "I posti liberati vengono assegnati alla lista d'attesa"),
                ("xmark", "Chi non si presenta senza disdire potrà avere limitazioni sugli eventi futuri"),
                ("heart", "Qui si viene per stare bene: rispetto per il gruppo prima di tutto"),
                ("sparkles", closingSentence)
            ]
        }
        if policy.isFlexible {
            return [
                ("checkmark", "Se dobbiamo annullare noi, ti rimborsiamo tutto senza stress"),
                ("checkmark", "Se cambi idea, puoi disdire fino a \(policy.requiredHours ?? 24)h prima dell'evento"),
                ("info", "In questo caso riceverai il rimborso dell'importo versato, escluso il costo del servizio di 1€"),
                ("heart", "Qui si viene per stare bene: rispetto, puntualità e voglia di condividere"),
                ("sparkles", closingSentence)
            ]
        }
        return [
            ("checkmark", "Se dobbiamo annullare noi, ti rimborsiamo tutto senza stress"),
            ("xmark", "Questo evento non è rimborsabile in caso di cancellazione"),
            ("info", "Organizziamo tutto in anticipo per garantire l'esperienza"),
            ("heart", "Qui si viene per stare bene: rispetto, puntualità e voglia di condividere"),
            ("sparkles", closingSentence)
        ]
    }
}

