struct CancellationPolicyInfo {
    let type: String

    init(raw: String?) {
        let normalized = raw?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? ""
        if ["moderate", "moderata", "flexible_48h"].contains(normalized) {
            type = "flexible_48h"
        } else if ["strict", "rigida", "non_refundable"].contains(normalized) || normalized.hasPrefix("custom:") {
            type = "non_refundable"
        } else {
            type = "flexible_24h"
        }
    }

    var isFlexible: Bool { type != "non_refundable" }
    var requiredHours: Int? { type == "flexible_48h" ? 48 : (type == "flexible_24h" ? 24 : nil) }
    var title: String {
        switch type {
        case "flexible_48h": return "Flessibile 48h"
        case "non_refundable": return "Non rimborsabile"
        default: return "Flessibile 24h"
        }
    }

    var description: String {
        if let requiredHours {
            return "Rimborso completo fino a \(requiredHours) ore prima dell'evento, escluso il costo del servizio di 1€."
        }
        return "Nessun rimborso in caso di cancellazione del partecipante."
    }

    var shortInfoLabel: String? {
        guard let requiredHours else { return nil }
        return "Rimborso disponibile fino a \(requiredHours)h prima"
    }

    func isRefundEligible(for event: Event) -> Bool {
        guard let requiredHours, let startDate = event.calendarStartDate else { return false }
        let hoursUntilEvent = startDate.timeIntervalSinceNow / 3600
        return hoursUntilEvent >= Double(requiredHours)
    }
}

