    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let event: Event
    var requestApprovalOverride = false
    let onComplete: (CheckoutResult) -> Void
    @State private var selectedMeetingPointId: String?
    @State private var selectedPriceOptionId: String?
    @State private var equipmentConfirmed = false
    @State private var discountCode = ""
    @State private var appliedDiscount: DiscountCode?
    @State private var validatingDiscount = false
    @State private var discountMessage: String?
    @State private var paymentChoice = "deposit"
    @State private var carAvailability = ""
    @State private var sportLevel = ""
    @State private var customResponses: [String: String] = [:]
    @State private var submitting = false
    @State private var attemptedSubmit = false
    @State private var showMembershipProfileEditor = false
    @State private var membershipProfileEditorFocus: ProfileEditInitialFocus?
    @State private var promoNow = Date()

    var priceEligibilityContext: PriceEligibilityContext {
        PriceEligibilityContext(profile: store.profile, badges: store.badges, registrations: store.myEvents)
    }

    var customFields: [CheckoutCustomField] {
        event.checkoutCustomFields
    }

    var eligiblePriceOptions: [PriceOption] {
        event.priceOptions.available(for: priceEligibilityContext)
    }

    var singlePriceOption: PriceOption? {
        eligiblePriceOptions.count == 1 ? eligiblePriceOptions[0] : nil
    }

    var selectedPriceOption: PriceOption? {
        guard let selectedPriceOptionId else { return nil }
        return eligiblePriceOptions.first { $0.id == selectedPriceOptionId }
    }

    var selectedPaymentType: String {
        selectedPriceOption?.effectivePaymentType(fallback: event) ?? event.paymentType ?? "free"
    }

    var selectedRequiresOnlinePayment: Bool {
        selectedPriceOption?.requiresOnlinePayment(fallback: event) ?? event.requiresOnlinePayment
    }

    var selectedOptionIsWaitlist: Bool {
        guard let selectedPriceOption else { return event.isFull }
        return selectedPriceOption.canJoinWaitlist(in: event)
    }

    var selectedOptionIsUnavailable: Bool {
        guard let selectedPriceOption else { return false }
        return !selectedPriceOption.isBookable(in: event) && !selectedPriceOption.canJoinWaitlist(in: event)
    }

    var selectedPrice: Double {
        if let selectedPriceOption {
            return selectedPriceOption.totalPrice(fallback: event)
        }
        return event.price ?? 0
    }

    var todayAmount: Double {
        if selectedOptionIsWaitlist { return 0 }
        if selectedPaymentType == "deposit" && paymentChoice == "deposit" {
            return selectedPriceOption?.effectiveDepositAmount(fallback: event) ?? event.deposit ?? 0
        }
        if selectedPaymentType == "free" || selectedPaymentType == "location" { return 0 }
        return selectedPrice
    }

    var discountAmount: Double {
        appliedDiscount?.discountAmount(for: todayAmount) ?? 0
    }

    var totalDueToday: Double {
        max(0, todayAmount - discountAmount) + serviceFee
    }

    var serviceFee: Double {
        selectedRequiresOnlinePayment && !selectedOptionIsWaitlist && appliedDiscount?.waivesServiceFee != true ? 1 : 0
    }

    var hasMandatoryEquipment: Bool {
        event.equipmentItems.contains { $0.isMandatory == true }
    }

    var hasParticipationDetails: Bool {
        !event.meetingPoints.isEmpty || event.asksCarAvailability || event.isSportCategory || !customFields.isEmpty || hasMandatoryEquipment
    }

    var hasIncompleteRequiredCustomFields: Bool {
        customFields.contains { field in
            field.required && customResponses[field.label]?.nilIfBlank == nil
        }
    }

    var shouldRequestApproval: Bool {
        requestApprovalOverride || event.requiresManualApproval
    }

    var sportLevelOptions: [(value: String, label: String)] {
        [
            ("Beginner", "Principiante"),
            ("Intermediate", "Intermedio"),
            ("Advanced", "Avanzato")
        ]
    }

    var canUseDiscount: Bool {
        !selectedOptionIsWaitlist && selectedRequiresOnlinePayment && selectedPrice > 0
    }

    var hasUnappliedDiscountCode: Bool {
        canUseDiscount && discountCode.nilIfBlank != nil && appliedDiscount == nil
    }

    var missingCheckoutMessage: String? {
        if !event.meetingPoints.isEmpty && selectedMeetingPointId == nil { return "Scegli un punto di ritrovo per continuare." }
        if !eligiblePriceOptions.isEmpty && selectedPriceOptionId == nil { return "Scegli una formula di partecipazione." }
        if hasIncompleteRequiredCustomFields { return "Completa i campi obbligatori evidenziati." }
        if hasMandatoryEquipment && !equipmentConfirmed { return "Conferma l'attrezzatura obbligatoria per completare l'iscrizione." }
        if hasUnappliedDiscountCode { return "Applica o rimuovi il codice sconto prima di continuare." }
        return nil
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 24) {
                    VStack(alignment: .leading, spacing: 8) {
                        Text("Completa l'iscrizione a \(event.title)")
                            .font(.system(.title2, design: .rounded, weight: .bold))
                        Text("Seleziona le opzioni richieste e controlla il riepilogo prima di procedere al pagamento.")
                            .font(.subheadline)
                            .foregroundStyle(Brand.mutedForeground)
                    }

                    if !event.acceptsRegistrations {
                        HStack(spacing: 10) {
                            Image(systemName: "lock.fill")
                            Text(event.registrationUnavailableMessage)
                                .font(.subheadline.weight(.semibold))
                        }
                        .foregroundStyle(Brand.mutedForeground)
                        .padding()
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .background(Brand.muted, in: RoundedRectangle(cornerRadius: 16))
                    }

                    participationSection

                    Divider()

                    priceAndMembershipSection

                    Divider()

                    summarySection

                    Button {
                        if missingCheckoutMessage != nil {
                            attemptedSubmit = true
                            return
                        }
                        Task {
                            guard ensureMembershipProfileDataIfNeeded() else { return }
                            submitting = true
                            let input = RegistrationInput(
                                meetingPointId: selectedMeetingPointId,
                                priceOptionId: selectedPriceOptionId,
                                asWaitlist: selectedOptionIsWaitlist,
                                carAvailability: event.asksCarAvailability ? carAvailability.nilIfBlank : nil,
                                sportLevel: event.isSportCategory ? sportLevel.nilIfBlank : nil,
                                additionalResponses: customResponses,
                                requestApproval: shouldRequestApproval,
                                discountCodeId: selectedOptionIsWaitlist ? nil : appliedDiscount?.id,
                                paymentChoice: paymentChoice
                            )
                            if let result = await store.register(event: event, input: input) {
                                onComplete(result)
                                dismiss()
                            }
                            submitting = false
                        }
                    } label: {
                        HStack(spacing: 8) {
                            if submitting {
                                ProgressView()
                                    .tint(.white)
                            }
                            Text(submitting ? "Prepariamo il checkout..." : ctaTitle)
                        }
                    }
                    .buttonStyle(PrimaryButtonStyle())
                    .disabled(submitting || !event.acceptsRegistrations || selectedOptionIsUnavailable)
                    if attemptedSubmit, let missingCheckoutMessage {
                        Text(missingCheckoutMessage)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.destructive)
                            .frame(maxWidth: .infinity, alignment: .leading)
                    }
                }
                .padding(20)
            }
            .background(Brand.background)
            .disabled(submitting)
            .overlay {
                if submitting {
                    CheckoutProgressOverlay()
                }
            }
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Chiudi") { dismiss() }
                        .disabled(submitting)
                }
            }
            .onAppear {
                promoNow = Date()
                selectDefaultPriceOptionIfNeeded()
            }
            .onReceive(Timer.publish(every: 60, on: .main, in: .common).autoconnect()) { now in
                promoNow = now
            }
            .sheet(isPresented: $showMembershipProfileEditor, onDismiss: {
                membershipProfileEditorFocus = nil
            }) {
                if let profile = store.profile {
                    ProfileEditSheet(profile: profile, initialFocus: membershipProfileEditorFocus)
                        .presentationDetents([.fraction(0.86), .large])
                        .presentationDragIndicator(.hidden)
                }
            }
        }
    }

    @ViewBuilder
    private var participationSection: some View {
        if hasParticipationDetails {
            VStack(alignment: .leading, spacing: 14) {
                CheckoutSectionTitle("Dettagli partecipazione")

                if !event.meetingPoints.isEmpty {
                    Text("Punto di Ritrovo *")
                        .font(.headline.weight(.bold))
                        .foregroundStyle(Brand.foreground)

                    VStack(spacing: 10) {
                        ForEach(event.meetingPoints) { point in
                            CheckoutMeetingPointRow(
                                point: point,
                                selected: selectedMeetingPointId == point.id
                            ) {
                                selectedMeetingPointId = point.id
                            }
                        }
                    }
                    if attemptedSubmit && selectedMeetingPointId == nil {
                        Text("Scegli un punto di ritrovo per continuare.")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.destructive)
                    }
                }

                ForEach(customFields) { field in
                    CheckoutCustomFieldView(field: field, responses: $customResponses)
                }

                if event.asksCarAvailability {
                    carAvailabilitySection
                }

                if event.isSportCategory {
                    sportLevelSection
                }

                if hasMandatoryEquipment {
                    equipmentConfirmationRow
                }
            }
        }
    }

    private var carAvailabilitySection: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Saresti disposto a prendere la macchina?")
                .font(.headline.weight(.bold))
                .foregroundStyle(Brand.foreground)
            SelectionRow(selected: carAvailability == "yes", title: "Si", subtitle: "Posso mettere a disposizione l'auto.", trailing: "") {
                carAvailability = "yes"
            }
            SelectionRow(selected: carAvailability == "prefer_not", title: "Preferirei di no", subtitle: "Posso valutare se necessario.", trailing: "") {
                carAvailability = "prefer_not"
            }
            SelectionRow(selected: carAvailability == "no_car", title: "Non sono automunito", subtitle: "Partecipo senza auto.", trailing: "") {
                carAvailability = "no_car"
            }
        }
    }

    private var sportLevelSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Livello sportivo")
                .font(.headline.weight(.bold))
                .foregroundStyle(Brand.foreground)

            HStack(spacing: 8) {
                ForEach(sportLevelOptions, id: \.value) { option in
                    Button {
                        sportLevel = sportLevel == option.value ? "" : option.value
                    } label: {
                        Text(option.label)
                            .font(.caption.weight(.bold))
                            .foregroundStyle(sportLevel == option.value ? .white : Brand.primary)
                            .padding(.horizontal, 12)
                            .frame(height: 34)
                            .background(sportLevel == option.value ? Brand.primary : Brand.primary.opacity(0.08), in: Capsule())
                    }
                    .buttonStyle(.plain)
                }
            }

            HStack(spacing: 10) {
                Image(systemName: "figure.run")
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(Brand.inputMutedForeground)
                TextField("Oppure inserisci il livello personalizzato", text: Binding(
                    get: {
                        sportLevelOptions.contains { $0.value == sportLevel } ? "" : sportLevel
                    },
                    set: { sportLevel = $0 }
                ))
                .foregroundStyle(Brand.inputForeground)
                .tint(Brand.primary)
            }
            .padding(.horizontal, 12)
            .frame(height: 46)
            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
        }
    }

    @ViewBuilder
    private var equipmentConfirmationRow: some View {
        Button {
            equipmentConfirmed.toggle()
        } label: {
            HStack(alignment: .top, spacing: 12) {
                Image(systemName: equipmentConfirmed ? "checkmark.circle.fill" : "circle")
                    .font(.body)
                    .foregroundStyle(equipmentConfirmed ? Brand.primary : Brand.primary.opacity(0.78))
                Text("Confermo di avere tutta l'attrezzatura obbligatoria richiesta per questa attività")
                    .font(.subheadline.weight(.medium))
                    .foregroundStyle(Brand.foreground)
                    .multilineTextAlignment(.leading)
                    .fixedSize(horizontal: false, vertical: true)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
            .padding()
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Color.yellow.opacity(0.08), in: RoundedRectangle(cornerRadius: 16))
            .overlay(
                RoundedRectangle(cornerRadius: 16)
                    .stroke(attemptedSubmit && !equipmentConfirmed ? Brand.destructive : Color.yellow.opacity(0.55), lineWidth: attemptedSubmit && !equipmentConfirmed ? 2 : 1)
            )
        }
        .buttonStyle(.plain)
        if attemptedSubmit && !equipmentConfirmed {
            Text("Conferma l'attrezzatura obbligatoria per continuare.")
                .font(.caption.weight(.semibold))
                .foregroundStyle(Brand.destructive)
        }
    }

    private var priceAndMembershipSection: some View {
        VStack(alignment: .leading, spacing: 14) {
            CheckoutSectionTitle("Prezzo e tessera")

            if let singlePriceOption {
                CheckoutSinglePriceOptionRow(option: singlePriceOption, event: event, now: promoNow)
            } else if !eligiblePriceOptions.isEmpty {
                Text("Scegli la formula *")
                    .font(.headline.weight(.bold))
                    .foregroundStyle(Brand.foreground)

                VStack(spacing: 10) {
                    ForEach(eligiblePriceOptions) { option in
                        CheckoutPriceOptionRow(
                            option: option,
                            selected: selectedPriceOptionId == option.id,
                            event: event,
                            now: promoNow
                        ) {
                            guard option.isBookable(in: event, now: promoNow) || option.canJoinWaitlist(in: event, now: promoNow) else { return }
                            selectedPriceOptionId = option.id
                            appliedDiscount = nil
                            discountMessage = nil
                            paymentChoice = "deposit"
                        }
                    }
                }
                if attemptedSubmit && selectedPriceOptionId == nil {
                    Text("Scegli una formula di partecipazione.")
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(Brand.destructive)
                }
            }

            membershipStatusCard

            if canUseDiscount {
                couponSection
            }

            paymentChoiceSection
        }
    }

    @ViewBuilder
    private var membershipStatusCard: some View {
        if let profile = store.profile, profile.hasActiveMembership {
            HStack(spacing: 12) {
                Image(systemName: "checkmark.shield.fill")
                    .font(.title3.weight(.semibold))
                    .foregroundStyle(Brand.success)
                    .frame(width: 28)
                VStack(alignment: .leading, spacing: 3) {
                    Text("Tessera attiva")
                        .font(.headline.weight(.bold))
                        .foregroundStyle(Brand.success)
                    Text("Valida fino al \(profile.membershipExpiryShortSlashes)")
                        .font(.subheadline.weight(.medium))
                        .foregroundStyle(Brand.success.opacity(0.82))
                }
                Spacer(minLength: 0)
            }
            .padding()
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Brand.success.opacity(0.08), in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.success.opacity(0.28), lineWidth: 1))
        } else if let profile = store.profile, !profile.hasCompleteMembershipProfile {
            VStack(alignment: .leading, spacing: 12) {
                HStack(alignment: .top, spacing: 12) {
                    Image(systemName: "person.text.rectangle")
                        .font(.title3.weight(.semibold))
                        .foregroundStyle(Brand.warning)
                        .frame(width: 28)
                    VStack(alignment: .leading, spacing: 5) {
                        Text("Completa i dati tessera")
                            .font(.headline.weight(.bold))
                            .foregroundStyle(Brand.foreground)
                        Text("Mancano: \(profile.missingMembershipFieldLabels.joined(separator: ", ")).")
                            .font(.caption.weight(.medium))
                            .foregroundStyle(Brand.mutedForeground)
                            .fixedSize(horizontal: false, vertical: true)
                    }
                }

                Button {
                    membershipProfileEditorFocus = profile.isMissingMembershipSex ? .membershipSex : .membership
                    showMembershipProfileEditor = true
                } label: {
                    Label("Completa dati profilo", systemImage: "pencil")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(CheckoutSecondaryButtonStyle(height: 42))
            }
            .padding()
            .frame(maxWidth: .infinity, alignment: .leading)
            .background(Brand.warning.opacity(0.10), in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.warning.opacity(0.30), lineWidth: 1))
        } else {
            Text("La tessera verrà aggiunta al checkout se richiesta.")
                .font(.subheadline)
                .foregroundStyle(Brand.warning)
                .padding()
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(Brand.warning.opacity(0.10), in: RoundedRectangle(cornerRadius: 16))
        }
    }

    private var couponSection: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text("Hai un codice sconto?")
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(Brand.mutedForeground)

            HStack(spacing: 10) {
                HStack(spacing: 10) {
                    Image(systemName: "ticket")
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(Brand.inputMutedForeground)
                    TextField("Codice sconto", text: $discountCode)
                        .textInputAutocapitalization(.characters)
                        .autocorrectionDisabled()
                        .foregroundStyle(Brand.inputForeground)
                        .tint(Brand.primary)
                }
                .padding(.horizontal, 12)
                .frame(height: 46)
                .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
                .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))

                Button {
                    if appliedDiscount == nil {
                        Task { await applyDiscountCode() }
                    } else {
                        removeDiscountCode()
                    }
                } label: {
                    if validatingDiscount {
                        ProgressView()
                            .controlSize(.small)
                            .tint(Brand.primary)
                            .frame(width: 58)
                    } else {
                        Text(appliedDiscount == nil ? "Applica" : "Rimuovi")
                            .font(.subheadline.weight(.semibold))
                            .frame(width: 58)
                    }
                }
                .buttonStyle(CheckoutSecondaryButtonStyle(width: 94, height: 46))
                .disabled(validatingDiscount || (appliedDiscount == nil && discountCode.nilIfBlank == nil))
            }

            if let appliedDiscount {
                HStack(spacing: 8) {
                    Image(systemName: "checkmark.seal.fill")
                    Text("Coupon applicato: \(appliedDiscount.displayDescription)")
                }
                .font(.caption.weight(.semibold))
                .foregroundStyle(Brand.success)
            } else if let discountMessage {
                Text(discountMessage)
                    .font(.caption)
                    .foregroundStyle(Brand.destructive)
            }
        }
        .onChange(of: discountCode) { _, value in
            let normalized = value.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if normalized != appliedDiscount?.code.uppercased() {
                appliedDiscount = nil
            }
            discountMessage = nil
        }
    }

    @ViewBuilder
    private var paymentChoiceSection: some View {
        if selectedPaymentType == "deposit", !selectedOptionIsWaitlist {
            VStack(alignment: .leading, spacing: 10) {
                Text("Come vuoi pagare?")
                    .font(.headline.weight(.bold))
                    .foregroundStyle(Brand.foreground)
                SelectionRow(selected: paymentChoice == "deposit", title: "Paga acconto", subtitle: "Oggi paghi €\(money(selectedPriceOption?.effectiveDepositAmount(fallback: event) ?? event.deposit ?? 0)). Restano €\(money(balanceDueAfterToday)).", trailing: "") {
                    paymentChoice = "deposit"
                }
                if (selectedPriceOption?.effectiveBalancePaymentMode(fallback: event) ?? event.balancePaymentMode ?? "online") != "on_site" {
                    SelectionRow(selected: paymentChoice == "full", title: "Paga tutto", subtitle: "Completa l'intero pagamento ora.", trailing: "") {
                        paymentChoice = "full"
                    }
                }
            }
        }
    }

    private var summarySection: some View {
        VStack(alignment: .leading, spacing: 14) {
            CheckoutSectionTitle("Riepilogo")

            if shouldRequestApproval {
                CheckoutSummaryCard(title: "Approvazione richiesta", tone: .warning) {
                    SummaryRow("Stato iniziale", "Da approvare")
                    SummaryRow("Pagamento oggi", "€0", bold: true)
                }
            } else if selectedOptionIsWaitlist {
                CheckoutSummaryCard(title: "Lista d'attesa", tone: .warning) {
                    SummaryRow("Pagamento oggi", "€0", bold: true)
                    SummaryRow("Formula", selectedPriceOption?.displayName ?? "Partecipazione")
                }
            } else {
                CheckoutSummaryCard(title: "Da pagare oggi") {
                    SummaryRow(todayLineTitle, "€\(money(todayAmount))")
                    if discountAmount > 0 {
                        SummaryRow("Sconto", "-€\(money(discountAmount))")
                    }
                    if serviceFee > 0 {
                        SummaryRow("Costo del servizio", "€\(money(serviceFee))")
                    }
                    Divider()
                    SummaryRow("Totale da pagare oggi", "€\(money(totalDueToday))", bold: true)
                }
            }

            if selectedPaymentType == "deposit", paymentChoice == "deposit", !selectedOptionIsWaitlist {
                CheckoutSummaryCard(title: "Da pagare dopo", tone: .warning) {
                    SummaryRow("Saldo evento", "€\(money(balanceDueAfterToday))")
                }
            }

            CheckoutCancellationPolicyCard(policy: CancellationPolicyInfo(raw: event.cancellationPolicy))

            if selectedPaymentType == "deposit", paymentChoice == "deposit", !selectedOptionIsWaitlist {
                Text((selectedPriceOption?.effectiveBalancePaymentMode(fallback: event) ?? event.balancePaymentMode ?? "online") == "on_site" ? "Pagherai l'acconto online ora. Il saldo rimanente andrà versato sul posto." : "Pagherai l'acconto online ora. Potrai completare il saldo online quando previsto.")
                    .font(.caption.weight(.medium))
                    .foregroundStyle(Brand.mutedForeground)
                    .multilineTextAlignment(.center)
                    .frame(maxWidth: .infinity)
            }

            if let ctaHelperText {
                Text(ctaHelperText)
                    .font(.caption.weight(.medium))
                    .foregroundStyle(Brand.mutedForeground)
                    .multilineTextAlignment(.center)
                    .frame(maxWidth: .infinity)
            }
        }
    }

    private var ctaTitle: String {
        if !event.acceptsRegistrations { return "Iscrizioni chiuse" }
        if selectedOptionIsUnavailable { return "Formula sold out" }
        if shouldRequestApproval { return "Invia richiesta di iscrizione" }
        if selectedOptionIsWaitlist { return "Entra in lista d'attesa" }
        if selectedPaymentType == "deposit" { return paymentChoice == "full" ? "Paga tutto e iscriviti" : "Paga acconto e iscriviti" }
        if selectedRequiresOnlinePayment || store.profile?.hasActiveMembership != true { return "Paga e completa l'iscrizione" }
        return "Conferma iscrizione"
    }

    private var ctaHelperText: String? {
        if shouldRequestApproval { return "La richiesta verra inviata agli organizzatori per l'approvazione." }
        if selectedOptionIsWaitlist { return "Entrerai in lista d'attesa: nessun pagamento viene avviato ora." }
        if selectedPaymentType == "deposit", paymentChoice == "deposit" { return nil }
        if selectedRequiresOnlinePayment || store.profile?.hasActiveMembership != true { return "Verrai reindirizzato al pagamento sicuro per completare l'iscrizione." }
        return "L'iscrizione verra confermata subito."
    }

    private var needsMembershipProfileData: Bool {
        store.profile?.hasActiveMembership != true && !selectedOptionIsWaitlist
    }

    private func ensureMembershipProfileDataIfNeeded() -> Bool {
        guard needsMembershipProfileData,
              let profile = store.profile,
              !profile.hasCompleteMembershipProfile else {
            return true
        }
        membershipProfileEditorFocus = profile.isMissingMembershipSex ? .membershipSex : .membership
        showMembershipProfileEditor = true
        return false
    }

    private func selectDefaultPriceOptionIfNeeded() {
        if let selectedPriceOptionId, eligiblePriceOptions.contains(where: { $0.id == selectedPriceOptionId }) {
            return
        }
        selectedPriceOptionId = eligiblePriceOptions.first(where: { $0.isBookable(in: event) })?.id
            ?? eligiblePriceOptions.first(where: { $0.canJoinWaitlist(in: event) })?.id
            ?? eligiblePriceOptions.first?.id
    }

    private var todayLineTitle: String {
        selectedPaymentType == "deposit" && paymentChoice == "deposit" ? "Acconto evento" : "Evento"
    }

    private var balanceDueAfterToday: Double {
        max(0, selectedPrice - (selectedPriceOption?.effectiveDepositAmount(fallback: event) ?? event.deposit ?? 0))
    }

    private func applyDiscountCode() async {
        let code = discountCode.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !code.isEmpty else {
            discountMessage = "Inserisci un codice sconto."
            return
        }
        validatingDiscount = true
        defer { validatingDiscount = false }

        if let discount = await store.resolveDiscountCode(code, eventId: event.id) {
            appliedDiscount = discount
            discountCode = discount.code
            discountMessage = nil
        } else {
            appliedDiscount = nil
            discountMessage = "Codice non valido o non applicabile."
        }
    }

    private func removeDiscountCode() {
        appliedDiscount = nil
        discountCode = ""
        discountMessage = nil
    }
}

struct CheckoutCustomFieldView: View {
    let field: CheckoutCustomField
    @Binding var responses: [String: String]

    private var value: Binding<String> {
        Binding {
            responses[field.label] ?? ""
        } set: { newValue in
            responses[field.label] = newValue
        }
    }

    private var displayLabel: String {
        field.required ? "\(field.label) *" : field.label
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            Text(displayLabel)
                .font(.headline.weight(.bold))
                .foregroundStyle(Brand.foreground)

            if field.type == "dropdown" || field.type == "select" {
                dropdownField
            } else {
                textInputField
                    .keyboardType(field.type == "number" ? .decimalPad : .default)
            }
        }
    }

    private var textInputField: some View {
        HStack(spacing: 10) {
            Image(systemName: field.type == "number" ? "number" : "text.cursor")
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(Brand.inputMutedForeground)
            TextField(field.placeholder.nilIfBlank ?? field.label, text: value)
                .foregroundStyle(Brand.inputForeground)
                .tint(Brand.primary)
        }
        .padding(.horizontal, 12)
        .frame(height: 46)
        .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
        .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
    }

    private var dropdownField: some View {
        Menu {
            ForEach(field.options, id: \.self) { option in
                Button(option) {
                    responses[field.label] = option
                }
            }
        } label: {
            HStack(spacing: 10) {
                Image(systemName: "chevron.up.chevron.down")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(Brand.inputMutedForeground)
                Text(responses[field.label]?.nilIfBlank ?? "Seleziona...")
                    .font(.subheadline.weight(.medium))
                    .foregroundStyle(responses[field.label]?.nilIfBlank == nil ? Brand.inputMutedForeground : Brand.inputForeground)
                    .frame(maxWidth: .infinity, alignment: .leading)
                Image(systemName: "chevron.down")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(Brand.inputMutedForeground)
            }
            .padding(.horizontal, 12)
            .frame(height: 46)
            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
        }
        .buttonStyle(.plain)
        .disabled(field.options.isEmpty)
    }
}

