struct CheckoutPriceOptionRow: View {
    let option: PriceOption
    let selected: Bool
    let event: Event
    let now: Date
    let action: () -> Void

    private var price: Double {
        option.totalPrice(fallback: event)
    }

    private var isFree: Bool {
        option.effectivePaymentType(fallback: event) == "free"
    }

    private var priceLabel: String {
        isFree ? "Gratis" : "€\(money(price))"
    }

    private var isDisabled: Bool {
        !option.isBookable(in: event, now: now) && !option.canJoinWaitlist(in: event, now: now)
    }

    private var showsPromoBadge: Bool {
        option.showsPromoBadge(now: now)
    }

    private var promoIsActive: Bool {
        option.hasActivePromo(now: now)
    }

    private var selectionStroke: Color {
        selected && promoIsActive ? Brand.warning : (selected ? Brand.primary.opacity(0.35) : Brand.muted.opacity(0.72))
    }

    var body: some View {
        Button(action: action) {
            HStack(alignment: .center, spacing: 12) {
                Image(systemName: selected ? "largecircle.fill.circle" : "circle")
                    .font(.title3)
                    .foregroundStyle(isDisabled ? Brand.mutedForeground : (promoIsActive ? Brand.warning : Brand.primary))

                VStack(alignment: .leading, spacing: 5) {
                    if showsPromoBadge {
                        PromoOptionLabel(text: option.promoBadgeCountdownText(now: now))
                    }

                    HStack(spacing: 8) {
                        Text(option.displayName)
                            .font(.subheadline.weight(.bold))
                            .foregroundStyle(isDisabled ? Brand.mutedForeground : Brand.foreground)
                            .lineLimit(2)
                    }

                    if !option.detailText.isEmpty, !showsPromoBadge {
                        Text(option.detailText)
                            .font(.caption.weight(.medium))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    if !isFree {
                        Text(option.paymentSummary(in: event))
                            .font(.caption.weight(.medium))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    Label(option.availabilityText(in: event, now: now), systemImage: option.isBookable(in: event, now: now) ? "person.2" : (option.canJoinWaitlist(in: event, now: now) ? "list.bullet" : "xmark.circle"))
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(option.isBookable(in: event, now: now) ? Brand.success : (option.canJoinWaitlist(in: event, now: now) ? Brand.warning : Brand.destructive))
                }

                Spacer(minLength: 8)

                VStack(alignment: .trailing, spacing: 3) {
                    if let originalPrice = option.originalPrice, originalPrice > price {
                        Text("€\(money(originalPrice))")
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.mutedForeground)
                            .strikethrough(true, color: Brand.mutedForeground)
                    }
                    Text(priceLabel)
                        .font(.headline.weight(.bold))
                        .foregroundStyle(isDisabled ? Brand.mutedForeground : (promoIsActive ? Brand.warning : Brand.primary))
                }
            }
            .padding()
            .background(selected ? Brand.primary.opacity(0.05) : (isDisabled ? Brand.muted.opacity(0.45) : Brand.card), in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(selectionStroke, lineWidth: 1.2))
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
    }
}

