struct CancelRegistrationSheet: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let event: Event
    let registration: Registration?
    @Binding var feedback: AppFeedback?
    @State private var isCancelling = false

    var body: some View {
        VStack(spacing: 18) {
            Image(systemName: "calendar.badge.minus")
                .font(.system(size: 38, weight: .semibold))
                .foregroundStyle(Brand.destructive)
                .frame(width: 72, height: 72)
                .background(Brand.destructive.opacity(0.10), in: Circle())

            VStack(spacing: 8) {
                Text("Annullare l'iscrizione?")
                    .font(.system(.title3, design: .rounded, weight: .bold))
                    .foregroundStyle(Brand.foreground)
                Text(event.title)
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(Brand.foreground)
                    .multilineTextAlignment(.center)
                Text(cancellationDialogMessage)
                    .font(.caption)
                    .foregroundStyle(Brand.mutedForeground)
                    .multilineTextAlignment(.center)
                    .padding(.horizontal, 4)
                Text("Aggiorniamo subito i tuoi eventi appena l'operazione è conclusa.")
                    .font(.subheadline)
                    .foregroundStyle(Brand.mutedForeground)
                    .multilineTextAlignment(.center)
            }

            VStack(spacing: 10) {
                Button {
                    Task { await cancel() }
                } label: {
                    HStack(spacing: 8) {
                        if isCancelling {
                            ProgressView()
                                .tint(.white)
                        }
                        Text(isCancelling ? "Annullamento..." : "Annulla iscrizione")
                    }
                }
                .buttonStyle(DestructiveButtonStyle())
                .disabled(isCancelling)

                Button("Tieni iscrizione") { dismiss() }
                    .buttonStyle(SecondaryButtonStyle())
                    .disabled(isCancelling)
            }
        }
        .padding(24)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Brand.background)
        .interactiveDismissDisabled(isCancelling)
    }

    private var cancellationDialogMessage: String {
        guard let registration else {
            return CancellationPolicyInfo(raw: event.cancellationPolicy).description
        }
        return registration.cancellationDialogMessage(for: event)
    }

    private func cancel() async {
        isCancelling = true
        if await store.cancelRegistration(eventId: event.id) {
            feedback = AppFeedback(title: "Iscrizione annullata", message: "Abbiamo aggiornato i tuoi eventi.", icon: "checkmark.circle.fill", tone: .success)
            dismiss()
        }
        isCancelling = false
    }
}

// MARK: - My Events

struct MyEventsView: View {
    @EnvironmentObject private var store: AppStore
    @Binding var showAuth: Bool
    @Binding var routedEvent: EventNavigationTarget?
    @State private var tab = 0
    @State private var selectedEvent: Event?
    @State private var presentedRoutedEvent: EventNavigationTarget?

    var latestRegistrations: [Registration] {
        store.myEvents.latestPerEvent()
    }

    var upcoming: [Registration] {
        latestRegistrations.filter { $0.isActive && !($0.event?.isPastOrCancelled ?? false) }
    }

    var past: [Registration] {
        latestRegistrations.filter { $0.isActive && ($0.event?.isPastOrCancelled ?? false) }
    }

    var body: some View {
        NavigationStack {
            ZStack {
                Brand.background.ignoresSafeArea()
                Group {
                    if !store.isAuthenticated {
                        SignedOutPrompt(title: "My events", message: "Accedi per visualizzare iscrizioni e salvati.", showAuth: $showAuth)
                    } else {
                        GeometryReader { proxy in
                            ScrollView {
                                VStack(alignment: .leading, spacing: 16) {
                                    HStack(spacing: 10) {
                                        Image(systemName: AppTab.events.systemImage)
                                            .foregroundStyle(Brand.primary)
                                        Text("My events")
                                    }
                                    .font(.system(.title, design: .rounded, weight: .bold))
                                    Picker("Vista", selection: $tab) {
                                        Text("Prossimi (\(upcoming.count))").tag(0)
                                        Text("Passati (\(past.count))").tag(1)
                                        Text("Salvati (\(store.savedEvents.count))").tag(2)
                                    }
                                    .pickerStyle(.segmented)

                                    if tab == 0 {
                                        EventRegistrationList(
                                            registrations: upcoming,
                                            selectedEvent: $selectedEvent,
                                            showActions: true,
                                            emptyTitle: "Nessun evento in programma",
                                            emptyMessage: "Non hai ancora iscrizioni future.",
                                            emptyActionTitle: "Scopri eventi"
                                        ) {
                                            store.homeDiscoveryRequest = HomeDiscoveryRequest()
                                        }
                                    } else if tab == 1 {
                                        EventRegistrationList(
                                            registrations: past,
                                            selectedEvent: $selectedEvent,
                                            isPast: true,
                                            emptyTitle: "Nessun evento passato",
                                            emptyMessage: "Qui troverai gli eventi a cui hai partecipato."
                                        )
                                    } else {
                                        SavedEventList(savedEvents: store.savedEvents, selectedEvent: $selectedEvent)
                                    }
                                }
                                .frame(width: max(proxy.size.width - 32, 0), alignment: .leading)
                                .padding(16)
                                .padding(.bottom, 0)
                            }
                            .contentMargins(.bottom, 0, for: .scrollContent)
                        }
                    }
                }
            }
            .navigationDestination(item: $selectedEvent) { event in
                EventDetailView(eventId: event.id, showAuth: $showAuth)
            }
            .navigationDestination(item: $presentedRoutedEvent) { target in
                EventDetailView(eventId: target.eventId, showAuth: $showAuth, openParticipantsOnAppear: target.opensParticipants)
            }
            .refreshable { await store.refreshEventData() }
            .onAppear {
                openRoutedEventIfNeeded()
            }
            .onChange(of: routedEvent) { _, _ in
                openRoutedEventIfNeeded()
            }
        }
    }

    private func openRoutedEventIfNeeded() {
        guard let target = routedEvent else { return }
        presentedRoutedEvent = target
        routedEvent = nil
    }
}

struct EventRegistrationList: View {
    let registrations: [Registration]
    @Binding var selectedEvent: Event?
    var showActions = false
    var isPast = false
    var emptyTitle = "Nessun evento"
    var emptyMessage = "Quando ti iscrivi a una scampagnata la troverai qui."
    var emptyActionTitle: String?
    var emptyAction: (() -> Void)?

    init(
        registrations: [Registration],
        selectedEvent: Binding<Event?>,
        showActions: Bool = false,
        isPast: Bool = false,
        emptyTitle: String = "Nessun evento",
        emptyMessage: String = "Quando ti iscrivi a una scampagnata la troverai qui.",
        emptyActionTitle: String? = nil,
        emptyAction: (() -> Void)? = nil
    ) {
        self.registrations = registrations
        self._selectedEvent = selectedEvent
        self.showActions = showActions
        self.isPast = isPast
        self.emptyTitle = emptyTitle
        self.emptyMessage = emptyMessage
        self.emptyActionTitle = emptyActionTitle
        self.emptyAction = emptyAction
    }

    var body: some View {
        if registrations.isEmpty {
            VStack(spacing: 14) {
                EmptyState(icon: "calendar", title: emptyTitle, message: emptyMessage)
                if let emptyActionTitle, let emptyAction {
                    Button(emptyActionTitle, action: emptyAction)
                        .buttonStyle(SecondaryButtonStyle())
                        .padding(.horizontal, 12)
                }
            }
        } else {
            LazyVStack(spacing: 12) {
                ForEach(registrations) { registration in
                    EventRegistrationCard(
                        registration: registration,
                        selectedEvent: $selectedEvent,
                        showActions: showActions,
                        isPast: isPast
                    )
                }
            }
        }
    }
}

struct EventRegistrationCard: View {
    @EnvironmentObject private var store: AppStore
    let registration: Registration
    @Binding var selectedEvent: Event?
    var showActions = false
    var isPast = false
    @State private var showShare = false
    @State private var showCalendar = false
    @State private var showCancelConfirm = false
    @State private var showEdit = false
    @State private var feedback: AppFeedback?
    @State private var activeCheckout: ActiveCheckout?
    @State private var paymentLoading = false

    private var event: Event? {
        registration.event
    }

    private var shouldShowUtilityActions: Bool {
        guard showActions, !isPast, registration.normalizedStatus != "cancelled", let event else { return false }
        return !event.isPastOrCancelled
    }

    private var canCancel: Bool {
        shouldShowUtilityActions && registration.canCancel
    }

    private var canCompletePayment: Bool {
        guard shouldShowUtilityActions, let event else { return false }
        return store.pendingCheckout(for: registration, event: event) != nil || registration.canResumePayment(in: event)
    }

    private var canEditDetails: Bool {
        guard shouldShowUtilityActions, let event else { return false }
        let hasEditableFields = !event.meetingPoints.isEmpty || event.asksCarAvailability || !event.checkoutCustomFields.isEmpty || event.priceOptions.count > 1
        guard hasEditableFields else { return false }
        return event.calendarStartDate.map { $0 > Date() } ?? false
    }

    var body: some View {
        if let event {
            VStack(spacing: 0) {
                Button {
                    selectedEvent = event
                } label: {
                    HStack(spacing: 12) {
                        RemoteImage(urlString: event.cardImageUrl)
                            .frame(width: 76, height: 76)
                            .clipShape(RoundedRectangle(cornerRadius: 14))
                        VStack(alignment: .leading, spacing: 6) {
                            HStack(alignment: .top, spacing: 8) {
                                Text(event.title)
                                    .font(.subheadline.weight(.bold))
                                    .foregroundStyle(Brand.foreground)
                                    .lineLimit(2)
                                    .frame(maxWidth: .infinity, alignment: .leading)
                                let statusStyle = registration.displayStatusStyle(in: event)
                                BadgeLabel(text: registration.displayStatusLabel(in: event), color: statusStyle.background, foreground: statusStyle.foreground)
                            }
                            Label(dateTimeText(for: event), systemImage: "calendar")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(1)
                            Label(event.displayLocation, systemImage: "mappin")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(1)
                            if let meetingPoint = registration.meetingPoint {
                                Label([meetingPoint.name, meetingPoint.time.map { String($0.prefix(5)) }].compactMap { $0?.nilIfBlank }.joined(separator: " · "), systemImage: "clock")
                                    .font(.caption.weight(.medium))
                                    .foregroundStyle(Brand.secondary)
                                    .lineLimit(1)
                            }
                            if let priceLine = registration.priceOptionLine(in: event) {
                                Text(priceLine)
                                    .font(.caption2.weight(.medium))
                                    .foregroundStyle(Brand.mutedForeground)
                                    .lineLimit(1)
                            }
                            if let paymentLine = registration.paymentProgressLine {
                                Text(paymentLine)
                                    .font(.caption2)
                                    .foregroundStyle(Brand.mutedForeground)
                                    .lineLimit(1)
                            }
                        }
                    }
                    .padding(12)
                }
                .buttonStyle(.plain)

                if shouldShowUtilityActions {
                    Divider()
                        .padding(.horizontal, 12)
                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(spacing: 8) {
                            MyEventActionButton(icon: "square.and.arrow.up", title: "Condividi") {
                                showShare = true
                            }
                            MyEventActionButton(icon: "calendar.badge.plus", title: "Calendario") {
                                showCalendar = true
                            }
                            if canCompletePayment {
                                MyEventActionButton(icon: "bolt.fill", title: resumeActionTitle(for: event), tint: Brand.primary, isLoading: paymentLoading, isDisabled: paymentLoading) {
                                    Task { await resumePayment() }
                                }
                            }
                            if canEditDetails {
                                MyEventActionButton(icon: "square.and.pencil", title: "Modifica") {
                                    showEdit = true
                                }
                            }
                            Spacer(minLength: 0)
                            if canCancel {
                                MyEventActionButton(icon: "xmark", title: "Annulla", tint: Brand.destructive) {
                                    showCancelConfirm = true
                                }
                            }
                        }
                        .padding(.horizontal, 12)
                        .padding(.vertical, 10)
                    }
                }
            }
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 18))
            .clipShape(RoundedRectangle(cornerRadius: 18))
            .sheet(isPresented: $showShare) {
                ShareSheet(activityItems: shareItems(for: event))
                    .presentationDetents([.medium])
            }
            .sheet(isPresented: $showCalendar) {
                CalendarEventEditView(event: event)
            }
            .sheet(isPresented: $showCancelConfirm) {
                CancelRegistrationSheet(event: event, registration: registration, feedback: $feedback)
                    .presentationDetents([.height(360)])
            }
            .sheet(isPresented: $showEdit) {
                EditRegistrationDetailsSheet(event: event, registration: registration) {
                    feedback = AppFeedback(title: "Iscrizione aggiornata", message: "I dettagli di partecipazione sono stati salvati.", icon: "checkmark.seal.fill", tone: .success)
                }
                .presentationDetents([.large])
            }
            .sheet(item: $feedback) { feedback in
                AppFeedbackSheet(feedback: feedback)
                    .presentationDetents([.height(300)])
            }
            .fullScreenCover(item: $activeCheckout) { checkout in
                PaymentAuthenticationView(checkout: checkout) { result in
                    feedback = result
                }
            }
        }
    }

    private func shareItems(for event: Event) -> [Any] {
        var items: [Any] = ["\(event.title)\n\(formatLongDate(event.date))"]
        if let url = event.webURL { items.append(url) }
        return items
    }

    private func dateTimeText(for event: Event) -> String {
        var parts: [String] = []
        if let date = formatDate(event.date).nilIfBlank {
            parts.append(date)
        }
        if let time = event.time.map({ String($0.prefix(5)) })?.nilIfBlank {
            parts.append(time)
        }
        return parts.joined(separator: " · ")
    }

    private func resumePayment() async {
        guard !paymentLoading else { return }
        guard let event else { return }
        paymentLoading = true
        defer { paymentLoading = false }

        if let pendingCheckout = store.pendingCheckout(for: registration, event: event) {
            activeCheckout = ActiveCheckout(
                url: pendingCheckout.checkoutURL,
                sessionId: pendingCheckout.sessionId,
                kind: .eventPayment,
                eventId: event.id,
                registrationId: registration.id
            )
            return
        }

        if registration.waitlistSpotAvailable(in: event), !registration.requiresOnlinePayment(in: event) {
            if await store.completeWaitlistBooking(for: registration) {
                feedback = AppFeedback(title: "Prenotazione completata", message: "Il posto è tuo. Abbiamo aggiornato i tuoi eventi.", icon: "checkmark.seal.fill", tone: .success)
            }
            return
        }

        if let result = await store.resumeCheckout(for: registration, event: event) {
            if result.free {
                feedback = AppFeedback(title: "Prenotazione completata", message: "Abbiamo aggiornato i tuoi eventi.", icon: "checkmark.seal.fill", tone: .success)
            } else if let url = result.url {
                activeCheckout = ActiveCheckout(url: url, sessionId: result.sessionId, kind: result.kind, eventId: event.id, registrationId: registration.id)
            }
        }
    }

    private func resumeActionTitle(for event: Event) -> String {
        guard store.pendingCheckout(for: registration, event: event) != nil else {
            return registration.resumeActionTitle(in: event)
        }
        if registration.normalizedStatus == "deposit_paid" || registration.paymentStatus == "deposit_paid" {
            return "Completa il saldo"
        }
        if registration.waitlistSpotAvailable(in: event) {
            return registration.requiresOnlinePayment(in: event) ? "Completa prenotazione" : "Conferma il posto"
        }
        return registration.resumeActionTitle(in: event)
    }
}

struct EditRegistrationDetailsSheet: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let event: Event
    let registration: Registration
    let onSaved: () -> Void
    @State private var selectedMeetingPointId = ""
    @State private var selectedPriceOptionId = ""
    @State private var priceChangeQuote: RegistrationChangeQuote?
    @State private var priceChangeLoading = false
    @State private var priceChangeSubmitting = false
    @State private var carAvailability = ""
    @State private var customResponses: [String: String] = [:]
    @State private var saving = false
    @State private var activeCheckout: ActiveCheckout?
    @State private var feedback: AppFeedback?

    private var customFields: [CheckoutCustomField] {
        event.checkoutCustomFields
    }

    private var hasEditableDetailFields: Bool {
        !event.meetingPoints.isEmpty || event.asksCarAvailability || !customFields.isEmpty
    }

    private var canChangeFormula: Bool {
        event.priceOptions.count > 1 && ["registered", "paid", "deposit_paid"].contains(registration.normalizedStatus)
    }

    private var hasSelectedDifferentFormula: Bool {
        selectedPriceOptionId.nilIfBlank != nil && selectedPriceOptionId != (registration.priceOptionId ?? "")
    }

    private var hasIncompleteRequiredCustomFields: Bool {
        customFields.contains { field in
            field.required && customResponses[field.label]?.nilIfBlank == nil
        }
    }

    private var saveDisabled: Bool {
        saving || !hasEditableDetailFields || (!event.meetingPoints.isEmpty && selectedMeetingPointId.nilIfBlank == nil) || hasIncompleteRequiredCustomFields
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(alignment: .leading, spacing: 18) {
                    VStack(alignment: .leading, spacing: 6) {
                        Text("Modifica iscrizione")
                            .font(.system(.title2, design: .rounded, weight: .bold))
                            .foregroundStyle(Brand.foreground)
                        Text("Aggiorna solo i dettagli di partecipazione configurati per questo evento.")
                            .font(.subheadline)
                            .foregroundStyle(Brand.mutedForeground)
                    }

                    if !event.meetingPoints.isEmpty {
                        VStack(alignment: .leading, spacing: 10) {
                            Text("Punto di ritrovo *")
                                .font(.headline.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                            ForEach(event.meetingPoints) { point in
                                CheckoutMeetingPointRow(point: point, selected: selectedMeetingPointId == point.id) {
                                    selectedMeetingPointId = point.id
                                }
                            }
                        }
                    }

                    if event.asksCarAvailability {
                        VStack(alignment: .leading, spacing: 10) {
                            Text("Saresti disposto a prendere la macchina?")
                                .font(.headline.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                            SelectionRow(selected: carAvailability == "yes", title: "Si", subtitle: "Posso mettere a disposizione l'auto.", trailing: "") {
                                carAvailability = "yes"
                            }
                            SelectionRow(selected: carAvailability == "prefer_not", title: "Preferirei di no", subtitle: "Posso valutare se necessario.", trailing: "") {
                                carAvailability = "prefer_not"
                            }
                            SelectionRow(selected: carAvailability == "no_car", title: "Non sono automunito", subtitle: "Partecipo senza auto.", trailing: "") {
                                carAvailability = "no_car"
                            }
                        }
                    }

                    ForEach(customFields) { field in
                        CheckoutCustomFieldView(field: field, responses: $customResponses)
                    }

                    if canChangeFormula {
                        formulaChangeSection
                    }

                    Button {
                        Task { await save() }
                    } label: {
                        HStack(spacing: 8) {
                            if saving {
                                ProgressView()
                                    .tint(.white)
                            }
                            Text(saving ? "Salvataggio..." : "Salva modifiche")
                        }
                    }
                    .buttonStyle(PrimaryButtonStyle())
                    .disabled(saveDisabled)
                }
                .padding(20)
            }
            .background(Brand.background)
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button("Chiudi") { dismiss() }
                        .disabled(saving)
                }
            }
            .onAppear {
                selectedMeetingPointId = registration.meetingPointId
                    ?? registration.meetingPoint?.id
                    ?? ""
                selectedPriceOptionId = registration.priceOptionId ?? ""
                carAvailability = registration.carAvailability ?? ""
                customResponses = registration.additionalResponses ?? [:]
            }
            .fullScreenCover(item: $activeCheckout) { checkout in
                PaymentAuthenticationView(checkout: checkout) { result in
                    feedback = result
                    if result?.tone == .success {
                        onSaved()
                        dismiss()
                    }
                }
            }
            .sheet(item: $feedback) { feedback in
                AppFeedbackSheet(feedback: feedback)
                    .presentationDetents([.height(300)])
            }
            .interactiveDismissDisabled(saving)
        }
    }

    private var formulaChangeSection: some View {
        VStack(alignment: .leading, spacing: 12) {
            Text("Formula di iscrizione")
                .font(.headline.weight(.bold))
                .foregroundStyle(Brand.foreground)

            VStack(spacing: 10) {
                ForEach(event.priceOptions) { option in
                    SelectionRow(
                        selected: selectedPriceOptionId == option.id,
                        title: option.displayName,
                        subtitle: option.paymentSummary(in: event),
                        trailing: "€\(money(option.totalPrice(fallback: event)))"
                    ) {
                        selectedPriceOptionId = option.id
                        priceChangeQuote = nil
                        if option.id != (registration.priceOptionId ?? "") {
                            Task { await quoteFormulaChange(option.id) }
                        }
                    }
                }
            }

            if hasSelectedDifferentFormula {
                VStack(alignment: .leading, spacing: 8) {
                    if priceChangeLoading {
                        HStack(spacing: 8) {
                            ProgressView()
                                .controlSize(.small)
                            Text("Calcolo differenza...")
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                    } else if let priceChangeQuote {
                        SummaryRow("Prezzo attuale", "€\(money(priceChangeQuote.oldTotalAmount))")
                        SummaryRow("Nuovo prezzo", "€\(money(priceChangeQuote.newTotalAmount))")
                        if priceChangeQuote.additionalPaymentAmount > 0 {
                            SummaryRow("Saldo da pagare", "€\(money(priceChangeQuote.additionalPaymentAmount))", bold: true)
                        }
                        if priceChangeQuote.refundAmount > 0 {
                            SummaryRow("Rimborso automatico", "€\(money(priceChangeQuote.refundAmount))", bold: true)
                        }
                        if priceChangeQuote.newBalanceDueAmount > 0 {
                            SummaryRow("Saldo residuo", "€\(money(priceChangeQuote.newBalanceDueAmount))")
                        }
                        if priceChangeQuote.additionalPaymentAmount == 0 && priceChangeQuote.refundAmount == 0 {
                            Text("Nessun pagamento o rimborso immediato.")
                                .font(.caption.weight(.medium))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                    }

                    Button {
                        Task { await confirmFormulaChange() }
                    } label: {
                        HStack(spacing: 8) {
                            if priceChangeSubmitting {
                                ProgressView()
                                    .tint(.white)
                            }
                            Text(priceChangeSubmitting ? "Aggiornamento..." : "Conferma cambio formula")
                        }
                    }
                    .buttonStyle(PrimaryButtonStyle())
                    .disabled(priceChangeSubmitting || priceChangeLoading || priceChangeQuote == nil)
                }
                .padding()
                .background(Brand.muted, in: RoundedRectangle(cornerRadius: 16))
            }
        }
    }

    private func quoteFormulaChange(_ priceOptionId: String) async {
        guard !priceChangeLoading else { return }
        priceChangeLoading = true
        priceChangeQuote = await store.quoteRegistrationPriceChange(
            registrationId: registration.id,
            eventId: event.id,
            priceOptionId: priceOptionId
        )
        priceChangeLoading = false
    }

    private func confirmFormulaChange() async {
        guard hasSelectedDifferentFormula, !priceChangeSubmitting else { return }
        priceChangeSubmitting = true
        defer { priceChangeSubmitting = false }
        guard let result = await store.commitRegistrationPriceChange(
            registrationId: registration.id,
            eventId: event.id,
            priceOptionId: selectedPriceOptionId
        ) else { return }

        if let url = result.url {
            activeCheckout = ActiveCheckout(
                url: url,
                sessionId: result.sessionId,
                kind: .eventPayment,
                eventId: event.id,
                registrationId: registration.id
            )
            return
        }

        onSaved()
        feedback = AppFeedback(
            title: "Formula aggiornata",
            message: result.refunded == true ? "Abbiamo aggiornato l'iscrizione e avviato il rimborso automatico." : "La tua iscrizione è stata aggiornata.",
            icon: "checkmark.seal.fill",
            tone: .success
        )
        dismiss()
    }

    private func save() async {
        guard !saving else { return }
        saving = true
        let ok = await store.updateRegistrationDetails(
            registrationId: registration.id,
            event: event,
            meetingPointId: event.meetingPoints.isEmpty ? nil : selectedMeetingPointId.nilIfBlank,
            carAvailability: event.asksCarAvailability ? carAvailability.nilIfBlank : nil,
            additionalResponses: customResponses
        )
        saving = false
        if ok {
            onSaved()
            dismiss()
        }
    }
}

struct MyEventActionButton: View {
    let icon: String
    let title: String
    var tint: Color = Brand.mutedForeground
    var isLoading = false
    var isDisabled = false
    let action: () -> Void

    var body: some View {
        Button(action: action) {
            HStack(spacing: 6) {
                if isLoading {
                    ProgressView()
                        .controlSize(.small)
                        .tint(tint)
                } else {
                    Image(systemName: icon)
                }
                Text(title)
            }
            .font(.caption.weight(.semibold))
            .foregroundStyle(isDisabled ? Brand.mutedForeground : tint)
            .padding(.horizontal, 12)
            .frame(height: 34)
            .background((isDisabled ? Brand.mutedForeground : tint).opacity(0.10), in: RoundedRectangle(cornerRadius: 12))
        }
        .buttonStyle(.plain)
        .disabled(isDisabled)
    }
}

struct SavedEventList: View {
    let savedEvents: [SavedEvent]
    @Binding var selectedEvent: Event?

    var body: some View {
        if savedEvents.isEmpty {
            EmptyState(icon: "bookmark", title: "Nessun evento salvato", message: "Tocca il segnalibro sugli eventi che vuoi tenere d'occhio.")
        } else {
            LazyVStack(spacing: 12) {
                ForEach(savedEvents) { saved in
                    SavedEventCard(savedEvent: saved) { event in
                        selectedEvent = event
                    }
                }
            }
        }
    }
}

struct SavedEventCard: View {
    @EnvironmentObject private var store: AppStore
    let savedEvent: SavedEvent
    let onOpen: (Event) -> Void
    @State private var removing = false

    private var event: Event? {
        savedEvent.event
    }

    var body: some View {
        if let event {
            HStack(spacing: 12) {
                Button {
                    onOpen(event)
                } label: {
                    HStack(spacing: 12) {
                        RemoteImage(urlString: event.cardImageUrl)
                            .frame(width: 76, height: 76)
                            .clipShape(RoundedRectangle(cornerRadius: 14))
                            .saturation(event.isPastOrCancelled ? 0.35 : 1)

                        VStack(alignment: .leading, spacing: 6) {
                            HStack(spacing: 8) {
                                Text(event.title)
                                    .font(.subheadline.weight(.bold))
                                    .foregroundStyle(Brand.foreground)
                                    .lineLimit(2)
                                    .frame(maxWidth: .infinity, alignment: .leading)
                                EventCardPillLabel(
                                    text: savedStatusText(for: event),
                                    color: savedStatusColor(for: event).opacity(0.12),
                                    foreground: savedStatusColor(for: event)
                                )
                            }
                            Label(formatDate(event.date), systemImage: "calendar")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(1)
                            Label(event.displayLocation, systemImage: "mappin")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(1)
                            Text(event.displayPrice(profile: store.profile, badges: store.badges, registrations: store.myEvents))
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                        }
                    }
                }
                .buttonStyle(.plain)

                Button {
                    Task { await removeSaved(event) }
                } label: {
                    if removing {
                        ProgressView()
                            .controlSize(.small)
                            .tint(Brand.primary)
                            .frame(width: 32, height: 32)
                    } else {
                        Image(systemName: "bookmark.fill")
                            .font(.headline.weight(.semibold))
                            .foregroundStyle(Brand.primary)
                            .frame(width: 32, height: 32)
                    }
                }
                .buttonStyle(.plain)
                .disabled(removing)
            }
            .padding(12)
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 18))
        }
    }

    private func removeSaved(_ event: Event) async {
        guard !removing else { return }
        removing = true
        await store.toggleSave(eventId: event.id)
        removing = false
    }

    private func savedStatusText(for event: Event) -> String {
        event.isPastOrCancelled ? "Passato" : "Disponibile"
    }

    private func savedStatusColor(for event: Event) -> Color {
        event.isPastOrCancelled ? Brand.destructive : Brand.success
    }
}

// MARK: - Organizer

struct OrganizerEditorRoute: Identifiable, Hashable {
    enum Mode: Hashable {
        case create
        case edit(String)
        case duplicate(String)
        case proposal(ActivityProposalAdmin)
    }

    let id = UUID()
    let mode: Mode

    var title: String {
        switch mode {
        case .create: "Nuovo evento"
        case .edit: "Modifica evento"
        case .duplicate: "Duplica evento"
        case .proposal: "Crea da proposta"
        }
    }
}

private extension OrganizerEditorRoute.Mode {
    var isDuplicate: Bool {
        if case .duplicate = self { return true }
        return false
    }

    var existingEventId: String? {
        if case .edit(let eventId) = self { return eventId }
        return nil
    }
}

private enum OrganizerEventBoardFilter: String, CaseIterable, Identifiable {
    case published
    case draft
    case cancelled

    var id: Self { self }

    var title: String {
        switch self {
        case .published: "Pubblicati"
        case .draft: "Bozze"
        case .cancelled: "Annullati"
        }
    }

    var systemImage: String {
        switch self {
        case .published: "calendar.badge.clock"
        case .draft: "square.and.pencil"
        case .cancelled: "xmark.octagon"
        }
    }

    var emptyTitle: String {
        switch self {
        case .published: "Nessun evento futuro"
        case .draft: "Nessuna bozza"
        case .cancelled: "Nessun evento annullato"
        }
    }

    var emptyMessage: String {
        switch self {
        case .published: "Crea il tuo primo evento o duplica uno esistente."
        case .draft: "Gli eventi salvati come bozza appariranno qui."
        case .cancelled: "Gli eventi annullati appariranno qui."
        }
    }
}

struct OrganizerDashboardView: View {
    @EnvironmentObject private var store: AppStore
    @Binding var showAuth: Bool
    @Binding var routedRoute: OrganizerDashboardRoute?
    @State private var tab = 0
    @State private var eventFilter: OrganizerEventBoardFilter = .published
    @State private var selectedEvent: Event?
    @State private var editorRoute: OrganizerEditorRoute?
    @State private var deleteCandidate: Event?
    @State private var deletingEventId: String?

    private var upcomingEvents: [Event] {
        store.organizerEvents.filter(\.organizerIsPublishedUpcoming)
    }

    private var draftEvents: [Event] {
        store.organizerEvents.filter(\.organizerIsDraft)
    }

    private var cancelledEvents: [Event] {
        store.organizerEvents.filter(\.organizerIsCancelled)
    }

    private var pastEvents: [Event] {
        store.organizerEvents.filter(\.organizerIsHistoric)
    }

    private var filteredBoardEvents: [Event] {
        switch eventFilter {
        case .published: upcomingEvents
        case .draft: draftEvents
        case .cancelled: cancelledEvents
        }
    }

    private var totalRegistrations: Int {
        store.organizerEvents.reduce(0) { $0 + ($1.spotsTaken ?? 0) }
    }

    private var dashboardLoadKey: String {
        [
            store.session?.user.id ?? "anonymous",
            store.isOrganizer ? "organizer" : "not-organizer",
            store.isAdmin ? "admin" : "scoped"
        ].joined(separator: "|")
    }

    private var dashboardPastStats: [OrganizerDashboardPastEventStat] {
        OrganizerDashboardPastEventStat.stats(events: pastEvents, registrations: store.organizerDashboardRegistrations)
    }

    private func count(for filter: OrganizerEventBoardFilter) -> Int {
        switch filter {
        case .published: upcomingEvents.count
        case .draft: draftEvents.count
        case .cancelled: cancelledEvents.count
        }
    }

    var body: some View {
        NavigationStack {
            ZStack {
                Brand.background.ignoresSafeArea()
                if !store.isAuthenticated {
                    SignedOutPrompt(title: "Organizzatore", message: "Accedi con un profilo abilitato per gestire gli eventi.", showAuth: $showAuth)
                } else if !store.isOrganizer {
                    EmptyState(icon: "lock.fill", title: "Accesso non abilitato", message: "Questa sezione compare solo per gli utenti organizer.")
                        .padding(.horizontal, 20)
                } else {
                    GeometryReader { proxy in
                        ScrollView {
                            VStack(alignment: .leading, spacing: 16) {
                                OrganizerHeader {
                                    editorRoute = OrganizerEditorRoute(mode: .create)
                                }

                                OrganizerDashboardTabBar(
                                    selection: $tab,
                                    upcomingCount: upcomingEvents.count,
                                    historyCount: pastEvents.count
                                )

                                switch tab {
                                case 0:
                                    VStack(alignment: .leading, spacing: 12) {
                                        LazyVGrid(columns: Array(repeating: GridItem(.flexible(), spacing: 10), count: 3), spacing: 10) {
                                            OrganizerMetricCard(title: "\(store.organizerEvents.count)", subtitle: "Eventi", icon: "calendar")
                                            OrganizerMetricCard(title: "\(totalRegistrations)", subtitle: "Iscrizioni", icon: "person.2.fill")
                                            OrganizerMetricCard(title: "\(upcomingEvents.count)", subtitle: "Futuri", icon: "chart.line.uptrend.xyaxis")
                                        }
                                        OrganizerEventBoardFilterBar(selection: $eventFilter) { filter in
                                            count(for: filter)
                                        }
                                        OrganizerEventList(
                                            events: filteredBoardEvents,
                                            emptyTitle: eventFilter.emptyTitle,
                                            emptyMessage: eventFilter.emptyMessage,
                                            selectedEvent: $selectedEvent,
                                            onDuplicate: { event in editorRoute = OrganizerEditorRoute(mode: .duplicate(event.id)) },
                                            onShare: shareEvent,
                                            onDelete: { event in deleteCandidate = event }
                                        )
                                    }
                                case 1:
                                    OrganizerPastEventList(
                                        stats: dashboardPastStats,
                                        loading: store.isLoadingOrganizerDashboard,
                                        selectedEvent: $selectedEvent
                                    )
                                case 2:
                                    OrganizerDashboardAnalytics(
                                        events: store.organizerEvents,
                                        registrations: store.organizerDashboardRegistrations,
                                        loading: store.isLoadingOrganizerDashboard
                                    )
                                case 3:
                                    OrganizerProposalsPanel { proposal in
                                        editorRoute = OrganizerEditorRoute(mode: .proposal(proposal))
                                    }
                                default:
                                    EmptyView()
                                }
                            }
                            .frame(width: max(proxy.size.width - 32, 0), alignment: .leading)
                            .padding(16)
                        }
                        .contentMargins(.bottom, 0, for: .scrollContent)
                    }
                }
            }
            .navigationDestination(item: $selectedEvent) { event in
                OrganizerEventManageView(eventId: event.id, showAuth: $showAuth)
            }
            .navigationDestination(item: $editorRoute) { route in
                OrganizerEventEditorView(route: route)
            }
            .alert("Eliminare evento?", isPresented: Binding(
                get: { deleteCandidate != nil },
                set: { if !$0 { deleteCandidate = nil } }
            )) {
                Button("Annulla", role: .cancel) {
                    deleteCandidate = nil
                }
                Button("Elimina", role: .destructive) {
                    guard let event = deleteCandidate else { return }
                    deletingEventId = event.id
                    Task {
                        if await store.deleteOrganizerEvent(eventId: event.id) {
                            if selectedEvent?.id == event.id {
                                selectedEvent = nil
                            }
                        }
                        deletingEventId = nil
                        deleteCandidate = nil
                    }
                }
                .disabled(deletingEventId != nil)
            } message: {
                Text("L'evento verra eliminato definitivamente insieme ai dati gestionali collegati. Operazione non reversibile.")
            }
            .task(id: dashboardLoadKey) {
                guard store.isOrganizer else { return }
                await loadDashboardData(reportingErrors: false)
                openRoutedRouteIfNeeded()
            }
            .refreshable {
                await store.refreshUserData()
                await loadDashboardData(reportingErrors: true)
            }
            .onChange(of: routedRoute) { _, _ in
                openRoutedRouteIfNeeded()
            }
            .onChange(of: store.organizerEvents) { _, _ in
                Task { await store.loadOrganizerDashboardRegistrations(reportingErrors: false) }
                openRoutedRouteIfNeeded()
            }
        }
    }

    private func shareEvent(_ event: Event) {
        guard let url = event.webURL else { return }
        UIPasteboard.general.string = url.absoluteString
        store.errorMessage = "Link evento copiato negli appunti."
    }

    @MainActor
    private func loadDashboardData(reportingErrors: Bool) async {
        await store.loadOrganizerDashboard(reportingErrors: reportingErrors)
    }

    private func openRoutedRouteIfNeeded() {
        guard let route = routedRoute else { return }
        tab = 0

        switch route.destination {
        case .create:
            editorRoute = OrganizerEditorRoute(mode: .create)
            routedRoute = nil
        case .edit(let eventId):
            editorRoute = OrganizerEditorRoute(mode: .edit(eventId))
            routedRoute = nil
        case .manage(let eventId):
            if let event = store.organizerEvents.first(where: { $0.id == eventId }) {
                selectedEvent = event
                routedRoute = nil
            }
        }
    }
}

private struct OrganizerDashboardPastEventStat: Identifiable {
    let event: Event
    let registered: Int
    let checkedIn: Int
    let noShows: Int
    let cancelled: Int

    var id: String { event.id }
    var spotsTotal: Int { event.spotsTotal ?? 0 }
    var attendanceRate: Int {
        guard registered > 0 else { return 0 }
        return Int(round(Double(checkedIn) / Double(registered) * 100))
    }
    var categoryText: String {
        categoryLabel(event.category)
    }

    static func stats(events: [Event], registrations: [OrganizerDashboardRegistration]) -> [OrganizerDashboardPastEventStat] {
        let registrationsByEvent = Dictionary(grouping: registrations) { $0.eventId ?? "" }
        return events.map { event in
            let rows = registrationsByEvent[event.id] ?? []
            let active = rows.filter(\.isActive)
            let checkedIn = active.filter { $0.checkedIn == true }
            let cancelled = rows.filter { $0.normalizedStatus == "cancelled" }
            return OrganizerDashboardPastEventStat(
                event: event,
                registered: active.count,
                checkedIn: checkedIn.count,
                noShows: active.count - checkedIn.count,
                cancelled: cancelled.count
            )
        }
    }
}

