    var body: some View {
        Label {
            Text(fact.text)
                .lineLimit(1)
                .minimumScaleFactor(0.8)
        } icon: {
            Image(systemName: fact.icon)
                .font(.caption2.weight(.semibold))
        }
        .font(.caption2)
        .foregroundStyle(Brand.mutedForeground)
    }
