private struct ActivityProposalStatusStyle {
    let rawValue: String
    let label: String
    let foreground: Color

    init(_ status: String?) {
        rawValue = status?.nilIfBlank ?? "pending"
        switch rawValue {
        case "reviewed":
            label = "Valutata"
            foreground = Brand.success
        case "archived":
            label = "Archiviata"
            foreground = Brand.mutedForeground
        case "converted":
            label = "Convertita"
            foreground = Brand.success
        default:
            label = "In attesa"
            foreground = Brand.warning
        }
    }

    var background: Color {
        foreground.opacity(rawValue == "archived" ? 0.10 : 0.14)
    }
}

struct OrganizerDiscountCodesPanel: View {
    @EnvironmentObject private var store: AppStore
    @State private var codes: [AdminDiscountCode] = []
    @State private var eventOptions: [DiscountEventOption] = []
    @State private var loading = true
    @State private var showForm = false
    @State private var editing: AdminDiscountCode?
    @State private var code = ""
    @State private var description = ""
    @State private var discountType = "percentage"
    @State private var discountValue = "10"
    @State private var selectedEventIds: [String] = []
    @State private var assignedUserId = ""
    @State private var maxUses = ""
    @State private var startsAt = ""
    @State private var expiresAt = ""
    @State private var appliesToAll = false
    @State private var isSingleUse = false
    @State private var waivesServiceFee = false

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Button {
                openForm(nil)
            } label: {
                Label("Nuovo codice", systemImage: "plus")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(SecondaryButtonStyle())
            if loading {
                ProgressView().tint(Brand.primary)
            } else if codes.isEmpty {
                EmptyState(icon: "ticket", title: "Nessun codice", message: "I codici sconto configurati appariranno qui.")
            } else {
                ForEach(codes) { code in
                    HStack(spacing: 12) {
                        VStack(alignment: .leading, spacing: 5) {
                            Text(code.code)
                                .font(.headline.weight(.bold))
                            Text(discountSubtitle(code))
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                        }
                        Spacer()
                        Button("Modifica") { openForm(code) }
                            .font(.caption.weight(.bold))
                        Toggle("", isOn: activeBinding(code))
                            .labelsHidden()
                    }
                    .padding(12)
                    .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
        .task { await load() }
        .sheet(isPresented: $showForm) {
            NavigationStack {
                Form {
                    Section("Codice") {
                        TextField("CODICE", text: $code)
                            .textInputAutocapitalization(.characters)
                            .editableTextInput()
                        TextField("Descrizione", text: $description)
                            .editableTextInput()
                    }
                    Section("Sconto") {
                        Picker("Tipo", selection: $discountType) {
                            Text("Percentuale").tag("percentage")
                            Text("Importo fisso").tag("fixed")
                        }
                        .editableControlSurface()
                        OrganizerUnitTextField(
                            "Valore",
                            text: $discountValue,
                            prefix: discountType == "fixed" ? "€" : nil,
                            suffix: discountType == "percentage" ? "%" : nil,
                            keyboard: .decimalPad
                        )
	                        TextField("Max usi", text: $maxUses)
	                            .keyboardType(.numberPad)
	                            .editableTextInput()
	                        Toggle("Azzera costo servizio (€1)", isOn: $waivesServiceFee)
	                            .editableControlSurface()
	                        OrganizerOptionalDatePickerField("Inizio validita", dateString: $startsAt)
	                        OrganizerOptionalDatePickerField("Scadenza", dateString: $expiresAt)
	                    }
                    Section("Regole") {
                        Toggle("Valido per tutti gli eventi", isOn: $appliesToAll)
                            .editableControlSurface()
                        if !appliesToAll {
                            OrganizerDiscountEventSelector(events: eventOptions, selectedIds: $selectedEventIds)
                        }
                        Toggle("Uso singolo", isOn: $isSingleUse)
                            .editableControlSurface()
                        OrganizerUserAssignmentPicker(selectedUserId: $assignedUserId)
                    }
                }
                .roundedInlineNavigationTitle(editing == nil ? "Nuovo sconto" : "Modifica sconto")
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) { Button("Annulla") { showForm = false } }
                    ToolbarItem(placement: .confirmationAction) {
                        Button("Salva") { Task { await save() } }
                            .disabled(code.nilIfBlank == nil || Double(discountValue.replacingOccurrences(of: ",", with: ".")) == nil)
                    }
                }
            }
        }
    }

    @MainActor
    private func load() async {
        loading = true
        async let codesTask = store.fetchDiscountCodes(reportingErrors: false)
        async let eventsTask = store.fetchDiscountEventOptions(reportingErrors: false)
        codes = await codesTask
        eventOptions = await eventsTask
        loading = false
    }

    private func activeBinding(_ code: AdminDiscountCode) -> Binding<Bool> {
        Binding {
            code.isActive ?? false
        } set: { value in
            Task {
                if await store.setDiscountCode(id: code.id, active: value) {
                    await load()
                }
            }
        }
    }

    private func discountSubtitle(_ code: AdminDiscountCode) -> String {
        let value = code.discountType == "fixed" ? "€\(money(code.discountValue ?? 0))" : "\(Int(code.discountValue ?? 0))%"
        let fee = code.waivesServiceFee == true ? " · fee €0" : ""
        return "\(value) · usi \(code.timesUsed ?? 0)/\(code.maxUses.map(String.init) ?? "∞")\(fee)"
    }

    private func openForm(_ item: AdminDiscountCode?) {
        editing = item
        code = item?.code ?? ""
        description = item?.description ?? ""
        discountType = item?.discountType ?? "percentage"
        discountValue = item?.discountValue?.cleanInputString ?? "10"
        selectedEventIds = item?.eventIds ?? []
        assignedUserId = item?.assignedUserId ?? ""
        maxUses = item?.maxUses.map(String.init) ?? ""
        startsAt = item?.startsAt?.prefix(10).description ?? ""
        expiresAt = item?.expiresAt?.prefix(10).description ?? ""
        appliesToAll = item?.appliesToAll ?? false
        isSingleUse = item?.isSingleUse ?? false
        waivesServiceFee = item?.waivesServiceFee ?? false
        showForm = true
    }

    private func save() async {
        let value = Double(discountValue.replacingOccurrences(of: ",", with: ".")) ?? 0
        let max = Int(maxUses)
        let eventIds = appliesToAll ? [] : selectedEventIds
        if await store.saveDiscountCode(id: editing?.id, code: code, description: description, discountType: discountType, discountValue: value, eventIds: eventIds, assignedUserId: assignedUserId.nilIfBlank, maxUses: max, startsAt: startsAt.nilIfBlank, expiresAt: expiresAt.nilIfBlank, appliesToAll: appliesToAll, isSingleUse: isSingleUse, waivesServiceFee: waivesServiceFee) {
            showForm = false
            await load()
        }
    }
}

