struct OrganizerUserAssignmentPicker: View {
    @EnvironmentObject private var store: AppStore
    @Binding var selectedUserId: String
    @State private var query = ""
    @State private var results: [OrganizerSearchProfile] = []
    @State private var loading = false

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            Text("Assegna a utente specifico")
                .font(.subheadline.weight(.bold))
            if selectedUserId.nilIfBlank != nil {
                HStack(spacing: 10) {
                    Image(systemName: "person.fill")
                        .foregroundStyle(Brand.primary)
                    VStack(alignment: .leading, spacing: 2) {
                        Text(selectedLabel)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.inputForeground)
                        Text(selectedUserId)
                            .font(.caption2)
                            .foregroundStyle(Brand.inputMutedForeground)
                            .lineLimit(1)
                    }
                    Spacer()
                    Button {
                        selectedUserId = ""
                    } label: {
                        Image(systemName: "xmark.circle.fill")
                            .foregroundStyle(Brand.mutedForeground)
                    }
                }
                .padding(10)
                .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
                .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
            } else {
                TextField("Cerca per nome o email", text: $query)
                    .textInputAutocapitalization(.never)
                    .editableTextInput()
                if loading {
                    ProgressView().tint(Brand.primary)
                } else {
                    ForEach(results) { profile in
                        Button {
                            selectedUserId = profile.id
                            query = ""
                            results = []
                        } label: {
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(profile.displayName)
                                        .font(.caption.weight(.semibold))
                                    Text(profile.email ?? profile.phone ?? String(profile.id.prefix(8)))
                                        .font(.caption2)
                                        .foregroundStyle(Brand.inputMutedForeground)
                                }
                                Spacer()
                            }
                            .foregroundStyle(Brand.inputForeground)
                            .padding(10)
                            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
                            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
                        }
                        .buttonStyle(.plain)
                    }
                }
            }
        }
        .task(id: query) { await search() }
    }

    private var selectedLabel: String {
        "Utente \(String(selectedUserId.prefix(8)))"
    }

    @MainActor
    private func search() async {
        let term = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard term.count >= 2, selectedUserId.nilIfBlank == nil else {
            results = []
            loading = false
            return
        }
        loading = true
        try? await Task.sleep(nanoseconds: 250_000_000)
        guard term == query.trimmingCharacters(in: .whitespacesAndNewlines), selectedUserId.nilIfBlank == nil else {
            loading = false
            return
        }
        results = await store.searchOrganizerProfiles(term)
        loading = false
    }
}

struct OrganizerMissionsPanel: View {
    @EnvironmentObject private var store: AppStore
    @State private var missions: [AdminMission] = []
    @State private var loading = true
    @State private var showForm = false
    @State private var editing: AdminMission?
    @State private var title = ""
    @State private var description = ""
    @State private var type = "one_time"
    @State private var targetAction = "event_attended"
    @State private var targetValue = "1"
    @State private var rewardPoints = "10"
    @State private var rewardType = "points"
    @State private var rewardValue = ""
    @State private var rewardBadgeId = ""
    @State private var category = ""
    @State private var icon = "🎯"
    @State private var isActive = true
    @State private var resetOnFailure = false
    @State private var streakCount = ""
    @State private var expiresAt = ""

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Button {
                openForm(nil)
            } label: {
                Label("Nuova missione", systemImage: "plus")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(SecondaryButtonStyle())
            if loading {
                ProgressView().tint(Brand.primary)
            } else if missions.isEmpty {
                EmptyState(icon: "target", title: "Nessuna missione", message: "Le missioni configurate appariranno qui.")
            } else {
                ForEach(Array(missions.enumerated()), id: \.element.id) { index, mission in
                    HStack(alignment: .top, spacing: 12) {
                        MissionDynamicIconView(value: mission.icon ?? "lucide:Target", size: 20, color: Brand.foreground)
                            .frame(width: 30, height: 30)
                            .background(Brand.muted.opacity(0.65), in: Circle())
                            .padding(.top, 2)
                        VStack(alignment: .leading, spacing: 6) {
                            Text(mission.title)
                                .font(.subheadline.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                                .lineLimit(2)
                                .fixedSize(horizontal: false, vertical: true)
                            Text(missionSubtitle(mission))
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(2)
                            BadgeLabel(
                                text: (mission.isActive ?? false) ? "Attiva" : "Inattiva",
                                color: (mission.isActive ?? false) ? Brand.primary.opacity(0.14) : Brand.muted,
                                foreground: (mission.isActive ?? false) ? Brand.primary : Brand.mutedForeground
                            )
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)
                        Menu {
                            Button {
                                Task { await moveMission(at: index, direction: -1) }
                            } label: {
                                Label("Sposta su", systemImage: "chevron.up")
                            }
                            .disabled(index == 0)
                            Button {
                                Task { await moveMission(at: index, direction: 1) }
                            } label: {
                                Label("Sposta giù", systemImage: "chevron.down")
                            }
                            .disabled(index == missions.count - 1)
                            Divider()
                            Button {
                                openForm(mission)
                            } label: {
                                Label("Modifica", systemImage: "pencil")
                            }
                            Button {
                                Task { await setMission(mission, active: !(mission.isActive ?? false)) }
                            } label: {
                                Label((mission.isActive ?? false) ? "Disattiva" : "Attiva", systemImage: (mission.isActive ?? false) ? "pause.circle" : "checkmark.circle")
                            }
                            Divider()
                            Button(role: .destructive) {
                                Task {
                                    if await store.deleteMission(id: mission.id) {
                                        await load()
                                    }
                                }
                            } label: {
                                Label("Elimina", systemImage: "trash")
                            }
                        } label: {
                            Image(systemName: "ellipsis.circle")
                                .font(.title3.weight(.semibold))
                                .foregroundStyle(Brand.primary)
                                .frame(width: 34, height: 34)
                                .background(Brand.muted.opacity(0.55), in: Circle())
                        }
                        .accessibilityLabel("Azioni missione")
                    }
                    .padding(12)
                    .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
        .task { await load() }
        .sheet(isPresented: $showForm) {
            NavigationStack {
                Form {
                    Section("Missione") {
                        TextField("Titolo", text: $title)
                            .editableTextInput()
                        TextField("Descrizione", text: $description)
                            .editableTextInput()
                        HStack(spacing: 10) {
                            MissionDynamicIconView(value: icon.nilIfBlank ?? "lucide:Target", size: 18, color: Brand.foreground)
                                .frame(width: 32, height: 32)
                                .background(Brand.muted.opacity(0.65), in: Circle())
                            TextField("Icona", text: $icon)
                                .editableTextInput()
                        }
                        Toggle("Attiva", isOn: $isActive)
                            .editableControlSurface()
                    }
                    Section("Obiettivo") {
                        Picker("Tipo", selection: $type) {
                            Text("Una tantum").tag("one_time")
                            Text("Settimanale").tag("weekly")
                            Text("Mensile").tag("monthly")
                            Text("Progressiva").tag("progressive")
                            Text("Streak").tag("streak")
                            Text("Categoria").tag("category")
                        }
                        .editableControlSurface()
                        Picker("Azione", selection: $targetAction) {
                            Text("Primo evento").tag("first_event_ever")
                            Text("Evento completato").tag("event_attended")
                            Text("Iscrizione evento").tag("event_registered")
                            Text("Categoria completata").tag("category_attended")
                            Text("Partecipazione categoria").tag("category_participation")
                            Text("Streak settimanale").tag("streak_weekly")
                            Text("Evento ultimi posti").tag("limited_spots")
                        }
                        .editableControlSurface()
                        TextField("Target", text: $targetValue)
                            .keyboardType(.numberPad)
                            .editableTextInput()
                        Field("Categoria evento", text: $category)
                        if type == "streak" {
                            TextField("Streak richiesto", text: $streakCount)
                                .keyboardType(.numberPad)
                                .editableTextInput()
                        }
                    }
                    Section("Ricompensa") {
                        TextField("Punti", text: $rewardPoints)
                            .keyboardType(.numberPad)
                            .editableTextInput()
                        Picker("Tipo premio", selection: $rewardType) {
                            Text("Punti").tag("points")
                            Text("Coupon").tag("coupon")
                            Text("Badge").tag("badge")
                            Text("Premio fisico").tag("physical")
                        }
                        .editableControlSurface()
                        if rewardType == "coupon" {
                            TextField("Valore coupon", text: $rewardValue)
                                .editableTextInput()
                        } else if rewardType == "physical" {
                            TextField("Descrizione premio fisico", text: $rewardValue)
                                .editableTextInput()
                        } else if rewardType == "badge" {
                            Picker("Badge da assegnare", selection: $rewardBadgeId) {
                                Text("Nessuno").tag("")
                                ForEach(store.allBadges) { badge in
                                    Text("\(badge.icon) \(badge.name)").tag(badge.id)
                                }
                            }
                            .editableControlSurface()
                        }
                    }
                    Section("Regole avanzate") {
                        OrganizerOptionalDatePickerField("Scadenza", dateString: $expiresAt)
                        Toggle("Reset progresso su no-show", isOn: $resetOnFailure)
                            .editableControlSurface()
                    }
                }
                .roundedInlineNavigationTitle(editing == nil ? "Nuova missione" : "Modifica missione")
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) { Button("Annulla") { showForm = false } }
                    ToolbarItem(placement: .confirmationAction) {
                        Button("Salva") { Task { await save() } }
                            .disabled(title.nilIfBlank == nil)
                    }
                }
            }
        }
    }

    @MainActor
    private func load() async {
        loading = true
        missions = await store.fetchAdminMissions(reportingErrors: false)
        loading = false
    }

    private func missionSubtitle(_ mission: AdminMission) -> String {
        var parts = [
            "\(mission.targetAction ?? "azione") x \(mission.targetValue ?? 1)",
            "+\(mission.rewardPoints ?? 0) pt"
        ]
        if let rewardType = mission.rewardType, rewardType != "points" {
            parts.append(rewardType)
        }
        if let category = mission.category?.nilIfBlank {
            parts.append(category)
        }
        return parts.joined(separator: " · ")
    }

    private func moveMission(at index: Int, direction: Int) async {
        let targetIndex = index + direction
        guard missions.indices.contains(index), missions.indices.contains(targetIndex) else { return }
        let current = missions[index]
        let target = missions[targetIndex]
        let currentOrder = current.sortOrder ?? index
        let targetOrder = target.sortOrder ?? targetIndex
        let updatedCurrent = await store.updateMissionSortOrder(id: current.id, sortOrder: targetOrder)
        let updatedTarget = await store.updateMissionSortOrder(id: target.id, sortOrder: currentOrder)
        if updatedCurrent && updatedTarget {
            await load()
        }
    }

    private func setMission(_ mission: AdminMission, active: Bool) async {
        if await store.setMission(id: mission.id, active: active) {
            await load()
        }
    }

    private func openForm(_ mission: AdminMission?) {
        editing = mission
        title = mission?.title ?? ""
        description = mission?.description ?? ""
        type = mission?.type ?? "one_time"
        targetAction = mission?.targetAction ?? "event_attended"
        targetValue = mission?.targetValue.map(String.init) ?? "1"
        rewardPoints = mission?.rewardPoints.map(String.init) ?? "10"
        rewardType = mission?.rewardType ?? "points"
        rewardValue = mission?.rewardValue ?? ""
        rewardBadgeId = mission?.rewardBadgeId ?? ""
        category = mission?.category ?? ""
        icon = mission?.icon ?? "🎯"
        isActive = mission?.isActive ?? true
        resetOnFailure = mission?.resetOnFailure ?? false
        streakCount = mission?.streakCount.map(String.init) ?? ""
        expiresAt = mission?.expiresAt?.prefix(10).description ?? ""
        showForm = true
    }

    private func save() async {
        let nextSortOrder = editing == nil ? ((missions.map { $0.sortOrder ?? 0 }.max() ?? -1) + 1) : nil
        if await store.saveMission(
            id: editing?.id,
            title: title,
            description: description,
            type: type,
            targetAction: targetAction,
            targetValue: Int(targetValue) ?? 1,
            rewardPoints: Int(rewardPoints) ?? 0,
            rewardType: rewardType,
            rewardValue: rewardValue.nilIfBlank,
            rewardBadgeId: rewardType == "badge" ? rewardBadgeId.nilIfBlank : nil,
            category: category.nilIfBlank,
            icon: icon,
            isActive: isActive,
            resetOnFailure: resetOnFailure,
            streakCount: Int(streakCount),
            expiresAt: expiresAt.nilIfBlank,
            sortOrder: nextSortOrder
        ) {
            showForm = false
            await load()
        }
    }
}

struct OrganizerIssuesPanel: View {
    @EnvironmentObject private var store: AppStore
    @State private var issues: [AdminIssue] = []
    @State private var loading = true
    @State private var selectedIssue: AdminIssue?
    @State private var resolutionNotes = ""
    @State private var resolving = false

    private var openIssues: [AdminIssue] { issues.filter { $0.status != "resolved" } }
    private var resolvedIssues: [AdminIssue] { issues.filter { $0.status == "resolved" } }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            if loading {
                ProgressView().tint(Brand.primary)
            } else if issues.isEmpty {
                EmptyState(icon: "checkmark.seal", title: "Nessuna issue", message: "Non ci sono segnalazioni.")
            } else {
                Text("Aperte (\(openIssues.count))")
                    .font(.headline.weight(.bold))
                ForEach(openIssues) { issue in
                    issueRow(issue, canResolve: true)
                }
                if !resolvedIssues.isEmpty {
                    Text("Risolte (\(resolvedIssues.count))")
                        .font(.headline.weight(.bold))
                    ForEach(resolvedIssues.prefix(5)) { issue in
                        issueRow(issue, canResolve: false)
                    }
                }
            }
        }
        .task { await load() }
        .sheet(item: $selectedIssue) { issue in
            NavigationStack {
                Form {
                    Section("Issue") {
                        Text(issue.title)
                            .font(.headline.weight(.bold))
                        Text(issue.description ?? "")
                            .font(.footnote)
                            .foregroundStyle(Brand.mutedForeground)
                        LabeledContent("Priorita", value: issue.priority ?? "medium")
                        LabeledContent("Segnalata da", value: issue.reporterName ?? "utente")
                    }
                    if let attachments = issue.mediaAttachments, !attachments.isEmpty {
                        Section("Allegati") {
                            AdminIssueMediaStrip(attachments: attachments, compact: false)
                        }
                    }
                    Section("Risoluzione") {
                        TextEditor(text: $resolutionNotes)
                            .frame(minHeight: 120)
                            .foregroundStyle(Brand.inputForeground)
                            .tint(Brand.primary)
                            .scrollContentBackground(.hidden)
                            .padding(8)
                            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 12))
                            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.inputBorder, lineWidth: 1))
                    }
                }
                .navigationTitle("Dettaglio issue")
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Annulla") { selectedIssue = nil }
                    }
                    ToolbarItem(placement: .confirmationAction) {
                        Button(resolving ? "Risolvo..." : "Risolvi") {
                            Task { await resolve(issue) }
                        }
                        .disabled(resolving)
                    }
                }
            }
        }
    }

    @ViewBuilder
    private func issueRow(_ issue: AdminIssue, canResolve: Bool) -> some View {
        HStack(alignment: .top, spacing: 12) {
            Image(systemName: issue.status == "resolved" ? "checkmark.circle.fill" : "exclamationmark.triangle.fill")
                .foregroundStyle(issue.status == "resolved" ? Brand.success : issuePriorityColor(issue.priority))
            VStack(alignment: .leading, spacing: 4) {
                Text(issue.title)
                    .font(.subheadline.weight(.bold))
                Text(issue.description ?? "")
                    .font(.caption)
                    .foregroundStyle(Brand.mutedForeground)
                    .lineLimit(2)
                if let attachments = issue.mediaAttachments, !attachments.isEmpty {
                    AdminIssueMediaStrip(attachments: attachments, compact: true)
                }
                Text("Da \(issue.reporterName ?? "utente")")
                    .font(.caption2)
                    .foregroundStyle(Brand.mutedForeground)
            }
            Spacer()
            if canResolve {
                Button("Risolvi") {
                    resolutionNotes = ""
                    selectedIssue = issue
                }
                .font(.caption.weight(.bold))
                .buttonStyle(.bordered)
            }
        }
        .padding(12)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
        .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
    }

    @MainActor
    private func load() async {
        loading = true
        issues = await store.fetchAdminIssues(reportingErrors: false)
        loading = false
    }

    private func resolve(_ issue: AdminIssue) async {
        resolving = true
        if await store.resolveAdminIssue(id: issue.id, notes: resolutionNotes) {
            selectedIssue = nil
            resolutionNotes = ""
            await load()
        }
        resolving = false
    }

    private func issuePriorityColor(_ priority: String?) -> Color {
        switch priority {
        case "high": Brand.destructive
        case "medium": Brand.warning
        default: Brand.mutedForeground
        }
    }
}

private struct AdminIssueMediaStrip: View {
    @EnvironmentObject private var store: AppStore
    let attachments: [IssueMediaAttachment]
    let compact: Bool
    @State private var signedURLs: [String: String] = [:]

    private var taskKey: String {
        attachments.map(\.path).joined(separator: "|")
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            if compact {
                HStack(spacing: 8) {
                    ForEach(attachments.prefix(3)) { attachment in
                        mediaPreview(for: attachment)
                            .frame(width: 72, height: 54)
                    }
                    if attachments.count > 3 {
                        Text("+\(attachments.count - 3)")
                            .font(.caption.weight(.bold))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                }
            } else {
                ForEach(attachments) { attachment in
                    VStack(alignment: .leading, spacing: 6) {
                        mediaPreview(for: attachment)
                            .frame(height: attachment.isVideo ? 88 : 160)
                        HStack(spacing: 6) {
                            Image(systemName: attachment.isVideo ? "video.fill" : "photo.fill")
                            Text(attachment.displayName)
                                .lineLimit(1)
                            Spacer()
                            Text(attachment.displaySize)
                            if let url = signedURL(for: attachment) {
                                Link(destination: url) {
                                    Image(systemName: "arrow.up.right.square")
                                }
                            }
                        }
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                    }
                    .padding(.vertical, 4)
                }
            }
        }
        .task(id: taskKey) {
            await loadSignedURLs()
        }
    }

    @ViewBuilder
    private func mediaPreview(for attachment: IssueMediaAttachment) -> some View {
        if attachment.isVideo {
            if let url = signedURL(for: attachment) {
                Link(destination: url) {
                    ZStack {
                        RoundedRectangle(cornerRadius: 12)
                            .fill(.black.opacity(0.86))
                        Image(systemName: "play.circle.fill")
                            .font(.title2)
                            .foregroundStyle(.white)
                    }
                }
                .buttonStyle(.plain)
            } else {
                placeholder(systemImage: "video.fill")
            }
        } else if let url = signedURL(for: attachment) {
            AsyncImage(url: url) { phase in
                switch phase {
                case .success(let image):
                    image
                        .resizable()
                        .scaledToFill()
                case .failure:
                    placeholder(systemImage: "photo.fill")
                default:
                    ProgressView()
                        .tint(Brand.primary)
                        .frame(maxWidth: .infinity, maxHeight: .infinity)
                }
            }
            .clipShape(RoundedRectangle(cornerRadius: 12))
            .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.muted, lineWidth: 1))
        } else {
            placeholder(systemImage: "photo.fill")
        }
    }

    private func placeholder(systemImage: String) -> some View {
        ZStack {
            RoundedRectangle(cornerRadius: 12)
                .fill(Brand.muted)
            Image(systemName: systemImage)
                .foregroundStyle(Brand.mutedForeground)
        }
    }

    private func signedURL(for attachment: IssueMediaAttachment) -> URL? {
        signedURLs[attachment.path].flatMap(URL.init(string:))
    }

    @MainActor
    private func loadSignedURLs() async {
        var urls: [String: String] = [:]
        for attachment in attachments {
            if let url = await store.signedIssueMediaURL(path: attachment.path) {
                urls[attachment.path] = url
            }
        }
        signedURLs = urls
    }
}

struct OrganizerBroadcastTemplatesPanel: View {
    @EnvironmentObject private var store: AppStore
    @State private var templates: [BroadcastTemplate] = []
    @State private var loading = true
    @State private var editing: BroadcastTemplate?
    @State private var title = ""
    @State private var message = ""
    @State private var sortOrder = "0"
    @State private var showForm = false

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            Button {
                openForm(nil)
            } label: {
                Label("Nuovo template", systemImage: "plus")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(SecondaryButtonStyle())

            if loading {
                ProgressView().tint(Brand.primary)
            } else if templates.isEmpty {
                EmptyState(icon: "text.bubble", title: "Nessun template", message: "Crea messaggi riutilizzabili per i broadcast.")
            } else {
                ForEach(templates) { template in
                    VStack(alignment: .leading, spacing: 8) {
                        HStack {
                            Text(template.title)
                                .font(.subheadline.weight(.bold))
                            Spacer()
                            Button("Modifica") { openForm(template) }
                                .font(.caption.weight(.bold))
                            Button(role: .destructive) {
                                Task {
                                    if await store.deleteBroadcastTemplate(id: template.id) {
                                        await load()
                                    }
                                }
                            } label: {
                                Image(systemName: "trash")
                            }
                        }
                        Text(template.message)
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    .padding(12)
                    .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
        .task { await load() }
        .sheet(isPresented: $showForm) {
            NavigationStack {
                Form {
                    Section("Template") {
                        TextField("Titolo", text: $title)
                            .editableTextInput()
                        TextEditor(text: $message)
                            .frame(minHeight: 130)
                            .foregroundStyle(Brand.inputForeground)
                            .tint(Brand.primary)
                            .scrollContentBackground(.hidden)
                            .padding(10)
                            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                            .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
                        TextField("Ordine", text: $sortOrder)
                            .keyboardType(.numberPad)
                            .editableTextInput()
                    }
                }
                .roundedInlineNavigationTitle(editing == nil ? "Nuovo template" : "Modifica template")
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) { Button("Annulla") { showForm = false } }
                    ToolbarItem(placement: .confirmationAction) {
                        Button("Salva") {
                            Task { await save() }
                        }
                        .disabled(title.nilIfBlank == nil || message.nilIfBlank == nil)
                    }
                }
            }
        }
    }

    @MainActor
    private func load() async {
        loading = true
        templates = await store.fetchBroadcastTemplates(reportingErrors: false)
        loading = false
    }

    private func openForm(_ template: BroadcastTemplate?) {
        editing = template
        title = template?.title ?? ""
        message = template?.message ?? ""
        sortOrder = "\(template?.sortOrder ?? 0)"
        showForm = true
    }

    private func save() async {
        if await store.saveBroadcastTemplate(id: editing?.id, title: title, message: message, sortOrder: Int(sortOrder) ?? 0) {
            showForm = false
            await load()
        }
    }
}

struct OrganizerIOSPushBroadcastPanel: View {
    @EnvironmentObject private var store: AppStore
    @State private var title = ""
    @State private var message = ""
    @State private var broadcasts: [IOSPushBroadcastCampaign] = []
    @State private var estimate: IOSPushBroadcastResponse?
    @State private var lastResult: IOSPushBroadcastResponse?
    @State private var loadingHistory = true
    @State private var estimating = false
    @State private var sending = false
    @State private var showConfirmation = false

    private var cleanTitle: String {
        title.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var cleanMessage: String {
        message.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var canSend: Bool {
        !cleanTitle.isEmpty && !cleanMessage.isEmpty && !sending && cleanTitle.count <= 120 && cleanMessage.count <= 800
    }

    private var estimatedTargets: String {
        guard let count = estimate?.targetCount else { return "Non stimati" }
        return "\(count)"
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            VStack(alignment: .leading, spacing: 10) {
                Text("Messaggio")
                    .font(.headline.weight(.bold))
                TextField("Titolo notifica", text: $title)
                    .editableTextInput()
                HStack {
                    Text("Titolo massimo 120 caratteri")
                    Spacer()
                    Text("\(cleanTitle.count)/120")
                }
                .font(.caption2)
                .foregroundStyle(cleanTitle.count > 120 ? Brand.destructive : Brand.mutedForeground)

                TextEditor(text: $message)
                    .frame(minHeight: 150)
                    .foregroundStyle(Brand.inputForeground)
                    .tint(Brand.primary)
                    .scrollContentBackground(.hidden)
                    .padding(10)
                    .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                    .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
                HStack {
                    Text("Testo massimo 800 caratteri")
                    Spacer()
                    Text("\(cleanMessage.count)/800")
                }
                .font(.caption2)
                .foregroundStyle(cleanMessage.count > 800 ? Brand.destructive : Brand.mutedForeground)
            }
            .padding(14)
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))

            VStack(alignment: .leading, spacing: 10) {
                HStack {
                    Label("Destinatari stimati", systemImage: "iphone.gen3")
                        .font(.subheadline.weight(.bold))
                    Spacer()
                    Text(estimatedTargets)
                        .font(.headline.weight(.bold))
                        .foregroundStyle(Brand.primary)
                }
                if let uniqueUsers = estimate?.uniqueUserCount {
                    Text("\(uniqueUsers) utenti con almeno un token iOS attivo.")
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                } else {
                    Text("Usa la stima prima di inviare, cosi controlli quanti token verranno raggiunti.")
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                }

                Button {
                    Task { await estimateAudience() }
                } label: {
                    if estimating {
                        Label("Stimo...", systemImage: "hourglass")
                    } else {
                        Label("Stima destinatari", systemImage: "person.2.fill")
                    }
                }
                .buttonStyle(SecondaryButtonStyle())
                .disabled(estimating || sending)

                Button {
                    showConfirmation = true
                } label: {
                    if sending {
                        Label("Invio in corso...", systemImage: "hourglass")
                    } else {
                        Label("Invia push iOS", systemImage: "paperplane.fill")
                    }
                }
                .buttonStyle(PrimaryButtonStyle())
                .disabled(!canSend)
            }

            if let result = lastResult {
                IOSPushBroadcastResultCard(result: result)
            }

            VStack(alignment: .leading, spacing: 10) {
                Text("Ultimi invii")
                    .font(.headline.weight(.bold))
                if loadingHistory {
                    ProgressView().tint(Brand.primary)
                } else if broadcasts.isEmpty {
                    EmptyState(icon: "tray", title: "Nessun broadcast iOS", message: "Gli invii globali appariranno qui.")
                } else {
                    ForEach(broadcasts) { broadcast in
                        IOSPushBroadcastHistoryRow(broadcast: broadcast)
                    }
                }
            }
        }
        .task { await loadHistory() }
        .alert("Inviare la push iOS?", isPresented: $showConfirmation) {
            Button("Annulla", role: .cancel) {}
            Button("Invia", role: .destructive) {
                Task { await send() }
            }
        } message: {
            Text("Destinatari stimati: \(estimatedTargets). L'azione non puo essere annullata.")
        }
    }

    @MainActor
    private func loadHistory() async {
        loadingHistory = true
        broadcasts = await store.fetchIOSPushBroadcasts(reportingErrors: false)
        loadingHistory = false
    }

    @MainActor
    private func estimateAudience() async {
        estimating = true
        estimate = await store.estimateIOSPushAudience()
        estimating = false
    }

    @MainActor
    private func send() async {
        guard canSend else { return }
        sending = true
        let result = await store.sendIOSPushBroadcast(title: cleanTitle, message: cleanMessage)
        lastResult = result
        if result?.success == true {
            title = ""
            message = ""
            estimate = nil
            await loadHistory()
        }
        sending = false
    }
}

private struct IOSPushBroadcastResultCard: View {
    let result: IOSPushBroadcastResponse

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Image(systemName: result.success == true ? "checkmark.circle.fill" : "exclamationmark.triangle.fill")
                    .foregroundStyle(result.success == true ? Brand.success : Brand.destructive)
                Text(result.success == true ? "Invio completato" : "Invio non riuscito")
                    .font(.headline.weight(.bold))
            }
            Text("\(result.sentCount ?? 0) inviate · \(result.failedCount ?? 0) fallite · \(result.expiredCount ?? 0) token disattivati")
                .font(.caption)
                .foregroundStyle(Brand.mutedForeground)
            if let error = result.error?.nilIfBlank {
                Text(error)
                    .font(.caption)
                    .foregroundStyle(Brand.destructive)
            }
        }
        .padding(14)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
        .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
    }
}

