struct OrganizerOwnerPickerSheet: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let event: Event
    let onSaved: () async -> Void
    @State private var options: [OrganizerOwnerOption] = []
    @State private var query = ""
    @State private var loading = true
    @State private var savingId: String?

    private var filteredOptions: [OrganizerOwnerOption] {
        let cleanQuery = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !cleanQuery.isEmpty else { return options }
        return options.filter { option in
            option.displayName.localizedCaseInsensitiveContains(cleanQuery)
                || (option.email?.localizedCaseInsensitiveContains(cleanQuery) == true)
                || option.roleLabel.localizedCaseInsensitiveContains(cleanQuery)
        }
    }

    var body: some View {
        NavigationStack {
            Form {
                Section("Evento") {
                    VStack(alignment: .leading, spacing: 4) {
                        Text(event.title)
                            .font(.subheadline.weight(.bold))
                        Text("Attuale: \(event.organizerDisplayName)")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    .padding(.vertical, 4)
                }

                Section("Cerca") {
                    TextField("Nome, email o ruolo", text: $query)
                        .textInputAutocapitalization(.words)
                        .editableTextInput()
                }

                Section("Organizzatori") {
                    if loading {
                        HStack {
                            Spacer()
                            ProgressView().tint(Brand.primary)
                            Spacer()
                        }
                    } else if filteredOptions.isEmpty {
                        Text("Nessun organizzatore disponibile")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                    } else {
                        ForEach(filteredOptions) { option in
                            Button {
                                Task { await save(option) }
                            } label: {
                                HStack(spacing: 12) {
                                    OrganizerOwnerAvatar(name: option.displayName, avatarUrl: option.avatarUrl, size: 40)
                                    VStack(alignment: .leading, spacing: 3) {
                                        Text(option.displayName)
                                            .font(.subheadline.weight(.bold))
                                            .foregroundStyle(Brand.foreground)
                                            .lineLimit(1)
                                        Text([option.roleLabel, option.email?.nilIfBlank].compactMap { $0 }.joined(separator: " · "))
                                            .font(.caption)
                                            .foregroundStyle(Brand.mutedForeground)
                                            .lineLimit(1)
                                    }
                                    Spacer()
                                    if savingId == option.id {
                                        ProgressView().tint(Brand.primary)
                                    } else if option.id == event.organizerId {
                                        Image(systemName: "checkmark.circle.fill")
                                            .foregroundStyle(Brand.success)
                                    }
                                }
                            }
                            .disabled(savingId != nil || option.id == event.organizerId)
                        }
                    }
                }
            }
            .navigationTitle("Cambia organizzatore")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Annulla") { dismiss() }
                }
            }
        }
        .task { await load() }
    }

    @MainActor
    private func load() async {
        loading = true
        options = await store.fetchOrganizerOwnerOptions(reportingErrors: false)
        loading = false
    }

    @MainActor
    private func save(_ option: OrganizerOwnerOption) async {
        guard savingId == nil else { return }
        savingId = option.id
        if await store.updateOrganizerOwner(eventId: event.id, organizer: option) {
            await onSaved()
            dismiss()
        }
        savingId = nil
    }
}

struct OrganizerOwnerAvatar: View {
    let name: String
    let avatarUrl: String?
    let size: CGFloat

    var body: some View {
        ZStack {
            if let avatarUrl, let url = URL(string: avatarUrl) {
                AsyncImage(url: url) { image in
                    image.resizable().scaledToFill()
                } placeholder: {
                    Brand.primary.opacity(0.12)
                }
            } else {
                Brand.primary.opacity(0.12)
                Text(String(name.prefix(1)).uppercased())
                    .font(.subheadline.weight(.bold))
                    .foregroundStyle(Brand.primary)
            }
        }
        .frame(width: size, height: size)
        .clipShape(Circle())
    }
}

private enum OrganizerEventManageConfirmation: Identifiable {
    case deleteEvent
    case cancelEvent
    case cancelRegistration(OrganizerRegistration)

    var id: String {
        switch self {
        case .deleteEvent:
            return "delete-event"
        case .cancelEvent:
            return "cancel-event"
        case .cancelRegistration(let registration):
            return "cancel-registration-\(registration.id)"
        }
    }

    var title: String {
        switch self {
        case .deleteEvent:
            return "Eliminare evento?"
        case .cancelEvent:
            return "Annullare evento?"
        case .cancelRegistration:
            return "Cancellare partecipante?"
        }
    }

    var confirmTitle: String {
        switch self {
        case .deleteEvent:
            return "Elimina"
        case .cancelEvent:
            return "Conferma cancellazione"
        case .cancelRegistration:
            return "Conferma"
        }
    }

    var message: String {
        switch self {
        case .deleteEvent:
            return "L'operazione usa le stesse regole Supabase della webapp e potrebbe essere bloccata se l'evento ha vincoli attivi."
        case .cancelEvent:
            return "L'evento verra segnato come cancellato e la funzione Supabase notifichera i partecipanti."
        case .cancelRegistration:
            return "Sei sicuro di voler cancellare questo partecipante?"
        }
    }
}

struct OrganizerEventManageView: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let eventId: String
    @Binding var showAuth: Bool
    @State private var event: Event?
    @State private var registrations: [OrganizerRegistration] = []
    @State private var meetingPoints: [MeetingPoint] = []
    @State private var priceOptions: [PriceOption] = []
    @State private var templates: [BroadcastTemplate] = []
    @State private var broadcastHistory: [EventBroadcast] = []
    @State private var tab = 0
    @State private var loading = true
    @State private var editorRoute: OrganizerEditorRoute?
    @State private var showAddParticipant = false
    @State private var showCapacity = false
    @State private var showBroadcast = false
    @State private var confirmation: OrganizerEventManageConfirmation?
    @State private var showStatusSheet = false
    @State private var showOwnerPicker = false
    @State private var sharePayload: SharePayload?
    @State private var exportingCSV = false
    @State private var selectedParticipantProfile: OrganizerRegistration?
    @State private var publicEventTarget: EventNavigationTarget?

    private var activeRegistrations: [OrganizerRegistration] {
        registrations.filter(\.isActive)
    }

    private var waitlistedRegistrations: [OrganizerRegistration] {
        registrations.filter { $0.normalizedStatus == "waitlist" }
    }

    private var pendingRegistrations: [OrganizerRegistration] {
        registrations.filter { ["pending_approval", "pending_payment"].contains($0.normalizedStatus) }
    }

    private var cancelledRegistrations: [OrganizerRegistration] {
        registrations.filter { $0.normalizedStatus == "cancelled" }
    }

    private var attendedCount: Int {
        registrations.filter { $0.checkedIn == true || $0.normalizedStatus == "attended" }.count
    }

    private var reminderCandidates: [OrganizerRegistration] {
        guard let event else { return [] }
        return registrations.filter { registration in
            guard registration.normalizedStatus == "deposit_paid", !registration.isManual else { return false }
            return (registration.priceOption?.effectiveBalancePaymentMode(fallback: event) ?? event.balancePaymentMode ?? "online") == "online"
        }
    }

    var body: some View {
        ZStack {
            Brand.background.ignoresSafeArea()
            if loading {
                ProgressView()
                    .tint(Brand.primary)
            } else if let event {
                GeometryReader { proxy in
                    ScrollView {
                        eventManagementContent(event: event, width: max(proxy.size.width - 32, 0))
                    }
                    .contentMargins(.bottom, 0, for: .scrollContent)
                }
            } else {
                EmptyState(icon: "exclamationmark.triangle", title: "Evento non disponibile", message: "Non sono riuscito a caricare questo evento.")
                    .padding(.horizontal, 20)
            }
        }
        .navigationTitle("Gestione")
        .navigationBarTitleDisplayMode(.inline)
        .navigationDestination(item: $editorRoute) { route in
            OrganizerEventEditorView(route: route)
        }
        .navigationDestination(item: $publicEventTarget) { target in
            EventDetailView(eventId: target.eventId, showAuth: $showAuth)
        }
        .sheet(isPresented: $showAddParticipant) {
            OrganizerAddParticipantSheet(eventId: eventId, meetingPoints: meetingPoints, priceOptions: priceOptions) {
                await load()
            }
        }
        .sheet(isPresented: $showCapacity) {
            OrganizerCapacitySheet(currentCapacity: event?.spotsTotal ?? 1, minimumCapacity: activeRegistrations.count) { capacity in
                if await store.updateOrganizerEventCapacity(eventId: eventId, capacity: capacity) {
                    await load()
                }
            }
        }
        .sheet(isPresented: $showBroadcast) {
            if let event {
                OrganizerBroadcastSheet(event: event, registrations: registrations, templates: templates, history: broadcastHistory) {
                    await load()
                }
            }
        }
        .sheet(isPresented: $showStatusSheet) {
            if let event {
                OrganizerEventStatusSheet(event: event) { status in
                    Task { await updateEventStatus(status) }
                }
            }
        }
        .sheet(isPresented: $showOwnerPicker) {
            if let event {
                OrganizerOwnerPickerSheet(event: event) {
                    await load()
                }
            }
        }
        .sheet(item: $selectedParticipantProfile) { registration in
            if let event {
                OrganizerParticipantProfileSheet(
                    registration: registration,
                    event: event,
                    levels: store.communityLevels,
                    history: []
                )
            }
        }
        .sheet(item: $sharePayload) { item in
            ShareSheet(activityItems: item.activityItems)
        }
        .alert(item: $confirmation) { confirmation in
            Alert(
                title: Text(confirmation.title),
                message: Text(confirmationMessage(for: confirmation)),
                primaryButton: .cancel(Text("Annulla")),
                secondaryButton: .destructive(Text(confirmation.confirmTitle)) {
                    performConfirmation(confirmation)
                }
            )
        }
        .task { await load() }
        .refreshable { await load() }
    }

    @ViewBuilder
    private func eventManagementContent(event: Event, width: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 16) {
            OrganizerManageHero(event: event) {
                publicEventTarget = EventNavigationTarget(id: event.id)
            }

            OrganizerManageQuickActions(
                onEdit: { editorRoute = OrganizerEditorRoute(mode: .edit(eventId)) },
                onDuplicate: { editorRoute = OrganizerEditorRoute(mode: .duplicate(eventId)) },
                onStatus: { showStatusSheet = true },
                onDelete: { confirmation = .deleteEvent }
            )

            if event.visibility != "public" {
                OrganizerPrivateLinkCard(
                    event: event,
                    onCopy: { shareEventLink(event) },
                    onWhatsApp: { openEventWhatsAppShare(event) }
                )
            }

            if store.isAdmin {
                OrganizerEventOwnerCard(event: event, isAdmin: true) {
                    showOwnerPicker = true
                }
            }

            OrganizerParticipationOptionsBreakdown(event: event, registrations: registrations, priceOptions: priceOptions)

            OrganizerManagePrimaryActions(
                showBalanceReminders: canShowBalanceReminderAction(for: event),
                reminderCount: reminderCandidates.count,
                onAddParticipant: { showAddParticipant = true },
                onBroadcast: { showBroadcast = true },
                onBalanceReminders: sendBalanceReminders
            )

            OrganizerManageTabBar(
                selection: $tab,
                participantCount: activeRegistrations.count,
                checkedInCount: attendedCount,
                waitlistCount: waitlistedRegistrations.count,
                pendingCount: pendingRegistrations.count
            )

            selectedManageTabContent(event: event)
        }
        .frame(width: width, alignment: .leading)
        .padding(16)
    }

    private func canShowBalanceReminderAction(for event: Event) -> Bool {
        reminderCandidates.count > 0
            || event.paymentType == "deposit"
            || priceOptions.contains { $0.effectivePaymentType(fallback: event) == "deposit" }
            || event.priceOptions.contains { $0.effectivePaymentType(fallback: event) == "deposit" }
    }

    @ViewBuilder
    private func selectedManageTabContent(event: Event) -> some View {
        switch tab {
        case 0:
            OrganizerParticipantsSection(
                event: event,
                registrations: registrations,
                meetingPoints: meetingPoints,
                priceOptions: priceOptions,
                onToggleCheckIn: toggleCheckIn,
                onStatus: updateStatus,
                onPayment: updatePayment,
                onMeetingPoint: updateMeetingPoint,
                onPriceOption: updatePriceOption,
                onOpenProfile: { selectedParticipantProfile = $0 },
                onExport: exportCSV,
                isExporting: exportingCSV
            )
        case 1:
            OrganizerCheckInSection(registrations: activeRegistrations, meetingPoints: meetingPoints, onToggleCheckIn: toggleCheckIn)
        case 2:
            OrganizerQueueSection(
                title: "Waitlist",
                emptyTitle: "Nessuno in waitlist",
                registrations: waitlistedRegistrations,
                meetingPoints: meetingPoints,
                event: event,
                priceOptions: priceOptions,
                onToggleCheckIn: toggleCheckIn,
                onStatus: updateStatus,
                onPayment: updatePayment,
                onMeetingPoint: updateMeetingPoint,
                onPriceOption: updatePriceOption,
                onOpenProfile: { selectedParticipantProfile = $0 },
                primaryTitle: "Promuovi",
                primaryAction: { updateStatus($0, status: "registered") },
                secondaryTitle: "Cancella",
                secondaryAction: { updateStatus($0, status: "cancelled") }
            )
            if !cancelledRegistrations.isEmpty {
                OrganizerQueueSection(
                    title: "Cancellati",
                    emptyTitle: "",
                    registrations: cancelledRegistrations,
                    meetingPoints: meetingPoints,
                    primaryTitle: nil,
                    primaryAction: nil,
                    secondaryTitle: nil,
                    secondaryAction: nil
                )
            }
        case 3:
            OrganizerQueueSection(
                title: "Approvazioni manuali",
                emptyTitle: "Nessuna approvazione pendente",
                registrations: pendingRegistrations,
                meetingPoints: meetingPoints,
                event: event,
                priceOptions: priceOptions,
                onToggleCheckIn: toggleCheckIn,
                onStatus: updateStatus,
                onPayment: updatePayment,
                onMeetingPoint: updateMeetingPoint,
                onPriceOption: updatePriceOption,
                onOpenProfile: { selectedParticipantProfile = $0 },
                primaryTitle: "Approva",
                primaryAction: { updateStatus($0, status: "registered") },
                secondaryTitle: "Rifiuta",
                secondaryAction: { updateStatus($0, status: "cancelled") }
            )
        case 4:
            OrganizerEventAnalyticsSection(event: event, registrations: registrations, priceOptions: priceOptions, broadcastHistory: broadcastHistory)
        default:
            OrganizerActionsSection(
                event: event,
                reminderCount: reminderCandidates.count,
                onAddParticipant: { showAddParticipant = true },
                onCapacity: { showCapacity = true },
                onBroadcast: { showBroadcast = true },
                onBalanceReminders: sendBalanceReminders,
                onExport: exportCSV,
                onShare: { shareEventLink(event) },
                onDuplicate: { editorRoute = OrganizerEditorRoute(mode: .duplicate(eventId)) },
                onStatus: { showStatusSheet = true },
                onCancelEvent: { confirmation = .cancelEvent },
                onDelete: { confirmation = .deleteEvent }
            )
        }
    }

    @MainActor
    private func load() async {
        loading = true
        async let eventTask = store.fetchOrganizerEvent(eventId: eventId, reportingErrors: false)
        async let registrationsTask = store.fetchOrganizerRegistrations(eventId: eventId, reportingErrors: false)
        async let meetingPointsTask = store.fetchOrganizerMeetingPoints(eventId: eventId, reportingErrors: false)
        async let priceOptionsTask = store.fetchOrganizerPriceOptions(eventId: eventId, reportingErrors: false)
        async let templatesTask = store.fetchBroadcastTemplates(reportingErrors: false)
        async let broadcastsTask = store.fetchEventBroadcasts(eventId: eventId, reportingErrors: false)
        event = await eventTask
        registrations = await registrationsTask
        meetingPoints = await meetingPointsTask
        priceOptions = await priceOptionsTask
        templates = await templatesTask
        broadcastHistory = await broadcastsTask
        loading = false
    }

    private func toggleCheckIn(_ registration: OrganizerRegistration) {
        Task {
            let nextCheckedIn = !(registrations.first { $0.id == registration.id }?.checkedIn ?? registration.checkedIn ?? false)
            let update = OrganizerRegistrationUpdate(checkedIn: nextCheckedIn)
            if await store.updateOrganizerRegistration(id: registration.id, updates: update, eventId: eventId) {
                if let index = registrations.firstIndex(where: { $0.id == registration.id }) {
                    registrations[index].checkedIn = nextCheckedIn
                }
            }
        }
    }

    private func updateStatus(_ registration: OrganizerRegistration, status: String) {
        if status == "cancelled" {
            confirmation = .cancelRegistration(registration)
            return
        }
        applyStatus(registration, status: status)
    }

    private func performConfirmation(_ confirmation: OrganizerEventManageConfirmation) {
        switch confirmation {
        case .deleteEvent:
            Task {
                if await store.deleteOrganizerEvent(eventId: eventId) {
                    dismiss()
                }
            }
        case .cancelEvent:
            Task {
                if await store.cancelOrganizerEvent(eventId: eventId) {
                    await load()
                }
            }
        case .cancelRegistration(let registration):
            applyStatus(registration, status: "cancelled")
        }
    }

    private func confirmationMessage(for confirmation: OrganizerEventManageConfirmation) -> String {
        switch confirmation {
        case .cancelEvent:
            let participantCount = activeRegistrations.count + waitlistedRegistrations.count + pendingRegistrations.count
            let title = event?.title.nilIfBlank ?? "questo evento"
            return "Sei sicuro di voler cancellare \"\(title)\"? Tutti i partecipanti (\(participantCount)) riceveranno una notifica e un'email di cancellazione. Le iscrizioni verranno annullate. Questa azione non può essere annullata."
        default:
            return confirmation.message
        }
    }

    private func applyStatus(_ registration: OrganizerRegistration, status: String) {
        Task {
            let update = OrganizerRegistrationUpdate(status: status)
            if await store.updateOrganizerRegistration(id: registration.id, updates: update, eventId: eventId) {
                await load()
            }
        }
    }

    private func updatePayment(_ registration: OrganizerRegistration, status: String) {
        Task {
            let update = OrganizerRegistrationUpdate(paymentStatus: status)
            if await store.updateOrganizerRegistration(id: registration.id, updates: update, eventId: eventId) {
                await load()
            }
        }
    }

    private func updateMeetingPoint(_ registration: OrganizerRegistration, meetingPointId: String?) {
        Task {
            let update = OrganizerRegistrationUpdate(meetingPointId: meetingPointId, hasMeetingPointUpdate: true)
            if await store.updateOrganizerRegistration(id: registration.id, updates: update, eventId: eventId) {
                await load()
            }
        }
    }

    private func updatePriceOption(_ registration: OrganizerRegistration, priceOptionId: String?) {
        Task {
            let update = OrganizerRegistrationUpdate(priceOptionId: priceOptionId, hasPriceOptionUpdate: true)
            if await store.updateOrganizerRegistration(id: registration.id, updates: update, eventId: eventId) {
                await load()
            }
        }
    }

    private func updateEventStatus(_ status: String) async {
        guard event?.normalizedStatus != status else { return }
        if await store.updateOrganizerEventStatus(eventId: eventId, status: status) {
            await load()
        }
    }

    private func shareEventLink(_ event: Event) {
        guard let url = event.webURL else { return }
        UIPasteboard.general.string = url.absoluteString
        store.errorMessage = "Link evento copiato negli appunti."
    }

    @MainActor
    private func openEventWhatsAppShare(_ event: Event) {
        guard let url = event.webURL else { return }
        let message = "\(event.title) - \(url.absoluteString)"
        let encoded = message.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? ""
        if let url = URL(string: "https://wa.me/?text=\(encoded)") {
            UIApplication.shared.open(url)
        }
    }

    private func sendBalanceReminders() {
        guard let event else { return }
        Task {
            if let sentCount = await store.sendBalanceReminders(event: event, recipients: registrations) {
                store.errorMessage = sentCount == 1
                    ? "Notifica saldo inviata con successo."
                    : "Notifiche saldo inviate a \(sentCount) partecipanti."
                await load()
            }
        }
    }

    private func exportCSV() {
        guard !exportingCSV else { return }
        exportingCSV = true
        let snapshot = registrations
        let meetingPointsSnapshot = meetingPoints
        let eventTitle = event?.title ?? "evento"

        DispatchQueue.global(qos: .userInitiated).async {
            do {
                let fileURL = try OrganizerParticipantCSVExporter.writeCSV(
                    eventTitle: eventTitle,
                    registrations: snapshot,
                    meetingPoints: meetingPointsSnapshot
                )
                DispatchQueue.main.async {
                    self.exportingCSV = false
                    self.sharePayload = SharePayload(activityItems: [fileURL])
                }
            } catch {
                DispatchQueue.main.async {
                    self.exportingCSV = false
                    self.store.errorMessage = "Non sono riuscito a generare il CSV. Riprova tra poco."
                }
            }
        }
    }
}

struct SharePayload: Identifiable {
    let id = UUID()
    let activityItems: [Any]
}

private enum OrganizerParticipantCSVExporter {
    static func writeCSV(eventTitle: String, registrations: [OrganizerRegistration], meetingPoints: [MeetingPoint]) throws -> URL {
        let csv = makeCSV(registrations: registrations, meetingPoints: meetingPoints)
        let filename = "partecipanti-\(safeFilenameComponent(eventTitle))-\(UUID().uuidString.prefix(8)).csv"
        let url = FileManager.default.temporaryDirectory.appendingPathComponent(filename)
        try csv.write(to: url, atomically: true, encoding: .utf8)
        return url
    }

    private static func makeCSV(registrations: [OrganizerRegistration], meetingPoints: [MeetingPoint]) -> String {
        let header = [
            "Nome",
            "Cognome",
            "Telefono",
            "Instagram",
            "Tipo",
            "Livello registrazione",
            "Formula",
            "Stato",
            "Pagamento",
            "Importo pagato",
            "Rimborso",
            "Ritrovo",
            "Check-in",
            "Registrato",
            "ID tessera",
            "Stato tessera",
            "Data di nascita",
            "Livello esperienza",
            "Esperienza trekking",
            "Frequenza attivita",
            "Grade esperienza",
            "Interessi",
            "Salute e sicurezza",
            "Note salute",
            "Farmaci salvavita",
            "Note farmaci",
            "Supporto richiesto"
        ].joined(separator: ",")
        let meetingPointNames = Dictionary(uniqueKeysWithValues: meetingPoints.map { ($0.id, $0.name ?? "") })
        let rows = registrations.filter(\.isActive).map { registration in
            let meetingPoint = registration.meetingPointId.flatMap { meetingPointNames[$0] } ?? ""
            let firstName = registration.isManual ? (registration.manualName ?? registration.displayName) : (registration.profiles?.firstName ?? "")
            let lastName = registration.isManual ? "(manuale)" : (registration.profiles?.lastName ?? "")
            let profile = registration.profiles
            return [
                (firstName.nilIfBlank ?? "-").csvEscaped,
                (lastName.nilIfBlank ?? "-").csvEscaped,
                (registration.isManual ? "-" : (profile?.phone ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.instagramDisplay ?? "-")).csvEscaped,
                (registration.isManual ? "manuale" : "utente").csvEscaped,
                (registration.isManual ? "-" : (registration.sportLevel ?? "-")).csvEscaped,
                (registration.priceOption?.displayName ?? "-").csvEscaped,
                registration.statusLabel.csvEscaped,
                (registration.paymentStatus ?? "-").csvEscaped,
                money(registration.amountPaid ?? 0).csvEscaped,
                money(registration.refundAmount ?? 0).csvEscaped,
                (meetingPoint.nilIfBlank ?? "-").csvEscaped,
                (registration.checkedIn == true ? "Si" : "No").csvEscaped,
                formattedRegistrationDate(registration.createdAt).csvEscaped,
                (registration.isManual ? "-" : (profile?.membershipId.map(String.init) ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.membershipStatus ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.birthDate ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.selfLevel ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.trekkingExperience ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.activityFrequency ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.experienceGrade.map(String.init) ?? "-")).csvEscaped,
                (registration.isManual ? "-" : formattedInterests(profile?.interests)).csvEscaped,
                (registration.isManual ? "-" : formattedHealthSafetyStatus(profile?.healthSafetyStatus)).csvEscaped,
                (registration.isManual ? "-" : (profile?.healthSafetyNotes ?? "-")).csvEscaped,
                (registration.isManual ? "-" : formattedEmergencyMedication(profile?.emergencyMedicationHas)).csvEscaped,
                (registration.isManual ? "-" : (profile?.emergencyMedicationNotes ?? "-")).csvEscaped,
                (registration.isManual ? "-" : (profile?.healthSafetyHelpNotes ?? "-")).csvEscaped
            ].joined(separator: ",")
        }
        return ([header] + rows).joined(separator: "\n")
    }

    private static func formattedHealthSafetyStatus(_ value: String?) -> String {
        switch value {
        case "none": return "Nessuna da segnalare"
        case "has_info": return "Informazioni da leggere"
        default: return "Non compilato"
        }
    }

    private static func formattedEmergencyMedication(_ value: Bool?) -> String {
        switch value {
        case true: return "Si"
        case false: return "No"
        default: return "-"
        }
    }

    private static func formattedInterests(_ value: [String]?) -> String {
        let interests = (value ?? []).filter { !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty }
        return interests.isEmpty ? "-" : interests.joined(separator: "; ")
    }

    private static func formattedRegistrationDate(_ value: String?) -> String {
        guard let date = value?.iso8601Date else { return value?.nilIfBlank ?? "-" }
        let formatter = DateFormatter()
        formatter.calendar = Calendar(identifier: .gregorian)
        formatter.locale = Locale(identifier: "it_IT")
        formatter.dateFormat = "dd/MM/yyyy HH:mm"
        return formatter.string(from: date)
    }

    private static func safeFilenameComponent(_ value: String) -> String {
        let allowed = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        let cleaned = value
            .lowercased()
            .unicodeScalars
            .map { allowed.contains($0) ? Character(String($0)) : "-" }
        let compact = String(cleaned)
            .split(separator: "-")
            .joined(separator: "-")
            .trimmingCharacters(in: CharacterSet(charactersIn: "-"))
        return compact.nilIfBlank ?? "evento"
    }
}

struct OrganizerManageHero: View {
    let event: Event
    let onOpenPublicEvent: () -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            RemoteImage(urlString: event.imageUrl)
                .frame(height: 160)
                .clipShape(RoundedRectangle(cornerRadius: 18))
            VStack(alignment: .leading, spacing: 7) {
                HStack {
                    BadgeLabel(text: event.statusStyle.label, color: event.statusStyle.background, foreground: event.statusStyle.foreground)
                    Spacer()
                    Text(event.visibility ?? "public")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.mutedForeground)
                }
                Button(action: onOpenPublicEvent) {
                    HStack(alignment: .firstTextBaseline, spacing: 8) {
                        Text(event.title)
                            .font(.system(.title2, design: .rounded, weight: .bold))
                            .foregroundStyle(Brand.foreground)
                            .multilineTextAlignment(.leading)
                            .fixedSize(horizontal: false, vertical: true)
                            .frame(maxWidth: .infinity, alignment: .leading)
