                Spacer(minLength: 0)
            }

            if hasActions {
                ViewThatFits(in: .horizontal) {
                    HStack(spacing: 8) {
                        actionButtons
                    }
                    VStack(spacing: 8) {
                        actionButtons
                    }
                }
            }
        }
        .padding(12)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
        .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
    }

    @ViewBuilder
