    }
}

struct OrganizerEventAnalyticsSection: View {
    let event: Event
    let registrations: [OrganizerRegistration]
    let priceOptions: [PriceOption]
    let broadcastHistory: [EventBroadcast]

    private var active: [OrganizerRegistration] { registrations.filter(\.isActive) }
    private var validRegistrations: [OrganizerRegistration] { registrations.filter { $0.normalizedStatus != "cancelled" } }
    private var waitlisted: [OrganizerRegistration] { registrations.filter { $0.normalizedStatus == "waitlist" } }
    private var pending: [OrganizerRegistration] { registrations.filter { ["pending_approval", "pending_payment"].contains($0.normalizedStatus) } }
    private var cancelled: [OrganizerRegistration] { registrations.filter { $0.normalizedStatus == "cancelled" } }
    private var attended: [OrganizerRegistration] { active.filter(isAttended) }
    private var noShows: [OrganizerRegistration] {
        guard isPastEvent else { return [] }
        return active.filter { !isAttended($0) }
    }
    private var capacity: Int { max(event.spotsTotal ?? active.count, 0) }
    private var availableSpots: Int { max(capacity - active.count - (event.reservedSpots ?? 0), 0) }
    private var fillRate: Int { percent(active.count, capacity) }
    private var attendanceRate: Int {
        guard !active.isEmpty else { return 0 }
        return Int(round(Double(attended.count) / Double(active.count) * 100))
    }
    private var noShowRate: Int { percent(noShows.count, active.count) }
    private var eventDate: Date? { event.date.flatMap { DateFormatter.eventDate.date(from: $0) } }
    private var isPastEvent: Bool {
        guard let eventDate else { return event.isPastOrCancelled }
        return Calendar.current.startOfDay(for: eventDate) < Calendar.current.startOfDay(for: Date())
    }
    private var trendPoints: [OrganizerAnalyticsTrendPoint] {
        let calendar = Calendar.current
        let dates = validRegistrations
            .compactMap { $0.createdAt?.isoDate }
            .map { calendar.startOfDay(for: $0) }
            .sorted()
        guard let firstDate = dates.first else { return [] }

        let today = calendar.startOfDay(for: Date())
        let eventDay = eventDate.map { calendar.startOfDay(for: $0) } ?? today
        let naturalEnd = eventDay < today ? eventDay : today
        let endDate = max(firstDate, naturalEnd)
        let countsByDay = Dictionary(grouping: dates) { $0 }.mapValues(\.count)

        var points: [OrganizerAnalyticsTrendPoint] = []
        var runningTotal = 0
        var day = firstDate
        while day <= endDate {
            runningTotal += countsByDay[day] ?? 0
            points.append(OrganizerAnalyticsTrendPoint(date: day, label: DateFormatter.analyticsDay.string(from: day), value: runningTotal))
            guard let nextDay = calendar.date(byAdding: .day, value: 1, to: day) else { break }
            day = nextDay
        }
        return points
    }
    private var statusItems: [OrganizerAnalyticsBreakdownItem] {
        [
            OrganizerAnalyticsBreakdownItem(label: "Attivi", value: active.count, color: Brand.primary),
            OrganizerAnalyticsBreakdownItem(label: "Lista attesa", value: waitlisted.count, color: Brand.warning),
            OrganizerAnalyticsBreakdownItem(label: "In sospeso", value: pending.count, color: Brand.secondary),
            OrganizerAnalyticsBreakdownItem(label: "Cancellati", value: cancelled.count, color: Brand.destructive)
        ].filter { $0.value > 0 }
    }
    private var attendanceItems: [OrganizerAnalyticsBreakdownItem] {
        [
            OrganizerAnalyticsBreakdownItem(label: "Presenti", value: attended.count, color: Brand.success),
            OrganizerAnalyticsBreakdownItem(label: "No-show", value: noShows.count, color: Brand.destructive)
        ].filter { $0.value > 0 }
    }
    private var meetingPointItems: [OrganizerAnalyticsBreakdownItem] {
        var items = event.meetingPoints.map { point in
            OrganizerAnalyticsBreakdownItem(
                label: point.name ?? "Ritrovo",
                value: active.filter { $0.meetingPointId == point.id }.count,
                color: Brand.primary
            )
        }
        let withoutMeetingPoint = active.filter { $0.meetingPointId?.nilIfBlank == nil }.count
        if withoutMeetingPoint > 0 {
            items.append(OrganizerAnalyticsBreakdownItem(label: "Senza ritrovo", value: withoutMeetingPoint, color: Brand.mutedForeground))
        }
        return items.filter { $0.value > 0 }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 14) {
            if registrations.isEmpty {
                EmptyState(icon: "chart.bar.xaxis", title: "No registration data yet", message: "Le analytics si popolano appena arrivano iscrizioni.")
            } else {
                LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
                    OrganizerAnalyticsMetricCard(
                        title: "Fill Rate",
                        value: "\(fillRate)%",
                        subtitle: "\(active.count)/\(capacity) posti · \(availableSpots) liberi",
                        icon: "percent",
                        tint: Brand.primary,
                        progress: Double(fillRate) / 100
                    )
                    OrganizerAnalyticsMetricCard(
                        title: "Total Signups",
                        value: "\(validRegistrations.count)",
                        subtitle: "\(active.count) attivi · \(priceOptions.count) prezzi",
                        icon: "person.2.fill",
                        tint: Brand.secondary
                    )
                    if isPastEvent {
                        OrganizerAnalyticsMetricCard(
                            title: "Attendance",
                            value: "\(attendanceRate)%",
                            subtitle: "\(attended.count) presenti",
                            icon: "checkmark.circle.fill",
                            tint: Brand.success,
                            progress: Double(attendanceRate) / 100
                        )
                        OrganizerAnalyticsMetricCard(
                            title: "No-Shows",
                            value: "\(noShows.count)",
                            subtitle: "\(noShowRate)% sul totale",
                            icon: "person.crop.circle.badge.xmark",
                            tint: Brand.destructive
                        )
                    } else {
                        OrganizerAnalyticsMetricCard(
                            title: "Waitlist",
                            value: "\(waitlisted.count)",
                            subtitle: "\(pending.count) in sospeso",
                            icon: "list.bullet",
                            tint: Brand.warning
                        )
                        OrganizerAnalyticsMetricCard(
                            title: "Cancelled",
                            value: "\(cancelled.count)",
                            subtitle: "\(broadcastHistory.count) broadcast",
                            icon: "xmark.circle",
                            tint: Brand.destructive
                        )
                    }
                }

                if trendPoints.count > 1 {
                    OrganizerAnalyticsPanel(title: "Registration Trend", systemImage: "chart.line.uptrend.xyaxis", subtitle: "Iscrizioni cumulative nel tempo") {
                        OrganizerAnalyticsLineChart(points: trendPoints, tint: Brand.primary)
                    }
                }

                if isPastEvent, !attendanceItems.isEmpty {
                    OrganizerAnalyticsPanel(title: "Attendance Breakdown", systemImage: "chart.pie", subtitle: "Presenti e no-show dell'evento") {
                        OrganizerAnalyticsDonut(items: attendanceItems)
                    }
                }

                if !statusItems.isEmpty {
                    OrganizerAnalyticsPanel(title: "Status Breakdown", systemImage: "slider.horizontal.3", subtitle: "Distribuzione delle iscrizioni") {
                        OrganizerAnalyticsBars(items: statusItems)
                    }
                }

                if !meetingPointItems.isEmpty {
                    OrganizerAnalyticsPanel(title: "Meeting Point Distribution", systemImage: "mappin.and.ellipse", subtitle: "Partecipanti per punto di ritrovo") {
                        OrganizerAnalyticsBars(items: meetingPointItems)
                    }
                }
            }

            if !broadcastHistory.isEmpty {
                OrganizerAnalyticsPanel(title: "Ultimi broadcast", systemImage: "megaphone", subtitle: "Comunicazioni inviate dall'organizzatore") {
                    VStack(spacing: 10) {
                        ForEach(broadcastHistory.prefix(5)) { broadcast in
                            HStack(alignment: .top, spacing: 10) {
                                Image(systemName: broadcast.channel == "whatsapp" ? "message.fill" : "bell.fill")
                                    .foregroundStyle(broadcast.channelColor)
                                    .frame(width: 24)
                                VStack(alignment: .leading, spacing: 3) {
                                    Text("\(broadcast.channelLabel) · \(broadcast.recipientsCount ?? 0) destinatari")
                                        .font(.caption.weight(.bold))
                                        .foregroundStyle(Brand.foreground)
                                    if let date = broadcast.displayDateTime {
                                        Text(date)
                                            .font(.caption2.weight(.semibold))
                                            .foregroundStyle(Brand.mutedForeground.opacity(0.75))
                                    }
                                    Text(broadcast.message)
                                        .font(.caption)
                                        .foregroundStyle(Brand.mutedForeground)
                                        .lineLimit(2)
                                }
                                Spacer()
                            }
                            .padding(12)
                            .background(Brand.muted.opacity(0.45), in: RoundedRectangle(cornerRadius: 12))
                        }
                    }
                }
            }
        }
    }

    private func isAttended(_ registration: OrganizerRegistration) -> Bool {
        registration.checkedIn == true || registration.normalizedStatus == "attended"
    }

    private func percent(_ numerator: Int, _ denominator: Int) -> Int {
        guard denominator > 0 else { return 0 }
        return Int(round(min(Double(numerator) / Double(denominator), 1) * 100))
    }
}

