private struct OrganizerAnalyticsLineChart: View {
    let points: [OrganizerAnalyticsTrendPoint]
    let tint: Color
    var valueSuffix = " iscrizioni"

    private var maxValue: Int {
        max(points.map(\.value).max() ?? 1, 1)
    }

    var body: some View {
        let chartMaxValue = maxValue
        VStack(spacing: 8) {
            Canvas { context, size in
                guard points.count > 1 else { return }
                let chartHeight = max(size.height - 8, 1)
                let chartWidth = max(size.width, 1)
                let step = chartWidth / CGFloat(max(points.count - 1, 1))

                func coordinate(for index: Int) -> CGPoint {
                    let value = CGFloat(points[index].value) / CGFloat(chartMaxValue)
                    return CGPoint(
                        x: CGFloat(index) * step,
                        y: chartHeight - (chartHeight * value)
                    )
                }

                for fraction in stride(from: CGFloat(0.25), through: CGFloat(0.75), by: CGFloat(0.25)) {
                    let y = chartHeight * fraction
                    var grid = Path()
                    grid.move(to: CGPoint(x: 0, y: y))
                    grid.addLine(to: CGPoint(x: chartWidth, y: y))
                    context.stroke(grid, with: .color(Brand.muted.opacity(0.9)), lineWidth: 1)
                }

                var line = Path()
                line.move(to: coordinate(for: 0))
                for index in points.indices.dropFirst() {
                    line.addLine(to: coordinate(for: index))
                }

                var area = line
                area.addLine(to: CGPoint(x: chartWidth, y: chartHeight))
                area.addLine(to: CGPoint(x: 0, y: chartHeight))
                area.closeSubpath()

                context.fill(area, with: .color(tint.opacity(0.14)))
                context.stroke(line, with: .color(tint), lineWidth: 3)

                for index in points.indices {
                    let point = coordinate(for: index)
                    let dot = CGRect(x: point.x - 3, y: point.y - 3, width: 6, height: 6)
                    context.fill(Path(ellipseIn: dot), with: .color(tint))
                }
            }
            .frame(height: 140)

            HStack {
                Text(points.first?.label ?? "")
                Spacer()
                Text("\(chartMaxValue)\(valueSuffix)")
                Spacer()
                Text(points.last?.label ?? "")
            }
            .font(.caption2.weight(.semibold))
            .foregroundStyle(Brand.mutedForeground)
        }
    }
}

private struct OrganizerAnalyticsComparisonBars: View {
    let items: [OrganizerAnalyticsComparisonItem]
    let firstLabel: String
    let secondLabel: String
    let firstColor: Color
    let secondColor: Color

    private var maxValue: Int {
        max(items.map { max($0.firstValue, $0.secondValue) }.max() ?? 1, 1)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack(spacing: 14) {
                OrganizerAnalyticsLegend(label: firstLabel, color: firstColor)
                OrganizerAnalyticsLegend(label: secondLabel, color: secondColor)
                Spacer(minLength: 0)
            }

            VStack(spacing: 12) {
                ForEach(items) { item in
                    VStack(alignment: .leading, spacing: 6) {
                        HStack {
                            Text(item.label)
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(Brand.foreground)
                                .lineLimit(1)
                                .minimumScaleFactor(0.72)
                            Spacer()
                            Text("\(item.firstValue)/\(item.secondValue)")
                                .font(.caption2.weight(.bold))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                        GeometryReader { proxy in
                            VStack(spacing: 4) {
                                Capsule()
                                    .fill(firstColor)
                                    .frame(width: proxy.size.width * (CGFloat(item.firstValue) / CGFloat(maxValue)), height: 7)
                                    .frame(maxWidth: .infinity, alignment: .leading)
                                Capsule()
                                    .fill(secondColor)
                                    .frame(width: proxy.size.width * (CGFloat(item.secondValue) / CGFloat(maxValue)), height: 7)
                                    .frame(maxWidth: .infinity, alignment: .leading)
                            }
                        }
                        .frame(height: 18)
                    }
                }
            }
        }
    }
}

