    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            Text(title)
                .font(.caption.weight(.bold))
                .foregroundStyle(Brand.foreground)
            HStack(alignment: .bottom, spacing: 8) {
                ForEach(items) { item in
                    VStack(spacing: 6) {
                        Text("\(item.value)")
                            .font(.caption2.weight(.bold))
                            .foregroundStyle(Brand.mutedForeground)
                            .lineLimit(1)
                        ZStack(alignment: .bottom) {
                            RoundedRectangle(cornerRadius: 7)
                                .fill(Brand.muted.opacity(0.7))
                            RoundedRectangle(cornerRadius: 7)
                                .fill(tint)
                                .frame(height: max(8, 82 * (CGFloat(item.value) / CGFloat(maxValue))))
                        }
                        .frame(height: 82)
                        Text(item.label)
                            .font(.caption2.weight(.semibold))
                            .foregroundStyle(Brand.mutedForeground)
                            .lineLimit(1)
                            .minimumScaleFactor(0.65)
                    }
                    .frame(maxWidth: .infinity)
                }
            }
        }
    }
}

private struct OrganizerAnalyticsDonut: View {
    let items: [OrganizerAnalyticsBreakdownItem]

    private var total: Int {
        items.reduce(0) { $0 + $1.value }
    }

    private var segments: [(item: OrganizerAnalyticsBreakdownItem, start: Double, end: Double)] {
        guard total > 0 else { return [] }
        var running = 0.0
        return items.map { item in
            let start = running
            running += Double(item.value) / Double(total)
            return (item, start, running)
        }
    }

    var body: some View {
        HStack(spacing: 18) {
            ZStack {
                Circle()
                    .stroke(Brand.muted.opacity(0.8), style: StrokeStyle(lineWidth: 18, lineCap: .round))
                ForEach(segments.indices, id: \.self) { index in
                    Circle()
                        .trim(from: segments[index].start, to: segments[index].end)
                        .stroke(segments[index].item.color, style: StrokeStyle(lineWidth: 18, lineCap: .round))
                        .rotationEffect(.degrees(-90))
                }
                VStack(spacing: 2) {
                    Text("\(total)")
                        .font(.title3.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                    Text("totale")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(Brand.mutedForeground)
                }
            }
            .frame(width: 116, height: 116)

            VStack(alignment: .leading, spacing: 10) {
                ForEach(items) { item in
                    HStack(spacing: 8) {
                        Circle()
                            .fill(item.color)
                            .frame(width: 9, height: 9)
                        Text(item.label)
                            .font(.caption.weight(.semibold))
                            .foregroundStyle(Brand.foreground)
                        Spacer()
                        Text("\(item.value)")
                            .font(.caption.weight(.bold))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                }
            }
        }
    }
}

private struct OrganizerAnalyticsEventRow: View {
    let event: Event

    private var taken: Int { event.spotsTaken ?? 0 }
    private var capacity: Int { max(event.spotsTotal ?? 0, 0) }
    private var available: Int { max(capacity - taken, 0) }
    private var progress: Double {
        guard capacity > 0 else { return 0 }
        return min(Double(taken) / Double(capacity), 1)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .top, spacing: 10) {
                VStack(alignment: .leading, spacing: 3) {
                    Text(event.title)
                        .font(.subheadline.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                        .lineLimit(2)
                    Text("\(formatDate(event.date))\(event.time.map { " · \(String($0.prefix(5)))" } ?? "")")
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                }
                Spacer()
                VStack(alignment: .trailing, spacing: 3) {
                    Text("\(taken)/\(capacity)")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                    Text("\(available) liberi")
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(available <= 3 ? Brand.warning : Brand.mutedForeground)
                }
            }
            ProgressView(value: progress)
                .tint(available <= 3 ? Brand.warning : Brand.primary)
        }
        .padding(.vertical, 2)
    }
}

struct OrganizerParticipantRow: View {
    let registration: OrganizerRegistration
    let event: Event
    let meetingPoint: MeetingPoint?
    let meetingPoints: [MeetingPoint]
    let priceOptions: [PriceOption]
    let onToggleCheckIn: () -> Void
    let onStatus: (String) -> Void
    let onPayment: (String) -> Void
    let onMeetingPoint: (String?) -> Void
    let onPriceOption: (String?) -> Void
    let onOpenProfile: () -> Void

    private static let noMeetingPointId = "__no_meeting_point__"
    private static let noPriceOptionId = "__no_price_option__"
    private static let enrollmentOptions = ["registered", "waitlist", "pending_approval"]
    private static let paymentOptions = ["pending", "deposit_paid", "paid", "pay_on_location", "not_required"]

    private var canOpenProfile: Bool {
        !registration.isManual && registration.userId?.nilIfBlank != nil
    }

    private var selectedEnrollmentStatus: String? {
        switch registration.normalizedStatus {
        case "waitlist", "pending_approval":
            return registration.normalizedStatus
        case "registered", "deposit_paid", "paid", "attended", "pending_payment":
            return "registered"
        default:
            return nil
        }
    }

    private var selectedPaymentStatus: String {
        if let payment = registration.paymentStatus?.nilIfBlank { return payment }
        if registration.normalizedStatus == "deposit_paid" { return "deposit_paid" }
        if registration.normalizedStatus == "paid" { return "paid" }
        return "pending"
    }

    private var selectedMeetingPointId: String {
        registration.meetingPointId?.nilIfBlank ?? Self.noMeetingPointId
    }

    private var selectedPriceOptionId: String {
        registration.priceOption?.id.nilIfBlank ?? Self.noPriceOptionId
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack(alignment: .top, spacing: 12) {
                OrganizerProfileAvatar(profile: registration.profiles, name: registration.displayName)
                VStack(alignment: .leading, spacing: 5) {
                    Text(registration.displayName)
                        .font(.subheadline.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                        .lineLimit(2)

                    VStack(alignment: .leading, spacing: 3) {
                        if let phone = registration.profiles?.phone?.nilIfBlank {
                            Label(phone, systemImage: "phone")
                        }
                        if registration.isActive,
                           let instagram = registration.profiles?.instagramDisplay,
                           let url = registration.profiles?.instagramURL {
                            Button {
                                UIApplication.shared.open(url)
                            } label: {
                                Label(instagram, systemImage: "camera")
                            }
                            .buttonStyle(.plain)
                            .foregroundStyle(Brand.primary)
                        }
                        if let meetingPoint {
                            Label(meetingPoint.name ?? "Ritrovo", systemImage: "mappin.and.ellipse")
                        }
                        if let priceOption = registration.priceOption?.displayName.nilIfBlank {
                            Label(priceOption, systemImage: "ticket")
                        }
                    }
                    .font(.caption)
                    .foregroundStyle(Brand.mutedForeground)
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                Spacer()
                VStack(alignment: .trailing, spacing: 8) {
                    BadgeLabel(text: registration.statusLabel, color: registration.statusColor.opacity(0.14), foreground: registration.statusColor)
                    Menu {
                        Section("Azioni") {
                            Button {
                                onOpenProfile()
                            } label: {
                                participantMenuLabel("Apri profilo", systemImage: "person.crop.circle")
                            }
                            .disabled(!canOpenProfile)

                            Button {
                                onStatus("no_show")
                            } label: {
                                participantMenuLabel("Segna come no-show", systemImage: "person.crop.circle.badge.exclamationmark", selected: registration.normalizedStatus == "no_show")
                            }

                            Button(role: .destructive) {
                                onStatus("cancelled")
                            } label: {
                                participantMenuLabel("Rimuovi dall'evento", systemImage: "trash")
                            }
                        }

                        Section("Iscrizione") {
                            ForEach(Self.enrollmentOptions, id: \.self) { status in
                                Button {
                                    onStatus(status)
                                } label: {
                                    participantMenuLabel(enrollmentMenuTitle(status), systemImage: "person.badge.key", selected: selectedEnrollmentStatus == status)
                                }
                            }
                        }

                        Section("Pagamento") {
                            ForEach(Self.paymentOptions, id: \.self) { status in
                                Button {
                                    onPayment(status)
                                } label: {
                                    participantMenuLabel(paymentMenuTitle(status), systemImage: "creditcard", selected: selectedPaymentStatus == status)
                                }
                            }
                        }

                        Section("Punto di ritrovo") {
                            Button {
                                onMeetingPoint(nil)
                            } label: {
                                participantMenuLabel("Nessun ritrovo", systemImage: "mappin.slash", selected: selectedMeetingPointId == Self.noMeetingPointId)
                            }
                            ForEach(Array(meetingPoints.enumerated()), id: \.element.id) { index, point in
                                Button {
                                    onMeetingPoint(point.id)
                                } label: {
                                    participantMenuLabel(meetingPointMenuTitle(point, index: index), systemImage: "mappin.and.ellipse", selected: selectedMeetingPointId == point.id)
                                }
                            }
                        }

                        Section("Formula prezzo") {
                            Button {
                                onPriceOption(nil)
                            } label: {
                                participantMenuLabel("Nessuna formula", systemImage: "ticket", selected: selectedPriceOptionId == Self.noPriceOptionId)
                            }
                            ForEach(priceOptions) { option in
                                Button {
                                    onPriceOption(option.id)
                                } label: {
                                    participantMenuLabel(option.displayName, systemImage: "ticket", selected: selectedPriceOptionId == option.id)
                                }
                            }
                        }
                    } label: {
                        Image(systemName: "ellipsis.circle")
                            .font(.title3.weight(.semibold))
                            .foregroundStyle(Brand.primary)
                            .frame(width: 34, height: 34)
                            .background(Brand.muted.opacity(0.55), in: Circle())
                    }
                    .accessibilityLabel("Azioni partecipante")
                }
            }

            let chips = participantChips
            if !chips.isEmpty {
                FlowLayout(spacing: 6, rowSpacing: 6) {
                    ForEach(chips) { chip in
                        OrganizerParticipantChip(chip: chip)
                    }
                }
            }
        }
        .padding(12)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
        .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
        .contentShape(Rectangle())
        .onTapGesture {
            if canOpenProfile {
                onOpenProfile()
            }
        }
        .accessibilityHint(Text(canOpenProfile ? "Tocca per aprire il profilo partecipante" : ""))
    }

    @ViewBuilder
    private func participantMenuLabel(_ title: String, systemImage: String, selected: Bool = false) -> some View {
        Label {
            Text(title)
        } icon: {
            Image(systemName: selected ? "checkmark.circle.fill" : systemImage)
        }
    }

    private func enrollmentMenuTitle(_ status: String) -> String {
        switch status {
        case "registered": return "Iscritto"
        case "waitlist": return "In lista d'attesa"
        case "pending_approval": return "In attesa di approvazione"
        default: return status.organizerStatusLabel
        }
    }

    private func paymentMenuTitle(_ status: String) -> String {
        switch status {
        case "pending": return "In attesa pagamento"
        case "deposit_paid": return "Acconto effettuato"
        case "paid": return "Pagamento effettuato"
        case "pay_on_location": return "Pagamento in loco"
        case "not_required": return "Pagamento non richiesto"
        default: return status.paymentStatusLabel
        }
    }

    private func meetingPointMenuTitle(_ point: MeetingPoint, index: Int) -> String {
        "Punto \(index + 1) - \(point.name ?? "Ritrovo")"
    }

    private var participantChips: [OrganizerParticipantChipModel] {
        var chips: [OrganizerParticipantChipModel] = []
        let specialRequests = registration.specialRequestAnswers(for: event)

        let levelValue = registration.isManual ? "-" : registration.profiles?.experienceGrade.map(String.init) ?? "-"
        chips.append(.init(text: "Liv. (1/5): \(levelValue)", icon: "chart.bar.fill", tint: Brand.mutedForeground, fill: Brand.muted.opacity(0.85)))

        let paymentBadge = registration.participantPaymentBadge(for: event)
        let paymentTint = paymentBadge.needsAttention ? Brand.warning : Brand.success
        chips.append(.init(text: paymentBadge.label, icon: "creditcard", tint: paymentTint, fill: paymentTint.opacity(0.12)))

        if registration.profiles?.healthSafetyStatus == "has_info" {
            chips.append(.init(text: "Salute", icon: "cross.case.fill", tint: Brand.warning, fill: Brand.warning.opacity(0.12)))
        }

        if !specialRequests.isEmpty {
            chips.append(.init(text: "Rich. speciale", icon: "exclamationmark.bubble.fill", tint: Brand.warning, fill: Brand.warning.opacity(0.12)))
        }
        return chips
    }
}

