struct OrganizerAddParticipantSheet: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let eventId: String
    let meetingPoints: [MeetingPoint]
    let priceOptions: [PriceOption]
    let onSaved: () async -> Void
    @State private var mode = 0
    @State private var manualName = ""
    @State private var manualLevel = "none"
    @State private var searchQuery = ""
    @State private var searchResults: [OrganizerSearchProfile] = []
    @State private var selectedProfile: OrganizerSearchProfile?
    @State private var meetingPointId = ""
    @State private var priceOptionId = ""
    @State private var paymentStatus = "not_required"
    @State private var saving = false

    var body: some View {
        NavigationStack {
            Form {
                Picker("Modalita", selection: $mode) {
                    Text("Manuale").tag(0)
                    Text("Profilo").tag(1)
                }
                .pickerStyle(.segmented)

                Section("Partecipante") {
                    if mode == 0 {
                        TextField("Nome partecipante", text: $manualName)
                            .editableTextInput()
                        Picker("Livello", selection: $manualLevel) {
                            Text("Nessuno").tag("none")
                            Text("Principiante").tag("beginner")
                            Text("Intermedio").tag("intermediate")
                            Text("Avanzato").tag("advanced")
                        }
                        .pickerStyle(.menu)
                        .editableControlSurface()
                    } else {
                        TextField("Cerca per nome o email", text: $searchQuery)
                            .textInputAutocapitalization(.words)
                            .editableTextInput()
                        if let selectedProfile {
                            OrganizerSearchProfileRow(profile: selectedProfile, selected: true)
                            Button("Cambia profilo") {
                                self.selectedProfile = nil
                                searchQuery = ""
                                searchResults = []
                            }
                        } else {
                            ForEach(searchResults) { profile in
                                Button {
                                    selectedProfile = profile
                                    searchQuery = profile.displayName
                                    searchResults = []
                                    dismissKeyboard()
                                } label: {
                                    OrganizerSearchProfileRow(profile: profile, selected: false)
                                }
                                .buttonStyle(.plain)
                            }
                        }
                    }
                }

                Section("Dettagli") {
                    if !priceOptions.isEmpty {
                        Picker("Formula", selection: $priceOptionId) {
                            ForEach(priceOptions) { option in
                                Text(option.displayName).tag(option.id)
                            }
                        }
                        .pickerStyle(.menu)
                        .editableControlSurface()
                    }
                    Picker("Ritrovo", selection: $meetingPointId) {
                        Text("Nessuno").tag("")
                        ForEach(meetingPoints) { point in
                            Text(point.name ?? "Ritrovo").tag(point.id)
                        }
                    }
                    .pickerStyle(.menu)
                    .editableControlSurface()
                    Picker("Pagamento", selection: $paymentStatus) {
                        ForEach(["deposit_paid", "paid", "pending", "pay_on_location", "not_required", "failed"], id: \.self) {
                            Text($0.paymentStatusLabel).tag($0)
                        }
                    }
                    .pickerStyle(.menu)
                    .editableControlSurface()
                }
            }
            .navigationTitle("Aggiungi")
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Annulla") { dismiss() }
                }
                ToolbarItem(placement: .confirmationAction) {
                    Button(saving ? "Salvo..." : "Salva") {
                        Task { await save() }
                    }
                    .disabled(!canSave || saving)
                }
            }
            .task(id: searchQuery) {
                guard mode == 1, selectedProfile == nil, searchQuery.count >= 2 else {
                    searchResults = []
                    return
                }
                try? await Task.sleep(nanoseconds: 250_000_000)
                guard selectedProfile == nil else { return }
                searchResults = await store.searchOrganizerProfiles(searchQuery)
            }
            .onChange(of: mode) { _, newMode in
                if newMode == 0 {
                    searchQuery = ""
                    searchResults = []
                    selectedProfile = nil
                }
            }
            .onAppear {
                if priceOptionId.isEmpty, let firstOption = priceOptions.first {
                    priceOptionId = firstOption.id
                }
            }
        }
    }

    private var canSave: Bool {
        if !priceOptions.isEmpty, priceOptionId.isEmpty { return false }
        if mode == 0 { return manualName.nilIfBlank != nil }
        return selectedProfile != nil
    }

    private func save() async {
        saving = true
        let mp = meetingPointId.nilIfBlank
        let selectedPriceOptionId = priceOptions.isEmpty ? nil : priceOptionId.nilIfBlank
        let ok: Bool
        if mode == 0 {
            ok = await store.addManualParticipant(eventId: eventId, name: manualName, level: manualLevel == "none" ? nil : manualLevel, meetingPointId: mp, priceOptionId: selectedPriceOptionId, paymentStatus: paymentStatus)
        } else if let selectedProfile {
            ok = await store.addExistingParticipant(eventId: eventId, userId: selectedProfile.id, meetingPointId: mp, priceOptionId: selectedPriceOptionId, paymentStatus: paymentStatus)
        } else {
            ok = false
        }
        if ok {
            await onSaved()
            dismiss()
        }
        saving = false
    }
}

