                                    .foregroundStyle(Brand.mutedForeground)
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 6)
                            }
                            Button("Aggiungi staff") {
                                draft.staffMembers.append(OrganizerEventStaffDraft())
                            }
                            .buttonStyle(SecondaryButtonStyle())
                        }

                        OrganizerEditorSection(title: "Lista attrezzatura") {
                            if !equipmentTemplates.isEmpty {
                                Menu("Carica template attrezzatura") {
                                    ForEach(equipmentTemplates) { template in
                                        Button("\(template.name) (\(template.sortedItems.count) elementi)") {
                                            draft.equipmentItems = template.sortedItems.map(OrganizerEquipmentItemDraft.init(templateItem:))
                                        }
                                    }
                                }
                                .buttonStyle(SecondaryButtonStyle())
                            }
                            ForEach(draft.equipmentItems) { item in
                                OrganizerEquipmentItemEditor(item: equipmentItemBinding(for: item.id)) {
                                    draft.equipmentItems.removeAll { $0.id == item.id }
                                }
                            }
                            if draft.equipmentItems.isEmpty {
                                Text("Nessun elemento. Seleziona un template o aggiungi manualmente.")
                                    .font(.caption)
                                    .foregroundStyle(Brand.mutedForeground)
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 6)
                            }
                            Button("Aggiungi oggetto") {
                                draft.equipmentItems.append(OrganizerEquipmentItemDraft())
                            }
                            .buttonStyle(SecondaryButtonStyle())
                        }

                        OrganizerEditorSection(title: "Disponibilità auto") {
                            Text("Chiedi ai partecipanti se possono guidare fino al luogo dell'evento.")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                            Toggle("Chiedi disponibilita auto", isOn: $draft.askCarAvailability)
                                .editableControlSurface()
                            if draft.askCarAvailability {
                                VStack(alignment: .leading, spacing: 4) {
                                    Text("Durante la registrazione, i partecipanti vedranno: \"Saresti disposto a prendere la macchina?\"")
                                    Text("Opzioni: Si · Preferirei di no · Non sono automunito")
                                        .font(.caption2)
                                }
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                                .padding(12)
                                .background(Brand.muted.opacity(0.45), in: RoundedRectangle(cornerRadius: 14))
                            }
                        }

                        OrganizerEditorSection(title: "Richieste speciali") {
                            Text("Aggiungi domande personalizzate che i partecipanti devono compilare durante la registrazione.")
                                .font(.caption)
                                .foregroundStyle(Brand.mutedForeground)
                            ForEach(draft.additionalFields) { field in
                                OrganizerAdditionalFieldEditor(field: additionalFieldBinding(for: field.id)) {
                                    draft.additionalFields.removeAll { $0.id == field.id }
                                }
                            }
                            if draft.additionalFields.isEmpty {
                                Text("Nessun campo personalizzato.")
                                    .font(.caption)
                                    .foregroundStyle(Brand.mutedForeground)
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 6)
                            }
                            Button("Aggiungi campo iscrizione") {
                                draft.additionalFields.append(OrganizerAdditionalFieldDraft())
                            }
                            .buttonStyle(SecondaryButtonStyle())
                        }
                        }
                        .padding(16)
                        .padding(.bottom, 24)
                        .frame(width: proxy.size.width, alignment: .leading)
                    }
                    .clipped()
                    .scrollDismissesKeyboard(.interactively)
                }
            }
        }
        .roundedInlineNavigationTitle(route.title)
        .toolbar(.hidden, for: .tabBar)
        .toolbar {
            ToolbarItemGroup(placement: .topBarTrailing) {
                Button("Anteprima") {
                    showPreview = true
                }
                .disabled(saving || loading || uploadingImages)

                Button(saveButtonTitle) {
                    Task { await save() }
                }
                .disabled(saving || loading || uploadingImages)
            }
            ToolbarItemGroup(placement: .keyboard) {
                Spacer()
                Button("Fine") {
                    dismissKeyboard()
                }
            }
        }
        .sheet(isPresented: $showPreview) {
            OrganizerEventDraftPreviewSheet(
                draft: draft,
                categories: store.categories,
                directURL: route.mode.existingEventId.flatMap { URL(string: "\(ScampagnateConfig.stripeOrigin)/event/\($0)") }
            )
            .presentationDetents([.large])
        }
        .task { await load() }
        .onChange(of: selectedPhoto) { _, item in
            guard let item else { return }
            Task { await prepareCoverCrop(item) }
        }
        .onChange(of: selectedGalleryPhotos) { _, items in
            guard !items.isEmpty else { return }
            Task { await prepareGalleryUploadQueue(items) }
        }
        .sheet(item: $activeImageCrop) { crop in
            OrganizerImageCropView(
                image: crop.image,
                kind: crop.kind,
                onSubmit: { result in
                    Task { await handleImageCrop(result, crop: crop) }
                },
                onCancel: {
                    activeImageCrop = nil
                    pendingGalleryPhotos = []
                    selectedPhoto = nil
                    selectedGalleryPhotos = []
                    uploadingImages = false
                }
            )
        }
        .onChange(of: draft.fitScoreMainCategory) { _, category in
            draft.fitScoreSecondaryCategories.removeAll { $0 == category }
            if draft.fitScoreSecondaryCategories.count > 2 {
                draft.fitScoreSecondaryCategories = Array(draft.fitScoreSecondaryCategories.prefix(2))
            }
        }
        .onChange(of: draft.spotsTotal) { _, total in
            if draft.reservedSpots > total {
                draft.reservedSpots = max(total, 0)
            }
        }
        .onChange(of: draft.paymentType) { _, paymentType in
            if paymentType == "free" {
                draft.price = 0
                draft.deposit = 0
            } else if paymentType != "deposit" {
                draft.deposit = 0
            }
        }
    }

    private var saveButtonTitle: String {
        if uploadingImages { return "Carico..." }
        if saving { return "Salvo..." }
        return "Salva"
    }

    private var closingSentenceOptions: [String] {
        var values = store.eventClosingSentences
        if let selected = draft.closingSentence.nilIfBlank, !values.contains(selected) {
            values.append(selected)
        }
        return values
    }

    private func load() async {
        loading = true
        async let badgesTask = store.fetchSpecialBadges(reportingErrors: false)
        async let equipmentTemplatesTask = store.fetchEquipmentTemplates(reportingErrors: false)
        specialBadges = await badgesTask
        allBadges = store.allBadges.isEmpty ? specialBadges : store.allBadges
        equipmentTemplates = await equipmentTemplatesTask
        await store.refreshEventClosingSentences(reportingErrors: false)
        switch route.mode {
        case .create:
            break
        case .proposal(let proposal):
            draft = OrganizerEventDraft(proposal: proposal)
        case .edit(let eventId), .duplicate(let eventId):
            async let eventTask = store.fetchOrganizerEvent(eventId: eventId, reportingErrors: false)
            async let pointsTask = store.fetchOrganizerMeetingPoints(eventId: eventId, reportingErrors: false)
            async let staffTask = store.fetchOrganizerEventStaff(eventId: eventId, reportingErrors: false)
            async let pricesTask = store.fetchOrganizerPriceOptions(eventId: eventId, reportingErrors: false)
            async let specialBadgeIdsTask = store.fetchOrganizerSpecialBadgeIds(eventId: eventId, reportingErrors: false)
            if let event = await eventTask {
                let points = await pointsTask
                let staff = await staffTask
                let prices = await pricesTask
                let badges = await specialBadgeIdsTask
                draft = OrganizerEventDraft(event: event, meetingPoints: points, staffMembers: staff, priceOptions: prices, specialBadgeIds: badges, duplicate: route.mode.isDuplicate)
            }
        }
        loading = false
    }

    private func save() async {
        guard !saving else { return }
        guard !uploadingImages else {
            validationMessage = "Attendi il completamento del caricamento immagini."
            return
        }
        let messages = draft.validationMessages
        validationMessage = messages.isEmpty ? nil : "Completa prima:\n" + messages.map { "- \($0)" }.joined(separator: "\n")
        guard messages.isEmpty else { return }
        saving = true
        defer { saving = false }
        let existingId: String?
        if case .edit(let eventId) = route.mode {
            existingId = eventId
        } else {
            existingId = nil
        }
        if await store.saveOrganizerEventDraft(draft, existingEventId: existingId) != nil {
            if case .proposal(let proposal) = route.mode {
                _ = await store.updateActivityProposal(id: proposal.id, status: "converted")
            }
            dismiss()
        }
    }

    @MainActor
    private func prepareCoverCrop(_ item: PhotosPickerItem) async {
        selectedPhoto = nil
        guard let data = try? await item.loadTransferable(type: Data.self),
              let image = UIImage(data: data) else { return }
        activeImageCrop = OrganizerImageCropDraft(image: image, kind: .coverHero)
    }

    @MainActor
    private func prepareGalleryUploadQueue(_ items: [PhotosPickerItem]) async {
        let remaining = max(0, 5 - draft.galleryImageURLs.count)
        pendingGalleryPhotos = Array(items.prefix(remaining))
        selectedGalleryPhotos = []
        await uploadNextGalleryImage()
    }

    @MainActor
    private func uploadNextGalleryImage() async {
        guard activeImageCrop == nil, !pendingGalleryPhotos.isEmpty else { return }
        let item = pendingGalleryPhotos.removeFirst()
        guard let data = try? await item.loadTransferable(type: Data.self),
              let image = UIImage(data: data) else {
            await uploadNextGalleryImage()
            return
        }
        await uploadGalleryImage(image)
        await uploadNextGalleryImage()
    }

    @MainActor
    private func handleImageCrop(_ result: OrganizerImageCropResult, crop: OrganizerImageCropDraft) async {
        activeImageCrop = nil
        uploadingImages = true
        defer { uploadingImages = false }
        if let url = await store.uploadOrganizerEventImage(data: result.data, fileExtension: "jpg") {
            switch crop.kind {
            case .coverHero:
                draft.imageUrl = url
                draft.homeCardImageUrl = ""
            }
        }
    }

    @MainActor
    private func uploadGalleryImage(_ image: UIImage) async {
        guard let data = image.resizedJPEGData() else { return }
        uploadingImages = true
        if let url = await store.uploadOrganizerEventImage(data: data, fileExtension: "jpg"),
           !draft.galleryImageURLs.contains(url) {
            draft.galleryImageURLs.append(url)
        }
        uploadingImages = false
    }

    private func toggleValue(_ value: String, in values: inout [String]) {
        if values.contains(value) {
            values.removeAll { $0 == value }
        } else {
            values.append(value)
        }
    }

    private func meetingPointBinding(for id: UUID) -> Binding<OrganizerMeetingPointDraft> {
        Binding {
            draft.meetingPoints.first { $0.id == id } ?? OrganizerMeetingPointDraft()
        } set: { updated in
            guard let index = draft.meetingPoints.firstIndex(where: { $0.id == id }) else { return }
            draft.meetingPoints[index] = updated
        }
    }

    private func staffMemberBinding(for id: UUID) -> Binding<OrganizerEventStaffDraft> {
        Binding {
            draft.staffMembers.first { $0.id == id } ?? OrganizerEventStaffDraft()
        } set: { updated in
            guard let index = draft.staffMembers.firstIndex(where: { $0.id == id }) else { return }
            draft.staffMembers[index] = updated
        }
    }

    private func equipmentItemBinding(for id: UUID) -> Binding<OrganizerEquipmentItemDraft> {
        Binding {
            draft.equipmentItems.first { $0.id == id } ?? OrganizerEquipmentItemDraft()
        } set: { updated in
            guard let index = draft.equipmentItems.firstIndex(where: { $0.id == id }) else { return }
            draft.equipmentItems[index] = updated
        }
    }

    private func additionalFieldBinding(for id: UUID) -> Binding<OrganizerAdditionalFieldDraft> {
        Binding {
            draft.additionalFields.first { $0.id == id } ?? OrganizerAdditionalFieldDraft()
        } set: { updated in
            guard let index = draft.additionalFields.firstIndex(where: { $0.id == id }) else { return }
            draft.additionalFields[index] = updated
        }
    }
}

private struct OrganizerEventDraftPreviewSheet: View {
    @Environment(\.dismiss) private var dismiss
    let draft: OrganizerEventDraft
    let categories: [EventCategory]
    let directURL: URL?
    @State private var descriptionExpanded = false

    private var category: EventCategory? {
        categories.first { $0.id == draft.categoryId }
    }

    private var manualBadgeLabels: [String] {
        draft.manualBadges.map { badgeId in
            OrganizerEventDraft.manualBadgeOptions.first { $0.id == badgeId }?.label ?? badgeId
        }
    }

    private var allBadgeLabels: [String] {
        manualBadgeLabels + [draft.customBadge.nilIfBlank].compactMap { $0 }
    }

    private var descriptionPreviewText: String {
        EventDescriptionHTML.cleanStoredHTML(from: draft.description).htmlPlainText.nilIfBlank ?? "Nessuna descrizione disponibile"
    }

    var body: some View {
        VStack(spacing: 0) {
            previewHeader

            ScrollView {
                VStack(alignment: .leading, spacing: 18) {
                    hero
                    quickFacts
                    previewDescription
                    meetingPoints
                    equipment
                    pricing
                    registrationFields
                }
                .padding(16)
                .frame(maxWidth: .infinity, alignment: .leading)
            }
        }
        .background(Brand.background)
    }

    private var previewHeader: some View {
        HStack(alignment: .center, spacing: 12) {
            Text("Anteprima evento")
                .font(.system(.title3, design: .rounded, weight: .bold))
                .foregroundStyle(Brand.foreground)
            Spacer(minLength: 12)
            Button {
                dismiss()
            } label: {
                Text("Chiudi")
                    .font(.subheadline.weight(.bold))
                    .foregroundStyle(Brand.primary)
                    .padding(.horizontal, 10)
                    .frame(minHeight: 44)
            }
            .buttonStyle(.plain)
            .contentShape(Rectangle())
            .accessibilityLabel("Chiudi anteprima evento")
        }
        .padding(.horizontal, 16)
        .padding(.top, 16)
        .padding(.bottom, 10)
        .background(Brand.background)
    }

    @ViewBuilder
    private var titleBlock: some View {
        let title = draft.title.nilIfBlank ?? "Titolo evento"
        if let directURL {
            Button {
                UIApplication.shared.open(directURL)
            } label: {
                HStack(alignment: .top, spacing: 8) {
                    Text(title)
                        .font(.system(.title3, design: .rounded, weight: .bold))
                        .foregroundStyle(Brand.foreground)
                        .lineLimit(3)
                        .multilineTextAlignment(.leading)
                        .fixedSize(horizontal: false, vertical: true)
                        .frame(maxWidth: .infinity, alignment: .leading)
                    Image(systemName: "arrow.up.forward")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.primary)
                        .padding(.top, 5)
                }
                .frame(maxWidth: .infinity, alignment: .leading)
            }
            .buttonStyle(.plain)
            .accessibilityLabel("Apri link diretto evento")
        } else {
            Text(title)
                .font(.system(.title3, design: .rounded, weight: .bold))
                .foregroundStyle(Brand.foreground)
                .lineLimit(3)
                .multilineTextAlignment(.leading)
                .fixedSize(horizontal: false, vertical: true)
                .frame(maxWidth: .infinity, alignment: .leading)
        }
    }

    private var hero: some View {
        VStack(alignment: .leading, spacing: 12) {
            RemoteImage(urlString: draft.imageUrl)
                .frame(maxWidth: .infinity)
                .frame(height: 190)
                .clipShape(RoundedRectangle(cornerRadius: 20))
                .overlay(alignment: .topLeading) {
                    HStack(spacing: 6) {
                        BadgeLabel(text: statusLabel, color: statusColor.opacity(0.16), foreground: statusColor)
                        BadgeLabel(text: draft.visibility == "private" ? "Solo link" : "Pubblico", color: Brand.muted, foreground: Brand.mutedForeground)
                    }
                    .padding(12)
                }

            VStack(alignment: .leading, spacing: 8) {
                titleBlock

                VStack(alignment: .leading, spacing: 6) {
                    Label("\(formatLongDate(draft.date)) · \(draft.time.nilIfBlank ?? "Ora da definire")", systemImage: "calendar")
                    Label(draft.locationLabel.nilIfBlank ?? draft.location.nilIfBlank ?? "Luogo da definire", systemImage: "mappin.and.ellipse")
                    Label(categoryLabel(category), systemImage: "tag")
                }
                .font(.subheadline)
                .foregroundStyle(Brand.mutedForeground)
                .lineLimit(2)
                .fixedSize(horizontal: false, vertical: true)

                if !allBadgeLabels.isEmpty {
                    LazyVGrid(columns: [GridItem(.adaptive(minimum: 108), spacing: 6)], alignment: .leading, spacing: 6) {
                        ForEach(allBadgeLabels, id: \.self) { badge in
                            BadgeLabel(text: badge, color: Brand.primary.opacity(0.12), foreground: Brand.primary)
                        }
                    }
                }
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private var quickFacts: some View {
        LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 10) {
            OrganizerDraftPreviewFact(icon: "person.2", title: "Posti", value: "\(draft.spotsTotal)")
            if let difficulty = draft.difficulty.nilIfBlank {
                OrganizerDraftPreviewFact(icon: "mountain.2", title: "Difficoltà", value: "Livello \(difficulty)")
            }
            if let duration = draft.duration.nilIfBlank {
                OrganizerDraftPreviewFact(icon: "clock", title: "Durata", value: duration)
            }
            if let distance = draft.distance.nilIfBlank {
                OrganizerDraftPreviewFact(icon: "figure.hiking", title: "Distanza", value: distance.lowercased().contains("km") ? distance : "\(distance) km")
            }
            if let elevation = draft.elevation.nilIfBlank {
                OrganizerDraftPreviewFact(icon: "arrow.up.right", title: "Dislivello", value: elevation.lowercased().contains("m") ? elevation : "\(elevation) m")
            }
        }
        .frame(maxWidth: .infinity)
    }

    private var previewDescription: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionTitle("L'esperienza")
            Text(descriptionPreviewText)
                .font(.subheadline)
                .foregroundStyle(Brand.mutedForeground)
                .lineLimit(descriptionExpanded ? nil : 10)
                .fixedSize(horizontal: false, vertical: true)
            if descriptionPreviewText.count > 700 {
                Button(descriptionExpanded ? "Mostra meno" : "Leggi tutto") {
                    withAnimation(.easeInOut(duration: 0.2)) {
                        descriptionExpanded.toggle()
                    }
                }
                .font(.subheadline.weight(.bold))
                .foregroundStyle(Brand.primary)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .padding(14)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 18))
        .overlay(RoundedRectangle(cornerRadius: 18).stroke(Brand.muted, lineWidth: 1))
    }

    @ViewBuilder
    private var meetingPoints: some View {
        let visiblePoints = draft.meetingPoints.filter { $0.name.nilIfBlank != nil || $0.location.nilIfBlank != nil }
        if !visiblePoints.isEmpty {
            VStack(alignment: .leading, spacing: 10) {
                SectionTitle("Ritrovi")
                ForEach(visiblePoints) { point in
                    VStack(alignment: .leading, spacing: 3) {
                        Text(point.name.nilIfBlank ?? "Punto di ritrovo")
                            .font(.subheadline.weight(.bold))
                            .foregroundStyle(Brand.foreground)
                        Text("\(point.time.nilIfBlank ?? draft.time) · \(point.location.nilIfBlank ?? draft.location)")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                        if let notes = point.notes.nilIfBlank {
                            Text(notes)
                                .font(.caption2)
                                .foregroundStyle(Brand.mutedForeground)
                        }
                    }
                    .padding(12)
                    .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
    }

    @ViewBuilder
    private var equipment: some View {
        let visibleItems = draft.equipmentItems.filter { $0.name.nilIfBlank != nil }
        if !visibleItems.isEmpty {
            VStack(alignment: .leading, spacing: 10) {
                SectionTitle("Attrezzatura")
                ForEach(visibleItems) { item in
                    HStack(alignment: .top, spacing: 10) {
                        Image(systemName: item.isMandatory ? "checkmark.seal.fill" : "circle")
                            .foregroundStyle(item.isMandatory ? Brand.primary : Brand.mutedForeground)
                        VStack(alignment: .leading, spacing: 2) {
                            Text(item.name.nilIfBlank ?? "Oggetto")
                                .font(.subheadline.weight(.semibold))
                                .foregroundStyle(Brand.foreground)
                            if let notes = item.notes.nilIfBlank {
                                Text(notes)
                                    .font(.caption)
                                    .foregroundStyle(Brand.mutedForeground)
                            }
                        }
                    }
                    .padding(12)
                    .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                    .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
    }

    private var pricing: some View {
        VStack(alignment: .leading, spacing: 10) {
            SectionTitle("Formule")
            ForEach(draft.priceOptions) { option in
                VStack(alignment: .leading, spacing: 4) {
                    Text(option.name.priceOptionDisplayName)
                        .font(.subheadline.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                    Text(paymentSummary(for: option))
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                    if option.eligibleGroup != "all" {
                        Text(eligibilityLabel(for: option.eligibleGroup))
                            .font(.caption2.weight(.semibold))
                            .foregroundStyle(Brand.primary)
                    }
                }
                .padding(12)
                .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
            }
        }
    }

    @ViewBuilder
    private var registrationFields: some View {
        let visibleFields = draft.additionalFields.filter { $0.label.nilIfBlank != nil }
        if !visibleFields.isEmpty {
            VStack(alignment: .leading, spacing: 10) {
                SectionTitle("Domande iscrizione")
                ForEach(visibleFields) { field in
                    Text("\(field.required ? "* " : "")\(field.label)")
                        .font(.subheadline)
                        .foregroundStyle(Brand.foreground)
                        .padding(12)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
                        .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
                }
            }
        }
    }

    private var statusLabel: String {
        switch draft.status {
        case "draft": return "Non pubblicato"
        case "upcoming": return "In arrivo"
        case "closed": return "Chiuso"
        case "full": return "Sold out"
        case "cancelled": return "Annullato"
        default: return "Aperto"
        }
    }

    private var statusColor: Color {
        switch draft.status {
        case "cancelled", "closed": return Brand.destructive
        case "draft": return Brand.mutedForeground
        case "upcoming", "full": return Brand.warning
        default: return Brand.success
        }
    }

    private func paymentSummary(for option: OrganizerPriceOptionDraft) -> String {
        switch option.paymentType {
        case "free":
            return "Gratis"
        case "location":
            return "€\(money(option.price)) sul posto"
        case "deposit":
            let balance = max(0, option.price - option.depositAmount)
            let balanceMode = option.balancePaymentMode == "on_site" ? "sul posto" : "online"
            return "Acconto €\(money(option.depositAmount)) + saldo €\(money(balance)) \(balanceMode)"
        default:
            return "€\(money(option.price)) online"
        }
    }

    private func eligibilityLabel(for group: String) -> String {
        if group == "members" { return "Soci" }
        if group == "new_users" { return "Nuovi utenti" }
        if group == "experienced" { return "Esperti" }
        if group == "loyal" { return "Fedeli" }
        if group.hasPrefix("badge:") { return "Promo riservata" }
        if group.hasPrefix("trekking_gt:") || group.hasPrefix("events_gt:") { return "Promo riservata" }
        return group
    }
}

