struct OrganizerDurationSplitField: View {
    @Binding var duration: String
    @State private var amount = ""
    @State private var unit = "h"
    @FocusState private var isFocused: Bool

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text("Durata")
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(Brand.foreground)
            HStack(spacing: 10) {
                TextField("es. 4", text: $amount)
                    .keyboardType(.decimalPad)
                    .focused($isFocused)
                    .foregroundStyle(Brand.inputForeground)
                    .tint(Brand.primary)
                    .padding(.horizontal, 14)
                    .frame(height: 54)
                    .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                    .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
                Picker("Unità durata", selection: $unit) {
                    Text("ore (h)").tag("h")
                    Text("giorni").tag("giorni")
                }
                .labelsHidden()
                .pickerStyle(.menu)
                .foregroundStyle(Brand.inputForeground)
                .tint(Brand.primary)
                .padding(.horizontal, 10)
                .frame(width: 132, height: 54)
                .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
            }
        }
        .onAppear { syncFromDuration() }
        .onChange(of: duration) { _, _ in
            if !isFocused { syncFromDuration() }
        }
        .onChange(of: amount) { _, newValue in
            let sanitized = sanitizeAmount(newValue)
            if sanitized != newValue {
                amount = sanitized
                return
            }
            updateDuration()
        }
        .onChange(of: unit) { _, _ in
            updateDuration()
        }
        .onChange(of: isFocused) { _, focused in
            if !focused { syncFromDuration() }
        }
    }

    private func sanitizeAmount(_ value: String) -> String {
        var decimalSeparatorSeen = false
        return value.reduce(into: "") { result, character in
            if character.isNumber {
                result.append(character)
            } else if character == "," || character == ".", !decimalSeparatorSeen {
                decimalSeparatorSeen = true
                result.append(character)
            }
        }
    }

    private func updateDuration() {
        guard let cleanAmount = amount.nilIfBlank else {
            duration = ""
            return
        }
        duration = unit == "giorni" ? "\(cleanAmount) giorni" : "\(cleanAmount)h"
    }

    private func syncFromDuration() {
        let lower = duration.lowercased()
        unit = lower.contains("giorn") ? "giorni" : "h"
        amount = lower.firstRegexCapture(#"(\d+(?:[,.]\d+)?)"#) ?? ""
    }
}

