struct OrganizerDurationPickerField: View {
    let title: String
    @Binding var duration: String
    @State private var hours = 3
    @State private var minutes = 0
    @State private var isPresented = false

    init(_ title: String, duration: Binding<String>) {
        self.title = title
        self._duration = duration
    }

    var body: some View {
        OrganizerPickerSurface(title: title, value: displayText, systemImage: "timer") {
            syncDuration()
            isPresented = true
        }
        .onAppear { syncDuration() }
        .onChange(of: duration) { _, _ in syncDuration() }
        .sheet(isPresented: $isPresented) {
            NavigationStack {
                VStack(spacing: 18) {
                    HStack(spacing: 0) {
                        Picker("Ore", selection: $hours) {
                            ForEach(0...12, id: \.self) { hour in
                                Text("\(hour) h").tag(hour)
                            }
                        }
                        .pickerStyle(.wheel)
                        Picker("Minuti", selection: $minutes) {
                            ForEach([0, 15, 30, 45], id: \.self) { minute in
                                Text("\(minute) min").tag(minute)
                            }
                        }
                        .pickerStyle(.wheel)
                    }
                    .frame(height: 180)

                    Text(formattedDuration(hours: hours, minutes: minutes).nilIfBlank ?? "Durata non impostata")
                        .font(.headline.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                }
                .padding(20)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .background(Brand.background)
                .navigationTitle(title)
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Annulla") { isPresented = false }
                    }
                    ToolbarItem(placement: .confirmationAction) {
                        Button("Fine") {
                            duration = formattedDuration(hours: hours, minutes: minutes)
                            isPresented = false
                        }
                    }
                }
            }
            .presentationDetents([.height(400)])
            .presentationBackground(Brand.background)
        }
    }

    private var displayText: String {
        duration.nilIfBlank ?? "Seleziona durata"
    }

    private func syncDuration() {
        let parsed = parseDuration(duration)
        hours = parsed.hours
        minutes = parsed.minutes
    }

    private func parseDuration(_ value: String) -> (hours: Int, minutes: Int) {
        let lower = value.lowercased()
        let parsedHours = lower.firstRegexCapture(#"(\d+)\s*h"#).flatMap(Int.init) ?? 0
        let parsedMinutes = lower.firstRegexCapture(#"(\d+)\s*m"#).flatMap(Int.init) ?? 0
        if parsedHours > 0 || parsedMinutes > 0 {
            return (min(parsedHours, 12), closestQuarter(parsedMinutes))
        }
        if let numeric = Int(lower.filter(\.isNumber)), numeric > 0 {
            return numeric > 12 ? (min(numeric / 60, 12), closestQuarter(numeric % 60)) : (numeric, 0)
        }
        return (3, 0)
    }

    private func closestQuarter(_ value: Int) -> Int {
        [0, 15, 30, 45].min(by: { abs($0 - value) < abs($1 - value) }) ?? 0
    }

    private func formattedDuration(hours: Int, minutes: Int) -> String {
        if hours == 0 && minutes == 0 { return "" }
        if hours == 0 { return "\(minutes) min" }
        if minutes == 0 { return "\(hours)h" }
        return "\(hours)h \(minutes)m"
    }
}

struct OrganizerPickerSurface: View {
    let title: String
    let value: String
    let systemImage: String
    let action: () -> Void

