struct OrganizerEuroField: View {
    let title: String
    @Binding var value: Double
    @State private var text = ""
    @FocusState private var isFocused: Bool

    init(_ title: String, value: Binding<Double>) {
        self.title = title
        self._value = value
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(title)
                .font(.subheadline.weight(.semibold))
                .foregroundStyle(Brand.foreground)
            HStack(spacing: 8) {
                Text("€")
                    .font(.body.weight(.bold))
                    .foregroundStyle(Brand.primary)
                TextField("0,00", text: $text)
                    .keyboardType(.decimalPad)
                    .multilineTextAlignment(.trailing)
                    .focused($isFocused)
                    .foregroundStyle(Brand.inputForeground)
                    .tint(Brand.primary)
            }
            .padding(.horizontal, 14)
            .frame(height: 54)
            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
            .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
        }
        .onAppear { syncText() }
        .onChange(of: value) { _, _ in
            if !isFocused { syncText() }
        }
        .onChange(of: text) { _, newValue in
            if newValue.nilIfBlank == nil {
                value = 0
            } else if let parsed = parseDecimalInput(newValue) {
                value = parsed
            }
        }
        .onChange(of: isFocused) { _, focused in
            if focused, value == 0 {
                text = ""
            } else if !focused {
                syncText()
            }
        }
    }

    private func syncText() {
        text = euroInputText(value)
    }
}

