private func parseDecimalInput(_ value: String) -> Double? {
    let normalized = value
        .replacingOccurrences(of: "€", with: "")
        .replacingOccurrences(of: " ", with: "")
        .replacingOccurrences(of: ",", with: ".")
    return Double(normalized)
}

private func euroInputText(_ value: Double) -> String {
    money(value).replacingOccurrences(of: ".", with: ",")
}

struct OrganizerAddressSuggestion: Identifiable, Hashable, Sendable {
    let id: String
    let title: String
    let subtitle: String
    let placeId: String?
    let source: Source

    enum Source: String, Hashable, Sendable {
        case google
        case mapKit
    }

    init(title: String, subtitle: String, placeId: String? = nil, source: Source) {
        self.id = placeId ?? "\(source.rawValue):\(title.normalizedSearchKey)|\(subtitle.normalizedSearchKey)"
        self.title = title
        self.subtitle = subtitle
        self.placeId = placeId
        self.source = source
    }

    var query: String {
        [title, subtitle].compactMap(\.nilIfBlank).joined(separator: ", ")
    }
}

struct OrganizerAddressAutocompleteField: View {
    let title: String
    @Binding var text: String
    let label: Binding<String>?
    let labelFont: Font
    let labelSpacing: CGFloat
    let borderWidth: CGFloat
    let showsLeadingIcon: Bool
    let help: String?
    @StateObject private var autocomplete = OrganizerAddressAutocompleteModel()
    @FocusState private var isFocused: Bool
    @State private var resolving = false

    init(
        _ title: String,
        text: Binding<String>,
        label: Binding<String>? = nil,
        labelFont: Font = .subheadline.weight(.semibold),
        labelSpacing: CGFloat = 6,
        borderWidth: CGFloat = 1,
        showsLeadingIcon: Bool = true,
        help: String? = nil
    ) {
        self.title = title
        self._text = text
        self.label = label
        self.labelFont = labelFont
        self.labelSpacing = labelSpacing
        self.borderWidth = borderWidth
        self.showsLeadingIcon = showsLeadingIcon
        self.help = help
    }

    var body: some View {
        VStack(alignment: .leading, spacing: labelSpacing) {
            HStack(spacing: 6) {
                Text(title)
                    .font(labelFont)
                    .foregroundStyle(Brand.foreground)
                    .lineLimit(1)
                if let help {
                    InfoTooltipButton(text: help)
                }
            }
            HStack(spacing: showsLeadingIcon ? 10 : 0) {
                if showsLeadingIcon {
                    Image(systemName: "mappin.and.ellipse")
                        .foregroundStyle(Brand.primary)
                }
                TextField("", text: $text, prompt: Text(title).foregroundStyle(Brand.inputMutedForeground))
                    .focused($isFocused)
                    .textInputAutocapitalization(.words)
                    .keyboardType(.default)
                    .foregroundStyle(Brand.inputForeground)
                    .tint(Brand.primary)
                    .onSubmit {
                        autocomplete.clear()
                        isFocused = false
                    }
                if resolving {
                    ProgressView()
                        .controlSize(.small)
                        .tint(Brand.primary)
                }
            }
            .padding(.horizontal, 14)
            .frame(height: 54)
            .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
            .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: borderWidth))

            if isFocused && !autocomplete.results.isEmpty {
                let visibleResults = Array(autocomplete.results.prefix(5))
                VStack(spacing: 0) {
                    ForEach(Array(visibleResults.enumerated()), id: \.offset) { index, result in
                        Button {
                            select(result)
                        } label: {
                            HStack(alignment: .top, spacing: 10) {
                                Image(systemName: "mappin")
                                    .font(.caption.weight(.bold))
                                    .foregroundStyle(Brand.primary)
                                    .padding(.top, 3)
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(result.title)
                                        .font(.subheadline.weight(.semibold))
                                        .foregroundStyle(Brand.inputForeground)
                                        .lineLimit(1)
                                    if !result.subtitle.isEmpty {
                                        Text(result.subtitle)
                                            .font(.caption)
                                            .foregroundStyle(Brand.inputMutedForeground)
                                            .lineLimit(2)
                                    }
                                }
                                Spacer(minLength: 6)
                            }
                            .padding(.horizontal, 12)
                            .padding(.vertical, 10)
                            .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)
                        if index < visibleResults.count - 1 {
                            Divider().overlay(Brand.inputBorder)
                        }
                    }
                }
                .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
            }
        }
        .onAppear { autocomplete.update(query: text) }
        .onChange(of: text) { _, value in
            autocomplete.update(query: value)
        }
        .onChange(of: isFocused) { _, focused in
            if !focused { autocomplete.clear() }
        }
    }

    private func select(_ result: OrganizerAddressSuggestion) {
        resolving = true
        Task {
            let selection = await autocomplete.resolve(result)
            text = selection.address
            if let label, label.wrappedValue.nilIfBlank == nil {
                label.wrappedValue = selection.label
            }
            autocomplete.clear()
            isFocused = false
            resolving = false
        }
    }
}

struct OrganizerAddressSelection {
    let address: String
    let label: String
}

@MainActor
final class OrganizerAddressAutocompleteModel: NSObject, ObservableObject, MKLocalSearchCompleterDelegate {
    @Published var results: [OrganizerAddressSuggestion] = []
    private let completer = MKLocalSearchCompleter()
    private var searchTask: Task<Void, Never>?
    private var latestQuery = ""
    private var googleSessionToken = UUID().uuidString
    private var googleResults: [OrganizerAddressSuggestion] = []
    private var mapKitResults: [OrganizerAddressSuggestion] = []

    override init() {
        super.init()
        completer.delegate = self
        completer.resultTypes = [.address, .pointOfInterest]
        completer.region = Self.italyRegion
    }

    func update(query: String) {
        let value = query.trimmingCharacters(in: .whitespacesAndNewlines)
        guard value.count >= 3 else {
            clear()
            return
        }

        latestQuery = value
        googleResults = []
        mapKitResults = []
        results = []
        completer.queryFragment = value
        searchTask?.cancel()
        let sessionToken = googleSessionToken
        searchTask = Task { [weak self] in
            try? await Task.sleep(nanoseconds: 250_000_000)
            guard !Task.isCancelled, let self else { return }

            let googleResults = await Self.fetchGoogleSuggestions(query: value, sessionToken: sessionToken)
            guard !Task.isCancelled, self.latestQuery == value else { return }

            self.googleResults = googleResults
            self.publishMergedResults()
        }
    }

    func clear() {
        searchTask?.cancel()
        searchTask = nil
        latestQuery = ""
        googleSessionToken = UUID().uuidString
        completer.queryFragment = ""
        googleResults = []
        mapKitResults = []
        results = []
    }

    nonisolated func completerDidUpdateResults(_ completer: MKLocalSearchCompleter) {
        let suggestions = completer.results.prefix(6).map {
            OrganizerAddressSuggestion(title: $0.title, subtitle: $0.subtitle, source: .mapKit)
        }
        Task { @MainActor [weak self] in
            guard let self, !self.latestQuery.isEmpty else { return }
            self.mapKitResults = suggestions
            self.publishMergedResults()
        }
    }

    nonisolated func completer(_ completer: MKLocalSearchCompleter, didFailWithError error: Error) {
        Task { @MainActor [weak self] in
            guard let self else { return }
            self.mapKitResults = []
            self.publishMergedResults()
        }
    }

    private func publishMergedResults() {
        guard !latestQuery.isEmpty else {
            results = []
            return
        }
        results = Self.dedupedSuggestions(googleResults + mapKitResults)
    }

    private static func dedupedSuggestions(_ suggestions: [OrganizerAddressSuggestion]) -> [OrganizerAddressSuggestion] {
        var seen = Set<String>()
        var deduped: [OrganizerAddressSuggestion] = []
        for suggestion in suggestions {
            let key = suggestion.query.normalizedSearchKey
            guard !key.isEmpty, seen.insert(key).inserted else { continue }
            deduped.append(suggestion)
            if deduped.count == 6 { break }
        }
        return deduped
    }

    func resolve(_ suggestion: OrganizerAddressSuggestion) async -> OrganizerAddressSelection {
        if suggestion.source == .google,
           let placeId = suggestion.placeId,
           let selection = await Self.fetchGooglePlaceDetails(placeId: placeId, fallback: suggestion, sessionToken: googleSessionToken) {
            return selection
        }
        return await resolveWithMapKit(suggestion)
    }

    private func resolveWithMapKit(_ suggestion: OrganizerAddressSuggestion) async -> OrganizerAddressSelection {
        let request = MKLocalSearch.Request()
        request.naturalLanguageQuery = suggestion.query
        request.region = Self.italyRegion
        if let item = try? await MKLocalSearch(request: request).start().mapItems.first {
            let address = item.placemark.title?.nilIfBlank ?? suggestion.query
            let label = item.name?.nilIfBlank ?? suggestion.title
            return OrganizerAddressSelection(address: address, label: label)
        }
        return OrganizerAddressSelection(
            address: suggestion.query,
            label: suggestion.title
        )
    }

    private static func fetchGoogleSuggestions(query: String, sessionToken: String) async -> [OrganizerAddressSuggestion] {
        guard let url = URL(string: "https://places.googleapis.com/v1/places:autocomplete") else { return [] }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(ScampagnateConfig.googlePlacesAPIKey, forHTTPHeaderField: "X-Goog-Api-Key")
        let payload = GoogleAutocompleteRequest(input: query, includedRegionCodes: ["it"], languageCode: "it", sessionToken: sessionToken)
        guard let body = try? JSONEncoder().encode(payload) else { return [] }
        request.httpBody = body

        do {
            let (data, response) = try await URLSession.shared.data(for: request)
            guard (response as? HTTPURLResponse)?.statusCode == 200 else { return [] }
            let decoded = try JSONDecoder().decode(GoogleAutocompleteResponse.self, from: data)
            return decoded.suggestions.compactMap { suggestion in
                guard let prediction = suggestion.placePrediction else { return nil }
                let fullText = prediction.text?.text.nilIfBlank
                let title = prediction.structuredFormat?.mainText?.text.nilIfBlank ?? fullText
                guard let title else { return nil }
                return OrganizerAddressSuggestion(
                    title: title,
                    subtitle: prediction.structuredFormat?.secondaryText?.text ?? "",
                    placeId: prediction.placeId,
                    source: .google
                )
            }
        } catch {
            return []
        }
    }

    private static func fetchGooglePlaceDetails(placeId: String, fallback: OrganizerAddressSuggestion, sessionToken: String) async -> OrganizerAddressSelection? {
        var components = URLComponents()
        components.scheme = "https"
        components.host = "places.googleapis.com"
        components.path = "/v1/places/\(placeId)"
        components.queryItems = [
            URLQueryItem(name: "fields", value: "formattedAddress,displayName"),
            URLQueryItem(name: "languageCode", value: "it"),
            URLQueryItem(name: "sessionToken", value: sessionToken)
        ]
        guard let url = components.url else { return nil }

        var request = URLRequest(url: url)
        request.setValue(ScampagnateConfig.googlePlacesAPIKey, forHTTPHeaderField: "X-Goog-Api-Key")

        do {
            let (data, response) = try await URLSession.shared.data(for: request)
            guard (response as? HTTPURLResponse)?.statusCode == 200 else { return nil }
            let place = try JSONDecoder().decode(GooglePlaceDetailsResponse.self, from: data)
            return OrganizerAddressSelection(
                address: place.formattedAddress?.nilIfBlank ?? fallback.query,
                label: place.displayName?.text.nilIfBlank ?? fallback.title
            )
        } catch {
            return nil
        }
    }

    private static let italyRegion = MKCoordinateRegion(
        center: CLLocationCoordinate2D(latitude: 41.8719, longitude: 12.5674),
        span: MKCoordinateSpan(latitudeDelta: 14, longitudeDelta: 14)
    )
}

private struct GoogleAutocompleteRequest: Encodable {
    let input: String
    let includedRegionCodes: [String]
    let languageCode: String
    let sessionToken: String
}

private struct GoogleAutocompleteResponse: Decodable {
    let suggestions: [GoogleAutocompleteSuggestion]
}

private struct GoogleAutocompleteSuggestion: Decodable {
    let placePrediction: GooglePlacePrediction?
}

private struct GooglePlacePrediction: Decodable {
    let placeId: String
    let structuredFormat: GoogleStructuredFormat?
    let text: GoogleLocalizedText?
}

private struct GoogleStructuredFormat: Decodable {
    let mainText: GoogleLocalizedText?
    let secondaryText: GoogleLocalizedText?
}

private struct GoogleLocalizedText: Decodable {
    let text: String
}

private struct GooglePlaceDetailsResponse: Decodable {
    let formattedAddress: String?
    let displayName: GoogleLocalizedText?
}

