                }
                .padding(12)
                .background(Brand.muted.opacity(0.45), in: RoundedRectangle(cornerRadius: 12))
            }
            Toggle("Limite posti dedicato", isOn: dedicatedSpotsEnabledBinding)
                .editableControlSurface(cornerRadius: 12)
            if option.hasDedicatedSpots {
                OrganizerIntegerStepperField("Posti dedicati", value: $option.dedicatedSpots, range: 1...300)
            }
            Picker("Gruppo idoneo", selection: eligibleGroupModeBinding) {
                Text("Tutti").tag("all")
                Text("Membri attivi").tag("members")
                Text("Nuovi utenti").tag("new_users")
                Text("Esperti").tag("experienced")
                Text("Fedeli").tag("loyal")
                Text("Badge specifici").tag("badges")
                Text("Trekking > X").tag("trekking_gt")
                Text("Eventi > X").tag("events_gt")
            }
            .editableControlSurface(cornerRadius: 12)
            if eligibleGroupMode == "badges" || !option.badgeIds.isEmpty {
                LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 8) {
