                        OrganizerToggleChip(title: badge.name, selected: option.badgeIds.contains(badge.id)) {
                            if option.badgeIds.contains(badge.id) {
                                option.badgeIds.removeAll { $0 == badge.id }
                            } else {
                                option.badgeIds.append(badge.id)
