                            option.eligibleGroup = option.badgeIds.isEmpty ? "badges" : "badge:\(option.badgeIds.joined(separator: ","))"
                        }
                    }
                }
            }
            if eligibleGroupMode == "trekking_gt" {
                Field("Numero trekking maggiore di", text: thresholdBinding(prefix: "trekking_gt"), keyboard: .numberPad)
            }
            if eligibleGroupMode == "events_gt" {
                Field("Numero eventi maggiore di", text: thresholdBinding(prefix: "events_gt"), keyboard: .numberPad)
            }
            OrganizerOptionalEuroField("Prezzo originale", value: $option.originalPrice)
            Toggle("Promo a tempo limitato", isOn: $option.isPromotional)
                .editableControlSurface(cornerRadius: 12)
            if option.isPromotional {
                OrganizerOptionalDatePickerField("Promo dal", dateString: $option.promoStart)
                OrganizerOptionalDatePickerField("Promo al", dateString: $option.promoEnd)
            }
        }
        .padding(10)
        .background(Brand.background, in: RoundedRectangle(cornerRadius: 14))
    }

    private var paymentModeBinding: Binding<String> {
        Binding {
            switch option.paymentType {
            case "deposit":
                return option.balancePaymentMode == "on_site" ? "deposit_on_site" : "deposit_online"
            case "paid", "location", "free":
                return option.paymentType
            default:
                return option.price > 0 ? "paid" : "free"
            }
        } set: { mode in
            switch mode {
            case "free":
                option.paymentType = "free"
                option.price = 0
                option.depositAmount = 0
                option.balanceAmount = 0
                option.balancePaymentMode = "online"
            case "paid":
                option.paymentType = "paid"
                option.balancePaymentMode = "online"
            case "location":
                option.paymentType = "location"
                option.balancePaymentMode = "online"
            case "deposit_on_site":
                option.paymentType = "deposit"
                option.balancePaymentMode = "on_site"
                if option.balanceAmount <= 0 {
                    option.balanceAmount = max(0, option.price - option.depositAmount)
                }
            case "deposit_online":
                option.paymentType = "deposit"
                option.balancePaymentMode = "online"
                if option.balanceAmount <= 0 {
                    option.balanceAmount = max(0, option.price - option.depositAmount)
                }
            default:
                option.paymentType = "free"
                option.balancePaymentMode = "online"
            }
        }
    }

    private var optionPriceBinding: Binding<Double> {
        Binding {
            option.price
        } set: { price in
            option.price = price
            if option.paymentType == "deposit" {
                option.balanceAmount = max(0, price - option.depositAmount)
            }
        }
    }

    private var depositAmountBinding: Binding<Double> {
        Binding {
            option.depositAmount
        } set: { deposit in
            option.depositAmount = deposit
            option.balanceAmount = max(0, option.price - deposit)
        }
    }

    private var dedicatedSpotsEnabledBinding: Binding<Bool> {
        Binding {
            option.hasDedicatedSpots
        } set: { isEnabled in
            option.hasDedicatedSpots = isEnabled
            option.dedicatedSpots = isEnabled ? max(option.dedicatedSpots, 1) : 0
        }
    }

    private var eligibleGroupMode: String {
        if option.eligibleGroup.hasPrefix("badge:") || option.eligibleGroup == "badges" { return "badges" }
        if option.eligibleGroup.hasPrefix("trekking_gt:") { return "trekking_gt" }
        if option.eligibleGroup.hasPrefix("events_gt:") { return "events_gt" }
        return option.eligibleGroup.nilIfBlank ?? "all"
    }

    private var eligibleGroupModeBinding: Binding<String> {
        Binding {
            eligibleGroupMode
        } set: { value in
            switch value {
            case "badges":
                option.eligibleGroup = option.badgeIds.isEmpty ? "badges" : "badge:\(option.badgeIds.joined(separator: ","))"
            case "trekking_gt":
                option.eligibleGroup = "trekking_gt:1"
                option.badgeIds = []
            case "events_gt":
                option.eligibleGroup = "events_gt:1"
                option.badgeIds = []
            default:
                option.eligibleGroup = value
                option.badgeIds = []
            }
        }
    }

    private func thresholdBinding(prefix: String) -> Binding<String> {
        Binding {
            guard option.eligibleGroup.hasPrefix("\(prefix):") else { return "1" }
            return option.eligibleGroup.split(separator: ":", maxSplits: 1).dropFirst().first.map(String.init) ?? "1"
        } set: { value in
            option.eligibleGroup = "\(prefix):\(value.nilIfBlank ?? "1")"
        }
    }
}

