struct OrganizerGalleryEditor: View {
    @Binding var urls: [String]

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            HStack {
                Text("Galleria evento")
                    .font(.subheadline.weight(.bold))
                Spacer()
                Text("\(urls.count)/5 immagini")
                    .font(.caption2)
                    .foregroundStyle(Brand.mutedForeground)
            }
            ForEach(Array(urls.indices), id: \.self) { index in
                VStack(alignment: .leading, spacing: 8) {
                    let currentURL = urls.indices.contains(index) ? urls[index] : ""
                    HStack(spacing: 10) {
                        galleryThumbnail(for: currentURL)
                        VStack(alignment: .leading, spacing: 3) {
                            Text("Immagine \(index + 1)")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                            Text(currentURL.nilIfBlank == nil ? "Immagine non impostata" : "Foto galleria")
                                .font(.caption2)
                                .foregroundStyle(Brand.mutedForeground)
                                .lineLimit(1)
                        }
                        .frame(maxWidth: .infinity, alignment: .leading)

                        HStack(spacing: 6) {
                            galleryActionButton(systemName: "chevron.up", disabled: index == 0) {
                                move(index, by: -1)
                            }
                            galleryActionButton(systemName: "chevron.down", disabled: index == urls.count - 1) {
                                move(index, by: 1)
                            }
                            galleryActionButton(systemName: "trash", role: .destructive) {
                                guard urls.indices.contains(index) else { return }
                                urls.remove(at: index)
                            }
                        }
                    }
                }
                .padding(10)
                .background(Brand.background, in: RoundedRectangle(cornerRadius: 14))
            }
        }
    }

    private func move(_ index: Int, by offset: Int) {
        let target = index + offset
        guard urls.indices.contains(index), urls.indices.contains(target) else { return }
        urls.swapAt(index, target)
    }

    @ViewBuilder
    private func galleryThumbnail(for url: String) -> some View {
        if url.nilIfBlank != nil {
            RemoteImage(urlString: url, contentMode: .fit)
                .frame(width: 58, height: 58)
                .background(Brand.muted, in: RoundedRectangle(cornerRadius: 10))
                .clipShape(RoundedRectangle(cornerRadius: 10))
        } else {
            RoundedRectangle(cornerRadius: 10)
                .fill(Brand.muted)
                .frame(width: 58, height: 58)
                .overlay(Image(systemName: "photo").foregroundStyle(Brand.mutedForeground))
        }
    }

    private func galleryActionButton(
        systemName: String,
        role: ButtonRole? = nil,
        disabled: Bool = false,
        action: @escaping () -> Void
    ) -> some View {
        Button(role: role, action: action) {
            Image(systemName: systemName)
                .font(.caption.weight(.bold))
                .frame(width: 30, height: 30)
                .background(Brand.card, in: Circle())
                .overlay(Circle().stroke(Brand.muted, lineWidth: 1))
        }
        .buttonStyle(.plain)
        .foregroundStyle(role == .destructive ? Brand.destructive : Brand.primary)
        .opacity(disabled ? 0.35 : 1)
        .disabled(disabled)
    }

}

enum OrganizerImageCropKind {
    case coverHero

    var title: String {
        switch self {
        case .coverHero: "Immagine evento"
        }
    }

    var subtitle: String {
        switch self {
        case .coverHero: "Ritaglio 1:1 mostrato nell'evento e nelle card"
        }
    }

    var aspectRatio: CGFloat {
        switch self {
        case .coverHero: 1
        }
    }

    var outputSize: CGSize {
        switch self {
        case .coverHero: CGSize(width: 1200, height: 1200)
        }
    }
}

struct OrganizerImageCropDraft: Identifiable {
    let id = UUID()
    let image: UIImage
    let kind: OrganizerImageCropKind
}

struct OrganizerImageCropResult {
    let data: Data
}

struct OrganizerImageCropView: View {
    let image: UIImage
    let kind: OrganizerImageCropKind
    let onSubmit: (OrganizerImageCropResult) -> Void
    let onCancel: () -> Void

    @State private var zoom: CGFloat = 1
    @State private var committedZoom: CGFloat = 1
    @State private var offset: CGSize = .zero
    @State private var committedOffset: CGSize = .zero

    private let maxZoom: CGFloat = 4

    var body: some View {
        NavigationStack {
            GeometryReader { proxy in
                let cropSize = calculatedCropSize(in: proxy.size)
                VStack(spacing: 18) {
                    VStack(spacing: 5) {
                        Text(kind.subtitle)
                            .font(.footnote.weight(.semibold))
                            .foregroundStyle(Brand.mutedForeground)
                            .multilineTextAlignment(.center)
                    }
                    .padding(.top, 16)

                    cropPreview(cropSize: cropSize)

                    Text("Trascina e pizzica l'immagine per scegliere il ritaglio.")
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                        .multilineTextAlignment(.center)

                    Spacer(minLength: 8)

                    Button {
                        submit(cropSize: cropSize)
                    } label: {
                        Label("Ritaglia e carica", systemImage: "checkmark")
                            .frame(maxWidth: .infinity)
                    }
                    .buttonStyle(PrimaryButtonStyle())
                    .padding(.bottom, 18)
                }
                .padding(.horizontal, 22)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
            .background(Brand.background.ignoresSafeArea())
            .navigationTitle(kind.title)
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Annulla", action: onCancel)
                }
            }
        }
    }

    private func cropPreview(cropSize: CGSize) -> some View {
        ZStack {
            Brand.muted
            Image(uiImage: image)
                .resizable()
                .scaledToFill()
                .frame(width: cropSize.width, height: cropSize.height)
                .scaleEffect(zoom)
                .offset(offset)
        }
        .frame(width: cropSize.width, height: cropSize.height)
        .clipShape(RoundedRectangle(cornerRadius: 16))
        .overlay(RoundedRectangle(cornerRadius: 16).stroke(.white, lineWidth: 3))
        .shadow(color: .black.opacity(0.16), radius: 18, y: 10)
        .gesture(dragGesture(cropSize: cropSize).simultaneously(with: zoomGesture(cropSize: cropSize)))
        .frame(maxWidth: .infinity)
    }

    private func submit(cropSize: CGSize) {
        guard let data = image.croppedJPEGData(offset: offset, zoom: zoom, cropSize: cropSize, outputSize: kind.outputSize) else {
            return
        }
        onSubmit(OrganizerImageCropResult(data: data))
    }

    private func calculatedCropSize(in availableSize: CGSize) -> CGSize {
        let maxWidth = max(240, min(availableSize.width - 44, 380))
        let maxHeight = max(220, availableSize.height * 0.54)
        var width = maxWidth
        var height = width / kind.aspectRatio
        if height > maxHeight {
            height = maxHeight
            width = height * kind.aspectRatio
        }
        return CGSize(width: width, height: height)
    }

    private func dragGesture(cropSize: CGSize) -> some Gesture {
        DragGesture()
            .onChanged { value in
                offset = clampedOffset(
                    CGSize(width: committedOffset.width + value.translation.width, height: committedOffset.height + value.translation.height),
                    zoom: zoom,
                    cropSize: cropSize
                )
            }
            .onEnded { _ in
                committedOffset = clampedOffset(offset, zoom: zoom, cropSize: cropSize)
                offset = committedOffset
            }
    }

    private func zoomGesture(cropSize: CGSize) -> some Gesture {
        MagnificationGesture()
            .onChanged { value in
                zoom = min(max(committedZoom * value, 1), maxZoom)
                offset = clampedOffset(offset, zoom: zoom, cropSize: cropSize)
            }
            .onEnded { _ in
                committedZoom = zoom
                committedOffset = clampedOffset(offset, zoom: zoom, cropSize: cropSize)
                offset = committedOffset
            }
    }

    private func clampedOffset(_ proposed: CGSize, zoom: CGFloat, cropSize: CGSize) -> CGSize {
        guard image.size.width > 0, image.size.height > 0 else { return .zero }
        let baseScale = max(cropSize.width / image.size.width, cropSize.height / image.size.height)
        let scaledWidth = image.size.width * baseScale * zoom
        let scaledHeight = image.size.height * baseScale * zoom
        let maxX = max(0, (scaledWidth - cropSize.width) / 2)
        let maxY = max(0, (scaledHeight - cropSize.height) / 2)

        return CGSize(
            width: min(max(proposed.width, -maxX), maxX),
            height: min(max(proposed.height, -maxY), maxY)
        )
    }
}

struct OrganizerFitCategoryMultiSelector: View {
    let title: String
    let categories: [String]
    let mainCategory: String
    @Binding var selected: [String]
    private let maxSelection = 2

    private var visibleCategories: [String] {
        categories.filter { $0 != mainCategory }
    }

    private var extraValues: [String] {
        selected.filter { !categories.contains($0) }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Text(title)
                    .font(.subheadline.weight(.bold))
                Spacer()
                Text("\(selected.count)/\(maxSelection)")
                    .font(.caption2)
                    .foregroundStyle(Brand.mutedForeground)
            }
            LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 8) {
                ForEach(visibleCategories, id: \.self) { category in
                    let isSelected = selected.contains(category)
                    let isDisabled = !isSelected && selected.count >= maxSelection
                    OrganizerToggleChip(title: category, selected: isSelected) {
                        guard !isDisabled else { return }
                        if isSelected {
                            selected.removeAll { $0 == category }
                        } else {
                            selected.append(category)
                        }
                    }
                    .opacity(isDisabled ? 0.45 : 1)
                }
                ForEach(extraValues, id: \.self) { value in
                    OrganizerToggleChip(title: value, selected: true) {
                        selected.removeAll { $0 == value }
                    }
                }
            }
        }
    }
}

struct OrganizerCategoryMultiSelector: View {
    let title: String
    let categories: [EventCategory]
    @Binding var selected: [String]

    private var categoryValues: [String] {
        categories.compactMap { ($0.name ?? $0.id)?.nilIfBlank }
    }

    private var extraValues: [String] {
        selected.filter { !categoryValues.contains($0) }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            Text(title)
                .font(.subheadline.weight(.bold))
            if categories.isEmpty {
                OrganizerStringListEditor(title: "Valori", values: $selected, placeholder: "Categoria")
            } else {
                LazyVGrid(columns: [GridItem(.flexible()), GridItem(.flexible())], spacing: 8) {
                    ForEach(categories) { category in
                        let value = category.name ?? category.id ?? ""
                        OrganizerToggleChip(title: categoryLabel(category), selected: selected.contains(value)) {
                            if selected.contains(value) {
                                selected.removeAll { $0 == value }
                            } else if value.nilIfBlank != nil {
                                selected.append(value)
                            }
                        }
                    }
                    ForEach(extraValues, id: \.self) { value in
                        OrganizerToggleChip(title: value, selected: true) {
                            selected.removeAll { $0 == value }
                        }
                    }
                }
            }
        }
    }
}

struct OrganizerToggleChip: View {
    let title: String
    let selected: Bool
    let action: () -> Void

    var body: some View {
        Button(action: action) {
            Text(title)
                .font(.caption.weight(.bold))
                .lineLimit(2)
                .minimumScaleFactor(0.8)
                .frame(maxWidth: .infinity)
                .frame(minHeight: 42)
                .padding(.horizontal, 8)
                .background(selected ? Brand.primary : Brand.background, in: RoundedRectangle(cornerRadius: 12))
                .foregroundStyle(selected ? .white : Brand.foreground)
                .overlay(RoundedRectangle(cornerRadius: 12).stroke(selected ? Brand.primary : Brand.muted, lineWidth: 1))
        }
        .buttonStyle(.plain)
    }
}

// MARK: - Profile

struct ProfileView: View {
    @EnvironmentObject private var store: AppStore
    @Binding var showAuth: Bool
    @Binding var scrollTarget: ProfileScrollTarget?
    @Binding var openRewards: Bool
    @Binding var routedMission: MissionNavigationTarget?
    @State private var showEdit = false
    @State private var profileEditInitialFocus: ProfileEditInitialFocus?
    @State private var showHealthSafetyEdit = false
    @State private var showPointsInfo = false
    @State private var showRoutedRewards = false

    var body: some View {
        NavigationStack {
            ZStack {
                Brand.background.ignoresSafeArea()
                Group {
                    if !store.isAuthenticated {
                        SignedOutPrompt(title: "Profilo", message: "Accedi per visualizzare il tuo profilo.", showAuth: $showAuth)
                    } else if let profile = store.profile {
                        ScrollViewReader { scrollProxy in
                            GeometryReader { proxy in
                                ScrollView {
                                    VStack(alignment: .leading, spacing: 18) {
                                        HStack(spacing: 14) {
                                            AvatarView(profile: profile, size: 76)
                                            VStack(alignment: .leading, spacing: 4) {
                                                Text(profile.displayName.isEmpty ? "Scampagnatore" : profile.displayName)
                                                    .font(.system(.title2, design: .rounded, weight: .bold))
                                                    .lineLimit(2)
                                                Text(store.session?.user.email ?? "")
                                                    .font(.subheadline)
                                                    .foregroundStyle(Brand.mutedForeground)
                                                    .lineLimit(1)
                                                    .minimumScaleFactor(0.82)
                                                Button {
                                                    withAnimation(.easeInOut(duration: 0.18)) {
                                                        showPointsInfo.toggle()
                                                    }
                                                } label: {
                                                    HStack(spacing: 4) {
                                                        Label("\(profile.totalPoints ?? 0) punti", systemImage: "star.fill")
                                                        Image(systemName: "info.circle")
                                                            .font(.caption2.weight(.semibold))
                                                            .foregroundStyle(Brand.mutedForeground)
                                                    }
                                                    .font(.caption.weight(.semibold))
                                                    .foregroundStyle(Brand.secondary)
                                                }
                                                .buttonStyle(.plain)
                                            }
                                            Spacer()
                                            Button {
                                                profileEditInitialFocus = nil
                                                showEdit = true
                                            } label: {
                                                Image(systemName: "pencil")
                                                    .font(.system(size: 18, weight: .semibold))
                                                    .foregroundStyle(Brand.mutedForeground)
                                                    .frame(width: 38, height: 38)
                                                    .background(Brand.muted.opacity(0.65), in: Circle())
                                            }
                                        }
                                        .id(ProfileScrollTarget.profile)

                                        if showPointsInfo {
                                            PointsInfoCard {
                                                withAnimation(.easeInOut(duration: 0.18)) {
                                                    showPointsInfo = false
                                                }
                                            }
                                            .transition(.opacity.combined(with: .move(edge: .top)))
                                        }

                                        ProfileCompletenessCard(profile: profile) {
                                            profileEditInitialFocus = nil
                                            showEdit = true
                                        }
                                        if !profile.hasCompleteMembershipProfile {
                                            MembershipProfileCallout {
                                                profileEditInitialFocus = profile.isMissingMembershipSex ? .membershipSex : .membership
                                                showEdit = true
                                            }
                                        }
                                        if profile.healthSafetyStatus != "none" && profile.healthSafetyStatus != "has_info" {
                                            HealthSafetyProfileCallout {
                                                showHealthSafetyEdit = true
                                            }
                                        }
                                        MembershipCard(profile: profile)
                                            .id(ProfileScrollTarget.membership)
                                        ProfileProgressionSection(profile: profile, levels: store.communityLevels)
                                        MissionsSection(missions: store.missions, routedMission: $routedMission)
                                            .id(ProfileScrollTarget.missions)
                                        RewardsShortcutRow(rewards: store.rewards, badges: store.badges)
                                            .id(ProfileScrollTarget.rewards)
                                        ProfileBadgesSection(badges: store.badges, allBadges: store.allBadges, registrations: store.myEvents)
                                            .id(ProfileScrollTarget.badges)
                                        ProfileActivityHistorySection(registrations: store.myEvents)
                                            .id(ProfileScrollTarget.activity)
                                        HelpSection()
                                            .id(ProfileScrollTarget.help)
                                        ProfilePrivacySection()
                                        AccountSettingsSection()
                                    }
                                    .frame(width: max(proxy.size.width - 32, 0), alignment: .leading)
                                    .padding(16)
                                    .padding(.bottom, 0)
                                }
                                .contentMargins(.bottom, 0, for: .scrollContent)
                            }
                            .onAppear {
                                scrollToProfileTarget(with: scrollProxy)
                            }
                            .onChange(of: scrollTarget) { _, _ in
                                scrollToProfileTarget(with: scrollProxy)
                            }
                        }
                        .sheet(isPresented: $showEdit, onDismiss: {
                            profileEditInitialFocus = nil
                        }) {
                            ProfileEditSheet(profile: profile, initialFocus: profileEditInitialFocus)
                                .presentationDetents([.fraction(0.86), .large])
                                .presentationDragIndicator(.hidden)
                        }
                        .fullScreenCover(isPresented: $showHealthSafetyEdit) {
                            OnboardingView(mode: .healthSafetyEdit)
                        }
                    }
                }
            }
            .refreshable { await store.refreshUserData() }
            .navigationDestination(isPresented: $showRoutedRewards) {
                RewardsView(rewards: store.rewards, badges: store.badges)
            }
            .task(id: store.session?.user.id) {
                guard store.isAuthenticated else { return }
                await store.refreshUserData(reportingErrors: false)
            }
            .onAppear {
                openRewardsIfNeeded()
            }
            .onChange(of: openRewards) { _, _ in
                openRewardsIfNeeded()
            }
        }
    }

    private func openRewardsIfNeeded() {
        guard openRewards else { return }
        showRoutedRewards = true
        openRewards = false
    }

    private func scrollToProfileTarget(with proxy: ScrollViewProxy) {
        guard let target = scrollTarget else { return }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.2) {
            withAnimation(.snappy) {
                proxy.scrollTo(target, anchor: .top)
            }
            scrollTarget = nil
        }
    }
}

