struct ProfileCompletenessCard: View {
    let profile: Profile
    let action: () -> Void

    private struct CompletionField: Identifiable {
        let id = UUID()
        let label: String
        let completed: Bool
        let group: String
    }

    private var fields: [CompletionField] {
        [
            CompletionField(label: "Nome e cognome", completed: !(profile.firstName ?? "").isEmpty && !(profile.lastName ?? "").isEmpty, group: "Profilo"),
            CompletionField(label: "Telefono", completed: !profile.phone.isEmpty, group: "Profilo"),
            CompletionField(label: "Foto profilo", completed: !(profile.avatarUrl ?? "").isEmpty, group: "Profilo"),
            CompletionField(label: "Bio", completed: !(profile.bio ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty, group: "Profilo"),
            CompletionField(label: "Livello esperienza", completed: !(profile.selfLevel ?? "").isEmpty, group: "Preferenze"),
            CompletionField(label: "Esperienza trekking", completed: !(profile.trekkingExperience ?? "").isEmpty, group: "Preferenze"),
            CompletionField(label: "Frequenza attività", completed: !(profile.activityFrequency ?? "").isEmpty, group: "Preferenze"),
            CompletionField(label: "Interessi", completed: !(profile.interests ?? []).isEmpty, group: "Preferenze")
        ]
    }

    private var percentage: Int {
        guard !fields.isEmpty else { return 0 }
        return Int(round(Double(fields.filter(\.completed).count) / Double(fields.count) * 100))
    }

    private var missingProfileFields: [CompletionField] {
        fields.filter { !$0.completed && $0.group == "Profilo" }
    }

    private var missingPreferenceFields: [CompletionField] {
        fields.filter { !$0.completed && $0.group == "Preferenze" }
    }

    var body: some View {
        if percentage < 100 {
            VStack(alignment: .leading, spacing: 10) {
                HStack(spacing: 8) {
                    Image(systemName: "person.crop.circle.badge.checkmark")
                        .font(.system(size: 16, weight: .semibold))
                        .foregroundStyle(Brand.primary)
                    Text("Completa il tuo profilo")
                        .font(.system(.subheadline, design: .rounded, weight: .bold))
                    Spacer()
                    Text("\(percentage)%")
                        .font(.system(.subheadline, design: .rounded, weight: .bold))
                        .foregroundStyle(Brand.primary)
                }

                ProgressView(value: Double(percentage), total: 100)
                    .tint(Brand.primary)

                Text("Completa il profilo per migliorare i suggerimenti e accedere a tutti gli eventi")
                    .font(.caption)
                    .foregroundStyle(Brand.mutedForeground)

                VStack(alignment: .leading, spacing: 6) {
                    Text("Profilo")
                        .font(.caption2.weight(.bold))
                        .textCase(.uppercase)
                        .foregroundStyle(Brand.mutedForeground)
                    ForEach(fields.filter { $0.group == "Profilo" }) { field in
                        HStack(spacing: 7) {
                            Image(systemName: field.completed ? "checkmark.circle" : "xmark.circle")
                                .font(.caption)
                                .foregroundStyle(field.completed ? Brand.success : Brand.destructive.opacity(0.75))
                            Text(field.label)
                                .font(.caption)
                                .foregroundStyle(field.completed ? Brand.foreground : Brand.mutedForeground)
                        }
                    }

                    if !missingPreferenceFields.isEmpty {
                        Text("Preferenze")
                            .font(.caption2.weight(.bold))
                            .textCase(.uppercase)
                            .foregroundStyle(Brand.mutedForeground)
                            .padding(.top, 4)
                        ForEach(missingPreferenceFields) { field in
                            HStack(spacing: 7) {
                                Image(systemName: "xmark.circle")
                                    .font(.caption)
                                    .foregroundStyle(Brand.destructive.opacity(0.75))
                                Text(field.label)
                                    .font(.caption)
                                    .foregroundStyle(Brand.mutedForeground)
                            }
                        }
                    }
                }

                Button(missingProfileFields.isEmpty ? "Completa preferenze" : "Completa profilo", action: action)
                    .font(.system(.caption, design: .rounded, weight: .bold))
                    .foregroundStyle(.white)
                    .frame(maxWidth: .infinity)
                    .frame(height: 42)
                    .background(Brand.primary, in: RoundedRectangle(cornerRadius: 10))
            }
            .padding(14)
            .background(Brand.primary.opacity(0.055), in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.primary.opacity(0.18), lineWidth: 1))
        }
    }
}

