struct MembershipCard: View {
    @EnvironmentObject private var store: AppStore
    let profile: Profile
    @State private var benefitsExpanded = false
    @State private var isGeneratingWalletPass = false
    @State private var walletPassPayload: WalletPassPayload?

    private let membershipBenefits = [
        "Copertura assicurativa durante le attività",
        "Accesso alla community e agli eventi Scampagnate",
        "Prezzi dedicati su trekking, weekend ed esperienze",
        "Promo riservate ai soci durante l'anno",
        "Convenzioni e vantaggi del circuito AiCS",
        "Partecipazione alla vita dell'associazione"
    ]

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            ProfileSectionHeader(icon: "creditcard", title: "Tessera")
            VStack(alignment: .leading, spacing: 12) {
                HStack(alignment: .top) {
                    VStack(alignment: .leading, spacing: 6) {
                        Text("Stato tessera")
                            .font(.caption2.weight(.bold))
                            .textCase(.uppercase)
                            .foregroundStyle(Brand.mutedForeground)
                        HStack(spacing: 6) {
                            Circle()
                                .fill(statusColor)
                                .frame(width: 8, height: 8)
                            Text(statusLabel)
                                .font(.caption.weight(.bold))
                                .foregroundStyle(statusColor)
                            if profile.isFoundingMember == true {
                                Label("Fondatore", systemImage: "crown.fill")
                                    .font(.system(size: 9, weight: .bold))
                                    .textCase(.uppercase)
                                    .foregroundStyle(Brand.secondary)
                                    .padding(.horizontal, 7)
                                    .padding(.vertical, 3)
                                    .background(Brand.secondary.opacity(0.16), in: Capsule())
                            }
                        }
                    }
                    Spacer()
                    if let membershipId = profile.membershipId {
                        VStack(alignment: .trailing, spacing: 4) {
                            Text("Tessera N°")
                                .font(.caption2.weight(.bold))
                                .textCase(.uppercase)
                                .foregroundStyle(Brand.mutedForeground)
                            Button {
                                UIPasteboard.general.string = "\(membershipId)"
                            } label: {
                                HStack(spacing: 5) {
                                    Text("#\(membershipId)")
                                        .font(.system(.title3, design: .rounded, weight: .bold))
                                        .foregroundStyle(Brand.foreground)
                                    Image(systemName: "doc.on.doc")
                                        .font(.caption2.weight(.semibold))
                                        .foregroundStyle(Brand.mutedForeground)
                                }
                            }
                            .buttonStyle(.plain)
                        }
                    } else if profile.hasActiveMembership {
                        VStack(alignment: .trailing, spacing: 4) {
                            Text("Tessera N°")
                                .font(.caption2.weight(.bold))
                                .textCase(.uppercase)
                                .foregroundStyle(Brand.mutedForeground)
                            Text("In assegnazione")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                    }
                }

                if profile.hasActiveMembership {
                    Text("Tessera attiva fino al \(membershipExpiryLong)")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.success)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(.horizontal, 12)
                        .padding(.vertical, 10)
                        .background(Brand.success.opacity(0.12), in: RoundedRectangle(cornerRadius: 10))

                    HStack(spacing: 22) {
                        MembershipDateBlock(title: "Membro dal", value: membershipStartShort)
                        MembershipDateBlock(title: "Scadenza", value: membershipExpiryShort)
                    }

                    walletButton

                    VStack(alignment: .leading, spacing: 8) {
                        Button {
                            withAnimation(.easeInOut(duration: 0.22)) {
                                benefitsExpanded.toggle()
                            }
                        } label: {
                            HStack(spacing: 5) {
                                Text("Benefici inclusi")
                                Image(systemName: benefitsExpanded ? "chevron.up" : "chevron.down")
                            }
                            .font(.caption2.weight(.bold))
                            .textCase(.uppercase)
                            .foregroundStyle(Brand.mutedForeground)
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)
                        .accessibilityValue(benefitsExpanded ? "Aperto" : "Chiuso")

                        VStack(alignment: .leading, spacing: 7) {
                            if benefitsExpanded {
                                VStack(alignment: .leading, spacing: 7) {
                                    ForEach(membershipBenefits, id: \.self) { benefit in
                                        MembershipBenefitRow(benefit)
                                    }
                                }
                                .transition(.opacity.combined(with: .move(edge: .top)))
                            }
                        }
                        .clipped()
                    }
                    .padding(.top, 2)
                } else {
                    VStack(spacing: 8) {
                        Image(systemName: "creditcard")
                            .font(.title2)
                            .foregroundStyle(Brand.mutedForeground.opacity(0.55))
                        Text(profile.membershipStatus == "Expired" ? "La tua tessera è scaduta" : "Non hai ancora una tessera attiva")
                            .font(.subheadline.weight(.bold))
                        Text("Attivala per partecipare agli eventi e ottenere la copertura assicurativa.")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                            .multilineTextAlignment(.center)
                    }
                    .frame(maxWidth: .infinity)
                    .padding(14)
                    .background(Brand.muted.opacity(0.45), in: RoundedRectangle(cornerRadius: 12))
                }
            }
            .padding(14)
            .background(cardBackground, in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(cardBorder, lineWidth: 1))
        }
        .sheet(item: $walletPassPayload) { payload in
            WalletPassSheet(pass: payload.pass)
        }
    }

    private var walletButton: some View {
        Button {
            Task { await addWalletPass() }
        } label: {
            HStack(spacing: 8) {
                if isGeneratingWalletPass {
                    ProgressView()
                        .controlSize(.small)
                        .tint(Brand.primary)
                } else {
                    Image(systemName: "wallet.pass")
                        .font(.system(size: 13, weight: .bold))
                }
                Text(isGeneratingWalletPass ? "Preparo Wallet" : "Aggiungi a Wallet")
                    .font(.caption.weight(.bold))
                    .lineLimit(1)
                    .minimumScaleFactor(0.86)
            }
            .foregroundStyle(Brand.primary)
            .padding(.horizontal, 12)
            .frame(height: 34)
            .background(Brand.primary.opacity(0.10), in: Capsule())
            .overlay(Capsule().stroke(Brand.primary.opacity(0.20), lineWidth: 1))
        }
        .buttonStyle(.plain)
        .disabled(isGeneratingWalletPass)
        .opacity(isGeneratingWalletPass ? 0.72 : 1)
        .accessibilityLabel("Aggiungi tessera ad Apple Wallet")
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    @MainActor
    private func addWalletPass() async {
        guard !isGeneratingWalletPass else { return }
        guard PKAddPassesViewController.canAddPasses() else {
            store.errorMessage = "Apple Wallet non è disponibile su questo dispositivo."
            return
        }

        isGeneratingWalletPass = true
        defer { isGeneratingWalletPass = false }

        do {
            let passData = try await store.generateWalletPass()
            let pass = try PKPass(data: passData)
            walletPassPayload = WalletPassPayload(pass: pass)
        } catch {
            guard !error.isCancellation else { return }
            store.errorMessage = error.localizedDescription
        }
    }

    private var statusLabel: String {
        if profile.hasActiveMembership { return "Attiva" }
        if profile.membershipStatus == "Expired" { return "Scaduta" }
        return "Non attiva"
    }

    private var statusColor: Color {
        if profile.hasActiveMembership { return Brand.success }
        if profile.membershipStatus == "Expired" { return Brand.warning }
        return Brand.mutedForeground
    }

    private var cardBackground: Color {
        if profile.hasActiveMembership { return Brand.primary.opacity(0.055) }
        if profile.membershipStatus == "Expired" { return Brand.warning.opacity(0.055) }
        return Brand.muted.opacity(0.5)
    }

    private var cardBorder: Color {
        if profile.hasActiveMembership { return Brand.primary.opacity(0.18) }
        if profile.membershipStatus == "Expired" { return Brand.warning.opacity(0.2) }
        return Brand.muted
    }

    private var membershipYear: Int {
        profile.membershipYear ?? Calendar.current.component(.year, from: Date())
    }

    private var membershipExpiryDate: Date {
        var components = DateComponents()
        components.calendar = Calendar(identifier: .gregorian)
        components.year = membershipYear
        components.month = 12
        components.day = 31
        return components.date ?? Date()
    }

    private var membershipExpiryLong: String {
        DateFormatter.membershipLongItalian.string(from: membershipExpiryDate)
    }

    private var membershipExpiryShort: String {
        DateFormatter.membershipShortItalian.string(from: membershipExpiryDate)
    }

    private var membershipStartShort: String {
        guard let date = profile.membershipRegistrationDate?.iso8601Date else { return "N/D" }
        return DateFormatter.membershipShortItalian.string(from: date)
    }
}

