struct ProfileProgressionSection: View {
    let profile: Profile
    let levels: [CommunityLevelDefinition]

    private var displayLevels: [CommunityLevelDefinition] {
        CommunityLevelDefinition.displayLevels(levels)
    }

    private var points: Int {
        profile.totalPoints ?? 0
    }

    private var currentLevel: CommunityLevelDefinition? {
        CommunityLevelDefinition.currentLevel(points: points, levels: displayLevels)
    }

    private var nextLevel: CommunityLevelDefinition? {
        displayLevels.first(where: { $0.minPoints > points })
    }

    private var progress: Double {
        guard let currentLevel, let nextLevel else { return 1 }
        let span = max(nextLevel.minPoints - currentLevel.minPoints, 1)
        return Double(points - currentLevel.minPoints) / Double(span)
    }

    private var currentLevelColor: Color {
        currentLevel.flatMap { Color(hex: $0.color) } ?? Brand.primary
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            ProfileSectionHeader(icon: "chart.line.uptrend.xyaxis", title: "Progressione")

            VStack(alignment: .leading, spacing: 13) {
                HStack(spacing: 8) {
                    Image(systemName: "star")
                        .font(.system(size: 18, weight: .semibold))
                        .foregroundStyle(Brand.primary)
                    Text("\(points) punti")
                        .font(.system(.headline, design: .rounded, weight: .bold))
                }

                if let currentLevel {
                    HStack(spacing: 12) {
                        SupabaseIconView(value: currentLevel.icon, size: 19, color: currentLevelColor)
                            .frame(width: 46, height: 46)
                            .background(currentLevelColor.opacity(0.12), in: Circle())
                            .overlay(Circle().stroke(currentLevelColor.opacity(0.75), lineWidth: 1.5))

                        VStack(alignment: .leading, spacing: 3) {
                            Text("Livello \(currentLevel.levelNumber): \(currentLevel.name)")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                            if let nextLevel {
                                Text("\(max(nextLevel.minPoints - points, 0)) punti per \(nextLevel.name)")
                                    .font(.caption2)
                                    .foregroundStyle(Brand.mutedForeground)
                            } else {
                                Text("Livello massimo raggiunto")
                                    .font(.caption2.weight(.semibold))
                                    .foregroundStyle(Brand.primary)
                            }
                        }
                        Spacer(minLength: 0)
                    }

                    if let nextLevel {
                        HStack(spacing: 8) {
                            ProgressView(value: progress)
                                .tint(Brand.secondary)
                            Text("\(points)/\(nextLevel.minPoints)")
                                .font(.system(size: 10, weight: .bold))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                    }
                } else {
                    Text("Livelli community non disponibili.")
                        .font(.caption.weight(.semibold))
                        .foregroundStyle(Brand.mutedForeground)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(.vertical, 8)
                }
            }
            .padding(14)
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
        }
    }
}

struct MissionsSection: View {
    @EnvironmentObject private var store: AppStore
    let missions: [MissionCardModel]
    @Binding var routedMission: MissionNavigationTarget?
    @State private var selectedMission: MissionCardModel?
    @State private var showAdditionalActiveMissions = false
    @State private var showCompletedMissions = false

    private static let visibleActiveMissionLimit = 3

    private var activeMissions: [MissionCardModel] {
        missions.enumerated()
            .filter { !$0.element.isCompleted }
            .sorted { lhs, rhs in
                let lhsRatio = lhs.element.completionRatio
                let rhsRatio = rhs.element.completionRatio
                if lhsRatio != rhsRatio {
                    return lhsRatio > rhsRatio
                }
                return lhs.offset < rhs.offset
            }
            .map(\.element)
    }

    private var visibleActiveMissions: [MissionCardModel] {
        Array(activeMissions.prefix(Self.visibleActiveMissionLimit))
    }

    private var additionalActiveMissions: [MissionCardModel] {
        Array(activeMissions.dropFirst(Self.visibleActiveMissionLimit))
    }

    private var additionalActiveMissionTriggerText: String {
        let count = additionalActiveMissions.count
        return count == 1 ? "Mostra 1 altra missione" : "Mostra altre \(count) missioni"
    }

    private var completedMissions: [MissionCardModel] {
        missions.filter(\.isCompleted)
    }

    private var recentlyCompletedMissions: [MissionCardModel] {
        completedMissions.sorted { lhs, rhs in
            (lhs.completedAt ?? "") > (rhs.completedAt ?? "")
        }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            ProfileSectionHeader(icon: "target", title: "Missioni")
            if missions.isEmpty {
                EmptyState(icon: "target", title: "Nessuna missione", message: "Partecipa agli eventi per sbloccare missioni.")
            } else {
                if activeMissions.isEmpty {
                    Text("Hai completato tutte le missioni disponibili. Le trovi nello storico qui sotto.")
                        .font(.caption)
                        .foregroundStyle(Brand.mutedForeground)
                        .frame(maxWidth: .infinity, alignment: .leading)
                        .padding(12)
                        .background(Brand.card, in: RoundedRectangle(cornerRadius: 12))
                        .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.muted, lineWidth: 1))
                } else {
                    ForEach(visibleActiveMissions) { mission in
                        MissionRow(mission: mission) {
                            selectedMission = mission
                        }
                    }

                    if !additionalActiveMissions.isEmpty {
                        Button {
                            withAnimation(.easeInOut(duration: 0.18)) {
                                showAdditionalActiveMissions.toggle()
                            }
                        } label: {
                            HStack(spacing: 8) {
                                Text(showAdditionalActiveMissions ? "Nascondi missioni" : additionalActiveMissionTriggerText)
                                    .font(.caption.weight(.bold))
                                    .foregroundStyle(Brand.foreground)
                                Spacer()
                                Image(systemName: showAdditionalActiveMissions ? "chevron.up" : "chevron.down")
                                    .font(.caption2.weight(.bold))
                                    .foregroundStyle(Brand.mutedForeground)
                            }
                            .padding(.horizontal, 12)
                            .frame(height: 42)
                            .background(Brand.muted.opacity(0.45), in: RoundedRectangle(cornerRadius: 12))
                        }
                        .buttonStyle(.plain)

                        if showAdditionalActiveMissions {
                            ForEach(additionalActiveMissions) { mission in
                                MissionRow(mission: mission) {
                                    selectedMission = mission
                                }
                            }
                        }
                    }
                }

                if !completedMissions.isEmpty {
                    Button {
                        withAnimation(.easeInOut(duration: 0.18)) {
                            showCompletedMissions.toggle()
                        }
                    } label: {
                        HStack(spacing: 8) {
                            Image(systemName: "checkmark.seal")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.primary)
                            Text("Missioni completate (\(completedMissions.count))")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                            Spacer()
                            Image(systemName: showCompletedMissions ? "chevron.up" : "chevron.down")
                                .font(.caption2.weight(.bold))
                                .foregroundStyle(Brand.mutedForeground)
                        }
                        .padding(.horizontal, 12)
                        .frame(height: 42)
                        .background(Brand.muted.opacity(0.6), in: RoundedRectangle(cornerRadius: 12))
                    }
                    .buttonStyle(.plain)

                    if showCompletedMissions {
                        ForEach(completedMissions) { mission in
                            MissionRow(mission: mission) {
                                selectedMission = mission
                            }
                        }
                    }
                }
            }
        }
        .sheet(item: $selectedMission) { mission in
            MissionDetailSheet(mission: mission) {
                openEvents(for: mission)
                selectedMission = nil
            }
                .presentationDetents([.medium, .large])
                .presentationDragIndicator(.visible)
        }
        .onAppear {
            openRoutedMissionIfNeeded()
        }
        .onChange(of: routedMission?.id) { _, _ in
            openRoutedMissionIfNeeded()
        }
        .onChange(of: missions.map(\.id)) { _, _ in
            openRoutedMissionIfNeeded()
        }
    }

    private func openEvents(for mission: MissionCardModel) {
        store.homeDiscoveryRequest = HomeDiscoveryRequest(mission: mission)
    }

    private func openRoutedMissionIfNeeded() {
        guard let target = routedMission, !missions.isEmpty else { return }

        let mission: MissionCardModel?
        if let missionId = target.missionId?.nilIfBlank {
            mission = missions.first { $0.missionId == missionId || $0.id == missionId }
        } else {
            mission = routedCompletedMission(near: target.completedAtHint)
        }

        guard let mission else { return }
        if mission.isCompleted {
            showCompletedMissions = true
        } else if additionalActiveMissions.contains(where: { $0.id == mission.id }) {
            showAdditionalActiveMissions = true
        }
        selectedMission = mission
        routedMission = nil
    }

    private func routedCompletedMission(near completedAtHint: String?) -> MissionCardModel? {
        guard let hintDate = completedAtHint?.isoDate else {
            return recentlyCompletedMissions.first
        }

        return completedMissions.min { lhs, rhs in
            let lhsDistance = abs((lhs.completedAt?.isoDate ?? .distantPast).timeIntervalSince(hintDate))
            let rhsDistance = abs((rhs.completedAt?.isoDate ?? .distantPast).timeIntervalSince(hintDate))
            return lhsDistance < rhsDistance
        } ?? recentlyCompletedMissions.first
    }
}

