struct RewardCard: View {
    let reward: Reward
    @State private var copiedCode = false

    private var isDimmed: Bool {
        !reward.isCurrent
    }

    var body: some View {
        HStack(alignment: .top, spacing: 12) {
            RewardTypeIconView(reward: reward)

            VStack(alignment: .leading, spacing: 6) {
                HStack(alignment: .firstTextBaseline, spacing: 8) {
                    Text(reward.displayTitle)
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.foreground)
                        .lineLimit(2)
                    Spacer(minLength: 0)
                    RewardStatusPill(text: reward.statusStyle.label, color: reward.statusStyle.color)
                }

                if let description = reward.summaryDescription {
                    Text(description)
                        .font(.caption2)
                        .foregroundStyle(Brand.mutedForeground)
                        .lineLimit(2)
                }

                if reward.kind == .coupon, let code = reward.value?.nilIfBlank {
                    HStack(spacing: 8) {
                        Text(code)
                            .font(.system(size: 11, weight: .semibold, design: .monospaced))
                            .foregroundStyle(Brand.foreground)
                            .padding(.horizontal, 8)
                            .padding(.vertical, 4)
                            .background(Brand.muted.opacity(0.7), in: RoundedRectangle(cornerRadius: 7))

                        if reward.effectiveStatus == "active" {
                            Image(systemName: copiedCode ? "checkmark" : "doc.on.doc")
                                .font(.caption.weight(.bold))
                                .foregroundStyle(Brand.primary)
                                .padding(6)
                                .contentShape(Rectangle())
                                .onTapGesture {
                                    UIPasteboard.general.string = code
                                    copiedCode = true
                                }
                            .accessibilityLabel(copiedCode ? "Codice copiato" : "Copia codice")
                        }
                    }
                }

                if reward.kind == .physical, reward.effectiveStatus == "pending" {
                    HStack(spacing: 4) {
                        LucideIconView(name: "gift", size: 12, color: Brand.warning)
                        Text("Da ritirare al prossimo evento")
                            .font(.caption2)
                            .foregroundStyle(Brand.warning)
                    }
                }

                if let expiry = reward.expiryDate?.shortDateLabel {
                    HStack(spacing: 4) {
                        LucideIconView(name: "clock", size: 12, color: Brand.mutedForeground)
                        Text("Scade il \(expiry)")
                            .font(.system(size: 10))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                }

                if let missionTitle = reward.missions?.title?.nilIfBlank {
                    HStack(spacing: 5) {
                        MissionDynamicIconView(value: reward.missions?.icon ?? "", size: 12, color: Brand.mutedForeground)
                        Text(missionTitle)
                            .font(.system(size: 10))
                            .foregroundStyle(Brand.mutedForeground)
                            .lineLimit(1)
                    }
                }
            }

            Image(systemName: "chevron.right")
                .font(.caption2.weight(.bold))
                .foregroundStyle(Brand.mutedForeground.opacity(0.7))
        }
        .padding(12)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Brand.card, in: RoundedRectangle(cornerRadius: 12))
        .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.muted, lineWidth: 1))
        .opacity(isDimmed ? 0.62 : 1)
        .contentShape(RoundedRectangle(cornerRadius: 12))
    }
}

