struct NextBadgeCard: View {
    let badge: BadgeDefinition
    let attendedCount: Int

    private var target: Int { max(badge.requiredEvents ?? badge.requirementValue ?? 1, 1) }
    private var progress: Int { min(attendedCount, target) }

    var body: some View {
        HStack(spacing: 12) {
            BadgeIconView(icon: badge.icon, color: Brand.mutedForeground.opacity(0.55), size: 20)
                .frame(width: 40, height: 40)
                .background(Brand.muted.opacity(0.72), in: Circle())
            VStack(alignment: .leading, spacing: 4) {
                Text(badge.name)
                    .font(.caption.weight(.bold))
                    .foregroundStyle(Brand.foreground)
                Text(badge.description ?? "Partecipa agli eventi per sbloccarlo")
                    .font(.caption2)
                    .foregroundStyle(Brand.mutedForeground)
                HStack(spacing: 8) {
                    ProgressView(value: Double(progress), total: Double(target))
                        .tint(Brand.secondary)
                    Text("\(progress)/\(target)")
                        .font(.system(size: 10, weight: .bold))
                        .foregroundStyle(Brand.mutedForeground)
                }
            }
        }
        .padding(12)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(Brand.muted.opacity(0.42), in: RoundedRectangle(cornerRadius: 12))
        .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.muted, lineWidth: 1))
    }
}

