struct LucideIconView: View {
    let name: String
    var size: CGFloat
    var color: Color

    private var normalizedName: String {
        name
            .replacingOccurrences(of: "lucide:", with: "", options: .caseInsensitive)
            .replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: " ", with: "")
            .lowercased()
    }

    var body: some View {
        Canvas { context, canvasSize in
            let scale = min(canvasSize.width, canvasSize.height) / 24
            let offsetX = (canvasSize.width - 24 * scale) / 2
            let offsetY = (canvasSize.height - 24 * scale) / 2
            let stroke = StrokeStyle(lineWidth: max(1.35, 2 * scale), lineCap: .round, lineJoin: .round)

            func point(_ x: CGFloat, _ y: CGFloat) -> CGPoint {
                CGPoint(x: offsetX + x * scale, y: offsetY + y * scale)
            }

            func draw(_ path: Path) {
                context.stroke(path, with: .color(color), style: stroke)
            }

            func drawLine(_ x1: CGFloat, _ y1: CGFloat, _ x2: CGFloat, _ y2: CGFloat) {
                var path = Path()
                path.move(to: point(x1, y1))
                path.addLine(to: point(x2, y2))
                draw(path)
            }

            func drawCircle(centerX: CGFloat, centerY: CGFloat, radius: CGFloat) {
                let rect = CGRect(
                    x: point(centerX - radius, centerY - radius).x,
                    y: point(centerX - radius, centerY - radius).y,
                    width: radius * 2 * scale,
                    height: radius * 2 * scale
                )
                draw(Path(ellipseIn: rect))
            }

            switch normalizedName {
            case "flagtriangleright", "flag":
                drawLine(6, 3, 6, 22)
                var path = Path()
                path.move(to: point(6, 4))
                path.addCurve(to: point(19, 8), control1: point(10, 2.6), control2: point(14.5, 4.8))
                path.addLine(to: point(6, 15))
                draw(path)
            case "flame":
                var path = Path()
                path.move(to: point(12, 3))
                path.addCurve(to: point(18, 13), control1: point(12, 7), control2: point(18, 8))
                path.addCurve(to: point(12, 22), control1: point(18, 18), control2: point(15, 22))
                path.addCurve(to: point(6, 15), control1: point(8, 22), control2: point(6, 19))
                path.addCurve(to: point(9, 10), control1: point(6, 12.5), control2: point(8.2, 11.8))
                path.addCurve(to: point(12, 3), control1: point(10.5, 8), control2: point(9.8, 5.4))
                draw(path)
                var inner = Path()
                inner.move(to: point(12, 12))
                inner.addCurve(to: point(13, 19), control1: point(14, 15), control2: point(15, 17.5))
                inner.addCurve(to: point(10, 17), control1: point(11.5, 20), control2: point(9.8, 19))
                draw(inner)
            case "star":
                draw(starPath(point: point, outerRadius: 9.5, innerRadius: 4.2))
            case "sparkles":
                draw(diamondPath(point: point, centerX: 9, centerY: 8, radiusX: 3.5, radiusY: 5))
                draw(diamondPath(point: point, centerX: 17, centerY: 16, radiusX: 2.5, radiusY: 3.5))
                drawLine(18, 4, 18, 8)
                drawLine(16, 6, 20, 6)
            case "sprout":
                drawLine(12, 21, 12, 12)
                var left = Path()
                left.move(to: point(12, 12))
                left.addCurve(to: point(4, 7), control1: point(8, 12), control2: point(5.5, 9.5))
                left.addCurve(to: point(12, 12), control1: point(5.5, 5), control2: point(10, 6))
                draw(left)
                var right = Path()
                right.move(to: point(12, 12))
                right.addCurve(to: point(20, 6), control1: point(14, 8), control2: point(17, 6))
                right.addCurve(to: point(12, 12), control1: point(20, 10), control2: point(17, 13))
                draw(right)
            case "footprints":
                var left = Path()
                left.addEllipse(in: CGRect(x: point(7, 6).x, y: point(4.5, 5).y, width: 5 * scale, height: 8 * scale))
                draw(left)
                var right = Path()
                right.addEllipse(in: CGRect(x: point(13, 12).x, y: point(12, 11).y, width: 5 * scale, height: 8 * scale))
                draw(right)
                drawCircle(centerX: 14, centerY: 4, radius: 1.2)
                drawCircle(centerX: 17, centerY: 5, radius: 1.1)
                drawCircle(centerX: 7, centerY: 16, radius: 1.2)
                drawCircle(centerX: 10, centerY: 17, radius: 1.1)
            case "compass":
                drawCircle(centerX: 12, centerY: 12, radius: 9)
                var needle = Path()
                needle.move(to: point(15.5, 8.5))
                needle.addLine(to: point(13.5, 14))
                needle.addLine(to: point(8.5, 15.5))
                needle.addLine(to: point(10.5, 10))
                needle.closeSubpath()
                draw(needle)
            case "mountain":
                var path = Path()
                path.move(to: point(3, 20))
                path.addLine(to: point(9, 8))
                path.addLine(to: point(13, 15))
                path.addLine(to: point(15, 12))
                path.addLine(to: point(21, 20))
                draw(path)
                drawLine(9, 8, 11, 12)
            case "trophy":
                var cup = Path()
                cup.move(to: point(8, 4))
                cup.addLine(to: point(16, 4))
                cup.addLine(to: point(15, 12))
                cup.addCurve(to: point(9, 12), control1: point(14.5, 15), control2: point(9.5, 15))
                cup.closeSubpath()
                draw(cup)
                drawLine(12, 15, 12, 19)
                drawLine(8, 21, 16, 21)
                drawLine(10, 19, 14, 19)
                drawLine(8, 6, 4, 6)
                drawLine(16, 6, 20, 6)
                drawLine(4, 6, 6, 11)
                drawLine(20, 6, 18, 11)
            case "crown":
                var path = Path()
                path.move(to: point(4, 18))
                path.addLine(to: point(5, 8))
                path.addLine(to: point(10, 13))
                path.addLine(to: point(12, 6))
                path.addLine(to: point(14, 13))
                path.addLine(to: point(19, 8))
                path.addLine(to: point(20, 18))
                path.closeSubpath()
                draw(path)
                drawLine(5, 21, 19, 21)
            case "sunrise":
                drawLine(3, 18, 21, 18)
                var arc = Path()
                arc.addArc(center: point(12, 18), radius: 6 * scale, startAngle: .degrees(180), endAngle: .degrees(360), clockwise: false)
                draw(arc)
                drawLine(12, 4, 12, 7)
                drawLine(5, 9, 7, 11)
                drawLine(19, 9, 17, 11)
                drawLine(4, 22, 20, 22)
            case "wine":
                var bowl = Path()
                bowl.move(to: point(8, 3))
                bowl.addLine(to: point(16, 3))
                bowl.addLine(to: point(15, 10))
                bowl.addCurve(to: point(9, 10), control1: point(15, 14), control2: point(9, 14))
                bowl.closeSubpath()
                draw(bowl)
                drawLine(12, 14, 12, 20)
                drawLine(8, 21, 16, 21)
            case "medal":
                drawLine(8, 3, 10, 8)
                drawLine(16, 3, 14, 8)
                drawCircle(centerX: 12, centerY: 15, radius: 5)
                draw(starPath(point: point, centerX: 12, centerY: 15, outerRadius: 2.3, innerRadius: 1.0))
            case "ticket":
                var path = Path()
                path.move(to: point(5, 6))
                path.addLine(to: point(19, 6))
                path.addCurve(to: point(20, 10), control1: point(21, 7), control2: point(21, 9))
                path.addCurve(to: point(20, 14), control1: point(18.6, 11), control2: point(18.6, 13))
                path.addCurve(to: point(19, 18), control1: point(21, 15), control2: point(21, 17))
                path.addLine(to: point(5, 18))
                path.addCurve(to: point(4, 14), control1: point(3, 17), control2: point(3, 15))
                path.addCurve(to: point(4, 10), control1: point(5.4, 13), control2: point(5.4, 11))
                path.addCurve(to: point(5, 6), control1: point(3, 9), control2: point(3, 7))
                draw(path)
                drawLine(9, 8, 9, 16)
            case "gift":
                var box = Path()
                box.addRoundedRect(in: CGRect(x: point(4, 9).x, y: point(4, 9).y, width: 16 * scale, height: 11 * scale), cornerSize: CGSize(width: 2 * scale, height: 2 * scale))
                draw(box)
                drawLine(4, 13, 20, 13)
                drawLine(12, 9, 12, 20)
                drawLine(8, 9, 7, 6)
                drawLine(7, 6, 12, 9)
                drawLine(16, 9, 17, 6)
                drawLine(17, 6, 12, 9)
            case "clock":
                drawCircle(centerX: 12, centerY: 12, radius: 9)
                drawLine(12, 7, 12, 12)
                drawLine(12, 12, 16, 14)
            default:
                draw(diamondPath(point: point, centerX: 12, centerY: 12, radiusX: 4, radiusY: 6))
            }
        }
        .frame(width: size, height: size)
    }

    private func starPath(
        point: (CGFloat, CGFloat) -> CGPoint,
        centerX: CGFloat = 12,
        centerY: CGFloat = 12,
        outerRadius: CGFloat,
        innerRadius: CGFloat
    ) -> Path {
        var path = Path()
        for index in 0..<10 {
            let angle = CGFloat(index) * .pi / 5 - .pi / 2
            let radius = index.isMultiple(of: 2) ? outerRadius : innerRadius
            let x = centerX + cos(angle) * radius
            let y = centerY + sin(angle) * radius
            if index == 0 {
                path.move(to: point(x, y))
            } else {
                path.addLine(to: point(x, y))
            }
        }
        path.closeSubpath()
        return path
    }

    private func diamondPath(
        point: (CGFloat, CGFloat) -> CGPoint,
        centerX: CGFloat,
        centerY: CGFloat,
        radiusX: CGFloat,
        radiusY: CGFloat
    ) -> Path {
        var path = Path()
        path.move(to: point(centerX, centerY - radiusY))
        path.addLine(to: point(centerX + radiusX, centerY))
        path.addLine(to: point(centerX, centerY + radiusY))
        path.addLine(to: point(centerX - radiusX, centerY))
        path.closeSubpath()
        return path
    }
}

struct ProfileActivityHistorySection: View {
    let registrations: [Registration]
    @State private var showTimeline = false
    @State private var timelineLimit = 8
    @State private var showStreakDetail = false
    @State private var activeStatsHelp: StatsHelp?
    private let timelinePageSize = 8

    private enum StatsHelp: Equatable {
        case reliability
        case frequency

        var text: String {
            switch self {
            case .reliability:
                return "Percentuale degli eventi passati in cui eri iscritto e ti sei presentato. I check-in la alzano; no-show e assenze senza check-in la abbassano. Le cancellazioni corrette non la abbassano."
            case .frequency:
                return "Media mensile degli eventi completati negli ultimi 6 mesi. Conta solo le partecipazioni con check-in confermato."
            }
        }
    }

    private var uniqueRegistrations: [Registration] {
        var byEvent: [String: Registration] = [:]

        for registration in registrations {
            let key = registration.eventId ?? registration.event?.id ?? registration.id
            guard !key.isEmpty else { continue }

            if let current = byEvent[key] {
                let nextRank = activityRank(registration)
                let currentRank = activityRank(current)
                if nextRank > currentRank || (nextRank == currentRank && registrationTime(registration) > registrationTime(current)) {
                    byEvent[key] = registration
                }
            } else {
                byEvent[key] = registration
            }
        }

        return Array(byEvent.values)
    }

    private var joined: Int {
        uniqueRegistrations.filter { ["registered", "deposit_paid", "paid", "pending_payment", "waitlist"].contains($0.normalizedStatus) }.count
    }

    private var attended: Int {
        uniqueRegistrations.filter(isAttended).count
    }

    private var cancelled: Int {
        uniqueRegistrations.filter { $0.normalizedStatus == "cancelled" }.count
    }

    private var noShows: Int {
        uniqueRegistrations.filter { registration in
            if registration.normalizedStatus == "no_show" { return true }
            return isPast(registration) && isActiveAttendanceStatus(registration.status) && !isAttended(registration)
        }.count
    }

    private var reliability: Int {
        let total = attended + noShows
        guard total > 0 else { return 100 }
        return Int(round(Double(attended) / Double(total) * 100))
    }

    private var frequency: String {
        let sixMonthsAgo = Calendar.current.date(byAdding: .month, value: -6, to: Calendar.current.startOfDay(for: Date())) ?? Date()
        let recent = uniqueRegistrations.filter { registration in
            guard let date = eventDate(registration), isAttended(registration) else { return false }
            return date >= sixMonthsAgo
        }
        return String(format: "%.1f", Double(recent.count) / 6.0)
    }

    private var streak: Int {
        streakRegistrations.count
    }

    private var streakRegistrations: [Registration] {
        uniqueRegistrations
            .filter { registration in
                isPast(registration) && (isActiveAttendanceStatus(registration.status) || registration.checkedIn == true)
            }
            .sorted { lhs, rhs in
                (eventDate(lhs) ?? .distantPast) > (eventDate(rhs) ?? .distantPast)
            }
            .prefix(while: isAttended)
            .map { $0 }
    }

    private var topCategory: (name: String, icon: String?, percentage: Int)? {
        let attendedRegistrations = uniqueRegistrations.filter(isAttended)
        guard !attendedRegistrations.isEmpty else { return nil }

        var counts: [String: (count: Int, icon: String?)] = [:]
        for registration in attendedRegistrations {
            guard let category = registration.event?.eventCategories?.name else { continue }
            let current = counts[category] ?? (0, registration.event?.eventCategories?.icon)
            counts[category] = (current.count + 1, current.icon ?? registration.event?.eventCategories?.icon)
        }

        guard let best = counts.max(by: { $0.value.count < $1.value.count }) else { return nil }
        return (
            name: best.key,
            icon: best.value.icon,
            percentage: Int(round(Double(best.value.count) / Double(attendedRegistrations.count) * 100))
        )
    }

    private var timelineRegistrations: [Registration] {
        uniqueRegistrations
            .filter(isPast)
            .sorted { lhs, rhs in
                (eventDate(lhs) ?? .distantPast) > (eventDate(rhs) ?? .distantPast)
            }
    }

    private func isActiveAttendanceStatus(_ status: String?) -> Bool {
        let normalized = status?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() ?? "registered"
        return ["registered", "deposit_paid", "paid", "attended"].contains(normalized)
    }

    private func isAttended(_ registration: Registration) -> Bool {
        isActiveAttendanceStatus(registration.status) && (registration.checkedIn == true || registration.normalizedStatus == "attended")
    }

    private func isPast(_ registration: Registration) -> Bool {
        guard let date = eventDate(registration) else { return false }
        return date < Calendar.current.startOfDay(for: Date())
    }

    private func eventDate(_ registration: Registration) -> Date? {
        guard let value = registration.event?.date else { return nil }
        return DateFormatter.eventDate.date(from: value)
    }

    private func activityRank(_ registration: Registration) -> Int {
        if isAttended(registration) { return 5 }
        if isActiveAttendanceStatus(registration.status) { return 4 }
        if registration.normalizedStatus == "no_show" { return 3 }
        if registration.normalizedStatus == "cancelled" { return 2 }
        return 1
    }

    private func registrationTime(_ registration: Registration) -> TimeInterval {
        if let createdAt = registration.createdAt?.isoDate {
            return createdAt.timeIntervalSince1970
        }
        return eventDate(registration)?.timeIntervalSince1970 ?? 0
    }

    private func toggleStatsHelp(_ help: StatsHelp) {
        withAnimation(.easeInOut(duration: 0.16)) {
            activeStatsHelp = activeStatsHelp == help ? nil : help
        }
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            ProfileSectionHeader(icon: "clock.arrow.circlepath", title: "Cronologia Attività")

            HStack(spacing: 8) {
                ActivityStatCard(icon: "calendar", value: joined, label: "Iscritti", color: Brand.primary)
                ActivityStatCard(icon: "checkmark.circle", value: attended, label: "Completati", color: Brand.success)
                ActivityStatCard(icon: "exclamationmark.circle", value: noShows, label: "No-show", color: Brand.destructive)
                ActivityStatCard(icon: "calendar.badge.minus", value: cancelled, label: "Cancellati", color: Brand.destructive)
            }

            Button {
                showStreakDetail = true
            } label: {
                HStack {
                    VStack(alignment: .leading, spacing: 8) {
                        Label("Streak attuale", systemImage: "flame")
                            .font(.system(size: 11, weight: .bold))
                            .textCase(.uppercase)
                            .foregroundStyle(Brand.mutedForeground)
                            .labelStyle(.titleAndIcon)
                        Text("\(streak)")
                            .font(.system(size: 38, weight: .bold, design: .rounded))
                            .foregroundStyle(Brand.foreground)
                        Text(streak == 1 ? "evento consecutivo completato" : "eventi consecutivi completati")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    Spacer()
                    Image(systemName: "chevron.right")
                        .font(.caption.weight(.bold))
                        .foregroundStyle(Brand.mutedForeground.opacity(0.7))
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(14)
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.muted, lineWidth: 1))
            .contentShape(RoundedRectangle(cornerRadius: 16))
            .accessibilityLabel("Streak attuale, \(streak) eventi consecutivi completati")
            .accessibilityHint("Apri il dettaglio degli eventi che contano per la streak")

            VStack(alignment: .leading, spacing: 10) {
                Label("Statistiche", systemImage: "chart.bar")
                    .font(.caption2.weight(.bold))
                    .textCase(.uppercase)
                    .foregroundStyle(Brand.mutedForeground)
                VStack(spacing: 10) {
                    HStack {
                        HStack(spacing: 5) {
                            Label("Affidabilità", systemImage: "shield")
                                .font(.caption.weight(.semibold))
                            StatsInfoButton(
                                title: "Affidabilità",
                                isActive: activeStatsHelp == .reliability
                            ) {
                                toggleStatsHelp(.reliability)
                            }
                        }
                        Spacer()
                        Text("\(reliability)%")
                            .font(.caption.weight(.bold))
                            .foregroundStyle(reliability >= 80 ? Brand.success : Brand.warning)
                    }
                    ProgressView(value: Double(reliability), total: 100)
                        .tint(Brand.primary)
                    if activeStatsHelp == .reliability {
                        StatsInlineHelp(text: StatsHelp.reliability.text)
                    }
                    HStack {
                        HStack(spacing: 5) {
                            Label("Frequenza attività", systemImage: "chart.line.uptrend.xyaxis")
                                .font(.caption.weight(.semibold))
                            StatsInfoButton(
                                title: "Frequenza attività",
                                isActive: activeStatsHelp == .frequency
                            ) {
                                toggleStatsHelp(.frequency)
                            }
                        }
                        Spacer()
                        Text("\(frequency) eventi/mese")
                            .font(.caption.weight(.bold))
                    }
                    if activeStatsHelp == .frequency {
                        StatsInlineHelp(text: StatsHelp.frequency.text)
                    }
                    if let topCategory {
                        HStack {
                            HStack(spacing: 6) {
                                if let icon = topCategory.icon {
                                    SupabaseIconView(value: icon, size: 14, color: Brand.primary)
                                } else {
                                    Image(systemName: "mountain.2")
                                        .font(.caption.weight(.semibold))
                                        .foregroundStyle(Brand.primary)
                                }
                                Text("Categoria preferita")
                                    .font(.caption.weight(.semibold))
                            }
                            Spacer()
                            Text("\(topCategory.name) \(topCategory.percentage)%")
                                .font(.caption.weight(.bold))
                                .lineLimit(1)
                                .minimumScaleFactor(0.75)
                        }
                    }
                }
                .padding(12)
                .background(Brand.card, in: RoundedRectangle(cornerRadius: 12))
                .overlay(RoundedRectangle(cornerRadius: 12).stroke(Brand.muted, lineWidth: 1))
            }
            .padding(.top, 6)

            Button {
                withAnimation(.easeInOut(duration: 0.18)) {
                    showTimeline.toggle()
                    if !showTimeline {
                        timelineLimit = timelinePageSize
                    }
                }
            } label: {
                HStack(spacing: 5) {
                    Image(systemName: "clock")
                    Text("Timeline")
                    Image(systemName: showTimeline ? "chevron.up" : "chevron.down")
                }
                .font(.caption2.weight(.bold))
                .textCase(.uppercase)
                .foregroundStyle(Brand.mutedForeground)
            }
            .buttonStyle(.plain)
            .padding(.top, 8)

            if showTimeline {
                if timelineRegistrations.isEmpty {
                    EmptyState(icon: "calendar.badge.plus", title: "Non hai ancora partecipato a eventi", message: "Scopri le prossime esperienze disponibili.")
                } else {
                    VStack(alignment: .leading, spacing: 0) {
                        ForEach(timelineRegistrations.prefix(timelineLimit)) { registration in
                            TimelineRegistrationRow(registration: registration)
                        }
                    }
                    .padding(.leading, 6)
                    .overlay(alignment: .leading) {
                        Rectangle()
                            .fill(Brand.muted)
                            .frame(width: 2)
                            .padding(.leading, 10)
                    }

                    if timelineRegistrations.count > timelineLimit {
                        Button {
                            withAnimation(.easeInOut(duration: 0.18)) {
                                timelineLimit += timelinePageSize
                            }
                        } label: {
                            HStack(spacing: 6) {
                                Text("Mostra altri")
                                Image(systemName: "chevron.down")
                            }
                            .font(.caption.weight(.bold))
                            .foregroundStyle(Brand.primary)
                            .frame(maxWidth: .infinity)
                            .frame(height: 40)
                            .background(Brand.primary.opacity(0.08), in: RoundedRectangle(cornerRadius: 12))
                        }
                        .buttonStyle(.plain)
                        .padding(.top, 8)
                    }
                }
            }
        }
        .sheet(isPresented: $showStreakDetail) {
            StreakDetailSheet(streak: streak, registrations: streakRegistrations)
                .presentationDetents([.medium, .large])
                .presentationDragIndicator(.visible)
        }
    }
}

