struct TimelineRegistrationRow: View {
    let registration: Registration

    var body: some View {
        HStack(alignment: .top, spacing: 12) {
            Circle()
                .fill(statusColor)
                .frame(width: 10, height: 10)
                .padding(.top, 6)
            VStack(alignment: .leading, spacing: 3) {
                Text(registration.event?.title ?? "Evento")
                    .font(.caption.weight(.bold))
                    .foregroundStyle(Brand.foreground)
                    .lineLimit(2)
                HStack(spacing: 8) {
                    Text(formatDate(registration.event?.date))
                        .font(.caption2)
                        .foregroundStyle(Brand.mutedForeground)
                    Text(activityStatus.label)
                        .font(.caption2.weight(.semibold))
                        .foregroundStyle(activityStatus.color)
                }
            }
            Spacer()
        }
        .padding(.vertical, 9)
    }

    private var activityStatus: (label: String, color: Color) {
        if isAttended { return ("Partecipato", Brand.success) }
        if registration.normalizedStatus == "cancelled" { return ("Cancellato", Brand.destructive) }
        if registration.normalizedStatus == "no_show" { return ("No-show", Brand.destructive) }
        if isPast && registration.checkedIn != true { return ("Non presentato", Brand.warning) }
        return ("Iscritto", Brand.primary)
    }

    private var statusColor: Color {
        activityStatus.color
    }

    private var isAttended: Bool {
        ["registered", "deposit_paid", "paid", "attended"].contains(registration.normalizedStatus) &&
        (registration.checkedIn == true || registration.normalizedStatus == "attended")
    }

    private var isPast: Bool {
        guard let value = registration.event?.date,
              let date = DateFormatter.eventDate.date(from: value) else { return false }
        return date < Calendar.current.startOfDay(for: Date())
    }
}

