struct HelpContentBlock: Identifiable {
    enum Kind {
        case heading
        case subheading
        case paragraph
        case listItem
        case divider
        case image
    }

    let id = UUID()
    let kind: Kind
    let text: String

    static func blocks(from html: String) -> [HelpContentBlock] {
        let parsedBlocks = parse(html)
        if !parsedBlocks.isEmpty {
            return parsedBlocks
        }
        return html.htmlPlainText.nilIfBlank.map { [HelpContentBlock(kind: .paragraph, text: $0)] } ?? []
    }

    private static func parse(_ html: String) -> [HelpContentBlock] {
        let pattern = #"(?is)<(h1|h2|h3|h4|p|li)[^>]*>(.*?)</\1>|<img[^>]*src=["']([^"']+)["'][^>]*>|<hr\s*/?>"#
        guard let regex = try? NSRegularExpression(pattern: pattern) else { return [] }
        let source = html as NSString
        return regex.matches(in: html, range: NSRange(location: 0, length: source.length)).compactMap { match in
            let full = source.substring(with: match.range(at: 0)).lowercased()
            if full.hasPrefix("<hr") {
                return HelpContentBlock(kind: .divider, text: "")
            }
            if match.range(at: 3).location != NSNotFound {
                return HelpContentBlock(kind: .image, text: source.substring(with: match.range(at: 3)))
            }
            guard match.range(at: 1).location != NSNotFound, match.range(at: 2).location != NSNotFound else { return nil }
            let tag = source.substring(with: match.range(at: 1)).lowercased()
            let text = source.substring(with: match.range(at: 2)).htmlStripped
            guard !text.isEmpty else { return nil }
            switch tag {
            case "h1", "h2": return HelpContentBlock(kind: .heading, text: text)
            case "h3", "h4": return HelpContentBlock(kind: .subheading, text: text)
            case "li": return HelpContentBlock(kind: .listItem, text: text)
            default: return HelpContentBlock(kind: .paragraph, text: text)
            }
        }
    }
}

struct HelpContentBlockView: View {
    let block: HelpContentBlock

    var body: some View {
        switch block.kind {
        case .heading:
            Text(block.text)
