        !input.categoryId.isEmpty &&
        !submitting
    }

    var body: some View {
        NavigationStack {
            if submitted {
                ActivityProposalSuccessView {
                    store.homeDiscoveryRequest = HomeDiscoveryRequest()
                    dismiss()
                }
                .background(Brand.background)
                .navigationBarTitleDisplayMode(.inline)
            } else {
                ScrollView {
                    VStack(alignment: .leading, spacing: 16) {
                        Text("Suggerisci una nuova attività alla community. Il team valuterà la tua proposta.")
                            .font(.subheadline)
                            .foregroundStyle(Brand.mutedForeground)
                            .multilineTextAlignment(.center)
                            .frame(maxWidth: .infinity)

                        VStack(alignment: .leading, spacing: 6) {
                            Text("Il tuo nome")
                                .font(.caption.weight(.semibold))
                                .foregroundStyle(Brand.foreground)
                            Text(userName.isEmpty ? "Scampagnatore" : userName)
                                .font(.body)
                                .foregroundStyle(Brand.inputForeground)
                                .frame(maxWidth: .infinity, alignment: .leading)
                                .padding(.horizontal, 14)
                                .frame(height: 54)
                                .background(proposalFieldBackground, in: RoundedRectangle(cornerRadius: 14))
                                .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
                        }

                        ProposalSectionHeader("Raccontaci la tua idea")

                        Field("Titolo attività", text: $input.activityTitle)
                            .onChange(of: input.activityTitle) { _, value in
