                            Text("Descrizione")
                                .font(.subheadline.weight(.semibold))
                                .foregroundStyle(Brand.foreground)
                            ZStack(alignment: .topLeading) {
                                if input.description.isEmpty {
                                    Text("Descrivi l'attività, il ritmo e cosa la rende interessante")
                                        .font(.body)
                                    .foregroundStyle(Brand.inputMutedForeground)
                                        .padding(.horizontal, 15)
                                        .padding(.vertical, 14)
                                }
                                TextEditor(text: $input.description)
                                    .font(.body)
                                    .foregroundStyle(Brand.inputForeground)
                                    .tint(Brand.primary)
                                    .padding(.horizontal, 10)
                                    .padding(.vertical, 6)
                                    .scrollContentBackground(.hidden)
                                    .background(Color.clear)
                                    .onChange(of: input.description) { _, value in
                                        if value.count > 2000 { input.description = String(value.prefix(2000)) }
                                    }
                            }
                            .frame(minHeight: 140)
                            .background(proposalFieldBackground, in: RoundedRectangle(cornerRadius: 14))
                            .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
                            Text("\(input.description.count)/2000")
                                .font(.caption2)
                                .foregroundStyle(Brand.mutedForeground)
                        }

                        ProposalSectionHeader("Quando e dove")

                        OrganizerAddressAutocompleteField("Luogo", text: $input.location, label: $input.locationLabel)
                        Field("Nome del luogo (facoltativo)", text: $input.locationLabel)
                        Text("Se vuoto, verrà mostrato l'indirizzo completo")
                            .font(.caption)
                            .foregroundStyle(Brand.mutedForeground)

                        dateAndTimeFields

                        ProposalSectionHeader("Dettagli utili")

                        Field("Numero indicativo partecipanti", text: $participantsText)
                            .onChange(of: participantsText) { _, value in
                                if value.count > 40 { participantsText = String(value.prefix(40)) }
                                input.maxParticipants = participantsText.firstInteger
                            }

                        VStack(alignment: .leading, spacing: 8) {
                            HStack(spacing: 4) {
                                Text("Che tipo di esperienza è?")
                                Text("*")
                            }
                                .font(.subheadline.weight(.semibold))
                                .foregroundStyle(Brand.foreground)
                            LazyVGrid(columns: [GridItem(.adaptive(minimum: 142), spacing: 10)], alignment: .leading, spacing: 10) {
                                ForEach(categoryChoices) { category in
                                    Button {
                                        selectCategory(category)
                                    } label: {
                                        Text(category.displayName)
                                            .font(.caption.weight(.semibold))
                                            .lineLimit(1)
                                            .minimumScaleFactor(0.8)
                                            .foregroundStyle(input.categoryId == category.id ? .white : Brand.inputMutedForeground)
                                            .frame(maxWidth: .infinity)
                                            .padding(.horizontal, 12)
                                            .padding(.vertical, 9)
                                            .background(input.categoryId == category.id ? Brand.primary : proposalFieldBackground, in: Capsule())
                                            .overlay(Capsule().stroke(input.categoryId == category.id ? Brand.primary : Brand.inputBorder, lineWidth: 1))
                                    }
                                    .buttonStyle(.plain)
                                    .contentShape(Capsule())
