    private func selectCategory(_ category: ProposalCategoryChoice) {
        input.categoryId = category.id
        input.categoryName = category.name
        if validationMessage == "Compila titolo, descrizione, luogo e categoria." {
            validationMessage = nil
        }
    }

    private var dateAndTimeFields: some View {
        VStack(alignment: .leading, spacing: 10) {
            Toggle(isOn: $includeSuggestedDate) {
                Text("Proponi una data")
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(Brand.foreground)
            }
            .tint(Brand.primary)

            if includeSuggestedDate {
                DatePicker("Data", selection: $selectedSuggestedDate, displayedComponents: .date)
                    .datePickerStyle(.compact)
                    .environment(\.locale, Locale(identifier: "it_IT"))
                    .padding(.horizontal, 14)
                    .frame(height: 54)
                    .background(proposalFieldBackground, in: RoundedRectangle(cornerRadius: 14))
                    .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
            }

            Toggle(isOn: $includeSuggestedTime) {
                Text("Proponi un orario")
                    .font(.subheadline.weight(.semibold))
                    .foregroundStyle(Brand.foreground)
            }
            .tint(Brand.primary)

            if includeSuggestedTime {
                DatePicker("Ora", selection: $selectedSuggestedTime, displayedComponents: .hourAndMinute)
                    .datePickerStyle(.compact)
                    .environment(\.locale, Locale(identifier: "it_IT"))
                    .padding(.horizontal, 14)
                    .frame(height: 54)
                    .background(proposalFieldBackground, in: RoundedRectangle(cornerRadius: 14))
                    .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: 1))
            }
        }
    }

    private func submit() async {
        let cleanTitle = input.activityTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        let cleanDescription = input.description.trimmingCharacters(in: .whitespacesAndNewlines)
        let cleanLocation = input.location.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !cleanTitle.isEmpty, !cleanDescription.isEmpty, !cleanLocation.isEmpty, !input.categoryId.isEmpty else {
            validationMessage = "Compila titolo, descrizione, luogo e categoria."
            return
        }
        guard cleanTitle.count <= 160, cleanDescription.count <= 2000 else {
            validationMessage = "Il testo inserito è troppo lungo."
            return
        }

        validationMessage = nil
        submitting = true
        var submission = input
        submission.activityTitle = cleanTitle
        submission.description = cleanDescription
        submission.location = cleanLocation
        submission.suggestedDate = includeSuggestedDate ? DateFormatter.eventDate.string(from: selectedSuggestedDate) : ""
        submission.suggestedTime = includeSuggestedTime ? DateFormatter.proposalTime.string(from: selectedSuggestedTime) : ""
        let success = await store.submitActivityProposal(submission)
        submitting = false
        if success {
            input = ActivityProposalInput()
            participantsText = ""
            includeSuggestedDate = false
            selectedSuggestedDate = Date()
            includeSuggestedTime = false
            selectedSuggestedTime = Date()
            submitted = true
        }
    }
}

private struct ProposalCategoryChoice: Identifiable {
    let id: String
    let name: String
    let icon: String?

    var displayName: String {
        if let icon = icon?.nilIfBlank, icon.count <= 3, !name.contains(icon) {
            return "\(icon) \(name)"
        }
        return name
    }
}

