struct ProfileEditSheet: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let profile: Profile
    var initialFocus: ProfileEditInitialFocus? = nil
    @State private var input = ProfileEditInput()
    @State private var saving = false
    @State private var selectedAvatarItem: PhotosPickerItem?
    @State private var avatarCropDraft: AvatarCropDraft?
    @State private var previewAvatarImage: UIImage?
    @State private var uploadingAvatar = false
    @State private var showPreferenceEdit = false
    @State private var showEmailDialog = false
    @State private var showPasswordDialog = false
    @State private var newEmail = ""
    @State private var newPassword = ""
    @State private var confirmPassword = ""
    @State private var updatingAccount = false
    @State private var deleteDialog: DeleteAccountDialog?
    @State private var isDeletingAccount = false
    @State private var highlightedFocus: ProfileEditInitialFocus?

    var body: some View {
        NavigationStack {
            ZStack(alignment: .bottom) {
                Brand.background.ignoresSafeArea()

                ScrollViewReader { scrollProxy in
                    ScrollView {
                        VStack(alignment: .leading, spacing: 22) {
                            sheetHeader
                            profileFields
                            membershipFields

                            if hasChanges {
                                Button {
                                    Task { await saveProfile() }
                                } label: {
                                    HStack {
                                        if saving {
                                            ProgressView()
                                                .tint(.white)
                                        }
                                        Text(saving ? "Salvataggio..." : "Salva modifiche")
                                    }
                                    .frame(maxWidth: .infinity)
                                }
                                .buttonStyle(PrimaryButtonStyle())
                                .disabled(saving)
                            }

                            preferencesSection
                            accountSection
                        }
                        .padding(.horizontal, 22)
                        .padding(.top, 22)
                        .padding(.bottom, 42)
                    }
                    .onAppear {
                        scheduleInitialFocus(with: scrollProxy)
                    }
                }

                if let deleteDialog {
                    ProfileDeleteAccountDialog(
                        state: deleteDialog,
                        onCancel: {
                            guard !isDeletingAccount else { return }
                            withAnimation(.spring(response: 0.28, dampingFraction: 0.86)) {
                                self.deleteDialog = nil
                            }
                        },
                        onConfirm: {
                            Task { await deleteAccount() }
                        },
                        onFinish: {
                            store.finishDeletedAccountSession()
                            dismiss()
                        }
                    )
                    .transition(.opacity.combined(with: .scale(scale: 0.98)))
                }
            }
            .navigationBarHidden(true)
            .interactiveDismissDisabled(isDeletingAccount || deleteDialog != nil)
            .animation(.spring(response: 0.28, dampingFraction: 0.86), value: deleteDialog)
            .onAppear {
                resetInput()
            }
            .onChange(of: selectedAvatarItem) { _, item in
                Task { await uploadSelectedAvatar(item) }
            }
            .fullScreenCover(item: $avatarCropDraft) { draft in
                AvatarCropView(image: draft.image) { result in
                    avatarCropDraft = nil
                    Task { await uploadAvatarResult(result) }
                } onCancel: {
                    avatarCropDraft = nil
                }
            }
