    private var hasChanges: Bool {
        input.firstName != (profile.firstName ?? "") ||
        input.lastName != (profile.lastName ?? "") ||
        input.phone != profile.phone ||
        input.instagramHandle != (profile.instagramHandle ?? "") ||
        input.birthDate != (profile.birthDate ?? "") ||
        input.sex != (profile.sex ?? "") ||
        input.birthPlace != (profile.birthPlace ?? "") ||
        input.provinceOfBirth != (profile.provinceOfBirth ?? "") ||
        input.residentialAddress != (profile.residentialAddress ?? "") ||
        input.cityOfResidence != (profile.cityOfResidence ?? "") ||
        input.provinceOfResidence != (profile.provinceOfResidence ?? "") ||
        input.bio != (profile.bio ?? "")
    }

    private func resetInput() {
        input = ProfileEditInput(
            firstName: profile.firstName ?? "",
            lastName: profile.lastName ?? "",
            phone: profile.phone,
            instagramHandle: profile.instagramHandle ?? "",
            birthDate: profile.birthDate ?? "",
            sex: profile.sex ?? "",
            birthPlace: profile.birthPlace ?? "",
            provinceOfBirth: profile.provinceOfBirth ?? "",
            residentialAddress: profile.residentialAddress ?? "",
            cityOfResidence: profile.cityOfResidence ?? "",
            provinceOfResidence: profile.provinceOfResidence ?? "",
            bio: profile.bio ?? ""
        )
        input.normalizeProvinceFields()
    }

    private func scheduleInitialFocus(with proxy: ScrollViewProxy) {
        guard let initialFocus else { return }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.35) {
            withAnimation(.snappy) {
                proxy.scrollTo(initialFocus, anchor: initialFocus == .membershipSex ? .center : .top)
            }

            if initialFocus == .membershipSex {
                withAnimation(.easeInOut(duration: 0.18)) {
                    highlightedFocus = .membershipSex
                }
                DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) {
                    guard highlightedFocus == .membershipSex else { return }
                    withAnimation(.easeInOut(duration: 0.25)) {
                        highlightedFocus = nil
                    }
                }
            }
        }
    }

    private func saveProfile() async {
        input.normalizeProvinceFields()
        guard validateProfileInput() else { return }

        saving = true
        if await store.updateProfile(input) {
            dismiss()
        }
        saving = false
    }

    private func validateProfileInput() -> Bool {
        let hasBirthData = !input.birthDate.isEmpty || !input.birthPlace.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || !input.provinceOfBirth.isEmpty
        if hasBirthData, input.provinceOfBirth.count != 2 {
            store.errorMessage = "Inserisci la provincia di nascita con due lettere maiuscole."
            return false
        }

        if !input.sex.isEmpty && input.sex != "M" && input.sex != "F" {
            store.errorMessage = "Seleziona M o F per il sesso anagrafico."
            return false
        }

        let hasResidenceData = !input.residentialAddress.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || !input.cityOfResidence.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || !input.provinceOfResidence.isEmpty
        if hasResidenceData, input.provinceOfResidence.count != 2 {
            store.errorMessage = "Inserisci la provincia di residenza con due lettere maiuscole."
            return false
        }

        if !OnboardingInput.isValidInstagramHandle(input.normalizedInstagramHandle) {
            store.errorMessage = "Inserisci solo username, @username o link instagram.com/username."
            return false
        }

        return true
    }

    private func submitEmailChange() async {
        let email = newEmail.trimmingCharacters(in: .whitespacesAndNewlines)
        guard email.contains("@"), !updatingAccount else {
            store.errorMessage = "Inserisci un indirizzo email valido."
            return
        }
        updatingAccount = true
        if await store.updateEmail(email) {
            newEmail = ""
        }
        updatingAccount = false
    }

    private func submitPasswordChange() async {
        guard newPassword.count >= 6 else {
            store.errorMessage = "La password deve avere almeno 6 caratteri."
            return
        }
        guard newPassword == confirmPassword else {
            store.errorMessage = "Le password non corrispondono."
            return
        }
        guard !updatingAccount else { return }
        updatingAccount = true
        if await store.updatePassword(newPassword) {
            newPassword = ""
            confirmPassword = ""
        }
        updatingAccount = false
    }

    private func deleteAccount() async {
        guard !isDeletingAccount else { return }
        store.errorMessage = nil
        isDeletingAccount = true
        withAnimation(.spring(response: 0.28, dampingFraction: 0.86)) {
            deleteDialog = .deleting
        }
        let deleted = await store.deleteAccount()
        isDeletingAccount = false
        if deleted {
            withAnimation(.spring(response: 0.28, dampingFraction: 0.86)) {
                deleteDialog = .success
            }
        } else {
            let message = store.errorMessage ?? "Non siamo riusciti a completare la cancellazione. Riprova tra poco."
            store.errorMessage = nil
            withAnimation(.spring(response: 0.28, dampingFraction: 0.86)) {
                deleteDialog = .failure(message)
            }
        }
    }

    private func uploadSelectedAvatar(_ item: PhotosPickerItem?) async {
        guard let item else { return }
        defer {
            selectedAvatarItem = nil
        }

        do {
            guard let data = try await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: data) else {
                store.errorMessage = "Immagine non valida"
                return
            }
            avatarCropDraft = AvatarCropDraft(image: image)
        } catch {
            store.errorMessage = error.localizedDescription
        }
    }

    private func uploadAvatarResult(_ result: AvatarCropResult) async {
        uploadingAvatar = true
        defer { uploadingAvatar = false }

        previewAvatarImage = result.previewImage
        if await store.updateAvatar(data: result.data) {
            previewAvatarImage = nil
        }
    }
}

private let deleteAccountConfirmationPhrase = "CANCELLA IL MIO ACCOUNT"

private enum DeleteAccountDialog: Equatable {
    case confirm
    case deleting
    case success
    case failure(String)
}

private struct ProfileDeleteAccountDialog: View {
    let state: DeleteAccountDialog
    let onCancel: () -> Void
    let onConfirm: () -> Void
    let onFinish: () -> Void
    @State private var confirmation = ""

    private var canConfirmDeletion: Bool {
        confirmation.trimmingCharacters(in: .whitespacesAndNewlines) == deleteAccountConfirmationPhrase
    }

    var body: some View {
        ZStack {
            Color.black.opacity(0.34)
                .ignoresSafeArea()

            VStack(spacing: 18) {
                icon

                VStack(spacing: 8) {
                    Text(title)
                        .font(.system(.title3, design: .rounded, weight: .bold))
                        .foregroundStyle(Brand.foreground)
                        .multilineTextAlignment(.center)

                    Text(message)
                        .font(.subheadline)
                        .foregroundStyle(Brand.mutedForeground)
                        .multilineTextAlignment(.center)
                        .lineSpacing(2)
                        .fixedSize(horizontal: false, vertical: true)
                }

                confirmationPrompt

                actions
                    .padding(.top, 4)
            }
            .padding(22)
            .frame(maxWidth: 360)
            .background(Brand.card, in: RoundedRectangle(cornerRadius: 24))
            .overlay(RoundedRectangle(cornerRadius: 24).stroke(Brand.muted, lineWidth: 1))
            .shadow(color: .black.opacity(0.18), radius: 22, y: 12)
            .padding(.horizontal, 24)
        }
        .zIndex(20)
        .accessibilityElement(children: .contain)
    }

    private var icon: some View {
        ZStack {
            Circle()
                .fill(iconBackground)
                .frame(width: 74, height: 74)

            switch state {
            case .deleting:
                ProgressView()
                    .tint(Brand.primary)
                    .scaleEffect(1.18)
            default:
                Image(systemName: iconName)
                    .font(.system(size: 30, weight: .semibold))
                    .foregroundStyle(iconColor)
            }
        }
    }

    @ViewBuilder
    private var confirmationPrompt: some View {
        if case .confirm = state {
            VStack(alignment: .leading, spacing: 8) {
                Text("Per confermare scrivi \(deleteAccountConfirmationPhrase).")
                    .font(.caption.weight(.semibold))
                    .foregroundStyle(Brand.foreground)
                    .fixedSize(horizontal: false, vertical: true)

                TextField(deleteAccountConfirmationPhrase, text: $confirmation)
                    .textInputAutocapitalization(.characters)
                    .autocorrectionDisabled()
                    .font(.body)
                    .foregroundStyle(Brand.inputForeground)
                    .tint(Brand.primary)
                    .padding(.horizontal, 14)
                    .frame(height: 50)
                    .background(Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                    .overlay(RoundedRectangle(cornerRadius: 14).stroke(canConfirmDeletion ? Brand.destructive : Brand.inputBorder, lineWidth: 1))
            }
            .padding(12)
            .background(Brand.destructive.opacity(0.05), in: RoundedRectangle(cornerRadius: 16))
            .overlay(RoundedRectangle(cornerRadius: 16).stroke(Brand.destructive.opacity(0.18), lineWidth: 1))
        }
    }

    @ViewBuilder
    private var actions: some View {
        switch state {
        case .confirm:
            VStack(spacing: 10) {
                Button {
                    onConfirm()
                } label: {
                    Text("Cancella account")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(DestructiveButtonStyle())
                .disabled(!canConfirmDeletion)
                .opacity(canConfirmDeletion ? 1 : 0.55)

                Button {
                    onCancel()
                } label: {
                    Text("Annulla")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(SecondaryButtonStyle())
            }
        case .deleting:
            Text("Non chiudere l'app durante questa operazione.")
                .font(.caption)
                .foregroundStyle(Brand.mutedForeground)
                .multilineTextAlignment(.center)
        case .success:
            Button {
                onFinish()
            } label: {
                Text("Torna all'inizio")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(PrimaryButtonStyle())
        case .failure:
            VStack(spacing: 10) {
                Button {
                    onConfirm()
                } label: {
                    Text("Riprova")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(PrimaryButtonStyle())

                Button {
                    onCancel()
                } label: {
                    Text("Chiudi")
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(SecondaryButtonStyle())
            }
        }
    }

    private var title: String {
        switch state {
        case .confirm:
            return "Cancellare l'account?"
        case .deleting:
            return "Stiamo eliminando il tuo account"
        case .success:
            return "Account eliminato"
        case .failure:
            return "Cancellazione non riuscita"
        }
    }

    private var message: String {
        switch state {
        case .confirm:
            return "Questa azione cancella l'accesso e anonimizza i dati personali collegati al profilo. Non può essere annullata."
        case .deleting:
            return "Il sistema sta cancellando profilo, accesso, notifiche e dati collegati. Potrebbero volerci alcuni secondi."
        case .success:
            return "Il tuo account è stato rimosso. Verrai riportato alla schermata iniziale."
        case .failure(let message):
            return message
        }
    }

    private var iconName: String {
        switch state {
        case .confirm:
            return "trash"
        case .deleting:
            return "hourglass"
        case .success:
            return "checkmark"
        case .failure:
            return "exclamationmark.triangle"
        }
    }

    private var iconColor: Color {
        switch state {
        case .confirm, .failure:
            return Brand.destructive
        case .deleting, .success:
            return Brand.primary
        }
    }

    private var iconBackground: Color {
        switch state {
        case .confirm, .failure:
            return Brand.destructive.opacity(0.1)
        case .deleting, .success:
            return Brand.primary.opacity(0.12)
        }
    }
}

struct AvatarCropDraft: Identifiable {
    let id = UUID()
    let image: UIImage
}

struct AvatarCropResult {
    let previewImage: UIImage
    let data: Data
}

struct AvatarCropView: View {
    let image: UIImage
    let onSubmit: (AvatarCropResult) -> Void
    let onCancel: () -> Void

    @State private var zoom: CGFloat = 1
    @State private var committedZoom: CGFloat = 1
    @State private var offset: CGSize = .zero
    @State private var committedOffset: CGSize = .zero

    private let maxZoom: CGFloat = 4

    var body: some View {
        NavigationStack {
            GeometryReader { proxy in
                let cropSide = min(proxy.size.width - 56, min(max(proxy.size.height * 0.48, 260), 340))

                VStack(spacing: 18) {
                    cropPreview(cropSide: cropSide)
                        .padding(.top, 20)

                    Spacer(minLength: 12)

                    actionButtons(cropSide: cropSide)
                }
                .padding(.horizontal, 22)
                .padding(.bottom, 18)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
            .background(Brand.background.ignoresSafeArea())
            .navigationTitle("Foto profilo")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Annulla", action: onCancel)
                }
            }
        }
    }

    private func cropPreview(cropSide: CGFloat) -> some View {
        ZStack {
            Brand.muted
            Image(uiImage: image)
                .resizable()
                .scaledToFill()
                .frame(width: cropSide, height: cropSide)
                .scaleEffect(zoom)
                .offset(offset)
        }
        .frame(width: cropSide, height: cropSide)
        .clipShape(Circle())
        .overlay(Circle().stroke(.white, lineWidth: 3))
        .shadow(color: .black.opacity(0.16), radius: 18, y: 10)
        .gesture(dragGesture(cropSide: cropSide).simultaneously(with: zoomGesture(cropSide: cropSide)))
        .frame(maxWidth: .infinity)
    }

    private func actionButtons(cropSide: CGFloat) -> some View {
        VStack(spacing: 12) {
            Button {
                submitCropped(cropSide: cropSide)
            } label: {
                Label("Ritaglia e salva", systemImage: "checkmark")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(PrimaryButtonStyle())

            Button {
                guard let data = image.avatarJPEGData() else { return }
                onSubmit(AvatarCropResult(previewImage: image, data: data))
            } label: {
                Label("Usa senza ritaglio", systemImage: "photo")
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(SecondaryButtonStyle())
        }
    }

    private func submitCropped(cropSide: CGFloat) {
        guard let data = image.croppedAvatarJPEGData(offset: offset, zoom: zoom, cropSide: cropSide),
              let previewImage = UIImage(data: data) else {
            return
        }
        onSubmit(AvatarCropResult(previewImage: previewImage, data: data))
    }

    private func dragGesture(cropSide: CGFloat) -> some Gesture {
        DragGesture()
            .onChanged { value in
                offset = clampedOffset(
                    CGSize(width: committedOffset.width + value.translation.width, height: committedOffset.height + value.translation.height),
                    zoom: zoom,
                    cropSide: cropSide
                )
            }
            .onEnded { _ in
                committedOffset = clampedOffset(offset, zoom: zoom, cropSide: cropSide)
                offset = committedOffset
            }
    }

    private func zoomGesture(cropSide: CGFloat) -> some Gesture {
        MagnificationGesture()
            .onChanged { value in
                zoom = min(max(committedZoom * value, 1), maxZoom)
                offset = clampedOffset(offset, zoom: zoom, cropSide: cropSide)
            }
            .onEnded { _ in
                committedZoom = zoom
                committedOffset = clampedOffset(offset, zoom: zoom, cropSide: cropSide)
                offset = committedOffset
            }
    }

    private func clampedOffset(_ proposed: CGSize, zoom: CGFloat, cropSide: CGFloat) -> CGSize {
        guard image.size.width > 0, image.size.height > 0 else { return .zero }
        let baseScale = max(cropSide / image.size.width, cropSide / image.size.height)
        let scaledWidth = image.size.width * baseScale * zoom
        let scaledHeight = image.size.height * baseScale * zoom
        let maxX = max(0, (scaledWidth - cropSide) / 2)
        let maxY = max(0, (scaledHeight - cropSide) / 2)

        return CGSize(
            width: min(max(proposed.width, -maxX), maxX),
            height: min(max(proposed.height, -maxY), maxY)
        )
    }
}

