struct ProvinceLimitedTextField: UIViewRepresentable {
    @Binding var text: String

    func makeUIView(context: Context) -> UITextField {
        let textField = UITextField()
        textField.delegate = context.coordinator
        textField.keyboardType = .asciiCapable
        textField.autocapitalizationType = .allCharacters
        textField.autocorrectionType = .no
        textField.spellCheckingType = .no
        textField.font = .preferredFont(forTextStyle: .body)
        textField.adjustsFontForContentSizeCategory = true
        textField.textColor = UIColor(Brand.inputForeground)
        textField.tintColor = UIColor(Brand.primary)
        textField.attributedPlaceholder = NSAttributedString(
            string: "Provincia",
            attributes: [.foregroundColor: UIColor(Brand.inputMutedForeground)]
        )
        return textField
    }

    func updateUIView(_ uiView: UITextField, context: Context) {
        uiView.textColor = UIColor(Brand.inputForeground)
        uiView.tintColor = UIColor(Brand.primary)
        uiView.attributedPlaceholder = NSAttributedString(
            string: "Provincia",
            attributes: [.foregroundColor: UIColor(Brand.inputMutedForeground)]
        )
        let normalized = ProfileEditInput.normalizedProvince(text)
        if text != normalized {
            DispatchQueue.main.async {
                text = normalized
            }
        }
        if uiView.text != normalized {
            uiView.text = normalized
        }
    }

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    final class Coordinator: NSObject, UITextFieldDelegate {
        var parent: ProvinceLimitedTextField

        init(_ parent: ProvinceLimitedTextField) {
            self.parent = parent
        }

        func textField(_ textField: UITextField, shouldChangeCharactersIn range: NSRange, replacementString string: String) -> Bool {
            guard let current = textField.text, let swiftRange = Range(range, in: current) else { return false }

            let replacement = String(string.uppercased().filter { $0 >= "A" && $0 <= "Z" })
            let candidate = current.replacingCharacters(in: swiftRange, with: replacement)
            guard candidate.count <= 2 else { return false }

            textField.text = candidate
            parent.text = candidate
            return false
        }
    }
}

