struct OnboardingView: View {
    enum Mode {
        case onboarding
        case preferencesEdit
        case healthSafetyEdit

        var initialStep: Int {
            switch self {
            case .onboarding: 1
            case .preferencesEdit: 2
            case .healthSafetyEdit: 3
            }
        }
    }

    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let mode: Mode
    @State private var step: Int
    @State private var input = OnboardingInput()
    @State private var saving = false
    @State private var didPrefill = false
    @State private var validationMessage: String?
    @State private var direction = 1
    @State private var selectedAvatarItem: PhotosPickerItem?
    @State private var avatarCropDraft: AvatarCropDraft?
    @State private var previewAvatarImage: UIImage?
    @State private var uploadingAvatar = false
    @State private var showSuccess = false

    init(mode: Mode = .onboarding) {
        self.mode = mode
        self._step = State(initialValue: mode.initialStep)
    }

    var body: some View {
        Group {
            if showSuccess {
                OnboardingSuccessView {
                    dismiss()
                }
                .transition(.opacity.combined(with: .scale(scale: 0.96)))
            } else {
                NavigationStack {
                    VStack(spacing: 0) {
                        OnboardingProgressHeader(displayStep: displayStep, totalSteps: totalSteps, label: currentStepLabel)

                        ScrollViewReader { proxy in
                            ScrollView(showsIndicators: false) {
                                Color.clear
                                    .frame(height: 0)
                                    .id("onboarding-top")

                                ZStack(alignment: .top) {
                                    currentStepView
                                        .id(step)
                                        .transition(stepTransition)
                                }
                                .padding(.horizontal, 22)
                                .padding(.top, 24)
                                .padding(.bottom, 28)
                            }
                            .scrollDismissesKeyboard(.interactively)
                            .onChange(of: step) { _, _ in
                                proxy.scrollTo("onboarding-top", anchor: .top)
                            }
                        }

                        actionBar
                    }
                    .background(Brand.background.ignoresSafeArea())
                    .navigationBarHidden(true)
                    .onAppear {
                        prefillFromProfileIfNeeded()
                    }
                    .onChange(of: store.profile?.id) { _, _ in
                        prefillFromProfileIfNeeded()
                    }
                    .onChange(of: selectedAvatarItem) { _, item in
                        Task { await prepareSelectedAvatar(item) }
                    }
                    .fullScreenCover(item: $avatarCropDraft) { draft in
                        AvatarCropView(image: draft.image) { result in
                            avatarCropDraft = nil
                            Task { await uploadAvatarResult(result) }
                        } onCancel: {
                            avatarCropDraft = nil
                        }
                    }
                    .alert(validationAlertTitle, isPresented: Binding(get: { validationMessage != nil }, set: { if !$0 { validationMessage = nil } })) {
                        Button("OK") { validationMessage = nil }
                    } message: {
                        Text(validationMessage ?? "")
                    }
                }
            }
        }
        .animation(.easeInOut(duration: 0.24), value: showSuccess)
    }

    @ViewBuilder
    private var currentStepView: some View {
        switch step {
        case 1:
            stepOneView
        case 2:
            stepTwoView
        case 3:
            stepThreeView
        default:
            stepFourView
        }
    }

