                    .init(value: "socializing", emoji: "🤝", title: "Conoscere persone"),
                    .init(value: "exercise", emoji: "🏃", title: "Fare movimento"),
                    .init(value: "explore", emoji: "🗺️", title: "Scoprire posti nuovi"),
                    .init(value: "challenge", emoji: "🏔️", title: "Mettermi alla prova")
                ],
                selection: $input.motivation
            )
        }
    }

    private var actionBar: some View {
        VStack(spacing: 0) {
            Divider()
                .overlay(Brand.muted.opacity(0.75))
            HStack(spacing: 12) {
                if canGoBack {
                    Button {
                        goBack()
                    } label: {
                        Label(backButtonTitle, systemImage: "chevron.left")
                            .labelStyle(.titleAndIcon)
                    }
                    .buttonStyle(OnboardingSecondaryButtonStyle())
                }

                Button {
                    handlePrimaryAction()
                } label: {
                    HStack(spacing: 10) {
                        if saving {
                            ProgressView()
                                .tint(.white)
                        }
                        Text(primaryButtonTitle)
                            .lineLimit(1)
                            .minimumScaleFactor(0.76)
                        if shouldAdvanceToNextStep {
                            Image(systemName: "arrow.right")
                        }
                    }
                }
                .buttonStyle(OnboardingPrimaryButtonStyle())
                .disabled(saving || !canContinue)
            }
            .padding(.horizontal, 22)
            .padding(.top, 12)
            .padding(.bottom, 14)
        }
        .background(Brand.background)
    }

    private var stepTransition: AnyTransition {
        .asymmetric(
            insertion: .move(edge: direction > 0 ? .trailing : .leading).combined(with: .opacity),
            removal: .move(edge: direction > 0 ? .leading : .trailing).combined(with: .opacity)
        )
    }

    private var currentStepLabel: String {
        switch step {
        case 1: "Profilo base"
        case 2: "Esperienza"
        case 3: "Salute e sicurezza"
        default: "Preferenze"
        }
    }

    private var canContinue: Bool {
        switch step {
        case 1: return Self.isValidPhone(input.phone) && !input.birthDate.isEmpty && (input.sex == "M" || input.sex == "F") && OnboardingInput.isValidInstagramHandle(input.normalizedInstagramHandle)
        case 2: return !input.trekkingExperience.isEmpty && !input.selfLevel.isEmpty && !input.activityFrequency.isEmpty
        case 3: return input.healthSafetyIsValid
        default: return (2...4).contains(input.interests.count) && !input.motivation.isEmpty
        }
    }

    private var isEditingPreferences: Bool {
        mode == .preferencesEdit
    }

    private var isEditingHealthSafety: Bool {
        mode == .healthSafetyEdit
    }

    private var isEditingProfileDetails: Bool {
        mode != .onboarding
    }

    private var totalSteps: Int {
        if isEditingHealthSafety { return 1 }
        return isEditingPreferences ? 3 : 4
    }

    private var displayStep: Int {
        if isEditingHealthSafety { return 1 }
        return isEditingPreferences ? step - 1 : step
    }

    private var canGoBack: Bool {
        step > mode.initialStep || isEditingProfileDetails
    }

    private var backButtonTitle: String {
        isEditingProfileDetails && step == mode.initialStep ? "Annulla" : "Indietro"
    }

    private var primaryButtonTitle: String {
        if isEditingHealthSafety {
            return saving ? "Salvataggio..." : "Salva salute e sicurezza"
        }
        guard step == 4 else { return "Continua" }
        if saving { return "Salvataggio..." }
        return isEditingPreferences ? "Salva preferenze" : "Scopri gli eventi per te"
    }

    private var finalValidationMessage: String {
        if !input.healthSafetyIsValid {
            return "Completa la sezione salute e sicurezza."
        }
        if !(2...4).contains(input.interests.count) {
            return "Seleziona da 2 a 4 interessi."
        }
        if input.motivation.isEmpty {
            return "Seleziona cosa cerchi di più in un evento."
        }
        return "Completa tutti i campi richiesti."
    }

    private var validationAlertTitle: String {
        isEditingHealthSafety ? "Completa salute e sicurezza" : "Completa le preferenze"
    }

    private var shouldAdvanceToNextStep: Bool {
        !isEditingHealthSafety && step < 4
    }

    private func goBack() {
        if isEditingProfileDetails && step == mode.initialStep {
            dismiss()
            return
        }
        direction = -1
        withAnimation(.easeInOut(duration: 0.28)) {
            step -= 1
        }
    }

    private func handlePrimaryAction() {
        if shouldAdvanceToNextStep {
            direction = 1
            withAnimation(.easeInOut(duration: 0.28)) {
                step += 1
            }
            return
        }

        guard canContinue else {
            validationMessage = finalValidationMessage
            return
        }

        Task {
            guard !saving else { return }
            saving = true
            let didSave: Bool
            switch mode {
            case .onboarding:
                didSave = await store.updateOnboarding(input)
            case .preferencesEdit:
                didSave = await store.updatePreferences(input)
            case .healthSafetyEdit:
                didSave = await store.updateHealthSafety(input)
            }
            if didSave {
                if isEditingProfileDetails {
                    dismiss()
                } else {
                    withAnimation(.easeInOut(duration: 0.24)) {
                        showSuccess = true
                    }
                }
            }
            saving = false
        }
    }

    private func prepareSelectedAvatar(_ item: PhotosPickerItem?) async {
        guard let item else { return }
        defer { selectedAvatarItem = nil }

        do {
            guard let data = try await item.loadTransferable(type: Data.self),
                  let image = UIImage(data: data) else {
                store.errorMessage = "Immagine non valida"
                return
            }
            avatarCropDraft = AvatarCropDraft(image: image)
        } catch {
            store.errorMessage = error.localizedDescription
        }
    }

    private func uploadAvatarResult(_ result: AvatarCropResult) async {
        uploadingAvatar = true
        defer { uploadingAvatar = false }

        previewAvatarImage = result.previewImage
        if await store.updateAvatar(data: result.data) {
            previewAvatarImage = nil
        }
    }

    private func prefillFromProfileIfNeeded() {
        guard !didPrefill, let profile = store.profile else { return }
        input.phone = profile.phone
        input.birthDate = profile.birthDate ?? ""
        input.sex = profile.sex ?? ""
        input.instagramHandle = profile.instagramHandle ?? ""
        input.trekkingExperience = profile.trekkingExperience ?? ""
        input.selfLevel = profile.selfLevel ?? ""
        input.activityFrequency = profile.activityFrequency ?? ""
        input.hasCar = normalizedHasCar(profile.hasCar ?? "")
        input.healthSafetyStatus = normalizedHealthSafetyStatus(profile.healthSafetyStatus)
        input.healthSafetyNotes = profile.healthSafetyNotes ?? ""
        input.emergencyMedicationAnswer = profile.emergencyMedicationHas.map { $0 ? "yes" : "no" } ?? ""
        input.emergencyMedicationNotes = profile.emergencyMedicationNotes ?? ""
        input.healthSafetyHelpNotes = profile.healthSafetyHelpNotes ?? ""
        input.interests = normalizedInterests(profile.interests ?? [])
        input.motivation = profile.eventMotivation ?? ""
        didPrefill = true
    }

    private func normalizedHasCar(_ value: String) -> String {
        switch value {
        case "prefer_not": return "prefer_not_to_drive"
        case "no_car": return "no"
        default: return value
        }
    }

    private func normalizedHealthSafetyStatus(_ value: String?) -> String {
        guard value == "none" || value == "has_info" else { return "" }
        return value ?? ""
    }

    private func normalizedInterests(_ values: [String]) -> [String] {
        let validValues = Set(onboardingInterestOptions.map(\.value))
        let legacyMap = [
            "trekking": "trekking_giornalieri",
            "social": "aperitivi_cene",
            "sport": "sport_movimento",
            "culture": "weekend_fuori_porta",
            "nature": "trekking_giornalieri",
            "food": "aperitivi_cene"
        ]
        var normalized: [String] = []
        for value in values {
            let mapped = legacyMap[value] ?? value
            guard validValues.contains(mapped), !normalized.contains(mapped) else { continue }
            normalized.append(mapped)
        }
        return Array(normalized.prefix(4))
    }

    private static func filteredPhone(_ value: String) -> String {
        let allowed = CharacterSet(charactersIn: "+0123456789 -().")
        return String(value.unicodeScalars.filter { allowed.contains($0) })
    }

    private static func isValidPhone(_ value: String) -> Bool {
        let cleaned = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard cleaned.count >= 5, cleaned.count <= 20 else { return false }
        guard cleaned.rangeOfCharacter(from: .letters) == nil else { return false }
        return cleaned.range(of: #"^\+?[\d\s\-().]{5,20}$"#, options: .regularExpression) != nil
    }
}

struct OnboardingProgressHeader: View {
    let displayStep: Int
    let totalSteps: Int
    let label: String

    private var progress: CGFloat {
        guard totalSteps > 0 else { return 0 }
        return min(1, max(0, CGFloat(displayStep) / CGFloat(totalSteps)))
    }

    var body: some View {
        VStack(spacing: 12) {
            HStack(alignment: .firstTextBaseline) {
                Text("Step \(displayStep) di \(totalSteps)")
                    .font(.system(size: 17, weight: .bold, design: .rounded))
                    .foregroundStyle(Brand.foreground)
                Spacer(minLength: 12)
                Text(label)
                    .font(.system(size: 16, weight: .medium, design: .rounded))
                    .foregroundStyle(Brand.mutedForeground)
            }

            GeometryReader { proxy in
                ZStack(alignment: .leading) {
                    Capsule()
                        .fill(Brand.secondary)
                    Capsule()
                        .fill(Brand.primary)
                        .frame(width: max(0, proxy.size.width * progress))
                }
            }
            .frame(height: 6)
        }
        .padding(.horizontal, 22)
        .padding(.top, 14)
        .padding(.bottom, 14)
        .background(Brand.background.opacity(0.98))
        .overlay(alignment: .bottom) {
            Divider()
                .overlay(Brand.muted)
        }
    }
}

