                }

                Spacer(minLength: 8)

                if selected {
                    Image(systemName: "checkmark.circle.fill")
                        .font(.system(size: 20, weight: .bold))
                        .foregroundStyle(Brand.primary)
                        .transition(.scale.combined(with: .opacity))
                }
            }
            .padding(.horizontal, 14)
            .padding(.vertical, 12)
            .frame(maxWidth: .infinity, minHeight: 64, alignment: .leading)
            .background(selected ? Brand.primary.opacity(0.06) : Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
            .overlay(RoundedRectangle(cornerRadius: 14).stroke(selected ? Brand.primary.opacity(0.50) : Brand.inputBorder, lineWidth: selected ? 2 : 1))
            .contentShape(RoundedRectangle(cornerRadius: 14))
        }
        .buttonStyle(.plain)
    }
}

struct OnboardingInterestGrid: View {
    @Binding var selected: [String]
    private let columns = [GridItem(.flexible(), spacing: 10), GridItem(.flexible(), spacing: 10)]

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            VStack(alignment: .leading, spacing: 6) {
                OnboardingFieldLabel(title: "Quali esperienze ti attirano di più?", required: true)
                Text("Seleziona da 2 a 4 attività.")
                    .font(.footnote)
                    .foregroundStyle(Brand.mutedForeground)
            }

            LazyVGrid(columns: columns, spacing: 10) {
                ForEach(onboardingInterestOptions, id: \.value) { option in
                    let isSelected = selected.contains(option.value)
                    let isDisabled = !isSelected && selected.count >= 4

                    Button {
                        toggle(option.value)
                    } label: {
                        VStack(spacing: 8) {
                            Text(option.emoji)
                                .font(.system(size: 22))
                            Text(option.label)
                                .font(.footnote.weight(.bold))
                                .foregroundStyle(Brand.foreground)
                                .multilineTextAlignment(.center)
                                .lineLimit(2)
                                .minimumScaleFactor(0.80)
                                .frame(maxWidth: .infinity)
                        }
                        .padding(.horizontal, 10)
                        .padding(.vertical, 12)
                        .frame(maxWidth: .infinity, minHeight: 88)
                        .background(isSelected ? Brand.primary.opacity(0.06) : Brand.inputBackground, in: RoundedRectangle(cornerRadius: 14))
                        .overlay(alignment: .topTrailing) {
                            if isSelected {
                                Image(systemName: "checkmark.circle.fill")
                                    .font(.system(size: 18, weight: .bold))
                                    .foregroundStyle(Brand.primary)
                                    .padding(8)
                            }
                        }
                        .overlay(RoundedRectangle(cornerRadius: 14).stroke(isSelected ? Brand.primary.opacity(0.50) : Brand.inputBorder, lineWidth: isSelected ? 2 : 1))
                        .opacity(isDisabled ? 0.48 : 1)
                    }
                    .buttonStyle(.plain)
                    .disabled(isDisabled)
                }
            }
        }
    }

    private func toggle(_ value: String) {
        withAnimation(.spring(response: 0.24, dampingFraction: 0.82)) {
            if selected.contains(value) {
                selected.removeAll { $0 == value }
            } else if selected.count < 4 {
                selected.append(value)
            }
        }
    }
}

