struct OnboardingSuccessBadge: View {
    private let burstPieces = OnboardingBurstPiece.pieces

    var body: some View {
        TimelineView(.animation) { context in
            let time = context.date.timeIntervalSinceReferenceDate
            ZStack {
                Circle()
                    .fill(Brand.accent.opacity(0.14 + 0.08 * pulse(time, offset: 0)))
                    .frame(width: 126, height: 126)
                    .scaleEffect(0.96 + 0.10 * pulse(time, offset: 0.2))

                Circle()
                    .stroke(Brand.primary.opacity(0.24 * (1 - pulse(time, offset: 0.4))), lineWidth: 1.2)
                    .frame(width: 110, height: 110)
                    .scaleEffect(0.84 + 0.42 * pulse(time, offset: 0.4))

                ForEach(burstPieces) { piece in
                    let phase = burstPhase(time, delay: piece.delay)
                    Circle()
                        .fill(piece.color)
                        .frame(width: 9, height: 9)
                        .offset(x: piece.x * phase, y: piece.y * phase)
                        .scaleEffect(max(0.35, 1 - phase * 0.5))
                        .opacity(phase < 0.12 ? phase / 0.12 : max(0, 1 - phase))
                }

                Circle()
                    .fill(Brand.inputBackground)
                    .frame(width: 82, height: 82)
                    .overlay(Circle().stroke(Brand.inputBorder, lineWidth: 1))
                    .shadow(color: .black.opacity(0.08), radius: 10, x: 0, y: 4)

                Image(systemName: "party.popper.fill")
                    .font(.system(size: 48, weight: .semibold))
                    .foregroundStyle(Brand.primary)
                    .rotationEffect(.degrees(-6 + 12 * sin(time * 1.8)))
                    .scaleEffect(1 + 0.035 * sin(time * 2.1))
            }
            .frame(width: 156, height: 156)
        }
    }

    private func pulse(_ time: TimeInterval, offset: Double) -> CGFloat {
        let value = (sin((time + offset) * 2.2) + 1) / 2
        return CGFloat(value)
    }

    private func burstPhase(_ time: TimeInterval, delay: Double) -> CGFloat {
        let cycle = 2.3
        let value = (time + delay).truncatingRemainder(dividingBy: cycle) / cycle
        return CGFloat(value)
    }
}

struct OnboardingConfettiLayer: View {
    private let pieces = OnboardingConfettiPiece.pieces

    var body: some View {
        TimelineView(.animation) { context in
            GeometryReader { proxy in
                let time = context.date.timeIntervalSinceReferenceDate
                ForEach(pieces) { piece in
                    let phase = piece.phase(at: time)
                    let x = proxy.size.width * piece.left + CGFloat(sin((phase * .pi * 2) + piece.driftPhase)) * piece.drift
                    let y = -36 + (proxy.size.height + 72) * phase
                    RoundedRectangle(cornerRadius: piece.cornerRadius)
                        .fill(piece.color)
                        .frame(width: piece.size.width, height: piece.size.height)
                        .rotationEffect(.degrees(piece.rotation(at: phase)))
                        .position(x: x, y: y)
                        .opacity(piece.opacity(at: phase))
                }
            }
        }
    }
}

struct OnboardingConfettiPiece: Identifiable {
    let id: Int
    let left: CGFloat
    let delay: Double
    let duration: Double
    let drift: CGFloat
    let driftPhase: Double
    let rotation: Double
    let size: CGSize
    let cornerRadius: CGFloat
    let color: Color

    static let colors: [Color] = [
        Color(red: 1.000, green: 0.420, blue: 0.420),
        Color(red: 0.306, green: 0.804, blue: 0.769),
        Color(red: 1.000, green: 0.902, blue: 0.427),
        Color(red: 1.000, green: 0.624, blue: 0.110),
        Color(red: 0.796, green: 0.612, blue: 0.949),
        Color(red: 1.000, green: 0.600, blue: 0.784),
        Color(red: 0.639, green: 0.808, blue: 0.945),
        Color(red: 0.502, green: 0.929, blue: 0.600)
    ]

    static let pieces: [OnboardingConfettiPiece] = (0..<34).map { index in
        let width = CGFloat(5 + (index % 4) * 2)
        let height = CGFloat(index % 3 == 0 ? 11 : 7)
        return OnboardingConfettiPiece(
            id: index,
            left: CGFloat(0.04 + Double((index * 23) % 92) / 100.0),
            delay: Double(index % 8) * 0.28,
            duration: Double(5.2 + Double(index % 5) * 0.72),
            drift: CGFloat(18 + (index % 5) * 9),
            driftPhase: Double(index) * 0.71,
            rotation: Double((index % 2 == 0 ? 1 : -1) * (260 + (index % 4) * 95)),
            size: CGSize(width: width, height: height),
            cornerRadius: index % 3 == 0 ? 1.5 : width / 2,
            color: colors[index % colors.count]
        )
    }

    func phase(at time: TimeInterval) -> CGFloat {
        let shifted = time + delay
        return CGFloat(shifted.truncatingRemainder(dividingBy: duration) / duration)
    }

    func rotation(at phase: CGFloat) -> Double {
        rotation * Double(phase)
    }

    func opacity(at phase: CGFloat) -> Double {
        if phase < 0.08 { return Double(phase / 0.08) }
        if phase > 0.88 { return Double(max(0, (1 - phase) / 0.12)) }
        return 0.92
    }
}

struct OnboardingBurstPiece: Identifiable {
    let id: Int
    let x: CGFloat
    let y: CGFloat
    let delay: Double
    let color: Color

    static let pieces: [OnboardingBurstPiece] = (0..<12).map { index in
        let angle = (Double.pi * 2 * Double(index)) / 12
        let radius = CGFloat(46 + (index % 3) * 15)
        return OnboardingBurstPiece(
            id: index,
            x: CGFloat(cos(angle)) * radius,
            y: CGFloat(sin(angle)) * radius,
            delay: Double(index) * 0.06,
            color: OnboardingConfettiPiece.colors[index % OnboardingConfettiPiece.colors.count]
        )
    }
}

// MARK: - Notifications

struct NotificationsView: View {
    @EnvironmentObject private var store: AppStore
    @Environment(\.dismiss) private var dismiss
    let onNavigate: (NotificationDestination) -> Void
    @State private var expandedNotificationIds: Set<String> = []

    private var unreadNotifications: [UserNotification] {
        store.notifications.filter { !$0.read }
    }

    private var groupedNotifications: [NotificationDateGroup] {
        var groups: [NotificationDateGroup] = []
        var currentLabel: String?

        for notification in store.notifications {
            let label = notificationGroupLabel(notification.createdAt)
            if groups.isEmpty || currentLabel != label {
                groups.append(NotificationDateGroup(label: label, notifications: [notification]))
                currentLabel = label
            } else {
                groups[groups.count - 1].notifications.append(notification)
            }
        }

        return groups
    }

    var body: some View {
        VStack(spacing: 0) {
            header

            if store.notifications.isEmpty {
                Spacer(minLength: 0)
                EmptyState(icon: "bell", title: "Nessuna notifica", message: "Qui compariranno aggiornamenti, promemoria e conferme.")
                    .padding(.horizontal, 22)
                Spacer(minLength: 0)
            } else {
                ScrollView {
                    LazyVStack(alignment: .leading, spacing: 0) {
                        ForEach(groupedNotifications) { group in
                            Text(group.label)
                                .font(.system(size: 11, weight: .bold))
                                .textCase(.uppercase)
                                .tracking(1.2)
                                .foregroundStyle(Brand.mutedForeground.opacity(0.75))
                                .padding(.horizontal, 22)
                                .padding(.top, 16)
                                .padding(.bottom, 8)

                            VStack(spacing: 0) {
                                ForEach(group.notifications) { notification in
                                    NotificationRow(
                                        notification: notification,
                                        isExpanded: expandedNotificationIds.contains(notification.id),
                                        destinationHint: notification.destination?.actionTitle,
                                        onOpenURL: { url in UIApplication.shared.open(url) }
                                    )
                                    .contentShape(Rectangle())
                                    .onTapGesture {
                                        handleTap(notification)
                                    }
                                    .accessibilityAddTraits(.isButton)
                                    .accessibilityHint(notification.destination == nil ? "Espande la notifica" : "Apre la sezione collegata")

                                    if notification.id != group.notifications.last?.id {
                                        Divider()
                                            .overlay(Brand.muted)
                                            .padding(.leading, 72)
                                    }
                                }
                            }
                            .background(Brand.card)
                        }
                    }
                }
                .refreshable {
                    await store.refreshUserData()
                }
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        .background(Brand.background.ignoresSafeArea())
        .presentationBackground(Brand.background)
        .task {
            if store.isAuthenticated {
                await store.refreshUserData()
            }
        }
    }

    private var header: some View {
        HStack(alignment: .center, spacing: 14) {
            Text("Notifiche")
                .font(.system(.title2, design: .rounded, weight: .bold))
                .foregroundStyle(Brand.foreground)
                .lineLimit(1)

            Spacer(minLength: 8)

            if !unreadNotifications.isEmpty {
                Button {
                    Task {
                        for notification in unreadNotifications {
                            await store.markNotificationRead(notification.id)
                        }
                    }
                } label: {
                    Label("Leggi tutte", systemImage: "checkmark")
                        .font(.subheadline.weight(.semibold))
                        .labelStyle(.titleAndIcon)
                }
                .foregroundStyle(Brand.mutedForeground)
                .buttonStyle(.plain)
            }

            Button { dismiss() } label: {
                Image(systemName: "xmark")
                    .font(.system(size: 15, weight: .bold))
                    .foregroundStyle(Brand.mutedForeground)
                    .frame(width: 36, height: 36)
                    .background(Brand.muted, in: Circle())
            }
            .buttonStyle(.plain)
            .accessibilityLabel("Chiudi")
        }
        .padding(.horizontal, 22)
        .padding(.top, 24)
        .padding(.bottom, 18)
        .background(Brand.background)
        .overlay(alignment: .bottom) {
            Divider().overlay(Brand.muted)
        }
    }

    private func handleTap(_ notification: UserNotification) {
        if !notification.read {
            Task { await store.markNotificationRead(notification.id) }
        }

        if let destination = notification.destination {
            dismiss()
            onNavigate(destination)
        } else {
            withAnimation(.snappy) {
                if expandedNotificationIds.contains(notification.id) {
                    expandedNotificationIds.remove(notification.id)
                } else {
                    expandedNotificationIds.insert(notification.id)
                }
            }
        }
    }
}

struct NotificationDateGroup: Identifiable {
    let label: String
    var notifications: [UserNotification]

    var id: String { label }
}

struct NotificationRow: View {
    let notification: UserNotification
    let isExpanded: Bool
    let destinationHint: String?
    let onOpenURL: (URL) -> Void

    var body: some View {
        HStack(alignment: .top, spacing: 16) {
            Image(systemName: notificationIcon(notification.type))
                .font(.system(size: 22, weight: .medium))
                .foregroundStyle(iconColor)
                .frame(width: 40, height: 44, alignment: .top)
                .padding(.top, 2)

            VStack(alignment: .leading, spacing: 6) {
                HStack(alignment: .firstTextBaseline, spacing: 10) {
                    Text(notification.displayTitle)
                        .font(.system(.headline, design: .rounded, weight: notification.read ? .semibold : .bold))
                        .foregroundStyle(notification.read ? Brand.mutedForeground : Brand.foreground)
                        .lineLimit(2)
                        .fixedSize(horizontal: false, vertical: true)

                    Spacer(minLength: 8)

                    if !notification.read {
                        Circle()
                            .fill(Brand.primary)
                            .frame(width: 9, height: 9)
                    }
                }

                if notification.isDetailedReminder, !notification.reminderParts.isEmpty {
                    NotificationReminderMessageView(parts: notification.reminderParts, onOpenURL: onOpenURL)
                } else {
                    Text(notification.displayMessage)
                        .font(.system(.subheadline, design: .rounded))
                        .foregroundStyle(Brand.mutedForeground)
                        .lineLimit(isExpanded ? nil : 3)
                        .fixedSize(horizontal: false, vertical: true)
                }

                footer

                if let relativeTime = notificationRelativeTime(notification.createdAt) {
                    Text(relativeTime)
                        .font(.system(.caption, design: .rounded, weight: .medium))
                        .foregroundStyle(Brand.mutedForeground.opacity(0.62))
