            }
        }
        .padding(.horizontal, 22)
        .padding(.vertical, 18)
        .contentShape(Rectangle())
    }

    private var iconColor: Color {
        notificationTintColor(notification.type, read: notification.read)
    }

    @ViewBuilder
    private var footer: some View {
        if let destinationHint {
            HStack(spacing: 5) {
                Text(destinationHint)
                Image(systemName: "chevron.right")
                    .font(.caption2.weight(.bold))
            }
            .font(.system(.caption, design: .rounded, weight: .bold))
            .foregroundStyle(Brand.primary)
            .padding(.top, 2)
        } else if notification.canExpandInline {
            HStack(spacing: 5) {
                Text(isExpanded ? "Riduci" : "Leggi tutto")
                Image(systemName: isExpanded ? "chevron.up" : "chevron.down")
                    .font(.caption2.weight(.bold))
            }
            .font(.system(.caption, design: .rounded, weight: .bold))
            .foregroundStyle(Brand.primary)
            .padding(.top, 2)
        }
    }
}

struct NotificationReminderPart: Identifiable, Hashable {
    enum Kind: Hashable {
        case text
        case location
        case navigation(URL)
    }

    let id = UUID()
    let kind: Kind
    let text: String

    static func parts(from message: String) -> [NotificationReminderPart] {
        message
            .components(separatedBy: .newlines)
            .compactMap { rawLine -> NotificationReminderPart? in
                let line = rawLine.trimmingCharacters(in: .whitespacesAndNewlines)
                guard !line.isEmpty else { return nil }

                if let urlString = line.firstRegexCapture(#"(https?://[^\s]+)"#)?
                    .trimmingCharacters(in: CharacterSet(charactersIn: ".,);]")),
                   let url = URL(string: urlString) {
                    return NotificationReminderPart(kind: .navigation(url), text: "Apri navigazione")
                }

                if line.contains("📍") {
                    let cleaned = line
                        .replacingOccurrences(of: "📍", with: "")
                        .trimmingCharacters(in: .whitespacesAndNewlines)
                    return NotificationReminderPart(kind: .location, text: cleaned)
                }

                return NotificationReminderPart(kind: .text, text: line)
            }
    }
}

struct NotificationReminderMessageView: View {
    let parts: [NotificationReminderPart]
    let onOpenURL: (URL) -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            ForEach(parts) { part in
                switch part.kind {
                case .text:
                    Text(part.text)
                        .font(.system(.subheadline, design: .rounded))
                        .foregroundStyle(Brand.mutedForeground)
                        .fixedSize(horizontal: false, vertical: true)
                case .location:
                    HStack(alignment: .top, spacing: 6) {
                        Image(systemName: "mappin.and.ellipse")
                            .font(.caption.weight(.bold))
                            .foregroundStyle(Brand.primary)
                            .frame(width: 16, alignment: .leading)
                        Text(part.text)
                            .font(.system(.subheadline, design: .rounded, weight: .semibold))
                            .foregroundStyle(Brand.foreground)
                            .fixedSize(horizontal: false, vertical: true)
                    }
                case .navigation(let url):
                    Button {
                        onOpenURL(url)
                    } label: {
                        HStack(spacing: 6) {
                            Image(systemName: "location.fill")
                                .font(.caption.weight(.bold))
                            Text(part.text)
                                .font(.system(.subheadline, design: .rounded, weight: .bold))
                        }
                        .foregroundStyle(Brand.primary)
                    }
                    .buttonStyle(.plain)
                }
            }
        }
    }
}

// MARK: - Shop

struct ShopView: View {
    @EnvironmentObject private var store: AppStore
    @Binding var routedProductId: String?
    @State private var selectedProduct: MerchProduct?
    private let gridSpacing: CGFloat = 12

    var body: some View {
        NavigationStack {
            GeometryReader { proxy in
                let contentWidth = max(proxy.size.width - 32, 0)

                ScrollView {
                    VStack(alignment: .leading, spacing: 18) {
                        HStack(spacing: 10) {
                            Image(systemName: AppTab.shop.systemImage)
                                .foregroundStyle(Brand.primary)
                            Text("Shop")
                        }
                        .font(.system(.title, design: .rounded, weight: .bold))
                        Text("Prodotti ufficiali Scampagnate. Contattaci via WhatsApp per acquistare.")
                            .foregroundStyle(Brand.mutedForeground)
                            .font(.subheadline)

                        if store.products.isEmpty {
                            EmptyState(icon: "bag", title: "Shop in aggiornamento", message: "I prodotti disponibili appariranno qui.")
                        } else {
                            LazyVGrid(columns: productColumns(for: contentWidth), spacing: gridSpacing) {
                                ForEach(store.products) { product in
                                    ProductCard(product: product)
                                        .onTapGesture { selectedProduct = product }
                                }
                            }
                        }

                        ShopInfoFooter()
                }
                .frame(width: contentWidth, alignment: .leading)
                .padding(16)
                .padding(.bottom, 0)
            }
            .contentMargins(.bottom, 0, for: .scrollContent)
            .refreshable {
                await store.loadPublicData()
            }
            .background(Brand.background)
            .navigationDestination(item: $selectedProduct) { product in
                ProductDetailView(product: product)
            }
            .task(id: routedProductId ?? "") {
                await openRoutedProductIfNeeded()
            }
            .onChange(of: store.products) { _, _ in
                Task { await openRoutedProductIfNeeded() }
            }
        }
    }
    }

    private func openRoutedProductIfNeeded() async {
        guard let productId = routedProductId?.nilIfBlank else { return }
        if let product = store.products.first(where: { $0.id == productId }) {
            selectedProduct = product
            routedProductId = nil
            return
        }

        await store.loadPublicData(reportingErrors: false)
        if let product = store.products.first(where: { $0.id == productId }) {
            selectedProduct = product
        } else {
            store.errorMessage = "Prodotto non trovato"
        }
        routedProductId = nil
    }
}

private func productColumns(for width: CGFloat) -> [GridItem] {
    let gridSpacing: CGFloat = 12
    let columnCount: Int
    if width < 520 {
        columnCount = 2
    } else {
        columnCount = min(4, max(3, Int((width + gridSpacing) / (190 + gridSpacing))))
    }
    return Array(repeating: GridItem(.flexible(), spacing: gridSpacing), count: columnCount)
}

struct ProductCard: View {
