private enum SupabaseImageTransform {
    private static let objectPublicPath = "/storage/v1/object/public/"
    private static let renderPublicPath = "/storage/v1/render/image/public/"
    private static let transformQueryNames: Set<String> = ["width", "height", "resize", "quality"]

    static func url(from value: String?, maxWidth: Int = 1200, quality: Int = 75) -> URL? {
        guard let rawValue = value?.nilIfBlank else { return nil }
        let originalURL = URL(string: rawValue) ?? rawValue.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed).flatMap(URL.init(string:))
        guard let originalURL else { return nil }
        guard var components = URLComponents(url: originalURL, resolvingAgainstBaseURL: false),
              let host = components.host,
              host.contains("supabase.co"),
              components.path.contains("/storage/v1/")
        else {
            return originalURL
        }

        if components.path.contains(objectPublicPath) {
            components.path = components.path.replacingOccurrences(of: objectPublicPath, with: renderPublicPath)
        } else if !components.path.contains(renderPublicPath) {
            return originalURL
        }

        var queryItems = (components.queryItems ?? []).filter { !transformQueryNames.contains($0.name.lowercased()) }
        queryItems.append(URLQueryItem(name: "width", value: String(maxWidth)))
        queryItems.append(URLQueryItem(name: "quality", value: String(quality)))
        components.queryItems = queryItems

        return components.url ?? originalURL
    }
}

struct RemoteImage: View {
    let urlString: String?
    var contentMode: ContentMode = .fill
    var resolvedContentMode: ((CGSize) -> ContentMode)?
    @State private var phase: RemoteImageLoadPhase = .idle

    var body: some View {
        content
            .clipped()
            .task(id: imageURL?.absoluteString ?? urlString ?? "") {
                await loadImage()
            }
    }

    @ViewBuilder
    private var content: some View {
        switch phase {
        case .idle:
            placeholder(showProgress: true)
        case .loading:
            placeholder(showProgress: true)
        case .success(let image):
            let imageContentMode = resolvedContentMode?(image.size) ?? contentMode
            Image(uiImage: image)
                .resizable()
                .aspectRatio(contentMode: imageContentMode)
        case .failure:
            placeholder(showProgress: false)
        }
    }

    @ViewBuilder
    private func placeholder(showProgress: Bool) -> some View {
        ZStack {
            Brand.muted
            if showProgress {
                ProgressView()
                    .tint(Brand.primary)
            } else {
                Image(systemName: "photo")
                    .font(.title2)
                    .foregroundStyle(Brand.mutedForeground)
            }
        }
    }

    private var imageURL: URL? {
        SupabaseImageTransform.url(from: urlString)
    }

    @MainActor
    private func loadImage() async {
        guard let imageURL else {
            phase = .failure
            return
        }

        if let cachedImage = RemoteImageStore.shared.cachedImage(for: imageURL) {
            phase = .success(cachedImage)
            return
        }

        phase = .loading
        do {
            let image = try await RemoteImageStore.shared.image(for: imageURL)
            guard !Task.isCancelled else { return }
            phase = .success(image)
        } catch is CancellationError {
            return
        } catch {
            guard !Task.isCancelled else { return }
            phase = .failure
        }
    }
}

private enum RemoteImageLoadPhase {
    case idle
    case loading
    case success(UIImage)
    case failure
}

@MainActor
private final class RemoteImageStore {
    static let shared = RemoteImageStore()

    private static let maximumAttempts = 3
    private let cache = NSCache<NSURL, UIImage>()

    private init() {
        cache.countLimit = 180
        cache.totalCostLimit = 90 * 1024 * 1024
    }

    func cachedImage(for url: URL) -> UIImage? {
        cache.object(forKey: url as NSURL)
    }

    func image(for url: URL) async throws -> UIImage {
        let key = url as NSURL
        if let cachedImage = cache.object(forKey: key) {
            return cachedImage
        }

        var lastError: Error?
        for attempt in 0..<Self.maximumAttempts {
            do {
                var request = URLRequest(url: url)
                request.cachePolicy = .returnCacheDataElseLoad
                request.timeoutInterval = 20
                request.setValue("image/avif,image/webp,image/png,image/jpeg,*/*;q=0.8", forHTTPHeaderField: "Accept")

                let (data, response) = try await URLSession.shared.data(for: request)
                guard !Task.isCancelled else { throw CancellationError() }
                if let http = response as? HTTPURLResponse, !(200..<300).contains(http.statusCode) {
                    throw RemoteImageLoadError.httpStatus(http.statusCode)
                }
                guard let image = Self.decodedImage(from: data) else {
                    throw RemoteImageLoadError.invalidImageData
                }

                cache.setObject(image, forKey: key, cost: image.cacheCost)
                return image
            } catch is CancellationError {
                throw CancellationError()
            } catch {
                lastError = error
                if attempt < Self.maximumAttempts - 1 {
                    let delay = UInt64(250_000_000 * (attempt + 1))
                    try await Task.sleep(nanoseconds: delay)
                }
            }
        }

        throw lastError ?? RemoteImageLoadError.invalidImageData
    }

    private static func decodedImage(from data: Data) -> UIImage? {
        let sourceOptions: [CFString: Any] = [kCGImageSourceShouldCache: false]
        guard let source = CGImageSourceCreateWithData(data as CFData, sourceOptions as CFDictionary) else {
            return UIImage(data: data)
        }

        let options: [CFString: Any] = [
            kCGImageSourceCreateThumbnailFromImageAlways: true,
            kCGImageSourceCreateThumbnailWithTransform: true,
            kCGImageSourceShouldCacheImmediately: true,
            kCGImageSourceThumbnailMaxPixelSize: 2200
        ]

        if let cgImage = CGImageSourceCreateThumbnailAtIndex(source, 0, options as CFDictionary) {
            return UIImage(cgImage: cgImage)
        }

        return UIImage(data: data)
    }
}

private enum RemoteImageLoadError: Error {
    case httpStatus(Int)
    case invalidImageData
}

private func dismissKeyboard() {
    Task { @MainActor in
        UIApplication.shared.sendAction(#selector(UIResponder.resignFirstResponder), to: nil, from: nil, for: nil)
    }
}

private struct ReadableSwitchToggleStyle: ToggleStyle {
    @Environment(\.colorScheme) private var colorScheme

    func makeBody(configuration: Configuration) -> some View {
        HStack(spacing: 12) {
            configuration.label
                .foregroundStyle(Brand.inputForeground)
            Spacer(minLength: 12)
            ZStack(alignment: configuration.isOn ? .trailing : .leading) {
                Capsule()
                    .fill(configuration.isOn ? Brand.primary : offTrack)
                    .overlay(Capsule().stroke(offBorder, lineWidth: 1))
                Circle()
                    .fill(Color.white)
                    .shadow(color: Color.black.opacity(configuration.isOn ? 0.18 : 0.10), radius: 2, x: 0, y: 1)
                    .padding(3)
            }
            .frame(width: 52, height: 32)
            .animation(.easeInOut(duration: 0.16), value: configuration.isOn)
        }
        .contentShape(Rectangle())
        .onTapGesture {
            withAnimation(.easeInOut(duration: 0.16)) {
                configuration.isOn.toggle()
            }
        }
    }

    private var offTrack: Color {
        colorScheme == .dark
            ? Color(red: 0.34, green: 0.38, blue: 0.35)
            : Color(red: 0.78, green: 0.80, blue: 0.78)
    }

    private var offBorder: Color {
        colorScheme == .dark
            ? Color(red: 0.50, green: 0.56, blue: 0.52)
            : Color(red: 0.64, green: 0.67, blue: 0.64)
    }
}

