struct BirthDatePickerField: View {
    let title: String
    @Binding var dateString: String
    let background: Color
    let showsClearButton: Bool
    let labelFont: Font
    let labelSpacing: CGFloat
    let borderWidth: CGFloat
    let help: String?
    @State private var pickerDate = defaultBirthDate
    @State private var isPickerPresented = false

    init(
        _ title: String,
        dateString: Binding<String>,
        background: Color = Brand.inputBackground,
        showsClearButton: Bool = false,
        labelFont: Font = .subheadline.weight(.semibold),
        labelSpacing: CGFloat = 6,
        borderWidth: CGFloat = 1,
        help: String? = nil
    ) {
        self.title = title
        self._dateString = dateString
        self.background = background
        self.showsClearButton = showsClearButton
        self.labelFont = labelFont
        self.labelSpacing = labelSpacing
        self.borderWidth = borderWidth
        self.help = help
    }

    var body: some View {
        VStack(alignment: .leading, spacing: labelSpacing) {
            HStack(spacing: 6) {
                Text(title)
                    .font(labelFont)
                    .foregroundStyle(Brand.foreground)
                    .lineLimit(1)
                if let help {
                    InfoTooltipButton(text: help)
                }
            }

            HStack(spacing: 8) {
                Button {
                    syncPickerDate()
                    isPickerPresented = true
                } label: {
                    HStack(spacing: 8) {
                        Text(displayText)
                            .font(.body)
                            .foregroundStyle(dateString.isEmpty ? Brand.inputMutedForeground : Brand.inputForeground)
                            .lineLimit(1)
                            .minimumScaleFactor(0.82)
                            .allowsTightening(true)
                            .layoutPriority(1)
                        Spacer(minLength: 4)
                        Image(systemName: "calendar")
                            .font(.system(size: 16, weight: .semibold))
                            .foregroundStyle(Brand.primary)
                    }
                    .contentShape(Rectangle())
                }
                .buttonStyle(.plain)
                .accessibilityLabel(title)
                .accessibilityValue(dateString.isEmpty ? "Non impostata" : displayText)

                if showsClearButton, !dateString.isEmpty {
                    Button {
                        dateString = ""
                        pickerDate = Self.defaultBirthDate
                    } label: {
                        Image(systemName: "xmark.circle.fill")
                            .font(.system(size: 16, weight: .semibold))
                            .foregroundStyle(Brand.mutedForeground)
                    }
                    .buttonStyle(.plain)
                    .accessibilityLabel("Rimuovi data di nascita")
                }
            }
            .padding(.horizontal, 14)
            .frame(height: 54)
            .background(background, in: RoundedRectangle(cornerRadius: 14))
            .overlay(RoundedRectangle(cornerRadius: 14).stroke(Brand.inputBorder, lineWidth: borderWidth))
        }
        .onAppear {
            syncPickerDate()
        }
        .onChange(of: dateString) { _, _ in
            syncPickerDate()
        }
        .sheet(isPresented: $isPickerPresented) {
            NavigationStack {
                VStack(spacing: 18) {
                    DatePicker(
                        title,
                        selection: $pickerDate,
                        in: Self.allowedBirthDateRange,
                        displayedComponents: .date
                    )
                    .datePickerStyle(.wheel)
                    .labelsHidden()
                    .environment(\.locale, Locale(identifier: "it_IT"))

                    Text(DateFormatter.birthDateItalian.string(from: pickerDate))
                        .font(.system(.headline, design: .rounded, weight: .bold))
                        .foregroundStyle(Brand.foreground)
                }
                .padding(20)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .background(Brand.background)
                .navigationTitle(title)
                .navigationBarTitleDisplayMode(.inline)
                .toolbar {
                    ToolbarItem(placement: .cancellationAction) {
                        Button("Annulla") {
                            isPickerPresented = false
                        }
                    }
                    ToolbarItem(placement: .confirmationAction) {
                        Button("Fine") {
                            dateString = DateFormatter.birthDateStorage.string(from: pickerDate)
                            isPickerPresented = false
                        }
                    }
                }
            }
            .presentationDetents([.height(380)])
            .presentationBackground(Brand.background)
        }
    }

    private var displayText: String {
        guard let date = parseBirthDate(dateString) else { return "DD-MM-YYYY" }
        return DateFormatter.birthDateItalian.string(from: date)
    }

    private func syncPickerDate() {
        pickerDate = parseBirthDate(dateString) ?? Self.defaultBirthDate
    }

    private static var allowedBirthDateRange: ClosedRange<Date> {
        let calendar = Calendar(identifier: .gregorian)
        let earliest = calendar.date(from: DateComponents(year: 1900, month: 1, day: 1)) ?? Date.distantPast
        return earliest...Date()
    }

    private static var defaultBirthDate: Date {
        Calendar(identifier: .gregorian).date(byAdding: .year, value: -25, to: Date()) ?? Date()
    }
}

