// MARK: - Helpers

struct EventStatusStyle {
    let label: String
    let background: Color
    let foreground: Color
}

struct DifficultyStyle {
    let text: String
    let background: Color
    let foreground: Color
}

private func categoryLabel(_ category: EventCategory?) -> String {
    let icon = category?.icon ?? "🏔️"
    let name = category?.name ?? "Evento"
    if icon.count <= 3, !name.contains(icon) {
        return "\(icon) \(name)"
    }
    return name
}

private func compactDifficultyText(_ difficulty: DifficultyStyle) -> String {
    let parts = difficulty.text.split(separator: " ")
    guard let first = parts.first, let last = parts.last, last.contains("/") else {
        return difficulty.text
    }
    return "\(first) \(last)"
}

private extension Event {
    var calendarDay: Date? {
        guard let date else { return nil }
        return DateFormatter.eventDate.date(from: date).map { Calendar.current.startOfDay(for: $0) }
    }

    var organizerDate: Date? {
        guard let date else { return nil }
        return DateFormatter.eventDate.date(from: date)
    }

    var organizerIsPastByDate: Bool {
        if ["past", "completed"].contains(normalizedStatus) { return true }
        guard let organizerDate else { return false }
        return organizerDate < Calendar.current.startOfDay(for: Date())
    }

    var organizerIsDraft: Bool {
        normalizedStatus == "draft"
    }

    var organizerIsCancelled: Bool {
        normalizedStatus == "cancelled"
    }

    var organizerIsPublishedUpcoming: Bool {
        !organizerIsPastByDate && !["draft", "cancelled", "archived", "past", "completed"].contains(normalizedStatus)
    }

    var organizerIsHistoric: Bool {
        organizerIsPastByDate && !organizerIsDraft && !organizerIsCancelled
    }

    var organizerCapacityWarning: (text: String, icon: String, color: Color)? {
        guard let total = spotsTotal, total > 0 else { return nil }
        let taken = spotsTaken ?? 0
        let spotsLeft = total - taken
        guard spotsLeft > 0 else { return nil }
        if spotsLeft <= 3 {
            let noun = spotsLeft == 1 ? "posto" : "posti"
            return ("Solo \(spotsLeft) \(noun) rimasti", "info.circle.fill", Brand.destructive)
        }
        if capacityFillRatio >= EventAvailabilityRules.lastSpotsFillRatio {
            return ("Quasi pieno", "flame.fill", Brand.warning)
        }
        return nil
    }

    var organizerDisplayName: String {
        organizerName?.nilIfBlank
            ?? organizerId.map { "Organizer \(String($0.prefix(8)))" }
            ?? "Organizzatore non assegnato"
    }

    var statusStyle: EventStatusStyle {
        if ["draft", "unpublished"].contains(normalizedStatus) {
            return EventStatusStyle(label: "Non pubblicato", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "cancelled" {
            return EventStatusStyle(label: "Annullato", background: Brand.destructive.opacity(0.12), foreground: Brand.destructive)
        }
        if normalizedStatus == "rescheduled" {
            return EventStatusStyle(label: "Riprogrammato", background: Brand.warning.opacity(0.15), foreground: Brand.warning)
        }
        if ["past", "completed"].contains(normalizedStatus) || isPastOrCancelled {
            return EventStatusStyle(label: "Concluso", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "closed" || normalizedStatus == "archived" {
            return EventStatusStyle(label: "Iscrizioni chiuse", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "upcoming" {
            return EventStatusStyle(label: "In arrivo", background: Brand.warning.opacity(0.15), foreground: Brand.warning)
        }
        if normalizedStatus == "full" || isFull {
            if hasWaitlistParticipationOption {
                return EventStatusStyle(label: "Lista d'attesa", background: Brand.secondary.opacity(0.15), foreground: Brand.secondary)
            }
            return EventStatusStyle(label: "Sold out", background: Brand.destructive.opacity(0.14), foreground: Brand.destructive)
        }
        return EventStatusStyle(label: "Aperto", background: Brand.success.opacity(0.16), foreground: Brand.success)
    }

    func cardStatusStyle(registration: Registration?) -> EventStatusStyle {
        if let registration, registration.blocksNewRegistration {
            if isPastOrCancelled, registration.checkedIn == true || registration.normalizedStatus == "attended" {
                return EventStatusStyle(label: "Partecipato", background: Brand.primary.opacity(0.15), foreground: Brand.primary)
            }
            if registration.waitlistSpotAvailable(in: self) {
                return EventStatusStyle(label: "Posto disponibile", background: Brand.success.opacity(0.16), foreground: Brand.success)
            }
            switch registration.normalizedStatus {
            case "registered", "paid", "attended", "deposit_paid":
                return EventStatusStyle(label: "Iscritto", background: Brand.success.opacity(0.16), foreground: Brand.success)
            case "waitlist":
                return EventStatusStyle(label: "In lista d'attesa", background: Brand.warning.opacity(0.16), foreground: Brand.warning)
            case "pending_approval":
                return EventStatusStyle(label: "Da approvare", background: Brand.warning.opacity(0.16), foreground: Brand.warning)
            case "pending_payment":
                return EventStatusStyle(label: "Pagamento", background: Brand.warning.opacity(0.16), foreground: Brand.warning)
            default:
                break
            }
        }

        if ["draft", "unpublished"].contains(normalizedStatus) {
            return EventStatusStyle(label: "Non pubblicato", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "cancelled" {
            return EventStatusStyle(label: "Annullato", background: Brand.destructive.opacity(0.12), foreground: Brand.destructive)
        }
        if normalizedStatus == "rescheduled" {
            return EventStatusStyle(label: "Riprogrammato", background: Brand.warning.opacity(0.15), foreground: Brand.warning)
        }
        if ["past", "completed"].contains(normalizedStatus) || isPastOrCancelled {
            return EventStatusStyle(label: "Concluso", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "closed" || normalizedStatus == "archived" {
            return EventStatusStyle(label: "Iscrizioni chiuse", background: Brand.muted, foreground: Brand.mutedForeground)
        }
        if normalizedStatus == "upcoming" {
            return EventStatusStyle(label: "In arrivo", background: Brand.warning.opacity(0.15), foreground: Brand.warning)
        }
        if normalizedStatus == "full" || isFull {
            if hasWaitlistParticipationOption {
                return EventStatusStyle(label: "Lista d'attesa", background: Brand.warning.opacity(0.16), foreground: Brand.warning)
            }
            return EventStatusStyle(label: "Sold out", background: Brand.destructive.opacity(0.14), foreground: Brand.destructive)
        }
        return EventStatusStyle(label: "Aperto", background: Brand.success.opacity(0.16), foreground: Brand.success)
    }

    var difficultyLabel: DifficultyStyle? {
        guard let difficulty, !difficulty.isEmpty else { return nil }
        switch difficulty {
        case "1", "beginner", "easy":
            return DifficultyStyle(text: "🌱 Prima Volta 1/5", background: Brand.success.opacity(0.22), foreground: Brand.primary)
        case "2":
            return DifficultyStyle(text: "🥾 Esploratore 2/5", background: Brand.success.opacity(0.22), foreground: Brand.primary)
        case "3":
            return DifficultyStyle(text: "⛰️ Escursionista 3/5", background: Brand.warning.opacity(0.26), foreground: Brand.foreground)
        case "4":
            return DifficultyStyle(text: "💪 Intrepido 4/5", background: Brand.destructive.opacity(0.22), foreground: Brand.destructive)
        case "5":
            return DifficultyStyle(text: "🔥 Avanzato 5/5", background: Color.pink.opacity(0.22), foreground: Color.pink)
        default:
            return DifficultyStyle(text: difficulty.capitalized, background: Brand.success.opacity(0.16), foreground: Brand.success)
        }
    }

    var difficultyLevel: Int? {
        guard let raw = difficulty?.nilIfBlank?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() else { return nil }
        if let numeric = Int(raw), (1...5).contains(numeric) {
            return numeric
        }
        if let numericText = raw.firstRegexCapture(#"\b([1-5])(?:\s*/\s*5)?\b"#),
           let numeric = Int(numericText) {
            return numeric
        }
        return [
            "beginner": 1,
            "easy": 1,
            "facile": 1,
            "introduzione": 1,
            "esploratore": 2,
            "intermedio": 3,
            "escursionista": 3,
            "impegnativo": 4,
            "intrepido": 4,
            "advanced": 5,
            "hard": 5,
            "expert": 5,
            "avanzato": 5
        ][raw]
    }

    var isLongerThan24Hours: Bool {
        (durationHours ?? 0) > 24
    }

    var isThisWeek: Bool {
        guard let date, let eventDate = DateFormatter.eventDate.date(from: date) else { return false }
        let calendar = Self.quickFilterCalendar
        let nowComponents = calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: Date())
        let eventComponents = calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: eventDate)
        return nowComponents.yearForWeekOfYear == eventComponents.yearForWeekOfYear && nowComponents.weekOfYear == eventComponents.weekOfYear
    }

    var isNextWeek: Bool {
        guard
            let date,
            let eventDate = DateFormatter.eventDate.date(from: date),
            let nextWeek = Self.quickFilterCalendar.date(byAdding: .weekOfYear, value: 1, to: Date())
        else { return false }
        let calendar = Self.quickFilterCalendar
        let nextWeekComponents = calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: nextWeek)
        let eventComponents = calendar.dateComponents([.yearForWeekOfYear, .weekOfYear], from: eventDate)
        return nextWeekComponents.yearForWeekOfYear == eventComponents.yearForWeekOfYear && nextWeekComponents.weekOfYear == eventComponents.weekOfYear
    }

    var isWeekend: Bool {
        guard let date, let eventDate = DateFormatter.eventDate.date(from: date) else { return false }
        let weekday = Self.quickFilterCalendar.component(.weekday, from: eventDate)
        return weekday == 1 || weekday == 6 || weekday == 7
    }

    static var quickFilterCalendar: Calendar {
        var calendar = Calendar(identifier: .gregorian)
        calendar.locale = Locale(identifier: "it_IT")
        calendar.firstWeekday = 2
        return calendar
    }

    var webURL: URL? {
        URL(string: "\(ScampagnateConfig.stripeOrigin)/event/\(id)")
    }

    var organizerWebURL: URL? {
        guard let organizerId = organizerId?.nilIfBlank else { return nil }
        return URL(string: "\(ScampagnateConfig.stripeOrigin)/organizer/\(organizerId)")
    }

    var isDemanding: Bool {
        guard let raw = difficulty?.nilIfBlank?.lowercased() else { return false }
        if let difficultyLevel {
            return difficultyLevel >= 4
        }
        return ["advanced", "hard", "expert", "difficult"].contains(raw)
    }

    var calendarStartDate: Date? {
        guard let dateValue = date, let eventDate = DateFormatter.eventDate.date(from: dateValue) else { return nil }
        var components = Calendar.current.dateComponents([.year, .month, .day], from: eventDate)
        if let time = time?.prefix(5) {
            let parts = time.split(separator: ":").compactMap { Int($0) }
            if parts.count == 2 {
                components.hour = parts[0]
                components.minute = parts[1]
            }
        }
        return Calendar.current.date(from: components)
    }

    func calendarEndDate(from start: Date) -> Date {
        Calendar.current.date(byAdding: .minute, value: durationMinutes ?? 180, to: start) ?? start.addingTimeInterval(3 * 60 * 60)
    }

    private var durationMinutes: Int? {
        guard let durationHours else { return nil }
        let total = Int((durationHours * 60).rounded())
        return total > 0 ? total : nil
    }

    private var durationHours: Double? {
        guard let duration = duration?.nilIfBlank?.lowercased() else { return nil }
        let days = durationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:giorn(?:o|i)?|gg|g|days?|d)\b"#)
        let hours = durationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:h|ore?|hours?)\b"#)
        let minutes = durationComponent(in: duration, matching: #"(\d+(?:[,.]\d+)?)\s*(?:m|min|mins|minuti?)\b"#)
        let total = days * 24 + hours + minutes / 60
        return total > 0 ? total : nil
    }

    private func durationComponent(in duration: String, matching pattern: String) -> Double {
        duration
            .firstRegexCapture(pattern)?
            .replacingOccurrences(of: ",", with: ".")
            .nilIfBlank
            .flatMap(Double.init) ?? 0
    }

