        "pet_friendly": "🐶 Friendly"
    ]
}

private func formatDate(_ value: String?) -> String {
    guard let value, let date = DateFormatter.eventDate.date(from: value) else { return "Data da definire" }
    let today = Calendar.current.startOfDay(for: Date())
    let day = Calendar.current.startOfDay(for: date)
    if day == today { return "Oggi" }
    if day == Calendar.current.date(byAdding: .day, value: 1, to: today) { return "Domani" }
    return DateFormatter.shortItalian.string(from: date)
}

private func formatLongDate(_ value: String?) -> String {
    guard let value, let date = DateFormatter.eventDate.date(from: value) else { return "Data da definire" }
    return DateFormatter.longItalian.string(from: date)
}

private func countdown(_ value: String?) -> String {
    guard let value, let date = DateFormatter.eventDate.date(from: value) else { return "Presto" }
    let days = Calendar.current.dateComponents([.day], from: Calendar.current.startOfDay(for: Date()), to: Calendar.current.startOfDay(for: date)).day ?? 0
    if days <= 0 { return "Oggi" }
    if days == 1 { return "Domani" }
    return "Tra \(days) giorni"
}

private func timeRange(_ event: Event) -> String {
    guard let time = event.time?.prefix(5) else { return "" }
    return String(time)
}

