    let number = phone.filter { $0.isNumber || $0 == "+" }
    let encoded = message.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? ""
    if let url = URL(string: "https://wa.me/\(number)?text=\(encoded)") {
        UIApplication.shared.open(url)
    }
}

