private func parseBirthDate(_ value: String) -> Date? {
    let cleanedValue = value.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !cleanedValue.isEmpty else { return nil }
    return DateFormatter.birthDateStorage.date(from: cleanedValue)
        ?? DateFormatter.birthDateItalian.date(from: cleanedValue)
        ?? DateFormatter.birthDateItalianSlashes.date(from: cleanedValue)
}

private func calculateAge(from birthDate: String) -> Int? {
    guard let date = parseBirthDate(birthDate) else { return nil }
    return Calendar.current.dateComponents([.year], from: date, to: Date()).year
}

private extension URL {
    func appendingPath(_ path: String) -> URL {
        URL(string: absoluteString.trimmingCharacters(in: CharacterSet(charactersIn: "/")) + path)!
    }

    var stripeCheckoutSessionId: String? {
        if let queryItems = URLComponents(url: self, resolvingAgainstBaseURL: false)?.queryItems,
           let item = queryItems.first(where: { $0.name == "session_id" || $0.name == "sessionId" })?.value {
            return item
        }
        let components = pathComponents
        if let payIndex = components.firstIndex(of: "pay"), components.indices.contains(payIndex + 1) {
            return components[payIndex + 1]
        }
        return components.first(where: { $0.hasPrefix("cs_") })
    }

    func queryValue(named name: String) -> String? {
        URLComponents(url: self, resolvingAgainstBaseURL: false)?
            .queryItems?
            .first(where: { $0.name == name })?
            .value?
            .nilIfBlank
    }

    var isScampagnatePaymentCancellation: Bool {
        scheme == "scampagnate" && (host == "payment-cancelled" || path.contains("payment-cancelled"))
    }
}

private extension Calendar {
    func startOfMonth(for date: Date) -> Date {
        let components = dateComponents([.year, .month], from: date)
        return self.date(from: components) ?? startOfDay(for: date)
    }

    func days(from start: Date, to end: Date) -> [Date] {
        var days: [Date] = []
        var current = startOfDay(for: start)
        let final = startOfDay(for: end)
        while current < final {
            days.append(current)
            guard let next = date(byAdding: .day, value: 1, to: current) else { break }
            current = next
        }
        return days
    }
}

private extension Color {
    init?(hex: String) {
        let cleaned = hex.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
        guard cleaned.count == 6,
              let value = Int(cleaned, radix: 16) else { return nil }

        let red = Double((value >> 16) & 0xFF) / 255.0
        let green = Double((value >> 8) & 0xFF) / 255.0
        let blue = Double(value & 0xFF) / 255.0
        self.init(red: red, green: green, blue: blue)
    }
}

private extension String {
    var urlEncoded: String {
        addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? self
    }

    var nilIfBlank: String? {
        let trimmed = trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    var isGeneratedPriceOptionName: Bool {
        trimmingCharacters(in: .whitespacesAndNewlines)
            .range(of: #"^formula(?:\s+\d+)?$"#, options: [.regularExpression, .caseInsensitive]) != nil
    }

    var priceOptionDisplayName: String {
        guard let cleanName = nilIfBlank, !cleanName.isGeneratedPriceOptionName else {
            return "Partecipazione evento"
        }
        return cleanName
    }

    var normalizedSearchText: String {
        folding(options: [.diacriticInsensitive, .caseInsensitive], locale: Locale(identifier: "it_IT"))
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
    }

    var normalizedSearchKey: String {
        normalizedSearchText
            .replacingOccurrences(of: #"\s+"#, with: " ", options: .regularExpression)
            .replacingOccurrences(of: #"[^\p{L}\p{N} ]+"#, with: "", options: .regularExpression)
    }

    var sanitizedStorageFileName: String {
        let allowed = CharacterSet(charactersIn: "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-")
        let sanitized = unicodeScalars.map { scalar in
            allowed.contains(scalar) ? String(scalar) : "-"
        }
        .joined()
        .replacingOccurrences(of: #"-+"#, with: "-", options: .regularExpression)
        .trimmingCharacters(in: CharacterSet(charactersIn: "-."))
        return String(sanitized.prefix(90))
    }

    var recommendationLabel: String {
        replacingOccurrences(of: "_", with: " ")
            .replacingOccurrences(of: "-", with: " ")
            .capitalized
    }

    var whatsAppPhone: String? {
        let allowed = CharacterSet(charactersIn: "+0123456789")
        let cleaned = unicodeScalars.filter { allowed.contains($0) }.map(String.init).joined()
        return cleaned.nilIfBlank
    }

    var notificationTypeKey: String? {
        nilIfBlank?
            .lowercased()
            .replacingOccurrences(of: "-", with: "_")
            .replacingOccurrences(of: " ", with: "_")
    }

    var firstInteger: Int? {
        range(of: #"\d+"#, options: .regularExpression).flatMap { Int(self[$0]) }
    }

    var readableProfileValue: String {
        replacingOccurrences(of: "_", with: " ")
            .replacingOccurrences(of: "-", with: " ")
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .nilIfBlank ?? self
    }

    var readableTrekkingValue: String {
        switch self {
        case "5_plus", "5+": return "5+"
        case "3_5", "3-5": return "3-5"
        case "1_2", "1-2": return "1-2"
        default: return readableProfileValue
        }
    }

    var webTrekkingValue: String {
        switch self {
        case "5_plus", "5+": return "5+"
        default: return self
        }
    }

    var organizerStatusLabel: String {
        switch self {
        case "draft", "unpublished": return "Non pubblicato"
        case "upcoming": return "In arrivo"
        case "published", "available", "open": return "Aperto"
        case "full": return "Sold out"
        case "closed": return "Iscrizioni chiuse"
        case "rescheduled": return "Riprogrammato"
        case "cancelled": return "Annullato"
        case "past", "completed": return "Concluso"
        case "registered": return "Iscritto"
        case "deposit_paid": return "Acconto pagato"
        case "paid": return "Pagato"
        case "waitlist": return "In lista d'attesa"
        case "attended": return "Presente"
        case "no_show": return "No-show"
        case "pending_approval": return "Da approvare"
        case "pending_payment": return "Pagamento in sospeso"
        default: return replacingOccurrences(of: "_", with: " ").capitalized
        }
