    var webPaymentStatusLabel: String {
        switch self {
        case "deposit_paid": return "Acconto pagato"
        case "paid": return "Pagato"
        case "pending": return "In sospeso"
        case "pay_on_location": return "Sul posto"
        case "not_required": return "Non richiesto"
        case "failed": return "Fallito"
        default: return replacingOccurrences(of: "_", with: " ").capitalized
        }
    }

    var csvEscaped: String {
        let escaped = replacingOccurrences(of: "\"", with: "\"\"")
        if escaped.contains(",") || escaped.contains("\n") || escaped.contains("\"") {
            return "\"\(escaped)\""
        }
        return escaped
    }

    var normalizedClosingSentence: String {
        replacingOccurrences(of: "^(?:✨\\s*)+", with: "", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var htmlAttributed: AttributedString? {
        guard let data = data(using: .utf8),
              let attributed = try? NSAttributedString(
                data: data,
                options: [
                    .documentType: NSAttributedString.DocumentType.html,
                    .characterEncoding: String.Encoding.utf8.rawValue
                ],
                documentAttributes: nil
              ) else { return nil }
        return AttributedString(attributed)
    }

    var htmlPlainText: String {
        guard let data = data(using: .utf8),
              let attributed = try? NSAttributedString(
                data: data,
                options: [
                    .documentType: NSAttributedString.DocumentType.html,
                    .characterEncoding: String.Encoding.utf8.rawValue
                ],
                documentAttributes: nil
              ) else {
            return htmlStripped
        }
        return attributed.string
            .replacingOccurrences(of: "\u{FFFC}", with: "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var containsHTMLMarkup: Bool {
        range(of: "<[a-zA-Z][^>]*>", options: .regularExpression) != nil
    }

    var normalizedInlineWhitespace: String {
        replacingOccurrences(of: "[\\t\\r\\n ]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var htmlStripped: String {
        replacingOccurrences(of: "<br\\s*/?>", with: "\n", options: [.regularExpression, .caseInsensitive])
            .replacingOccurrences(of: "</p>", with: "\n", options: [.regularExpression, .caseInsensitive])
            .replacingOccurrences(of: "<[^>]+>", with: "", options: .regularExpression)
            .replacingOccurrences(of: "&nbsp;", with: " ")
            .replacingOccurrences(of: "&amp;", with: "&")
            .replacingOccurrences(of: "&quot;", with: "\"")
            .replacingOccurrences(of: "&#39;", with: "'")
            .replacingOccurrences(of: "&rsquo;", with: "'")
            .replacingOccurrences(of: "&ldquo;", with: "\"")
            .replacingOccurrences(of: "&rdquo;", with: "\"")
            .replacingOccurrences(of: "\n\n\n+", with: "\n\n", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var isoDate: Date? {
        let fractional = ISO8601DateFormatter()
        fractional.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return fractional.date(from: self) ?? ISO8601DateFormatter().date(from: self)
    }

    var isSingleEmoji: Bool {
        count <= 2 && contains { $0.isEmoji }
    }

    var dynamicLucideName: String? {
        let trimmed = trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.lowercased().hasPrefix("lucide:") else { return nil }
        return String(trimmed.dropFirst("lucide:".count))
    }

    func firstRegexCapture(_ pattern: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: .caseInsensitive) else { return nil }
        let nsString = self as NSString
        guard let match = regex.firstMatch(in: self, range: NSRange(location: 0, length: nsString.length)),
              match.numberOfRanges > 1,
              match.range(at: 1).location != NSNotFound else { return nil }
        return nsString.substring(with: match.range(at: 1))
    }

    var webBadgeLucideName: String {
        switch trimmingCharacters(in: .whitespacesAndNewlines) {
        case "🌱": "sprout"
        case "🥾": "footprints"
        case "🗺", "🗺️": "compass"
        case "⛰", "⛰️": "mountain"
        case "🏆": "trophy"
        case "👑": "crown"
        case "🌅": "sunrise"
        case "🍸": "wine"
        case "🔥": "flame"
        case "💫": "sparkles"
        case "🏅": "medal"
        default: "sparkles"
        }
    }

    var supabaseSystemImage: String? {
        let trimmed = trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        let emojiMap: [String: String] = [
            "🌱": "leaf.fill",
            "🥾": "figure.walk",
            "🗺": "safari.fill",
            "🗺️": "safari.fill",
            "⛰": "mountain.2.fill",
            "⛰️": "mountain.2.fill",
            "🏆": "trophy.fill",
            "👑": "crown.fill",
            "🌅": "sunrise.fill",
            "🍸": "wineglass.fill",
            "🔥": "flame.fill",
            "💫": "sparkles",
            "🏅": "medal.fill",
            "🏛": "building.columns.fill",
            "🏛️": "building.columns.fill",
            "💪": "figure.strengthtraining.traditional",
            "⭐": "star.fill"
        ]
        if let image = emojiMap[trimmed] { return image }

        let rawIconName: String
        if trimmed.lowercased().hasPrefix("lucide:") {
            rawIconName = String(trimmed.dropFirst("lucide:".count))
        } else {
            rawIconName = trimmed
        }

        let key = rawIconName
            .replacingOccurrences(of: "-", with: "")
            .replacingOccurrences(of: "_", with: "")
            .replacingOccurrences(of: " ", with: "")
            .lowercased()

        let lucideMap: [String: String] = [
            "award": "rosette",
            "badge": "rosette",
            "beermug": "mug.fill",
            "checkcircle": "checkmark.circle.fill",
            "compass": "safari.fill",
            "crown": "crown.fill",
            "flame": "flame.fill",
            "flagtriangleright": "flag.fill",
            "footprints": "figure.walk",
            "gift": "gift.fill",
            "medal": "medal.fill",
            "mountain": "mountain.2.fill",
            "sparkles": "sparkles",
            "sprout": "leaf.fill",
            "star": "star.fill",
            "target": "target",
            "ticket": "ticket.fill",
            "trophy": "trophy.fill",
            "wine": "wineglass.fill"
        ]
        return lucideMap[key]
    }

    var badgeSystemImage: String {
        supabaseSystemImage ?? "rosette"
    }

    var shortDateLabel: String? {
        guard let date = iso8601Date else { return nil }
        return DateFormatter.shortItalian.string(from: date)
    }

    var iso8601Date: Date? {
        let cleanedValue = trimmingCharacters(in: .whitespacesAndNewlines)
        guard !cleanedValue.isEmpty else { return nil }

        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        if let date = formatter.date(from: cleanedValue) {
            return date
        }

        if let date = ISO8601DateFormatter().date(from: cleanedValue) {
            return date
        }

        let dateOnlyFormatter = ISO8601DateFormatter()
        dateOnlyFormatter.formatOptions = [.withFullDate]
        return dateOnlyFormatter.date(from: cleanedValue)
    }
}

private extension Array where Element: Hashable {
    func removingDuplicates() -> [Element] {
        var seen = Set<Element>()
        return filter { seen.insert($0).inserted }
    }
}

private extension Array {
    func chunked(maxSize: Int) -> [[Element]] {
        guard maxSize > 0 else { return [self] }
        return stride(from: 0, to: count, by: maxSize).map {
            Array(self[$0..<Swift.min($0 + maxSize, count)])
        }
    }
}

private let defaultEventClosingSentences = [
    "Porta leggerezza, al resto pensiamo noi",
    "Una community che arriva per i sentieri... e resta per le persone",
    "Il difficile è venire. Poi non vorrai più andare via",
    "Fidati: sarà una di quelle giornate che ricordi",
    "Vieni con lo spirito giusto - il resto viene da sé",
    "Qui si conoscono persone, non solo posti"
]

private func deterministicClosingSentence(seed: String) -> String {
    let hash = seed.enumerated().reduce(0) { partial, pair in
        partial + Int(pair.element.unicodeScalars.first?.value ?? 0) * (pair.offset + 1)
    }
    return defaultEventClosingSentences[hash % defaultEventClosingSentences.count]
}

private func normalizeInterestCategory(_ value: String?) -> String? {
    guard let value = value?.nilIfBlank else { return nil }
    if interestAffinity[value] != nil { return value }
    let labelsById = [
        "trekking_giornalieri": "Trekking giornalieri",
        "cammini_plurigiornalieri": "Cammini plurigiornalieri",
        "notti_tenda": "Notti in tenda",
        "trekking_notturni": "Trekking notturni",
        "aperitivi_cene": "Aperitivi e cene",
        "sport_movimento": "Sport e movimento",
        "giochi_sfide": "Giochi e sfide",
        "weekend_fuori_porta": "Weekend fuori porta",
        "degustazioni_cantine": "Degustazioni e cantine",
        "mare_spiaggia": "Mare e spiaggia",
        "social": "Aperitivi e cene",
        "sport": "Sport e movimento",
        "food": "Aperitivi e cene",
        "trekking": "Trekking giornalieri",
        "nature": "Trekking giornalieri"
    ]
    return labelsById[value]
}

